export const useAppStore = create<AppState>()(
  persist(
    (set, get, store) => ({
      ...createNavigationSlice(set, get, store),
      ...createCoreSlice(set, get, store),

      ...createProgressSlice(set, get, store),

      ...createAuthSlice(set, get, store),
      ...createEventSlice(set, get, store),

      ...createDailyGrindSlice(set, get, store),
      ...createArenaSlice(set, get, store),
      ...createMockExamSlice(set, get, store),
      ...createSqlSlice(set, get, store),
      ...createAchievementSlice(set, get, store),
      ...createRealmSlice(set, get, store),
      ...createSyndicateSlice(set, get, store),

      ...createAdminSlice(set, get, store),
    }),
    {
      name: "codesnap-arena",
      storage: createJSONStorage(() => localStorage),
      partialize: partializeAppState,
      merge: mergeAppState,
    },
  ),
);

export function shouldSkipPublicDossierFetch(userId: string): boolean {
  const s = useAppStore.getState();
  return dossierMemoryHit(s, userId) && s.publicDossierData?.userId === userId;
}
