import { createClient, type SupabaseClient } from "@supabase/supabase-js";

let singleton: SupabaseClient | null = null;

function readEnv(): { url: string; anonKey: string } | null {
  const rawUrl = (import.meta.env.VITE_SUPABASE_URL as string | undefined)?.trim();
  const rawKey = (import.meta.env.VITE_SUPABASE_ANON_KEY as string | undefined)?.trim();
  if (!rawUrl || !rawKey) return null;
  const url = rawUrl.replace(/\uFEFF/g, "").replace(/\/+$/, "");
  const anonKey = rawKey.replace(/\uFEFF/g, "").replace(/\s+/g, "");
  if (!url || !anonKey) return null;
  return { url, anonKey };
}

/**
 * Singleton Supabase-Browser-Client (VITE_SUPABASE_URL + VITE_SUPABASE_ANON_KEY)
 * Liefert null wenn die Uplink-Umgebung nicht gesetzt ist
 */
export function getSupabase(): SupabaseClient | null {
  const env = readEnv();
  if (!env) return null;
  if (!singleton) {
    singleton = createClient(env.url, env.anonKey, {
      auth: {
        persistSession: true,
        autoRefreshToken: true,
        detectSessionInUrl: true,
        storage: typeof window !== "undefined" ? window.localStorage : undefined,
      },
    });
  }
  return singleton;
}

/** Nur für Tests oder Hot-Reload-Edgecases — setzt den Singleton zurück */
export function resetSupabaseClient(): void {
  singleton = null;
}
