type MasteryCertificateProps = {
  open: boolean;
  onClose: () => void;
  masteryPercent: number;
  solvedUnits: number;
  totalUnits: number;
  curriculumLabel: string;
  currentLevel: number;
  currentTitle: string;
  totalQueriesSolved: number;
};

export function MasteryCertificate({
  open,
  onClose,
  masteryPercent,
  solvedUnits,
  totalUnits,
  curriculumLabel,
  currentLevel,
  currentTitle,
  totalQueriesSolved,
}: MasteryCertificateProps) {
  if (!open) return null;

  const stampDate = new Date().toLocaleDateString("de-DE");

  async function shareResult() {
    const text = `${curriculumLabel} Mastery ${masteryPercent}% Level ${currentLevel} Rank ${currentTitle} Queries ${totalQueriesSolved}`;
    if (typeof navigator !== "undefined" && navigator.share) {
      try {
        await navigator.share({ title: "CodeSnap Mastery", text });
        return;
      } catch {
        return;
      }
    }
    if (typeof navigator !== "undefined" && navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(text);
    }
  }

  function buildCertificateSvg(): string {
    return `<svg xmlns="http://www.w3.org/2000/svg" width="1200" height="630" viewBox="0 0 1200 630">
<defs>
<linearGradient id="bg" x1="0" y1="0" x2="1" y2="1">
<stop offset="0%" stop-color="#04121a"/>
<stop offset="100%" stop-color="#120723"/>
</linearGradient>
</defs>
<rect width="1200" height="630" fill="url(#bg)"/>
<rect x="30" y="30" width="1140" height="570" rx="22" fill="none" stroke="#45F3FF" stroke-opacity="0.8" stroke-width="2"/>
<text x="70" y="95" fill="#45F3FF" font-size="24" font-family="Inter,Arial,sans-serif" letter-spacing="3">CODESNAP ACADEMY</text>
<text x="70" y="170" fill="#E2FBFF" font-size="54" font-weight="700" font-family="Inter,Arial,sans-serif">Digital Mastery Certificate</text>
<text x="70" y="225" fill="#9FE9FF" font-size="30" font-family="Inter,Arial,sans-serif">${curriculumLabel}</text>
<text x="70" y="285" fill="#6DFFB4" font-size="28" font-family="Inter,Arial,sans-serif">Level ${currentLevel}  Rank ${currentTitle}</text>
<text x="70" y="335" fill="#D2F7FF" font-size="26" font-family="Inter,Arial,sans-serif">Progress ${masteryPercent}%</text>
<text x="70" y="375" fill="#D2F7FF" font-size="26" font-family="Inter,Arial,sans-serif">Solved ${solvedUnits} of ${totalUnits}</text>
<text x="70" y="415" fill="#D2F7FF" font-size="26" font-family="Inter,Arial,sans-serif">Total Queries Solved ${totalQueriesSolved}</text>
<text x="70" y="500" fill="#88DFFF" font-size="20" font-family="Inter,Arial,sans-serif">Issued ${stampDate}</text>
<text x="70" y="540" fill="#88DFFF" font-size="20" font-family="Inter,Arial,sans-serif">Keep training keep learning</text>
</svg>`;
  }

  function downloadBlob(filename: string, blob: Blob) {
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    link.click();
    window.setTimeout(() => URL.revokeObjectURL(url), 800);
  }

  function exportSvg() {
    const svg = buildCertificateSvg();
    downloadBlob("codesnap-certificate.svg", new Blob([svg], { type: "image/svg+xml;charset=utf-8" }));
  }

  function exportPng() {
    const svg = buildCertificateSvg();
    const img = new Image();
    const svgBlob = new Blob([svg], { type: "image/svg+xml;charset=utf-8" });
    const svgUrl = URL.createObjectURL(svgBlob);
    img.onload = () => {
      const canvas = document.createElement("canvas");
      canvas.width = 1200;
      canvas.height = 630;
      const ctx = canvas.getContext("2d");
      if (!ctx) {
        URL.revokeObjectURL(svgUrl);
        return;
      }
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
      canvas.toBlob((blob) => {
        if (blob) downloadBlob("codesnap-certificate.png", blob);
        URL.revokeObjectURL(svgUrl);
      }, "image/png");
    };
    img.src = svgUrl;
  }

  return (
    <div className="fixed inset-0 z-[560] flex items-center justify-center bg-black/70 p-4" role="dialog" aria-modal="true" aria-label="Mastery Zertifikat">
      <div className="w-full max-w-xl rounded-xl border border-cyan-400/45 bg-slate-950/95 p-6 shadow-[0_0_28px_rgb(0_229_255_/_0.2)]">
        <p className="text-[10px] uppercase tracking-[0.2em] text-cyan-300">CodeSnap Academy</p>
        <h3 className="mt-2 text-2xl font-semibold text-cyan-100">Digital Mastery Certificate</h3>
        <p className="mt-3 text-sm text-slate-200">{curriculumLabel}</p>
        <p className="mt-1 text-sm text-slate-300">Progress {masteryPercent}%</p>
        <p className="mt-1 text-sm text-slate-300">Solved {solvedUnits} von {totalUnits}</p>
        <p className="mt-1 text-sm text-slate-300">Level {currentLevel}</p>
        <p className="mt-1 text-sm text-slate-300">Champion Rank {currentTitle}</p>
        <p className="mt-1 text-sm text-slate-300">Total Queries Solved {totalQueriesSolved}</p>
        <div className="mt-6 flex flex-wrap gap-3">
          <button
            type="button"
            className="rounded-md border border-cyan-300/55 bg-cyan-950/35 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-cyan-100"
            onClick={shareResult}
          >
            Share Result
          </button>
          <button
            type="button"
            className="rounded-md border border-fuchsia-300/55 bg-fuchsia-950/35 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-fuchsia-100"
            onClick={exportPng}
          >
            Export PNG
          </button>
          <button
            type="button"
            className="rounded-md border border-cyan-300/55 bg-cyan-950/35 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-cyan-100"
            onClick={exportSvg}
          >
            Export SVG
          </button>
          <button
            type="button"
            className="rounded-md border border-slate-500/60 bg-slate-900/70 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-slate-200"
            onClick={onClose}
          >
            Schliessen
          </button>
        </div>
      </div>
    </div>
  );
}
