import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useRef, useState } from "react";
import { LORE_REGISTRY } from "../../data/loreRegistry";
import { useFeedback } from "../../hooks/useFeedback";
import { cn } from "../../lib/cn";
import { getGlobalFrictionData, refreshGlobalLoreStateAndPulse } from "../../lib/syncController";
import { getAudioRuntimeHealth } from "../../lib/webAudioUi";
import { useAppStore } from "../../store/useAppStore";

type RuntimeAudio = ReturnType<typeof getAudioRuntimeHealth>;
type CorePulseProfile = {
  humPeriodSec: number;
  pulseDuration: number;
};

type DialogueEntry = {
  id: string;
  role: "operator" | "core";
  raw: string;
  shown: string;
  done: boolean;
};

function tokenizeCommand(input: string): { cmd: string; args: string[] } {
  const clean = input.trim();
  if (!clean) return { cmd: "", args: [] };
  const parts = clean.split(/\s+/);
  return { cmd: parts[0]?.toUpperCase() ?? "", args: parts.slice(1) };
}

function synthesizeAdviceLine(params: {
  friction: number;
  module: string;
  overdriveActive: boolean;
  overdriveModule: string | null;
}): string {
  const frictionPct = Math.round(params.friction * 100);
  if (params.overdriveActive) {
    return `TACTICAL VECTOR LOCK MODULE ${params.overdriveModule ?? "UNKNOWN"} PRIORITY BURN HOLD ACCURACY CHAIN`;
  }
  if (frictionPct >= 35) {
    return `HIGH DRAG DETECTED MODULE ${params.module.toUpperCase()} SWITCH TO CONTROLLED PACE FIRST HIT DISCIPLINE`;
  }
  if (frictionPct >= 20) {
    return `MEDIUM DRAG MODULE ${params.module.toUpperCase()} REINFORCE BLUEPRINT PATTERNS AND ERROR REVIEW LOOP`;
  }
  return `LOW DRAG STABLE GRID MAINTAIN COMBO RHYTHM AND FARM PRECISION XP`;
}

function matrixMask(text: string, revealed: number): string {
  const glyph = "01#%<>[]{}";
  if (revealed >= text.length) return text;
  const shown = text.slice(0, revealed);
  const restLen = Math.max(0, text.length - revealed);
  let scrambled = "";
  for (let i = 0; i < restLen; i += 1) scrambled += glyph[(i * 7 + revealed * 3) % glyph.length]!;
  return shown + scrambled;
}

export function VoidCore() {
  const prefersReduced = !!useReducedMotion();
  const feedback = useFeedback();
  const overdrive = useAppStore((s) => s.activeEventModifier);
  const friction = useAppStore((s) => s.globalFrictionAvg);
  const activity = useAppStore((s) => s.nexusActivity.length);
  const feedbackEnabled = useAppStore((s) => s.feedbackEnabled);
  const audioActivityTick = useAppStore((s) => s.audioActivityTick);
  const globalLore = useAppStore((s) => s.globalLore);
  const userLevel = useAppStore((s) => s.userLevel);
  const syncStatus = useAppStore((s) => s.syncStatus);
  const duelState = useAppStore((s) => s.duelState);
  const neuralOutbreak = useAppStore((s) => s.neuralOutbreak);

  const [audioRuntime, setAudioRuntime] = useState<RuntimeAudio>(() => getAudioRuntimeHealth());
  const [hovered, setHovered] = useState(false);
  const [impulse, setImpulse] = useState(0);
  const [consoleOpen, setConsoleOpen] = useState(false);
  const [input, setInput] = useState("");
  const [dialogue, setDialogue] = useState<DialogueEntry[]>([
    {
      id: "boot-core",
      role: "core",
      raw: "VOID CORE ONLINE AWAITING DIRECTIVE",
      shown: "VOID CORE ONLINE AWAITING DIRECTIVE",
      done: true,
    },
  ]);
  const [streamTargetId, setStreamTargetId] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => {
    const id = window.setInterval(() => setAudioRuntime(getAudioRuntimeHealth()), 1200);
    return () => window.clearInterval(id);
  }, []);

  const humPeriodSec = audioRuntime.ambientActive && feedbackEnabled ? 8.33 : 5.8;
  const frictionBoost = 1 + Math.max(0, Math.min(1, friction)) * 1.1;
  const overdriveBoost = overdrive ? 1.45 : 1;
  const hotZoneBoost = duelState?.bountyHotZone ? 1.28 : 1;
  const outbreakBoost = neuralOutbreak.infected ? 1.22 : 1;
  const pulseProfile: CorePulseProfile = {
    humPeriodSec,
    pulseDuration: Math.max(1.6, humPeriodSec / (frictionBoost * overdriveBoost * hotZoneBoost * outbreakBoost)),
  };
  const pulseDuration = pulseProfile.pulseDuration;
  const density = Math.min(22, 8 + Math.round(friction * 10) + (overdrive ? 6 : 0) + Math.min(4, activity / 12));
  const aura = neuralOutbreak.infected
    ? "from-emerald-400/42 via-lime-300/34 to-cyan-300/30"
    : duelState?.bountyHotZone
    ? "from-red-500/42 via-fuchsia-400/34 to-cyan-300/28"
    : overdrive
      ? "from-orange-400/35 via-fuchsia-300/30 to-cyan-300/28"
      : "from-cyan-400/26 via-fuchsia-300/18 to-transparent";

  const particles = useMemo(
    () =>
      Array.from({ length: density }, (_, i) => ({
        id: i,
        angle: (i / Math.max(1, density)) * Math.PI * 2,
        radius: 58 + ((i * 13) % 56),
        size: 2 + (i % 4),
        dur: 2.3 + (i % 5) * 0.35,
      })),
    [density],
  );

  useEffect(() => {
    if (!consoleOpen) return;
    const id = window.setTimeout(() => inputRef.current?.focus(), 140);
    return () => window.clearTimeout(id);
  }, [consoleOpen]);

  useEffect(() => {
    if (!streamTargetId) return;
    const id = window.setInterval(() => {
      setDialogue((rows) =>
        rows.map((row) => {
          if (row.id !== streamTargetId || row.done) return row;
          const nextCount = Math.min(row.raw.length, row.shown.length + 2);
          const done = nextCount >= row.raw.length;
          return {
            ...row,
            shown: matrixMask(row.raw, done ? row.raw.length : nextCount),
            done,
          };
        }),
      );
    }, prefersReduced ? 0 : 24);
    return () => window.clearInterval(id);
  }, [prefersReduced, streamTargetId]);

  useEffect(() => {
    if (!streamTargetId) return;
    const row = dialogue.find((x) => x.id === streamTargetId);
    if (!row || row.done) setStreamTargetId(null);
  }, [dialogue, streamTargetId]);

  const pushCoreLine = (text: string) => {
    const id = `core-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
    const clean = text.trim();
    if (!clean) return;
    const nextEntry: DialogueEntry = {
      id,
      role: "core",
      raw: clean,
      shown: prefersReduced ? clean : matrixMask(clean, 0),
      done: prefersReduced,
    };
    setDialogue((rows) => [...rows, nextEntry].slice(-18));
    if (!prefersReduced) setStreamTargetId(id);
  };

  const onSend = async () => {
    const raw = input.trim();
    if (!raw) return;
    const operatorId = `op-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
    const operatorLine: DialogueEntry = {
      id: operatorId,
      role: "operator",
      raw,
      shown: raw,
      done: true,
    };
    setDialogue((rows) => [...rows, operatorLine].slice(-18));
    setInput("");

    const { cmd } = tokenizeCommand(raw);
    const snapshot = await getGlobalFrictionData();
    const top = snapshot.rows[0];
    const topModule = top?.module ?? "process";
    const topFriction = top?.frictionRate ?? friction;

    if (cmd === "STATUS") {
      pushCoreLine(
        `STATUS UPLINK ${syncStatus.toUpperCase()} FRICTION ${Math.round(topFriction * 100)} OVERDRIVE ${overdrive ? "ACTIVE" : "IDLE"} LEVEL ${userLevel} LORE ${globalLore.unlockedLoreIds.length}`,
      );
      return;
    }
    if (cmd === "LORE") {
      await refreshGlobalLoreStateAndPulse();
      const refreshedLore = useAppStore.getState().globalLore;
      const unlocked = refreshedLore.unlockedLoreIds;
      const latest = unlocked.length > 0 ? LORE_REGISTRY.find((x) => x.id === unlocked[unlocked.length - 1]) : null;
      if (!latest) {
        pushCoreLine(`LORE LOCKED GLOBAL_XP ${refreshedLore.totalGlobalXp} NEXT ${LORE_REGISTRY[0]?.xpThreshold ?? 0}`);
        return;
      }
      pushCoreLine(`LORE FRAGMENT ${latest.title.toUpperCase()} THRESHOLD ${latest.xpThreshold} GLOBAL_XP ${refreshedLore.totalGlobalXp}`);
      return;
    }
    if (cmd === "ADVICE") {
      pushCoreLine(
        synthesizeAdviceLine({
          friction: topFriction,
          module: topModule,
          overdriveActive: !!overdrive,
          overdriveModule: overdrive?.targetModule ?? null,
        }),
      );
      return;
    }

    pushCoreLine(
      `UNKNOWN DIRECTIVE MAP STATUS LORE ADVICE PRIMARY MODULE ${String(topModule).toUpperCase()} FRICTION ${Math.round(topFriction * 100)}`,
    );
  };

  void audioActivityTick;

  return (
    <section className="relative overflow-hidden border border-cyan-300/22 bg-black/40 p-4 sm:p-5">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.05]" />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.16]" />
      <div className="relative flex flex-col items-center gap-3">
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.32em] text-cyan-200/85">
          V O I D Core
        </p>
        {duelState?.bountyHotZone ? (
          <motion.p
            className="font-mono text-[9px] font-black uppercase tracking-[0.24em] text-red-100"
            animate={prefersReduced ? { opacity: 1 } : { opacity: [0.45, 1, 0.5], x: [0, 1, -1, 0] }}
            transition={prefersReduced ? { duration: 0 } : { duration: 0.5, repeat: Infinity, ease: "linear" }}
          >
            SIREN HOT ZONE CONTRACT LIVE
          </motion.p>
        ) : null}
        {neuralOutbreak.infected ? (
          <motion.p
            className="font-mono text-[9px] font-black uppercase tracking-[0.24em] text-emerald-100"
            animate={prefersReduced ? { opacity: 1 } : { opacity: [0.45, 1, 0.55], x: [0, -1, 1, 0] }}
            transition={prefersReduced ? { duration: 0 } : { duration: 0.62, repeat: Infinity, ease: "linear" }}
          >
            MATRIX INFECTION ACTIVE PURGE {neuralOutbreak.progress}/{Math.max(1, neuralOutbreak.target)}
          </motion.p>
        ) : null}

        <motion.button
          type="button"
          onPointerEnter={() => {
            if (!hovered) feedback.hoverTick();
            setHovered(true);
          }}
          onPointerLeave={() => setHovered(false)}
          onClick={() => {
            setImpulse((n) => n + 1);
            feedback.menuTap();
            setConsoleOpen((v) => !v);
          }}
          className={cn(
            "relative grid place-items-center rounded-full border border-cyan-300/28 bg-black/55 p-12 sm:p-14",
            "shadow-[0_0_36px_rgb(56_189_248/0.2),inset_0_0_30px_rgb(56_189_248/0.14)]",
          )}
          aria-label="Void Core Interface"
        >
          <motion.div
            className={cn("absolute inset-2 rounded-full bg-gradient-to-br blur-xl", aura)}
            animate={
              prefersReduced
                ? { opacity: 0.55 }
                : { opacity: [0.28, 0.74, 0.33, 0.62], scale: [0.97, 1.06, 1, 1.03] }
            }
            transition={{ duration: pulseDuration, repeat: Infinity, ease: "linear" }}
          />

          <motion.div
            key={`imp-${impulse}`}
            className="absolute inset-5 rounded-full border border-fuchsia-300/45"
            initial={{ opacity: 0.7, scale: 0.72 }}
            animate={{ opacity: 0, scale: 1.32 }}
            transition={{ duration: prefersReduced ? 0.001 : 0.9, ease: "easeOut" }}
          />

          <motion.div
            className="absolute inset-4 rounded-full border border-cyan-300/35"
            animate={prefersReduced ? { rotate: 0 } : { rotate: overdrive ? 360 : 220 }}
            transition={{ duration: overdrive ? 3.4 : 8.4, repeat: Infinity, ease: "linear" }}
          />
          <motion.div
            className="absolute inset-9 rounded-full border border-fuchsia-300/30"
            animate={prefersReduced ? { rotate: 0 } : { rotate: overdrive ? -300 : -180 }}
            transition={{ duration: overdrive ? 4.1 : 9.6, repeat: Infinity, ease: "linear" }}
          />
          <motion.div
            className="relative size-14 rounded-full bg-gradient-to-br from-cyan-200/45 via-fuchsia-200/45 to-transparent shadow-[0_0_30px_rgb(56_189_248/0.35)]"
            animate={
              prefersReduced
                ? { scale: 1 }
                : { scale: hovered ? [1, 1.11, 1.03] : [0.98, 1.07, 1], filter: ["hue-rotate(0deg)", "hue-rotate(26deg)", "hue-rotate(0deg)"] }
            }
            transition={{ duration: Math.max(1.6, pulseDuration * 0.7), repeat: Infinity, ease: "easeInOut" }}
          />

          {particles.map((p) => (
            <motion.span
              key={p.id}
              className="pointer-events-none absolute rounded-full bg-cyan-200/70"
              style={{
                width: p.size,
                height: p.size,
                left: `calc(50% + ${Math.cos(p.angle) * p.radius}px)`,
                top: `calc(50% + ${Math.sin(p.angle) * p.radius}px)`,
              }}
              animate={prefersReduced ? { opacity: 0.35 } : { opacity: [0.1, 0.9, 0.16], scale: [0.7, 1.45, 0.85] }}
              transition={{ duration: p.dur, repeat: Infinity, ease: "easeInOut", delay: (p.id % 5) * 0.14 }}
            />
          ))}
        </motion.button>

        <p className="font-mono text-[9px] uppercase tracking-[0.18em] text-cyan-100/80">
          Adaptive neural shell friction {Math.round(friction * 100)} pulse {pulseDuration.toFixed(1)}s
        </p>

        <AnimatePresence initial={false}>
          {consoleOpen ? (
            <motion.div
              initial={prefersReduced ? false : { opacity: 0, y: -10, scaleY: 0.9 }}
              animate={{ opacity: 1, y: 0, scaleY: 1 }}
              exit={prefersReduced ? undefined : { opacity: 0, y: -8, scaleY: 0.92 }}
              transition={{ duration: prefersReduced ? 0 : 0.2, ease: [0.22, 1, 0.36, 1] }}
              className="relative w-full max-w-3xl border border-cyan-300/28 bg-black/55 p-3 shadow-[inset_0_0_20px_rgb(56_189_248/0.12)]"
            >
              <div className="pointer-events-none absolute inset-0 opacity-[0.08]" />
              <div className="mb-2 max-h-44 overflow-auto border border-cyan-300/18 bg-black/65 p-2 question-scrollbar">
                {dialogue.map((row) => (
                  <p
                    key={row.id}
                    className={cn(
                      "font-mono text-[10px] uppercase tracking-[0.12em]",
                      row.role === "operator" ? "text-cyan-200/88" : "text-fuchsia-200/88",
                    )}
                  >
                    {row.role === "operator" ? "OP " : "VOID "}
                    {row.shown}
                  </p>
                ))}
              </div>

              <div className="flex items-center gap-2 border border-cyan-300/28 bg-black/70 px-2 py-1">
                <span className="font-mono text-[10px] uppercase tracking-[0.16em] text-cyan-200/90">Input</span>
                <input
                  ref={inputRef}
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") {
                      e.preventDefault();
                      void onSend();
                    }
                  }}
                  placeholder="STATUS LORE ADVICE"
                  className="w-full border-0 bg-transparent font-mono text-[11px] uppercase tracking-[0.12em] text-cyan-100 outline-none placeholder:text-cyan-400/45"
                />
                <button
                  type="button"
                  onClick={() => void onSend()}
                  className="border border-cyan-300/35 bg-cyan-500/12 px-2 py-1 font-mono text-[9px] font-bold uppercase tracking-[0.14em] text-cyan-100 hover:bg-cyan-500/20"
                >
                  Send
                </button>
              </div>
            </motion.div>
          ) : null}
        </AnimatePresence>
      </div>
    </section>
  );
}
