import { create } from "zustand";
import type { SqlUniverseId } from "../data/universes";
import { DEFAULT_ACADEMY_LOCALE, academyLoreTitles, type AcademyLocale } from "../i18n/academyStrings";

const STORAGE_KEY = "codesnap-academy-progress-v1";

type ChapterProgress = {
  solvedTaskIds: string[];
  masteredQuizIds: string[];
};

type UniverseProgress = Record<string, ChapterProgress>;

type AcademyAchievementId =
  | "first_gains"
  | "streak_five"
  | "quiz_apprentice"
  | "hundred_club"
  | "career_five";

type AchievementToastItem = {
  id: string;
  achievementId: AcademyAchievementId;
  label: string;
};

type AcademyMetaState = {
  totalXP: number;
  currentLevel: number;
  currentTitle: string;
  dailyStreak: number;
  lastActiveYmd: string | null;
  awardedTaskIds: string[];
  awardedQuizIds: string[];
  careerCompletedIds: string[];
  unlockedAchievementIds: AcademyAchievementId[];
};

type MetaByUniverse = Record<SqlUniverseId, AcademyMetaState>;

type XpGainEvent = {
  nonce: number;
  universeId: SqlUniverseId;
  chapterId: string;
  entityId: string;
  entityType: "task" | "quiz";
  amount: number;
};

type LevelUpEvent = {
  nonce: number;
  universeId: SqlUniverseId;
  newLevel: number;
  newTitle: string;
};

type ChapterTimer = {
  attempts: number;
  personalBestMs: number | null;
  currentRunMs: number;
  lastStartedAtMs: number | null;
  isRunning: boolean;
};

type TimerByChapter = Record<string, ChapterTimer>;
type TimerByUniverse = Record<SqlUniverseId, TimerByChapter>;

type LeagueTier = "Bronze" | "Silver" | "Gold" | "Platinum" | "Diamond" | "Master";
type PreferredSqlDialect = "postgresql" | "mysql" | "sqlite";
type LearningTrack = "sql" | "web_basics" | "c_sharp";

type SpeedrunPbEntry = {
  universeId: SqlUniverseId;
  chapterId: string;
  personalBestMs: number;
  recordedAtMs: number;
};

type WebTrackProgress = {
  masteredWebStepIds: string[];
  masteredCSharpMissionIds: string[];
  systemStatusText: string;
  shieldValue: number;
  inventoryItems: string[];
  droidPowerLevel: number;
  updatedAtMs: number | null;
};

type GlobalRankingState = {
  masteryScore: number;
  league: LeagueTier;
  preferredDialect: PreferredSqlDialect;
  preferredTrack: LearningTrack;
  webTrackProgress: WebTrackProgress;
  speedrunPbQueue: SpeedrunPbEntry[];
  lastSyncedAtMs: number | null;
};

type CloudSnapshot = {
  v: 1;
  l: AcademyLocale;
  p: Record<SqlUniverseId, UniverseProgress>;
  m: MetaByUniverse;
  t: TimerByUniverse;
  g?: GlobalRankingState;
};

type GlobalSyncInput = {
  snapshot: Partial<CloudSnapshot>;
};

type AcademyProgressState = {
  locale: AcademyLocale;
  byUniverse: Record<SqlUniverseId, UniverseProgress>;
  metaByUniverse: MetaByUniverse;
  achievementToastQueue: AchievementToastItem[];
  persistenceHealthy: boolean;
  lastXpGain: XpGainEvent | null;
  lastLevelUp: LevelUpEvent | null;
  timerByUniverse: TimerByUniverse;
  globalRanking: GlobalRankingState;
  markTaskSolved: (input: { universeId: SqlUniverseId; chapterId: string; taskId: string; solved: boolean }) => void;
  setLocale: (locale: AcademyLocale) => void;
  markQuizMastered: (input: { universeId: SqlUniverseId; chapterId: string; quizId: string }) => void;
  markCareerAssignmentCompleted: (input: { universeId: SqlUniverseId; assignmentId: string }) => void;
  countCareerAssignmentsCompleted: (universeId: SqlUniverseId) => number;
  isQuizMastered: (input: { universeId: SqlUniverseId; chapterId: string; quizId: string }) => boolean;
  countChapterSolvedTasks: (input: { universeId: SqlUniverseId; chapterId: string }) => number;
  countChapterMasteredQuizzes: (input: { universeId: SqlUniverseId; chapterId: string }) => number;
  getUniverseMeta: (universeId: SqlUniverseId) => AcademyMetaState;
  getChapterTimer: (input: { universeId: SqlUniverseId; chapterId: string }) => ChapterTimer;
  startChapterRun: (input: { universeId: SqlUniverseId; chapterId: string }) => void;
  pauseChapterRun: (input: { universeId: SqlUniverseId; chapterId: string }) => void;
  finishChapterRun: (input: { universeId: SqlUniverseId; chapterId: string }) => void;
  syncGlobalRankings: () => void;
  syncGlobalProgress: (input: GlobalSyncInput) => boolean;
  queueSpeedrunPbForSync: (input: { universeId: SqlUniverseId; chapterId: string; personalBestMs: number }) => void;
  flushSpeedrunPbQueue: () => SpeedrunPbEntry[];
  getLeagueTier: () => LeagueTier;
  getPreferredDialect: () => PreferredSqlDialect;
  setPreferredDialect: (dialect: PreferredSqlDialect) => void;
  getPreferredTrack: () => LearningTrack;
  setPreferredTrack: (track: LearningTrack) => void;
  getWebTrackProgress: () => WebTrackProgress;
  setWebTrackProgress: (input: Partial<WebTrackProgress>) => void;
  getCloudSnapshot: () => CloudSnapshot;
  ingestCloudSnapshot: (snapshot: unknown) => boolean;
  isPersistenceHealthy: () => boolean;
  dismissAchievementToast: () => void;
  resetUniverseProgress: (universeId: SqlUniverseId) => void;
};

function levelFromXP(xp: number): number {
  return Math.max(1, Math.floor(Math.sqrt(Math.max(0, xp) / 120)) + 1);
}

export function getUniverseTitle(level: number, universeId: SqlUniverseId, locale: AcademyLocale = DEFAULT_ACADEMY_LOCALE): string {
  const rankStep = Math.min(5, Math.floor((Math.max(1, level) - 1) / 2));
  const lore = academyLoreTitles[locale];
  return lore[universeId][rankStep] ?? lore[universeId][0];
}

function ymdNow(): string {
  const now = new Date();
  const y = now.getFullYear();
  const m = String(now.getMonth() + 1).padStart(2, "0");
  const d = String(now.getDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
}

function yesterdayYmd(input: string): string {
  const dt = new Date(`${input}T00:00:00`);
  dt.setDate(dt.getDate() - 1);
  const y = dt.getFullYear();
  const m = String(dt.getMonth() + 1).padStart(2, "0");
  const d = String(dt.getDate()).padStart(2, "0");
  return `${y}-${m}-${d}`;
}

function emptyUniverseProgress(): UniverseProgress {
  return {};
}

function emptyMeta(): AcademyMetaState {
  return {
    totalXP: 0,
    currentLevel: 1,
    currentTitle: getUniverseTitle(1, "bodybuilding"),
    dailyStreak: 0,
    lastActiveYmd: null,
    awardedTaskIds: [],
    awardedQuizIds: [],
    careerCompletedIds: [],
    unlockedAchievementIds: [],
  };
}

function defaultState(): Record<SqlUniverseId, UniverseProgress> {
  return {
    star_wars: emptyUniverseProgress(),
    nutrition: emptyUniverseProgress(),
    cs_tactical: emptyUniverseProgress(),
    anime: emptyUniverseProgress(),
    warzone: emptyUniverseProgress(),
    wow: emptyUniverseProgress(),
    bodybuilding: emptyUniverseProgress(),
  };
}

function defaultMetaState(): MetaByUniverse {
  return {
    star_wars: { ...emptyMeta(), currentTitle: getUniverseTitle(1, "star_wars") },
    nutrition: { ...emptyMeta(), currentTitle: getUniverseTitle(1, "nutrition") },
    cs_tactical: { ...emptyMeta(), currentTitle: getUniverseTitle(1, "cs_tactical") },
    anime: { ...emptyMeta(), currentTitle: getUniverseTitle(1, "anime") },
    warzone: { ...emptyMeta(), currentTitle: getUniverseTitle(1, "warzone") },
    wow: { ...emptyMeta(), currentTitle: getUniverseTitle(1, "wow") },
    bodybuilding: { ...emptyMeta(), currentTitle: getUniverseTitle(1, "bodybuilding") },
  };
}

function emptyTimer(): ChapterTimer {
  return {
    attempts: 0,
    personalBestMs: null,
    currentRunMs: 0,
    lastStartedAtMs: null,
    isRunning: false,
  };
}

function defaultTimerState(): TimerByUniverse {
  return {
    star_wars: {},
    nutrition: {},
    cs_tactical: {},
    anime: {},
    warzone: {},
    wow: {},
    bodybuilding: {},
  };
}

function resolveLeagueTier(score: number): LeagueTier {
  if (score >= 95) return "Master";
  if (score >= 86) return "Diamond";
  if (score >= 72) return "Platinum";
  if (score >= 56) return "Gold";
  if (score >= 38) return "Silver";
  return "Bronze";
}

function defaultGlobalRanking(): GlobalRankingState {
  return {
    masteryScore: 0,
    league: "Bronze",
    preferredDialect: "postgresql",
    preferredTrack: "sql",
    webTrackProgress: {
      masteredWebStepIds: [],
      masteredCSharpMissionIds: [],
      systemStatusText: "Standby",
      shieldValue: 100,
      inventoryItems: [],
      droidPowerLevel: 0,
      updatedAtMs: null,
    },
    speedrunPbQueue: [],
    lastSyncedAtMs: null,
  };
}

function mergeWebTrackProgress(local: WebTrackProgress, remote?: Partial<WebTrackProgress>): WebTrackProgress {
  if (!remote) return local;
  return {
    masteredWebStepIds: Array.from(new Set([...(local.masteredWebStepIds ?? []), ...(remote.masteredWebStepIds ?? [])])),
    masteredCSharpMissionIds: Array.from(
      new Set([...(local.masteredCSharpMissionIds ?? []), ...(remote.masteredCSharpMissionIds ?? [])]),
    ),
    systemStatusText: remote.systemStatusText ?? local.systemStatusText,
    shieldValue:
      typeof remote.shieldValue === "number"
        ? Math.max(0, Math.min(100, Math.round(remote.shieldValue)))
        : local.shieldValue,
    inventoryItems: Array.from(new Set([...(local.inventoryItems ?? []), ...(remote.inventoryItems ?? [])])),
    droidPowerLevel:
      typeof remote.droidPowerLevel === "number"
        ? Math.max(0, Math.min(100, Math.round(remote.droidPowerLevel)))
        : local.droidPowerLevel,
    updatedAtMs: Math.max(local.updatedAtMs ?? 0, remote.updatedAtMs ?? 0) || null,
  };
}

function mergeUniverseProgressState(
  local: Record<SqlUniverseId, UniverseProgress>,
  remote: Record<SqlUniverseId, UniverseProgress>,
): Record<SqlUniverseId, UniverseProgress> {
  const merged = { ...local };
  const universeIds = Object.keys(local) as SqlUniverseId[];
  for (const universeId of universeIds) {
    const localUniverse = local[universeId] ?? {};
    const remoteUniverse = remote[universeId] ?? {};
    const chapterIds = new Set([...Object.keys(localUniverse), ...Object.keys(remoteUniverse)]);
    const nextUniverse: UniverseProgress = {};
    for (const chapterId of chapterIds) {
      const localChapter = localUniverse[chapterId] ?? { solvedTaskIds: [], masteredQuizIds: [] };
      const remoteChapter = remoteUniverse[chapterId] ?? { solvedTaskIds: [], masteredQuizIds: [] };
      nextUniverse[chapterId] = {
        solvedTaskIds: Array.from(new Set([...localChapter.solvedTaskIds, ...remoteChapter.solvedTaskIds])),
        masteredQuizIds: Array.from(new Set([...localChapter.masteredQuizIds, ...remoteChapter.masteredQuizIds])),
      };
    }
    merged[universeId] = nextUniverse;
  }
  return merged;
}

function computeMasteryScore(input: {
  byUniverse: Record<SqlUniverseId, UniverseProgress>;
  metaByUniverse: MetaByUniverse;
  timerByUniverse: TimerByUniverse;
}): number {
  const solvedUnits = Object.values(input.byUniverse).reduce(
    (acc, universe) =>
      acc +
      Object.values(universe).reduce((sum, chapter) => sum + chapter.solvedTaskIds.length + chapter.masteredQuizIds.length, 0),
    0,
  );
  const xpSum = Object.values(input.metaByUniverse).reduce((acc, meta) => acc + meta.totalXP, 0);
  const speedSignals = Object.values(input.timerByUniverse).flatMap((chapterMap) =>
    Object.values(chapterMap)
      .map((timer) => timer.personalBestMs)
      .filter((value): value is number => typeof value === "number" && value > 0),
  );
  const speedBonus = speedSignals.length > 0 ? Math.round(120000 / Math.max(1, Math.min(...speedSignals))) : 0;
  const rawScore = solvedUnits * 2.2 + xpSum / 60 + speedBonus;
  return Math.max(0, Math.min(100, Math.round(rawScore)));
}

function ensureTimer(timerMap: TimerByChapter, chapterId: string): ChapterTimer {
  return timerMap[chapterId] ?? emptyTimer();
}

function runTimestamp(timer: ChapterTimer | undefined): number {
  return timer?.lastStartedAtMs ?? 0;
}

function mergeTimerState(local: TimerByUniverse, remote: TimerByUniverse): TimerByUniverse {
  const merged = defaultTimerState();
  const universeIds = Object.keys(merged) as SqlUniverseId[];
  for (const universeId of universeIds) {
    const localChapterMap = local[universeId] ?? {};
    const remoteChapterMap = remote[universeId] ?? {};
    const chapterIds = new Set([...Object.keys(localChapterMap), ...Object.keys(remoteChapterMap)]);
    const nextMap: TimerByChapter = {};
    for (const chapterId of chapterIds) {
      const localTimer = localChapterMap[chapterId];
      const remoteTimer = remoteChapterMap[chapterId];
      const winner = runTimestamp(remoteTimer) > runTimestamp(localTimer) ? remoteTimer : localTimer;
      if (winner) nextMap[chapterId] = winner;
    }
    merged[universeId] = nextMap;
  }
  return merged;
}

function readInitial(): {
  locale: AcademyLocale;
  byUniverse: Record<SqlUniverseId, UniverseProgress>;
  metaByUniverse: MetaByUniverse;
  timerByUniverse: TimerByUniverse;
  globalRanking: GlobalRankingState;
} {
  if (typeof window === "undefined") {
    return {
      locale: DEFAULT_ACADEMY_LOCALE,
      byUniverse: defaultState(),
      metaByUniverse: defaultMetaState(),
      timerByUniverse: defaultTimerState(),
      globalRanking: defaultGlobalRanking(),
    };
  }
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return {
        locale: DEFAULT_ACADEMY_LOCALE,
        byUniverse: defaultState(),
        metaByUniverse: defaultMetaState(),
        timerByUniverse: defaultTimerState(),
        globalRanking: defaultGlobalRanking(),
      };
    }
    const parsed = JSON.parse(raw) as {
      locale?: AcademyLocale;
      byUniverse?: Partial<Record<SqlUniverseId, UniverseProgress>>;
      metaByUniverse?: Partial<Record<SqlUniverseId, AcademyMetaState>>;
      timerByUniverse?: Partial<Record<SqlUniverseId, TimerByChapter>>;
      globalRanking?: Partial<GlobalRankingState>;
    };
    const locale = parsed.locale === "en" ? "en" : "de";
    const byUniverse = {
      ...defaultState(),
      ...(parsed.byUniverse ?? {}),
    };
    const metaByUniverse = {
      ...defaultMetaState(),
      ...(parsed.metaByUniverse
        ? Object.fromEntries(
            Object.entries(parsed.metaByUniverse).map(([k, v]) => [
              k,
              {
                ...emptyMeta(),
                ...v,
                currentLevel: levelFromXP(v?.totalXP ?? 0),
                currentTitle: getUniverseTitle(levelFromXP(v?.totalXP ?? 0), k as SqlUniverseId, locale),
              },
            ]),
          )
        : {}),
    } as MetaByUniverse;
    const timerByUniverse = {
      ...defaultTimerState(),
      ...(parsed.timerByUniverse ?? {}),
    } as TimerByUniverse;
    const masteryScore = computeMasteryScore({ byUniverse, metaByUniverse, timerByUniverse });
    const globalRanking: GlobalRankingState = {
      ...defaultGlobalRanking(),
      ...(parsed.globalRanking ?? {}),
      webTrackProgress: mergeWebTrackProgress(
        defaultGlobalRanking().webTrackProgress,
        parsed.globalRanking?.webTrackProgress,
      ),
      masteryScore,
      league: resolveLeagueTier(masteryScore),
      speedrunPbQueue: parsed.globalRanking?.speedrunPbQueue ?? [],
    };
    return {
      locale,
      byUniverse,
      metaByUniverse,
      timerByUniverse,
      globalRanking,
    };
  } catch {
    return {
      locale: DEFAULT_ACADEMY_LOCALE,
      byUniverse: defaultState(),
      metaByUniverse: defaultMetaState(),
      timerByUniverse: defaultTimerState(),
      globalRanking: defaultGlobalRanking(),
    };
  }
}

function writePersisted(next: {
  locale: AcademyLocale;
  byUniverse: Record<SqlUniverseId, UniverseProgress>;
  metaByUniverse: MetaByUniverse;
  timerByUniverse: TimerByUniverse;
  globalRanking: GlobalRankingState;
}): boolean {
  if (typeof window === "undefined") return true;
  try {
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(next));
    return true;
  } catch {
    return false;
  }
}

function ensureChapter(progress: UniverseProgress, chapterId: string): ChapterProgress {
  return progress[chapterId] ?? { solvedTaskIds: [], masteredQuizIds: [] };
}

function unlockAchievementIfNeeded(input: {
  meta: AcademyMetaState;
  byUniverse: UniverseProgress;
  chapterId: string;
  queue: AchievementToastItem[];
}): { nextMeta: AcademyMetaState; nextQueue: AchievementToastItem[] } {
  let nextMeta = { ...input.meta };
  let nextQueue = [...input.queue];

  const chapter = ensureChapter(input.byUniverse, input.chapterId);
  const totalSolvedTasks = Object.values(input.byUniverse).reduce((acc, row) => acc + row.solvedTaskIds.length, 0);
  const totalSolvedQuizzes = Object.values(input.byUniverse).reduce((acc, row) => acc + row.masteredQuizIds.length, 0);

  function award(id: AcademyAchievementId, label: string) {
    if (nextMeta.unlockedAchievementIds.includes(id)) return;
    nextMeta = {
      ...nextMeta,
      unlockedAchievementIds: [...nextMeta.unlockedAchievementIds, id],
    };
    nextQueue = [
      ...nextQueue,
      {
        id: `${id}-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
        achievementId: id,
        label,
      },
    ];
  }

  if (totalSolvedTasks >= 1) award("first_gains", "First Gains freigeschaltet");
  if (chapter.solvedTaskIds.length >= 5) award("streak_five", "Five In A Row freigeschaltet");
  if (totalSolvedQuizzes >= 5) award("quiz_apprentice", "Quiz Apprentice freigeschaltet");
  if (totalSolvedTasks + totalSolvedQuizzes >= 20) award("hundred_club", "Hundred Club freigeschaltet");
  if (input.meta.careerCompletedIds.length >= 5) award("career_five", "Legendary Career freigeschaltet");

  return { nextMeta, nextQueue };
}

const initialSnapshot = readInitial();

export const useAcademyStore = create<AcademyProgressState>((set, get) => ({
  locale: initialSnapshot.locale,
  byUniverse: initialSnapshot.byUniverse,
  metaByUniverse: initialSnapshot.metaByUniverse,
  achievementToastQueue: [],
  persistenceHealthy: true,
  lastXpGain: null,
  lastLevelUp: null,
  timerByUniverse: initialSnapshot.timerByUniverse,
  globalRanking: initialSnapshot.globalRanking,

  setLocale: (locale) =>
    set((state) => {
      if (state.locale === locale) return {};
      const metaByUniverse = Object.fromEntries(
        (Object.keys(state.metaByUniverse) as SqlUniverseId[]).map((universeId) => {
          const meta = state.metaByUniverse[universeId] ?? emptyMeta();
          return [
            universeId,
            {
              ...meta,
              currentTitle: getUniverseTitle(meta.currentLevel, universeId, locale),
            },
          ];
        }),
      ) as MetaByUniverse;
      const persistenceHealthy = writePersisted({
        locale,
        byUniverse: state.byUniverse,
        metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking: state.globalRanking,
      });
      return { locale, metaByUniverse, persistenceHealthy };
    }),

  markTaskSolved: ({ universeId, chapterId, taskId, solved }) =>
    set((state) => {
      const universe = state.byUniverse[universeId] ?? {};
      const chapter = ensureChapter(universe, chapterId);
      const prevMeta = state.metaByUniverse[universeId] ?? emptyMeta();
      const nextSolved = solved
        ? Array.from(new Set([...chapter.solvedTaskIds, taskId]))
        : chapter.solvedTaskIds.filter((id) => id !== taskId);
      const nextUniverse: UniverseProgress = {
        ...universe,
        [chapterId]: {
          ...chapter,
          solvedTaskIds: nextSolved,
        },
      };
      let nextMeta = prevMeta;
      let toastQueue = state.achievementToastQueue;
      let xpEvent: XpGainEvent | null = null;
      let levelUpEvent: LevelUpEvent | null = null;
      const taskLedgerId = `${chapterId}:${taskId}`;
      if (solved && !prevMeta.awardedTaskIds.includes(taskLedgerId)) {
        const today = ymdNow();
        const streak =
          prevMeta.lastActiveYmd === today
            ? prevMeta.dailyStreak
            : prevMeta.lastActiveYmd === yesterdayYmd(today)
              ? prevMeta.dailyStreak + 1
              : 1;
        const totalXP = prevMeta.totalXP + 18;
        const nextLevel = levelFromXP(totalXP);
        const nextTitle = getUniverseTitle(nextLevel, universeId, state.locale);
        nextMeta = {
          ...prevMeta,
          totalXP,
          currentLevel: nextLevel,
          currentTitle: nextTitle,
          dailyStreak: streak,
          lastActiveYmd: today,
          awardedTaskIds: [...prevMeta.awardedTaskIds, taskLedgerId],
        };
        if (nextLevel > prevMeta.currentLevel) {
          levelUpEvent = {
            nonce: Date.now(),
            universeId,
            newLevel: nextLevel,
            newTitle: nextTitle,
          };
        }
        xpEvent = {
          nonce: Date.now(),
          universeId,
          chapterId,
          entityId: taskId,
          entityType: "task",
          amount: 18,
        };
      }
      const unlocked = unlockAchievementIfNeeded({
        meta: nextMeta,
        byUniverse: nextUniverse,
        chapterId,
        queue: toastQueue,
      });
      nextMeta = unlocked.nextMeta;
      toastQueue = unlocked.nextQueue;

      const byUniverse = { ...state.byUniverse, [universeId]: nextUniverse };
      const metaByUniverse = { ...state.metaByUniverse, [universeId]: nextMeta };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse,
        metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking: state.globalRanking,
      });
      return {
        byUniverse,
        metaByUniverse,
        achievementToastQueue: toastQueue,
        persistenceHealthy,
        lastXpGain: xpEvent,
        lastLevelUp: levelUpEvent ?? state.lastLevelUp,
      };
    }),

  markQuizMastered: ({ universeId, chapterId, quizId }) =>
    set((state) => {
      const universe = state.byUniverse[universeId] ?? {};
      const chapter = ensureChapter(universe, chapterId);
      const prevMeta = state.metaByUniverse[universeId] ?? emptyMeta();
      const nextUniverse: UniverseProgress = {
        ...universe,
        [chapterId]: {
          ...chapter,
          masteredQuizIds: Array.from(new Set([...chapter.masteredQuizIds, quizId])),
        },
      };
      let nextMeta = prevMeta;
      let toastQueue = state.achievementToastQueue;
      let xpEvent: XpGainEvent | null = null;
      let levelUpEvent: LevelUpEvent | null = null;
      const quizLedgerId = `${chapterId}:${quizId}`;
      if (!prevMeta.awardedQuizIds.includes(quizLedgerId)) {
        const today = ymdNow();
        const streak =
          prevMeta.lastActiveYmd === today
            ? prevMeta.dailyStreak
            : prevMeta.lastActiveYmd === yesterdayYmd(today)
              ? prevMeta.dailyStreak + 1
              : 1;
        const totalXP = prevMeta.totalXP + 24;
        const nextLevel = levelFromXP(totalXP);
        const nextTitle = getUniverseTitle(nextLevel, universeId, state.locale);
        nextMeta = {
          ...prevMeta,
          totalXP,
          currentLevel: nextLevel,
          currentTitle: nextTitle,
          dailyStreak: streak,
          lastActiveYmd: today,
          awardedQuizIds: [...prevMeta.awardedQuizIds, quizLedgerId],
        };
        if (nextLevel > prevMeta.currentLevel) {
          levelUpEvent = {
            nonce: Date.now(),
            universeId,
            newLevel: nextLevel,
            newTitle: nextTitle,
          };
        }
        xpEvent = {
          nonce: Date.now(),
          universeId,
          chapterId,
          entityId: quizId,
          entityType: "quiz",
          amount: 24,
        };
      }

      const unlocked = unlockAchievementIfNeeded({
        meta: nextMeta,
        byUniverse: nextUniverse,
        chapterId,
        queue: toastQueue,
      });
      nextMeta = unlocked.nextMeta;
      toastQueue = unlocked.nextQueue;

      const byUniverse = { ...state.byUniverse, [universeId]: nextUniverse };
      const metaByUniverse = { ...state.metaByUniverse, [universeId]: nextMeta };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse,
        metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking: state.globalRanking,
      });
      return {
        byUniverse,
        metaByUniverse,
        achievementToastQueue: toastQueue,
        persistenceHealthy,
        lastXpGain: xpEvent,
        lastLevelUp: levelUpEvent ?? state.lastLevelUp,
      };
    }),

  markCareerAssignmentCompleted: ({ universeId, assignmentId }) =>
    set((state) => {
      const prevMeta = state.metaByUniverse[universeId] ?? emptyMeta();
      if (prevMeta.careerCompletedIds.includes(assignmentId)) return {};
      let nextMeta: AcademyMetaState = {
        ...prevMeta,
        careerCompletedIds: [...prevMeta.careerCompletedIds, assignmentId],
      };
      const unlocked = unlockAchievementIfNeeded({
        meta: nextMeta,
        byUniverse: state.byUniverse[universeId] ?? {},
        chapterId: "career",
        queue: state.achievementToastQueue,
      });
      nextMeta = unlocked.nextMeta;
      const metaByUniverse = { ...state.metaByUniverse, [universeId]: nextMeta };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking: state.globalRanking,
      });
      return {
        metaByUniverse,
        achievementToastQueue: unlocked.nextQueue,
        persistenceHealthy,
      };
    }),

  countCareerAssignmentsCompleted: (universeId) => {
    const meta = get().metaByUniverse[universeId] ?? emptyMeta();
    return meta.careerCompletedIds.length;
  },

  isQuizMastered: ({ universeId, chapterId, quizId }) => {
    const universe = get().byUniverse[universeId] ?? {};
    const chapter = ensureChapter(universe, chapterId);
    return chapter.masteredQuizIds.includes(quizId);
  },

  countChapterSolvedTasks: ({ universeId, chapterId }) => {
    const universe = get().byUniverse[universeId] ?? {};
    const chapter = ensureChapter(universe, chapterId);
    return chapter.solvedTaskIds.length;
  },

  countChapterMasteredQuizzes: ({ universeId, chapterId }) => {
    const universe = get().byUniverse[universeId] ?? {};
    const chapter = ensureChapter(universe, chapterId);
    return chapter.masteredQuizIds.length;
  },

  getUniverseMeta: (universeId) => get().metaByUniverse[universeId] ?? emptyMeta(),
  getChapterTimer: ({ universeId, chapterId }) => {
    const universeTimers = get().timerByUniverse[universeId] ?? {};
    const timer = ensureTimer(universeTimers, chapterId);
    if (!timer.isRunning || timer.lastStartedAtMs === null) return timer;
    return {
      ...timer,
      currentRunMs: timer.currentRunMs + Math.max(0, Date.now() - timer.lastStartedAtMs),
    };
  },
  startChapterRun: ({ universeId, chapterId }) =>
    set((state) => {
      const universeTimers = state.timerByUniverse[universeId] ?? {};
      const current = ensureTimer(universeTimers, chapterId);
      if (current.isRunning) return {};
      const next: ChapterTimer = {
        ...current,
        attempts: current.attempts + 1,
        currentRunMs: 0,
        lastStartedAtMs: Date.now(),
        isRunning: true,
      };
      const nextUniverse = { ...universeTimers, [chapterId]: next };
      const timerByUniverse = { ...state.timerByUniverse, [universeId]: nextUniverse };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse,
        globalRanking: state.globalRanking,
      });
      return { timerByUniverse, persistenceHealthy };
    }),
  pauseChapterRun: ({ universeId, chapterId }) =>
    set((state) => {
      const universeTimers = state.timerByUniverse[universeId] ?? {};
      const current = ensureTimer(universeTimers, chapterId);
      if (!current.isRunning || current.lastStartedAtMs === null) return {};
      const elapsed = Math.max(0, Date.now() - current.lastStartedAtMs);
      const next: ChapterTimer = {
        ...current,
        currentRunMs: current.currentRunMs + elapsed,
        lastStartedAtMs: null,
        isRunning: false,
      };
      const nextUniverse = { ...universeTimers, [chapterId]: next };
      const timerByUniverse = { ...state.timerByUniverse, [universeId]: nextUniverse };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse,
        globalRanking: state.globalRanking,
      });
      return { timerByUniverse, persistenceHealthy };
    }),
  finishChapterRun: ({ universeId, chapterId }) =>
    set((state) => {
      const universeTimers = state.timerByUniverse[universeId] ?? {};
      const current = ensureTimer(universeTimers, chapterId);
      const liveElapsed = current.isRunning && current.lastStartedAtMs !== null ? Math.max(0, Date.now() - current.lastStartedAtMs) : 0;
      const finalMs = current.currentRunMs + liveElapsed;
      const nextBest = current.personalBestMs === null ? finalMs : Math.min(current.personalBestMs, finalMs);
      const pbImproved = current.personalBestMs === null || nextBest < current.personalBestMs;
      const next: ChapterTimer = {
        ...current,
        personalBestMs: nextBest,
        currentRunMs: 0,
        lastStartedAtMs: null,
        isRunning: false,
      };
      const nextUniverse = { ...universeTimers, [chapterId]: next };
      const timerByUniverse = { ...state.timerByUniverse, [universeId]: nextUniverse };
      const globalRanking: GlobalRankingState = pbImproved
        ? {
            ...state.globalRanking,
            speedrunPbQueue: [
              ...state.globalRanking.speedrunPbQueue,
              {
                universeId,
                chapterId,
                personalBestMs: nextBest,
                recordedAtMs: Date.now(),
              },
            ],
          }
        : state.globalRanking;
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse,
        globalRanking,
      });
      return { timerByUniverse, globalRanking, persistenceHealthy };
    }),
  syncGlobalRankings: () =>
    set((state) => {
      const masteryScore = computeMasteryScore({
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse: state.timerByUniverse,
      });
      const globalRanking: GlobalRankingState = {
        ...state.globalRanking,
        masteryScore,
        league: resolveLeagueTier(masteryScore),
        lastSyncedAtMs: Date.now(),
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking,
      });
      return { globalRanking, persistenceHealthy };
    }),
  syncGlobalProgress: ({ snapshot }) => {
    const remote = snapshot as Partial<CloudSnapshot> | null;
    if (!remote || remote.v !== 1 || !remote.p || !remote.m || !remote.t) return false;
    set((state) => {
      const mergedByUniverse = mergeUniverseProgressState(state.byUniverse, { ...defaultState(), ...remote.p });
      const nextMetaByUniverse = { ...state.metaByUniverse, ...remote.m } as MetaByUniverse;
      const remoteTimerByUniverse = { ...defaultTimerState(), ...remote.t } as TimerByUniverse;
      const nextTimerByUniverse = mergeTimerState(state.timerByUniverse, remoteTimerByUniverse);
      const masteryScore = computeMasteryScore({
        byUniverse: mergedByUniverse,
        metaByUniverse: nextMetaByUniverse,
        timerByUniverse: nextTimerByUniverse,
      });
      const nextGlobalRanking: GlobalRankingState = {
        ...state.globalRanking,
        ...(remote.g ?? {}),
        webTrackProgress: mergeWebTrackProgress(state.globalRanking.webTrackProgress, remote.g?.webTrackProgress),
        masteryScore,
        league: resolveLeagueTier(masteryScore),
        speedrunPbQueue: state.globalRanking.speedrunPbQueue,
        lastSyncedAtMs: Date.now(),
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: mergedByUniverse,
        metaByUniverse: nextMetaByUniverse,
        timerByUniverse: nextTimerByUniverse,
        globalRanking: nextGlobalRanking,
      });
      return {
        byUniverse: mergedByUniverse,
        metaByUniverse: nextMetaByUniverse,
        timerByUniverse: nextTimerByUniverse,
        globalRanking: nextGlobalRanking,
        persistenceHealthy,
      };
    });
    return true;
  },
  queueSpeedrunPbForSync: ({ universeId, chapterId, personalBestMs }) =>
    set((state) => {
      const entry: SpeedrunPbEntry = {
        universeId,
        chapterId,
        personalBestMs,
        recordedAtMs: Date.now(),
      };
      const globalRanking: GlobalRankingState = {
        ...state.globalRanking,
        speedrunPbQueue: [...state.globalRanking.speedrunPbQueue, entry],
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking,
      });
      return { globalRanking, persistenceHealthy };
    }),
  flushSpeedrunPbQueue: () => {
    const queued = get().globalRanking.speedrunPbQueue;
    set((state) => {
      const globalRanking: GlobalRankingState = {
        ...state.globalRanking,
        speedrunPbQueue: [],
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking,
      });
      return { globalRanking, persistenceHealthy };
    });
    return queued;
  },
  getLeagueTier: () => get().globalRanking.league,
  getPreferredDialect: () => get().globalRanking.preferredDialect,
  setPreferredDialect: (dialect) =>
    set((state) => {
      if (state.globalRanking.preferredDialect === dialect) return {};
      const globalRanking: GlobalRankingState = {
        ...state.globalRanking,
        preferredDialect: dialect,
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking,
      });
      return { globalRanking, persistenceHealthy };
    }),
  getPreferredTrack: () => get().globalRanking.preferredTrack,
  setPreferredTrack: (track) =>
    set((state) => {
      if (state.globalRanking.preferredTrack === track) return {};
      const globalRanking: GlobalRankingState = {
        ...state.globalRanking,
        preferredTrack: track,
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking,
      });
      return { globalRanking, persistenceHealthy };
    }),
  getWebTrackProgress: () => get().globalRanking.webTrackProgress,
  setWebTrackProgress: (input) =>
    set((state) => {
      const webTrackProgress = mergeWebTrackProgress(state.globalRanking.webTrackProgress, input);
      const globalRanking: GlobalRankingState = {
        ...state.globalRanking,
        webTrackProgress: {
          ...webTrackProgress,
          updatedAtMs: Date.now(),
        },
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse: state.byUniverse,
        metaByUniverse: state.metaByUniverse,
        timerByUniverse: state.timerByUniverse,
        globalRanking,
      });
      return { globalRanking, persistenceHealthy };
    }),
  getCloudSnapshot: () => {
    const state = get();
    return {
      v: 1,
      l: state.locale,
      p: state.byUniverse,
      m: state.metaByUniverse,
      t: state.timerByUniverse,
      g: state.globalRanking,
    };
  },
  ingestCloudSnapshot: (snapshot) => {
    const data = snapshot as Partial<CloudSnapshot> | null;
    if (!data || data.v !== 1 || !data.p || !data.m || !data.t) return false;
    const locale: AcademyLocale = data.l === "en" ? "en" : "de";
    const nextByUniverse = { ...defaultState(), ...data.p };
    const nextMetaByUniverse = { ...defaultMetaState(), ...data.m } as MetaByUniverse;
    const nextTimerByUniverse = { ...defaultTimerState(), ...data.t } as TimerByUniverse;
    const computedMasteryScore = computeMasteryScore({
      byUniverse: nextByUniverse,
      metaByUniverse: nextMetaByUniverse,
      timerByUniverse: nextTimerByUniverse,
    });
    const nextGlobalRanking: GlobalRankingState = {
      ...defaultGlobalRanking(),
      ...(data.g ?? {}),
      webTrackProgress: mergeWebTrackProgress(defaultGlobalRanking().webTrackProgress, data.g?.webTrackProgress),
      masteryScore: computedMasteryScore,
      league: resolveLeagueTier(computedMasteryScore),
      speedrunPbQueue: data.g?.speedrunPbQueue ?? [],
    };
    set(() => {
      const persistenceHealthy = writePersisted({
        locale,
        byUniverse: nextByUniverse,
        metaByUniverse: nextMetaByUniverse,
        timerByUniverse: nextTimerByUniverse,
        globalRanking: nextGlobalRanking,
      });
      return {
        locale,
        byUniverse: nextByUniverse,
        metaByUniverse: nextMetaByUniverse,
        timerByUniverse: nextTimerByUniverse,
        globalRanking: nextGlobalRanking,
        persistenceHealthy,
      };
    });
    return true;
  },
  isPersistenceHealthy: () => get().persistenceHealthy,

  dismissAchievementToast: () =>
    set((state) => ({
      achievementToastQueue: state.achievementToastQueue.slice(1),
    })),

  resetUniverseProgress: (universeId) =>
    set((state) => {
      const byUniverse = {
        ...state.byUniverse,
        [universeId]: {},
      };
      const metaByUniverse = {
        ...state.metaByUniverse,
        [universeId]: { ...emptyMeta(), currentTitle: getUniverseTitle(1, universeId, state.locale) },
      };
      const timerByUniverse = {
        ...state.timerByUniverse,
        [universeId]: {},
      };
      const persistenceHealthy = writePersisted({
        locale: state.locale,
        byUniverse,
        metaByUniverse,
        timerByUniverse,
        globalRanking: state.globalRanking,
      });
      return { byUniverse, metaByUniverse, timerByUniverse, persistenceHealthy };
    }),
}));
