import type { ExamId } from "../data/exams";
import { isQuestionBankEntry, type QuestionBankEntry, type SqlChallengePayload } from "../data/questionSchema";
import type { QuestionModule } from "../data/questionSchema";
import { loadMasterQuestionSeed } from "./questionImporter";
import { useAppStore } from "../store/useAppStore";

export interface ArenaQuestion {
  id: string;
  slug: string;
  type: "multiple_choice" | "sql_challenge";
  prompt: string;
  options: [string, string, string, string];
  correctIndex: 0 | 1 | 2 | 3;
  explanation?: string;
  contextCode?: string;
  tags: string[];
  module?: QuestionModule;
  difficulty: "easy" | "medium" | "hard";
  imagePath?: string;
  imageUrl?: string;
  codeSnippet?: string;
  /** Phase 63 — Oracle-Leitung (statisch oder dynamisch aufgelöst) */
  hint?: string;
}

/** Effektive Bildquelle: imageUrl schlägt imagePath (URLs und data-URIs) */
export function resolveQuestionBlueprintImageSrc(
  q: Pick<ArenaQuestion, "imageUrl" | "imagePath">,
): string | undefined {
  const u = q.imageUrl?.trim();
  if (u) return u;
  const p = q.imagePath?.trim();
  if (p) return p;
  return undefined;
}

const CACHE_KEY = "codesnap-question-bank-v1";
let memoryBank: QuestionBankEntry[] | null = null;

