function readLocalCache(): QuestionBankEntry[] {
  if (memoryBank) return memoryBank;
  try {
    const raw = typeof localStorage !== "undefined" ? localStorage.getItem(CACHE_KEY) : null;
    if (!raw) {
      memoryBank = [];
      return memoryBank;
    }
    const parsed = JSON.parse(raw) as unknown;
    if (!Array.isArray(parsed)) {
      memoryBank = [];
      return memoryBank;
    }
    memoryBank = parsed.filter(isQuestionBankEntry);
    return memoryBank;
  } catch {
    memoryBank = [];
    return memoryBank;
  }
}

export function setQuestionBankCache(entries: QuestionBankEntry[]): void {
  memoryBank = [...entries];
  try {
    if (typeof localStorage !== "undefined") {
      localStorage.setItem(CACHE_KEY, JSON.stringify(memoryBank));
    }
  } catch {
    /* ignore private mode */
  }
}

export function getQuestionBankVersion(): number {
  const bank = readLocalCache();
  return bank.reduce((max, row) => Math.max(max, row.version), 0);
}

export function getCachedQuestionBank(): QuestionBankEntry[] {
  return [...readLocalCache()];
}

function toArenaQuestion(entry: QuestionBankEntry): ArenaQuestion {
  const payload = entry.payload;
  const sqlPayload = entry.type === "sql_challenge" ? (payload as SqlChallengePayload) : null;
  return {
    id: entry.id,
    slug: entry.slug,
    type: entry.type,
    prompt: sqlPayload?.prompt ?? entry.prompt,
    options: payload.options,
    correctIndex: payload.correctIndex,
    explanation: entry.explanation,
    contextCode: sqlPayload?.starterSql,
    tags: entry.tags,
    module: entry.module,
    difficulty: entry.difficulty,
    imagePath: entry.imagePath,
    imageUrl: entry.imageUrl,
    codeSnippet: entry.codeSnippet,
    hint: entry.hint,
  };
}

export function getQuestionsForExam(examId: ExamId): ArenaQuestion[] {
  const careerPath = useAppStore.getState().careerPath;
  const bank = readLocalCache()
    .filter(
      (entry) =>
        entry.examId === examId &&
        entry.isPublished &&
        (!careerPath || entry.careerPaths.includes(careerPath)),
    )
    .map(toArenaQuestion);
  return bank.length > 0 ? bank : FALLBACK_POOL;
}

function shuffled<T>(input: T[]): T[] {
  const a = [...input];
  for (let i = a.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    const tmp = a[i];
    a[i] = a[j];
    a[j] = tmp;
  }
  return a;
}

/** Phase 55 — offizielles Mock-Exam zieht 30-40 zufällige Fragen aus dem Gesamtpool */
export function getRandomMockExamQuestions(minCount = 30, maxCount = 40): ArenaQuestion[] {
  const careerPath = useAppStore.getState().careerPath;
  const bank = readLocalCache()
    .filter((entry) => entry.isPublished && (!careerPath || entry.careerPaths.includes(careerPath)))
    .map(toArenaQuestion);

  const uniq = new Map<string, ArenaQuestion>();
  for (const q of bank.length > 0 ? bank : FALLBACK_POOL) {
    if (!uniq.has(q.id)) uniq.set(q.id, q);
  }

  const pool = shuffled([...uniq.values()]);
  const lo = Math.max(1, Math.floor(minCount));
  const hi = Math.max(lo, Math.floor(maxCount));
  const target = lo + Math.floor(Math.random() * (hi - lo + 1));
  return pool.slice(0, Math.min(target, pool.length));
}

let masterArenaBySlug: Map<string, ArenaQuestion> | null = null;

function getMasterArenaBySlug(): Map<string, ArenaQuestion> {
  if (!masterArenaBySlug) {
    masterArenaBySlug = new Map();
    for (const entry of loadMasterQuestionSeed().valid) {
      masterArenaBySlug.set(entry.slug, toArenaQuestion(entry));
    }
  }
  return masterArenaBySlug;
}

/** Lokal gecachte Bank zuerst, danach Master-Seed — gleiche Normalisierung wie in der Arena */
export function getArenaQuestionBySlug(slug: string): ArenaQuestion | null {
  const trimmed = slug.trim();
  if (!trimmed) return null;
  const fromBank = readLocalCache().find((e) => e.slug === trimmed);
  if (fromBank) return toArenaQuestion(fromBank);
  return getMasterArenaBySlug().get(trimmed) ?? null;
}

/** Lookup für Social Uplink Challenge-IDs */
export function getArenaQuestionById(id: string): ArenaQuestion | null {
  const trimmed = id.trim();
  if (!trimmed) return null;
  const fromBank = readLocalCache().find((e) => e.id === trimmed);
  if (fromBank) return toArenaQuestion(fromBank);
  for (const entry of loadMasterQuestionSeed().valid) {
    if (entry.id === trimmed) return toArenaQuestion(entry);
  }
  return null;
}
