export type BossModifierId = "CHRONO_CRUNCH" | "DATA_BLUR" | "NEURAL_STATIC";

export type BossModifier = {
  id: BossModifierId;
  label: string;
  shortLabel: string;
  description: string;
  timeScale: number;
  optionBlurPx: number;
  xpExponentBoost: number;
  glitchTokens: [string, string, string];
};

export const BOSS_MODIFIERS: BossModifier[] = [
  {
    id: "CHRONO_CRUNCH",
    label: "Chrono Crunch",
    shortLabel: "T-CRUNCH",
    description: "Timer komprimiert jede Sekunde zählt doppelt",
    timeScale: 0.72,
    optionBlurPx: 0,
    xpExponentBoost: 1,
    glitchTokens: ["<T>", "[!]", "<T>"],
  },
  {
    id: "DATA_BLUR",
    label: "Data Blur",
    shortLabel: "D-BLUR",
    description: "Antworten laufen unter Signalrauschen",
    timeScale: 1,
    optionBlurPx: 1.6,
    xpExponentBoost: 1,
    glitchTokens: ["{?}", "<#>", "{?}"],
  },
  {
    id: "NEURAL_STATIC",
    label: "Neural Static",
    shortLabel: "N-STATIC",
    description: "Leichter Zeitverlust plus gestoertes Sichtfeld",
    timeScale: 0.86,
    optionBlurPx: 1.1,
    xpExponentBoost: 2,
    glitchTokens: ["<>", "##", "<>"],
  },
];

export function getBossModifierById(id: string | null | undefined): BossModifier | null {
  if (!id) return null;
  return BOSS_MODIFIERS.find((row) => row.id === id) ?? null;
}
