import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useState } from "react";
import { getBossModifierById } from "../../data/bossModifiers";
import type { ActiveFactionBounty } from "../../lib/syncController";

function fmt(ms: number): string {
  const sec = Math.max(0, Math.floor(ms / 1000));
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
}

export function BountyBoard() {
  const prefersReduced = !!useReducedMotion();
  const [busy, setBusy] = useState(false);
  const [rows, setRows] = useState<ActiveFactionBounty[]>([]);

  useEffect(() => {
    setBusy(true);
    void import("../../lib/syncController")
      .then((m) => m.fetchActiveFactionBounties())
      .then((next) => setRows(next))
      .finally(() => setBusy(false));
  }, []);

  return (
    <section className="relative overflow-hidden rounded-3xl border border-fuchsia-300/35 bg-gradient-to-br from-fuchsia-500/[0.12] via-black/45 to-cyan-500/[0.08] p-5 ring-1 ring-fuchsia-200/18">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.06]" aria-hidden />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.14]" aria-hidden />
      <div className="relative space-y-4">
        <div className="flex items-end justify-between gap-3">
          <div>
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-fuchsia-100/90">
              Bounty Contract
            </p>
            <h3 className="font-display text-xl font-bold uppercase tracking-wide text-fuchsia-50">
              Faction Targets
            </h3>
          </div>
          <span className="border border-cyan-200/30 bg-cyan-500/[0.12] px-2.5 py-1 font-mono text-[9px] uppercase tracking-[0.16em] text-cyan-100">
            Active {rows.length}
          </span>
        </div>

        {busy ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-fuchsia-100/85">
            Contract uplink synchronisiert
          </p>
        ) : rows.length === 0 ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-fuchsia-100/85">
            Kein aktiver Contract gefunden
          </p>
        ) : (
          <div className="space-y-2">
            {rows.map((row, idx) => {
              const mod = getBossModifierById(row.modifierId);
              return (
                <motion.article
                  key={`${row.bossGhostId}-${idx}`}
                  initial={prefersReduced ? false : { opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: prefersReduced ? 0 : 0.16, delay: prefersReduced ? 0 : idx * 0.03 }}
                  className={
                    row.isHotZone
                      ? "relative overflow-hidden border border-red-300/55 bg-gradient-to-r from-red-600/[0.26] via-fuchsia-600/[0.2] to-black/60 p-3 shadow-[0_0_24px_rgb(239_68_68/0.28)]"
                      : "border border-fuchsia-200/20 bg-black/35 p-3"
                  }
                >
                  {row.isHotZone ? (
                    <motion.div
                      aria-hidden
                      className="pointer-events-none absolute inset-0"
                      animate={prefersReduced ? { opacity: 0.2 } : { opacity: [0.12, 0.38, 0.16], x: [0, -2, 2, 0] }}
                      transition={prefersReduced ? { duration: 0 } : { duration: 0.55, repeat: Infinity, ease: "linear" }}
                    >
                      <div className="absolute inset-0 noise-overlay opacity-40" />
                    </motion.div>
                  ) : null}
                  <div className="flex flex-wrap items-center justify-between gap-2">
                    <p className="truncate font-mono text-[10px] font-semibold uppercase tracking-[0.16em] text-fuchsia-100">
                      {row.bossLabel} {row.examId}
                    </p>
                    <div className="flex items-center gap-1.5">
                      <span className="border border-amber-300/40 bg-amber-500/[0.14] px-2 py-0.5 font-mono text-[9px] uppercase tracking-[0.14em] text-amber-100">
                        {row.targetFaction} +{row.bonusGems}G
                      </span>
                      <span className="border border-cyan-300/35 bg-cyan-500/[0.14] px-2 py-0.5 font-mono text-[9px] uppercase tracking-[0.14em] text-cyan-100">
                        x{Math.max(1, row.decayStacks)}
                      </span>
                      {row.isHotZone ? (
                        <span className="border border-red-200/55 bg-red-500/[0.28] px-2 py-0.5 font-mono text-[9px] font-black uppercase tracking-[0.16em] text-red-100">
                          HOT ZONE
                        </span>
                      ) : null}
                    </div>
                  </div>
                  <div className="mt-1 flex flex-wrap items-center gap-2 font-mono text-[9px] uppercase tracking-[0.14em] text-cyan-100/88">
                    <span>Boss Score {row.bossScore}</span>
                    <span>Shadow {fmt(row.bossDurationMs)}</span>
                    {mod ? (
                      <span className="relative overflow-hidden border border-fuchsia-300/35 bg-fuchsia-500/[0.18] px-2 py-0.5">
                        <motion.span
                          aria-hidden
                          className="pointer-events-none absolute inset-0"
                          animate={prefersReduced ? { opacity: 0.15 } : { opacity: [0.08, 0.28, 0.1], x: [0, 2, -2, 0] }}
                          transition={prefersReduced ? { duration: 0 } : { duration: 0.6, repeat: Infinity, ease: "linear" }}
                        >
                          <span className="absolute inset-0 bg-gradient-to-r from-transparent via-white/15 to-transparent" />
                        </motion.span>
                        <span className="relative inline-flex items-center gap-1">
                          <span>{mod.glitchTokens[0]}</span>
                          <span>{mod.shortLabel}</span>
                          <span>{mod.glitchTokens[2]}</span>
                        </span>
                      </span>
                    ) : null}
                  </div>
                </motion.article>
              );
            })}
          </div>
        )}
      </div>
    </section>
  );
}
