import { useEffect, useState } from "react";
import type { SqlExerciseGroup } from "../../../data/sqlAcademyContent";

function decodeFrame(text: string, progress: number): string {
  const chars = "01ABCDEFGHIJKLMNOPQRSTUVWXYZ";
  const fixed = Math.floor(text.length * progress);
  return text
    .split("")
    .map((char, idx) => {
      if (idx < fixed || char === " " || char === "\n") return char;
      return chars[(idx + fixed) % chars.length] ?? char;
    })
    .join("");
}

export function ExerciseHub({ groups }: { groups: SqlExerciseGroup[] }) {
  const [openId, setOpenId] = useState<string | null>(null);
  const [phase, setPhase] = useState(0);

  const timerKey = `${openId ?? "none"}-${phase}`;
  useEffect(() => {
    if (!openId) return;
    if (phase >= 10) return;
    const timeout = window.setTimeout(() => setPhase((v) => v + 1), 24);
    return () => window.clearTimeout(timeout);
  }, [timerKey, openId, phase]);

  return (
    <div className="exercise-columns">
      {groups.map((group) => (
        <div key={group.id} className={`exercise-col ${group.id === "leicht" ? "easy" : group.id === "mittel" ? "medium" : "hard"}`}>
          <h4>{group.title}</h4>
          {group.exercises.map((exercise) => {
            const active = openId === exercise.id;
            const revealed = active && phase >= 10;
            const shownSql = active ? decodeFrame(exercise.solutionSql, phase / 10) : "";
            return (
              <div key={exercise.id} className="exercise-card">
                <div className="exercise-head">
                  <p className="exercise-title">{exercise.title}</p>
                </div>
                <p className="exercise-challenge">{exercise.challenge}</p>
                <button
                  type="button"
                  className="exercise-check-btn"
                  onClick={() => {
                    if (active) {
                      setOpenId(null);
                      setPhase(0);
                      return;
                    }
                    setOpenId(exercise.id);
                    setPhase(0);
                  }}
                >
                  {active ? "Lösung schließen" : "Lösung anzeigen"}
                </button>
                {active ? (
                  <div className="exercise-solution decoding">
                    <pre>{shownSql}</pre>
                    {revealed ? <p className="exercise-feedback success">Dekodierung abgeschlossen</p> : null}
                  </div>
                ) : null}
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
}
