type RadarMetric = {
  label: string;
  value: number;
};

type InsightRadarProps = {
  metrics: RadarMetric[];
  performanceHistory?: number[];
  primaryColor: string;
  accentColor: string;
};

function clamp(value: number): number {
  return Math.max(0, Math.min(100, value));
}

export function InsightRadar({ metrics, performanceHistory = [], primaryColor, accentColor }: InsightRadarProps) {
  const center = 140;
  const radius = 92;
  const levels = [0.2, 0.4, 0.6, 0.8, 1];
  const points = metrics.map((metric, index) => {
    const angle = (-Math.PI / 2) + (index * Math.PI * 2) / metrics.length;
    const r = radius * (clamp(metric.value) / 100);
    return {
      x: center + Math.cos(angle) * r,
      y: center + Math.sin(angle) * r,
      angle,
    };
  });
  const polygonPoints = points.map((point) => `${point.x},${point.y}`).join(" ");

  return (
    <div className="rounded-lg border border-cyan-400/30 bg-slate-950/80 p-4">
      <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Mastery Radar</p>
      <div className="mt-3 w-full">
        <svg viewBox="0 0 280 280" className="h-auto w-full max-w-[460px]">
          {levels.map((level) => {
            const ring = metrics
              .map((_, index) => {
                const angle = (-Math.PI / 2) + (index * Math.PI * 2) / metrics.length;
                const ringRadius = radius * level;
                const x = center + Math.cos(angle) * ringRadius;
                const y = center + Math.sin(angle) * ringRadius;
                return `${x},${y}`;
              })
              .join(" ");
            return <polygon key={`ring-${level}`} points={ring} fill="none" stroke={primaryColor} strokeOpacity="0.2" strokeWidth="1" />;
          })}
          {metrics.map((metric, index) => {
            const angle = (-Math.PI / 2) + (index * Math.PI * 2) / metrics.length;
            const x = center + Math.cos(angle) * radius;
            const y = center + Math.sin(angle) * radius;
            const labelX = center + Math.cos(angle) * (radius + 22);
            const labelY = center + Math.sin(angle) * (radius + 22);
            return (
              <g key={metric.label}>
                <line x1={center} y1={center} x2={x} y2={y} stroke={primaryColor} strokeOpacity="0.32" strokeWidth="1" />
                <text
                  x={labelX}
                  y={labelY}
                  fill={primaryColor}
                  fontSize="10"
                  textAnchor="middle"
                  dominantBaseline="middle"
                  style={{ fontFamily: '"JetBrains Mono", monospace' }}
                >
                  {metric.label}
                </text>
              </g>
            );
          })}
          <polygon points={polygonPoints} fill={accentColor} fillOpacity="0.22" stroke={accentColor} strokeWidth="2" />
          {points.map((point, index) => (
            <circle key={`dot-${metrics[index]?.label ?? index}`} cx={point.x} cy={point.y} r="3.5" fill={accentColor} />
          ))}
        </svg>
      </div>
      <div className="mt-2 grid grid-cols-2 gap-2 text-[10px] text-slate-200 sm:grid-cols-4">
        {metrics.map((metric) => (
          <div key={`legend-${metric.label}`} className="rounded-md border border-cyan-300/25 bg-slate-900/65 px-2 py-1.5">
            <p className="uppercase tracking-[0.12em] text-cyan-300">{metric.label}</p>
            <p className="mt-1 font-semibold text-cyan-100">{Math.round(clamp(metric.value))}%</p>
          </div>
        ))}
      </div>
      {performanceHistory.length > 0 ? (
        <div className="mt-3 rounded-md border border-fuchsia-300/30 bg-slate-900/65 p-2">
          <p className="text-[10px] uppercase tracking-[0.12em] text-fuchsia-200">Performance History Last 20 Queries</p>
          <div className="mt-2 flex items-end gap-1">
            {performanceHistory.slice(-20).map((score, idx) => {
              const height = Math.max(8, Math.round((clamp(score) / 100) * 52));
              const efficient = score <= 40;
              return (
                <div
                  key={`hist-${idx}-${score}`}
                  className={`w-2 rounded-sm ${efficient ? "bg-emerald-300/80" : score <= 65 ? "bg-amber-300/80" : "bg-rose-300/80"}`}
                  style={{ height }}
                  title={`Query ${idx + 1} cost ${Math.round(score)}`}
                />
              );
            })}
          </div>
          <p className="mt-1 text-[10px] text-fuchsia-100">
            Avg Cost {Math.round(performanceHistory.reduce((acc, value) => acc + value, 0) / Math.max(1, performanceHistory.length))}
          </p>
        </div>
      ) : null}
    </div>
  );
}
