import { motion } from "framer-motion";
import { usePwaInstall } from "../../hooks/usePwaInstall";
import { springHeavy } from "../../motion/variants";
import { cn } from "../../lib/cn";
import { IconDownload } from "../icons/ThinLineIcons";

export function PwaInstallButton({ className }: { className?: string }) {
  const { canShowInstall, install } = usePwaInstall();
  if (!canShowInstall) return null;
  return (
    <div className={cn("space-y-2", className)}>
      <p className="font-mono text-[10px] uppercase tracking-[0.22em] text-foreground-muted">
        System Update bereit
      </p>
      <motion.button
        type="button"
        whileTap={{ scale: 0.94, y: 3 }}
        transition={springHeavy}
        onClick={() => void install()}
        className="inline-flex w-full items-center justify-center gap-2 border border-emerald-400/35 bg-emerald-500/[0.1] py-3 font-mono text-xs font-semibold uppercase tracking-[0.2em] text-emerald-200 hover-breathe hover:border-emerald-300/55 hover:bg-emerald-500/[0.14]"
      >
        <IconDownload className="size-4" />
        Add to Nexus
      </motion.button>
    </div>
  );
}
