import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { buildWebBasicsJediPath } from "../../../data/factories/webBasicsFactory";
import { buildCSharpJediMissions } from "../../../data/factories/csharpFactory";
import {
  buildCSharpActionContracts,
  simulateCSharpClickEvent,
} from "../../../services/logic/CSharpActionHandler";
import { resolveMissionHandler, type MissionRuntimeState } from "../../../services/logic/MissionStrategy";
import { useAcademyStore } from "../../../store/academyStore";

export function buildWebShellPreviewDoc(html: string, css: string, cssVars: Record<string, string>): string {
  const cssVarBlock = `:root { ${Object.entries(cssVars)
    .map(([key, value]) => `${key}: ${value};`)
    .join(" ")} }`;
  return (
    "<!doctype html><html><head><meta charset='utf-8'/><meta name='viewport' content='width=device-width,initial-scale=1'/>" +
    "<style>" +
    "html,body{margin:0;min-height:100%;background:#020617;color:#dbeafe;font-family:JetBrains Mono,monospace}" +
    "body::before{content:'';position:fixed;inset:0;background:repeating-linear-gradient(0deg,transparent 0 2px,#22d3ee11 2px 4px);pointer-events:none}" +
    cssVarBlock +
    css +
    "</style></head><body>" +
    html +
    "</body></html>"
  );
}

type WebAcademyShellProps = {
  track?: "web_basics" | "c_sharp";
};

export function WebAcademyShell({ track = "web_basics" }: WebAcademyShellProps) {
  const reduceMotion = useReducedMotion();
  const path = useMemo(() => buildWebBasicsJediPath(), []);
  const csharpMissions = useMemo(() => buildCSharpJediMissions(), []);
  const shellSteps = track === "c_sharp" ? csharpMissions : path.steps;
  const webTrackProgress = useAcademyStore((s) => s.globalRanking.webTrackProgress);
  const setWebTrackProgress = useAcademyStore((s) => s.setWebTrackProgress);
  const [stepId, setStepId] = useState(shellSteps[0]?.id ?? "");
  const activeStep = shellSteps.find((step) => step.id === stepId) ?? shellSteps[0];
  const activeCSharpMission = track === "c_sharp" ? (activeStep as (typeof csharpMissions)[number]) : null;
  const initialStatus = track === "c_sharp" ? webTrackProgress.systemStatusText : "Standby";
  const [inventoryInput, setInventoryInput] = useState("Kyber Crystal");
  const [inventoryItems, setInventoryItems] = useState<string[]>(webTrackProgress.inventoryItems);
  const [shieldValue, setShieldValue] = useState<number>(webTrackProgress.shieldValue);
  const [droidModel, setDroidModel] = useState("R2 Unit");
  const [droidPowerInput, setDroidPowerInput] = useState<number>(webTrackProgress.droidPowerLevel);
  const [droidKind, setDroidKind] = useState<"battle" | "protocol">("protocol");
  const [droidArmy, setDroidArmy] = useState<Array<{ model: string; powerLevel: number; type: "BattleDroid" | "ProtocolDroid" }>>(
    [],
  );
  const [systemStatus, setSystemStatus] = useState(initialStatus);
  const [htmlCode, setHtmlCode] = useState(
    activeStep?.starterHtml ?? "",
  );
  const [cssCode, setCssCode] = useState(activeStep?.starterCss ?? "");
  const [cssVars, setCssVars] = useState<Record<string, string>>({});
  const [learningFlowIndex, setLearningFlowIndex] = useState(0);
  const contracts = useMemo(() => buildCSharpActionContracts(activeStep?.transitionIds ?? []), [activeStep]);
  const previewDoc = useMemo(() => buildWebShellPreviewDoc(htmlCode, cssCode, cssVars), [htmlCode, cssCode, cssVars]);
  const learningFlow = activeStep?.learningFlow ?? [];
  const activeLearningBlock = learningFlow[learningFlowIndex] ?? learningFlow[0];

  useEffect(() => {
    setLearningFlowIndex(0);
  }, [activeStep?.id]);

  useEffect(() => {
    if (track !== "c_sharp") return;
    setWebTrackProgress({
      systemStatusText: systemStatus,
      inventoryItems,
      shieldValue,
      droidPowerLevel: droidPowerInput,
    });
  }, [track, systemStatus, inventoryItems, shieldValue, droidPowerInput, setWebTrackProgress]);

  useEffect(() => {
    if (track !== "c_sharp" || !activeCSharpMission) return;
    const handler = resolveMissionHandler(activeCSharpMission);
    const baseState: MissionRuntimeState = {
      systemStatus,
      inventoryItems,
      shieldValue,
      droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
      droidArmy,
      cssVariables: cssVars,
    };
    const result =
      activeCSharpMission.missionType === "inventory_list"
        ? handler.executeAction({
            mission: activeCSharpMission,
            state: baseState,
            action: { type: "add_inventory", item: "" },
          })
        : activeCSharpMission.missionType === "shield_integrity"
          ? handler.executeAction({
              mission: activeCSharpMission,
              state: baseState,
              action: { type: "set_shield", value: shieldValue },
            })
          : activeCSharpMission.missionType === "droid_factory"
            ? handler.executeAction({
                mission: activeCSharpMission,
                state: baseState,
                action: { type: "execute_army" },
              })
          : activeCSharpMission.missionType === "droid_encapsulation"
            ? handler.executeAction({
                mission: activeCSharpMission,
                state: baseState,
                action: { type: "instantiate_droid", model: droidModel, powerLevel: droidPowerInput },
              })
            : handler.executeAction({
                mission: activeCSharpMission,
                state: baseState,
                action: { type: "trigger" },
              });
    setHtmlCode(result.html);
    setCssVars(result.state.cssVariables);
  }, [track, activeCSharpMission, systemStatus, inventoryItems, shieldValue, droidModel, droidPowerInput, droidArmy]);

  return (
    <section className="rounded-2xl border border-cyan-400/35 bg-slate-950/75 p-6">
      <div className="mb-3 flex items-end justify-between gap-3">
        <div>
          <p className="text-[10px] uppercase tracking-[0.16em] text-cyan-300">Web Academy Shell</p>
          <h2 className="mt-1 text-xl font-semibold text-cyan-100">
            {track === "c_sharp" ? "CSharp Logic Bridge Path" : path.pathLabel}
          </h2>
        </div>
        <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-200">
          Step {activeStep?.order}/{shellSteps.length}
        </p>
      </div>
      <div className="grid gap-4 lg:grid-cols-[1.2fr_2fr]">
        <aside className="rounded-lg border border-cyan-300/25 bg-slate-900/60 p-3">
          <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-200">Mission Control</p>
          <select
            className="mt-2 w-full rounded border border-cyan-300/35 bg-slate-950/70 px-2 py-1.5 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
            value={activeStep?.id ?? ""}
            onChange={(event) => {
              const next = shellSteps.find((step) => step.id === event.target.value);
              if (!next) return;
              setStepId(next.id);
              const nextStatus = track === "c_sharp" ? webTrackProgress.systemStatusText : systemStatus;
              setSystemStatus(nextStatus);
              setHtmlCode(next.starterHtml);
              setCssCode(next.starterCss);
            }}
          >
            {shellSteps.map((step) => (
              <option key={step.id} value={step.id}>
                {step.order} {step.title}
              </option>
            ))}
          </select>
          <p className="mt-2 text-[11px] text-slate-200">{activeStep?.mission}</p>
          <p className="mt-2 text-[10px] text-cyan-200">Concepts {activeStep?.concepts.join(" | ")}</p>
          <div className="mt-3 rounded border border-cyan-400/20 bg-slate-950/60 p-2.5">
            <p className="text-[10px] uppercase tracking-[0.12em] text-cyan-100">Lernaufbau</p>
            {activeLearningBlock ? (
              <div className="mt-2 rounded border border-slate-700/70 bg-slate-900/70 px-2 py-1.5">
                <p className="text-[9px] uppercase tracking-[0.12em] text-cyan-200">{activeLearningBlock.title}</p>
                <p className="mt-1 text-[10px] leading-5 text-slate-200">{activeLearningBlock.content}</p>
                <div className="mt-2 flex items-center justify-between">
                  <p className="text-[9px] uppercase tracking-[0.12em] text-slate-400">
                    Schritt {Math.min(learningFlowIndex + 1, learningFlow.length)}/{learningFlow.length}
                  </p>
                  <div className="flex gap-1.5">
                    <button
                      type="button"
                      className="rounded border border-cyan-300/35 bg-slate-950/80 px-1.5 py-0.5 text-[9px] uppercase tracking-[0.1em] text-cyan-100 disabled:opacity-40"
                      onClick={() => setLearningFlowIndex((prev) => Math.max(0, prev - 1))}
                      disabled={learningFlowIndex <= 0}
                    >
                      Zurueck
                    </button>
                    <button
                      type="button"
                      className="rounded border border-cyan-300/35 bg-slate-950/80 px-1.5 py-0.5 text-[9px] uppercase tracking-[0.1em] text-cyan-100 disabled:opacity-40"
                      onClick={() => setLearningFlowIndex((prev) => Math.min(learningFlow.length - 1, prev + 1))}
                      disabled={learningFlowIndex >= learningFlow.length - 1}
                    >
                      Weiter
                    </button>
                  </div>
                </div>
              </div>
            ) : null}
          </div>
          {track === "c_sharp" ? (
            <p className="mt-2 text-[10px] text-emerald-200">Variable {csharpMissions[0]?.statusVarName ?? "systemStatus"} {systemStatus}</p>
          ) : null}
          {track === "c_sharp" && activeCSharpMission?.missionType === "inventory_list" ? (
            <div className="mt-2 space-y-2">
              <p className="text-[10px] text-cyan-100">Add Kyber Crystal</p>
              <div className="flex gap-2">
                <input
                  className="w-full rounded border border-cyan-300/35 bg-slate-950/70 px-2 py-1 text-[10px] text-cyan-100 outline-none"
                  value={inventoryInput}
                  onChange={(event) => setInventoryInput(event.target.value)}
                />
                <button
                  type="button"
                  className="rounded border border-cyan-300/45 bg-cyan-950/25 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
                  onClick={() => {
                    if (!activeCSharpMission) return;
                    const handler = resolveMissionHandler(activeCSharpMission);
                    const row = handler.executeAction({
                      mission: activeCSharpMission,
                      state: {
                        systemStatus,
                        inventoryItems,
                        shieldValue,
                        droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
                        droidArmy,
                        cssVariables: cssVars,
                      },
                      action: { type: "add_inventory", item: inventoryInput },
                    });
                    if (!row.valid) return;
                    setInventoryItems(row.state.inventoryItems);
                    setHtmlCode(row.html);
                  }}
                >
                  Add
                </button>
              </div>
            </div>
          ) : null}
          {track === "c_sharp" && activeCSharpMission?.missionType === "shield_integrity" ? (
            <div className="mt-2 space-y-2">
              <p className="text-[10px] text-cyan-100">Shield Value {shieldValue}%</p>
              <input
                type="range"
                min={0}
                max={100}
                value={shieldValue}
                onChange={(event) => {
                  const nextShield = Number(event.target.value);
                  if (!activeCSharpMission) return;
                  const handler = resolveMissionHandler(activeCSharpMission);
                  const row = handler.executeAction({
                    mission: activeCSharpMission,
                    state: {
                      systemStatus,
                      inventoryItems,
                      shieldValue,
                      droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
                      droidArmy,
                      cssVariables: cssVars,
                    },
                    action: { type: "set_shield", value: nextShield },
                  });
                  if (!row.valid) return;
                  setShieldValue(row.state.shieldValue);
                  setCssVars(row.state.cssVariables);
                  setSystemStatus(row.state.systemStatus);
                  setHtmlCode(row.html);
                }}
              />
            </div>
          ) : null}
          {track === "c_sharp" && activeCSharpMission?.missionType === "droid_encapsulation" ? (
            <div className="mt-2 space-y-2">
              <p className="text-[10px] text-cyan-100">Droid Model</p>
              <input
                className="w-full rounded border border-cyan-300/35 bg-slate-950/70 px-2 py-1 text-[10px] text-cyan-100 outline-none"
                value={droidModel}
                onChange={(event) => setDroidModel(event.target.value)}
              />
              <p className="text-[10px] text-cyan-100">PowerLevel {droidPowerInput}</p>
              <input
                type="range"
                min={0}
                max={150}
                value={droidPowerInput}
                onChange={(event) => {
                  if (!activeCSharpMission) return;
                  const raw = Number(event.target.value);
                  const handler = resolveMissionHandler(activeCSharpMission);
                  const row = handler.executeAction({
                    mission: activeCSharpMission,
                    state: {
                      systemStatus,
                      inventoryItems,
                      shieldValue,
                      droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
                      droidArmy,
                      cssVariables: cssVars,
                    },
                    action: { type: "set_droid_power", value: raw },
                  });
                  if (!row.valid) return;
                  setDroidPowerInput(row.state.droid?.powerLevel ?? 0);
                  setHtmlCode(row.html);
                }}
              />
              <button
                type="button"
                className="rounded border border-cyan-300/45 bg-cyan-950/25 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
                onClick={() => {
                  if (!activeCSharpMission) return;
                  const handler = resolveMissionHandler(activeCSharpMission);
                  const row = handler.executeAction({
                    mission: activeCSharpMission,
                    state: {
                      systemStatus,
                      inventoryItems,
                      shieldValue,
                      droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
                      droidArmy,
                      cssVariables: cssVars,
                    },
                    action: { type: "instantiate_droid", model: droidModel, powerLevel: droidPowerInput },
                  });
                  if (!row.valid) return;
                  setDroidPowerInput(row.state.droid?.powerLevel ?? 0);
                  setHtmlCode(row.html);
                }}
              >
                Instantiate Droid
              </button>
            </div>
          ) : null}
          {track === "c_sharp" && activeCSharpMission?.missionType === "droid_factory" ? (
            <div className="mt-2 space-y-2">
              <p className="text-[10px] text-cyan-100">Droid Type</p>
              <select
                className="w-full rounded border border-cyan-300/35 bg-slate-950/70 px-2 py-1 text-[10px] text-cyan-100"
                value={droidKind}
                onChange={(event) => setDroidKind(event.target.value as "battle" | "protocol")}
              >
                <option value="battle">BattleDroid</option>
                <option value="protocol">ProtocolDroid</option>
              </select>
              <button
                type="button"
                className="rounded border border-cyan-300/45 bg-cyan-950/25 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
                onClick={() => {
                  if (!activeCSharpMission) return;
                  const handler = resolveMissionHandler(activeCSharpMission);
                  const row = handler.executeAction({
                    mission: activeCSharpMission,
                    state: {
                      systemStatus,
                      inventoryItems,
                      shieldValue,
                      droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
                      droidArmy,
                      cssVariables: cssVars,
                    },
                    action: { type: "add_droid", kind: droidKind, model: droidModel, powerLevel: droidPowerInput },
                  });
                  if (!row.valid) return;
                  setDroidArmy(row.state.droidArmy);
                  setHtmlCode(row.html);
                }}
              >
                Add to Base Registry
              </button>
              <button
                type="button"
                className="rounded border border-fuchsia-300/45 bg-fuchsia-950/25 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-fuchsia-100"
                onClick={() => {
                  if (!activeCSharpMission) return;
                  const handler = resolveMissionHandler(activeCSharpMission);
                  const row = handler.executeAction({
                    mission: activeCSharpMission,
                    state: {
                      systemStatus,
                      inventoryItems,
                      shieldValue,
                      droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
                      droidArmy,
                      cssVariables: cssVars,
                    },
                    action: { type: "execute_army" },
                  });
                  if (!row.valid) return;
                  setSystemStatus(row.state.systemStatus);
                  setCssVars(row.state.cssVariables);
                }}
              >
                Execute Army
              </button>
            </div>
          ) : null}
          <button
            type="button"
            className="mt-3 rounded border border-blue-300/55 bg-blue-950/25 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-blue-100"
            onClick={() => {
              const transitionId = activeStep?.transitionIds[0];
              if (!transitionId) return;
              const event = simulateCSharpClickEvent({
                transitionId,
                contracts,
                existingCssVariables: cssVars,
              });
              if (!event.triggered) return;
              setCssVars(event.cssVariables);
              if (track === "c_sharp") {
                const activeMission = csharpMissions.find((mission) => mission.id === activeStep?.id) ?? csharpMissions[0];
                if (activeMission?.missionType === "status_binding") {
                  const handler = resolveMissionHandler(activeMission);
                  const row = handler.executeAction({
                    mission: activeMission,
                    state: {
                      systemStatus,
                      inventoryItems,
                      shieldValue,
                      droid: { model: droidModel, powerLevel: droidPowerInput, type: "ProtocolDroid" },
                      droidArmy,
                      cssVariables: event.cssVariables,
                    },
                    action: { type: "trigger" },
                  });
                  if (!row.valid) return;
                  setSystemStatus(row.state.systemStatus);
                  setHtmlCode(row.html);
                }
              }
            }}
          >
            Simulate CSharp click
          </button>
        </aside>
        <motion.div
          initial={false}
          animate={reduceMotion ? { opacity: 1 } : { opacity: [0.96, 1] }}
          transition={{ duration: 0.28 }}
          className="space-y-3"
        >
          <div className="grid gap-3 md:grid-cols-2">
            <textarea
              className="h-44 rounded-lg border border-cyan-300/35 bg-slate-900/75 p-3 font-mono text-xs text-cyan-100 outline-none"
              value={htmlCode}
              onChange={(event) => setHtmlCode(event.target.value)}
              readOnly={track === "c_sharp"}
            />
            <textarea
              className="h-44 rounded-lg border border-fuchsia-300/35 bg-slate-900/75 p-3 font-mono text-xs text-fuchsia-100 outline-none"
              value={cssCode}
              onChange={(event) => setCssCode(event.target.value)}
            />
          </div>
          <div className="rounded-lg border border-cyan-300/35 bg-slate-950/80 p-2">
            <iframe title="web-academy-preview" className="h-80 w-full rounded border border-cyan-300/25 bg-slate-900" srcDoc={previewDoc} />
          </div>
        </motion.div>
      </div>
    </section>
  );
}
