import { EXAMS, type ExamId } from "../data/exams";
import type { DailyGrindState, MockExamHistoryEntry } from "../store/useAppStore";
import { sm2BucketsByTag } from "./dossierStats";
import type { FlashcardProgressEntry } from "./sm2";

export type MockExamSeriesPoint = {
  t: number;
  percent: number;
  grade: number;
};

export type TagSignalRow = {
  tag: string;
  hits: number;
};

export type ArenaBarRow = {
  examId: ExamId;
  title: string;
  bestScore: number;
};

export type FlashcardStabilityTotals = {
  cyan: number;
  yellow: number;
  magenta: number;
  totalReviews: number;
};

export type TelemetryPulseKpis = {
  userLevel: number;
  globalXP: number;
  globalXpToNext: number;
  gems: number;
  streakDays: number;
  arenaWinsToday: number;
  flashReviewsToday: number;
  sqlCheckpointToday: number;
};

export type TelemetrySnapshot = {
  mockExamSeries: MockExamSeriesPoint[];
  tagSignalMock: TagSignalRow[];
  arenaBars: ArenaBarRow[];
  flashcardStability: FlashcardStabilityTotals;
  pulseKpis: TelemetryPulseKpis;
};

export type TelemetryStateSlice = {
  mockExamHistory: MockExamHistoryEntry[];
  arenaBestScores: Record<string, number>;
  flashcardProgress: Record<string, FlashcardProgressEntry>;
  flashcardTotalReviews: number;
  userLevel: number;
  globalXP: number;
  globalXpToNext: number;
  gems: number;
  dailyGrind: DailyGrindState;
};

function aggregateCorrectTagHits(history: MockExamHistoryEntry[]): TagSignalRow[] {
  const map = new Map<string, number>();
  for (const row of history) {
    for (const [tag, n] of Object.entries(row.correctTagHits)) {
      const add = Math.max(0, Math.floor(Number(n) || 0));
      if (add === 0) continue;
      map.set(tag, (map.get(tag) ?? 0) + add);
    }
  }
  return [...map.entries()]
    .map(([tag, hits]) => ({ tag, hits }))
    .sort((a, b) => b.hits - a.hits)
    .slice(0, 14);
}

function sumFlashcardBuckets(
  progress: Record<string, FlashcardProgressEntry>,
): Pick<FlashcardStabilityTotals, "cyan" | "yellow" | "magenta"> {
  const buckets = sm2BucketsByTag(progress);
  let cyan = 0;
  let yellow = 0;
  let magenta = 0;
  for (const b of Object.values(buckets)) {
    cyan += b.cyan;
    yellow += b.yellow;
    magenta += b.magenta;
  }
  return { cyan, yellow, magenta };
}

/** Phase 59 — reine Ableitung aus Store-Slice, ohne React */
export function buildTelemetrySnapshot(slice: TelemetryStateSlice): TelemetrySnapshot {
  const mockExamSeries = [...slice.mockExamHistory]
    .sort((a, b) => a.completedAtMs - b.completedAtMs)
    .map((row) => ({
      t: row.completedAtMs,
      percent: row.percent,
      grade: row.grade,
    }));

  const tagSignalMock = aggregateCorrectTagHits(slice.mockExamHistory);

  const arenaBars: ArenaBarRow[] = EXAMS.map((exam) => ({
    examId: exam.id,
    title: exam.title,
    bestScore: Math.max(0, Math.floor(slice.arenaBestScores[exam.id] ?? 0)),
  }));

  const { cyan, yellow, magenta } = sumFlashcardBuckets(slice.flashcardProgress);

  return {
    mockExamSeries,
    tagSignalMock,
    arenaBars,
    flashcardStability: {
      cyan,
      yellow,
      magenta,
      totalReviews: slice.flashcardTotalReviews,
    },
    pulseKpis: {
      userLevel: slice.userLevel,
      globalXP: slice.globalXP,
      globalXpToNext: slice.globalXpToNext,
      gems: slice.gems,
      streakDays: slice.dailyGrind.streakDays,
      arenaWinsToday: slice.dailyGrind.arenaWinsToday,
      flashReviewsToday: slice.dailyGrind.flashReviewsToday,
      sqlCheckpointToday: slice.dailyGrind.sqlCheckpointToday,
    },
  };
}
