import type { StateCreator } from "zustand";
import {
  buildDailyMissionsForDay,
  isStreakChainBroken,
  localCalendarYmd,
  yesterdayYmd,
  type DailyMissionKind,
} from "../../lib/dailyGrindMissions";
import type { AppState, CareerPath, DailyGrindState } from "../useAppStore";

const initialDailyGrind: DailyGrindState = {
  ledgerYmd: null,
  streakDays: 0,
  dailyGoalMetYmd: null,
  arenaWinsToday: 0,
  flashReviewsToday: 0,
  sqlCheckpointToday: 0,
};

function missionTotalsForKind(dg: DailyGrindState, kind: DailyMissionKind): number {
  if (kind === "arena_win") return dg.arenaWinsToday;
  if (kind === "flashcard_reviews") return dg.flashReviewsToday;
  return dg.sqlCheckpointToday;
}

function allDailyMissionsComplete(careerPath: CareerPath | null, dg: DailyGrindState): boolean {
  const missions = buildDailyMissionsForDay(localCalendarYmd(), careerPath);
  return missions.every((m) => missionTotalsForKind(dg, m.kind) >= m.target);
}

export interface DailyGrindSlice {
  dailyGrind: DailyGrindState;
  reconcileDailyLedger: () => void;
  registerDailyGrindActivity: (kind: DailyMissionKind, amount?: number) => void;
}

export const createDailyGrindSlice: StateCreator<AppState, [], [], DailyGrindSlice> = (set, get) => ({
  dailyGrind: { ...initialDailyGrind },
  reconcileDailyLedger: () => {
    const today = localCalendarYmd();
    const dg = get().dailyGrind;
    const broken = isStreakChainBroken(today, dg.dailyGoalMetYmd);

    if (dg.ledgerYmd === today) {
      if (broken) {
        set({
          dailyGrind: { ...dg, streakDays: 0, dailyGoalMetYmd: null },
          progress: { ...get().progress, streakDays: 0 },
        });
        void import("../../lib/syncController").then((m) => m.scheduleBackgroundProgressSync());
      }
      return;
    }

    const nextStreak = broken ? 0 : dg.streakDays;
    set({
      dailyGrind: {
        ledgerYmd: today,
        streakDays: nextStreak,
        dailyGoalMetYmd: broken ? null : dg.dailyGoalMetYmd,
        arenaWinsToday: 0,
        flashReviewsToday: 0,
        sqlCheckpointToday: 0,
      },
      progress: { ...get().progress, streakDays: nextStreak },
    });
    void import("../../lib/syncController").then((m) => m.scheduleBackgroundProgressSync());
  },
  registerDailyGrindActivity: (kind, amount = 1) => {
    get().reconcileDailyLedger();
    const snap = get();
    const today = localCalendarYmd();
    const dg0 = snap.dailyGrind;
    const n = Math.max(0, Math.floor(amount));
    const dg: DailyGrindState = {
      ...dg0,
      arenaWinsToday: dg0.arenaWinsToday + (kind === "arena_win" ? n : 0),
      flashReviewsToday: dg0.flashReviewsToday + (kind === "flashcard_reviews" ? n : 0),
      sqlCheckpointToday: dg0.sqlCheckpointToday + (kind === "sql_checkpoint" ? n : 0),
    };

    const allDone = allDailyMissionsComplete(snap.careerPath, dg);
    let streak = dg.streakDays;
    let goalMet = dg.dailyGoalMetYmd;
    if (allDone && goalMet !== today) {
      const y = yesterdayYmd(today);
      streak = dg.dailyGoalMetYmd === y ? dg.streakDays + 1 : 1;
      goalMet = today;
    }

    set({
      dailyGrind: {
        ...dg,
        ledgerYmd: today,
        streakDays: streak,
        dailyGoalMetYmd: goalMet,
      },
      progress: { ...get().progress, streakDays: streak },
    });
    void import("../../lib/syncController").then((m) => m.scheduleBackgroundProgressSync());
    get().tryUnlockAchievements();
  },
});
