import { motion, useReducedMotion } from "framer-motion";
import { ARENA_NEURAL_GEM_COST } from "../../lib/neuralHintBridge";
import { cn } from "../../lib/cn";

export type NeuralLinkHintProps = {
  active: boolean;
  unlocked: boolean;
  hintLine: string | null;
  busy: boolean;
  error: string | null;
  /** Genug Gems für einen Kanal-Versuch */
  hasGemBudget: boolean;
  onOpenChannel: () => void;
};

const flickerTransition = {
  duration: 2.15,
  repeat: Infinity,
  ease: "easeInOut" as const,
};

export function NeuralLinkHint({
  active,
  unlocked,
  hintLine,
  busy,
  error,
  hasGemBudget,
  onOpenChannel,
}: NeuralLinkHintProps) {
  const prefersReduced = useReducedMotion();

  if (!active) return null;

  const costLabel = `${ARENA_NEURAL_GEM_COST} Gems`;

  return (
    <div
      className={cn(
        "pointer-events-auto absolute right-0 top-[14%] z-30 flex max-w-[min(19rem,46vw)] flex-col items-end gap-2 pr-0 sm:right-1",
      )}
      aria-live="polite"
    >
      {!prefersReduced ? (
        <motion.span
          aria-hidden
          className="pointer-events-none absolute -right-0.5 top-1 h-[70%] w-px bg-cyan-300/80 shadow-[0_0_14px_rgba(34,211,238,0.65)]"
          animate={{ opacity: [0.12, 0.95, 0.18, 0.88, 0.1], scaleY: [0.9, 1.02, 0.94, 1, 0.92] }}
          transition={{ ...flickerTransition, duration: 2.6 }}
        />
      ) : (
        <span
          aria-hidden
          className="pointer-events-none absolute -right-0.5 top-1 h-[70%] w-px bg-cyan-300/35"
        />
      )}

      <div className="relative border border-cyan-400/25 bg-void/70 px-3 py-2 backdrop-blur-sm">
        <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.28em] text-cyan-200/90">
          Neural-Link · abgefangenes Fragment
        </p>

        {!unlocked ? (
          <>
            <p className="mt-1 max-w-[16rem] font-sans text-[11px] leading-snug text-foreground-muted">
              Funkreste zucken am Rand · Kanal kostet {costLabel}
            </p>
            <motion.button
              type="button"
              disabled={busy || !hasGemBudget}
              whileTap={prefersReduced ? undefined : { scale: 0.97 }}
              onClick={onOpenChannel}
              className={cn(
                "mt-2 w-full border px-2 py-1.5 text-left font-mono text-[10px] font-bold uppercase tracking-[0.18em]",
                busy || !hasGemBudget
                  ? "cursor-not-allowed border-white/[0.08] text-foreground-muted opacity-50"
                  : "border-cyan-400/40 text-cyan-100 hover:border-cyan-300/55 hover:bg-cyan-500/10",
              )}
            >
              {busy ? "Abstimmung läuft" : "Frequenz scharf stellen"}
            </motion.button>
            {error ? (
              <p className="mt-1 font-mono text-[10px] uppercase tracking-wide text-signal">{error}</p>
            ) : null}
          </>
        ) : (
          <motion.p
            className="mt-2 max-w-[16rem] font-mono text-[11px] leading-relaxed text-cyan-50/95"
            animate={
              prefersReduced
                ? undefined
                : {
                    opacity: [1, 0.78, 1, 0.62, 0.92, 1],
                    x: [0, -0.4, 0.3, 0, -0.25, 0],
                  }
            }
            transition={prefersReduced ? undefined : { ...flickerTransition, duration: 1.85 }}
          >
            {hintLine ?? "—"}
          </motion.p>
        )}
      </div>
    </div>
  );
}
