export type HapticPattern = "light" | "medium" | "success" | "heavy" | "error" | "bass";

/** iOS/Android — Muster in ms, Pause = Eintrag 0 im Array */
const PATTERNS: Record<HapticPattern, number | number[]> = {
  /** Menü-Tap */
  light: 14,
  /** kurzer Impuls */
  medium: [20, 45, 24],
  /** Erfolg — doppelter Puls */
  success: [24, 38, 30, 38, 32],
  /** schwere Bestätigung */
  heavy: [48, 32, 56, 28, 72],
  /** Fehler — rauer Shake */
  error: [62, 42, 68, 38, 88, 36, 100],
  /** tiefer Uplink-Puls (Sync / Elite-Login) */
  bass: [96, 36, 110, 40, 128, 44, 140],
};

export function runHaptic(pattern: HapticPattern): void {
  if (typeof navigator === "undefined" || typeof navigator.vibrate !== "function") {
    return;
  }
  try {
    const v = PATTERNS[pattern];
    navigator.vibrate(v);
  } catch {
    /* noop */
  }
}
