import { type AchievementId, isAchievementId } from "../data/achievementSchema";

export type AchievementUnlockSnapshot = {
  unlocked: ReadonlySet<string>;
  resolvedTickets: number;
  helpdeskClears: number;
  bestArenaScoreMax: number;
  streakDays: number;
};

export function computeNewAchievementIds(s: AchievementUnlockSnapshot): AchievementId[] {
  const out: AchievementId[] = [];
  if (!s.unlocked.has("first_response") && s.resolvedTickets + s.helpdeskClears >= 1) {
    out.push("first_response");
  }
  if (!s.unlocked.has("s_tier_specialist") && s.bestArenaScoreMax >= 2000) {
    out.push("s_tier_specialist");
  }
  if (!s.unlocked.has("infinite_grind") && s.streakDays >= 7) {
    out.push("infinite_grind");
  }
  return out.filter(isAchievementId);
}
