import { getPrestigeRankIndex } from "../lib/rankEngine";

export type TerminalThemeId = "classic-amber" | "cyber-lime" | "plasma-purple" | "apex-gold";

export type TerminalThemeDefinition = {
  id: TerminalThemeId;
  /** UI label — kein Satzzeichen am Ende */
  displayName: string;
  /** Index in PRESTIGE_RANKS — 2 = Cyber Sentinel */
  minPrestigeRankIndex: number;
  signalHex: string;
  magentaHex: string;
  magentaDimRgb: string;
  selectionBg: string;
  focusRing: string;
  /** Basis Scanline-Stärke 0–1 */
  scanlineBase: number;
  /** Zusätzliche CRT-Bloom-Deckkraft 0–1 */
  crtBloomOpacity: number;
  /** Radial Phosphor-Tint (Mitte) */
  phosphorCenter: string;
  /** Dunkles Hex für PWA meta theme-color (Statusleiste) */
  pwaStatusBarHex: string;
};

