export const DEFAULT_TERMINAL_THEME_ID: TerminalThemeId = "classic-amber";

/** PWA meta theme-color bis Store rehydriert — gleicher Wert wie index.html */
export const PWA_THEME_COLOR_FALLBACK_HEX = "#050505" as const;

/** Hex für meta name=theme-color aus Rig-Preset */
export function getPwaThemeColorHexForTerminalThemeId(themeId: TerminalThemeId): string {
  const t = getTerminalThemeById(themeId);
  return t?.pwaStatusBarHex ?? PWA_THEME_COLOR_FALLBACK_HEX;
}

export function getTerminalThemeById(id: string | null | undefined): TerminalThemeDefinition | null {
  if (!id) return null;
  return TERMINAL_THEMES.find((t) => t.id === id) ?? null;
}

export function isTerminalThemeUnlocked(theme: TerminalThemeDefinition, prestigeRankIndex: number): boolean {
  return prestigeRankIndex >= theme.minPrestigeRankIndex;
}

export function prestigeRankIndexFromLifetimeXp(lifetimeXp: number): number {
  return getPrestigeRankIndex(Math.max(0, Math.floor(lifetimeXp)));
}

export function normalizeTerminalThemeId(
  stored: string | null | undefined,
  lifetimeXp: number,
): TerminalThemeId {
  const prestigeIdx = prestigeRankIndexFromLifetimeXp(lifetimeXp);
  const candidate = getTerminalThemeById(stored);
  if (candidate && isTerminalThemeUnlocked(candidate, prestigeIdx)) return candidate.id;
  return DEFAULT_TERMINAL_THEME_ID;
}

/** Scanline alpha: Theme-Basis × Nutzer-Dreh (0–100) × leichter Prestige-Boost */
export function resolveScanlineAlpha(
  theme: TerminalThemeDefinition,
  scanlineDial: number,
  prestigeRankIndex: number,
): number {
  const dial = Number.isFinite(scanlineDial) ? Math.min(100, Math.max(0, scanlineDial)) : 50;
  const dialNorm = 0.35 + (dial / 100) * 1.15;
  const prestigeBoost = 1 + prestigeRankIndex * 0.045;
  const raw = theme.scanlineBase * dialNorm * prestigeBoost;
  return Math.min(0.38, Math.max(0.04, raw));
}
