import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useRef, useState } from "react";
import { IconSkull, IconTrophy } from "../icons/ThinLineIcons";
import { ArtifactPedestal } from "../profile/ArtifactPedestal";
import { getExam } from "../../data/exams";
import { getBossModifierById } from "../../data/bossModifiers";
import { getArenaQuestionById, getQuestionsForExam } from "../../data/mockQuestions";
import { useFeedback } from "../../hooks/useFeedback";
import { AnalysisReportBlock } from "../blocks/AnalysisReportBlock";
import { QuestionBlueprintAfterPrompt } from "../blocks/QuestionBlueprintAfterPrompt";
import { HallOfFameView } from "./HallOfFameView";
import { NeuralLinkHint } from "./NeuralLinkHint";
import { cn } from "../../lib/cn";
import { computeLifetimeXp } from "../../lib/xpCurve";
import {
  getPrestigePaletteArtifact,
  getPrestigeRankByLifetimeXp,
  getRankArtifact,
  getStreakFlexBand,
  getStreakInsetGlowMotion,
} from "../../lib/rankEngine";
import { arenaContentSwap, arenaShakeKeyframes, arenaShakeTransition, springHeavy } from "../../motion/variants";
import { ARENA_NEURAL_GEM_COST, resolveNeuralHint } from "../../lib/neuralHintBridge";
import { useAppStore } from "../../store/useAppStore";
import type { ArenaLeaderboardEntry } from "../../lib/syncController";

function formatClock(totalSec: number): string {
  const s = Math.max(0, Math.floor(totalSec));
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `${String(m).padStart(2, "0")}:${String(r).padStart(2, "0")}`;
}

const dockTap = { scale: 0.94 as const, y: 3 as const };

export function ArenaView() {
  const prefersReduced = useReducedMotion();
  const feedback = useFeedback();
  const activeSection = useAppStore((s) => s.activeSection);
  const run = useAppStore((s) => s.arenaRun);
  const arenaFeedback = useAppStore((s) => s.arenaFeedback);
  const selectedPerkIds = useAppStore((s) => s.selectedPerkIds);
  const submitAnswer = useAppStore((s) => s.submitAnswer);
  const clearArenaFeedback = useAppStore((s) => s.clearArenaFeedback);
  const applyFiftyFifty = useAppStore((s) => s.applyFiftyFifty);
  const applySlowmo = useAppStore((s) => s.applySlowmo);
  const abandonArenaFlow = useAppStore((s) => s.abandonArenaFlow);
  const arenaBestNotice = useAppStore((s) => s.arenaBestNotice);
  const clearArenaBestNotice = useAppStore((s) => s.clearArenaBestNotice);
  const authUser = useAppStore((s) => s.authUser);
  const cloudLastError = useAppStore((s) => s.cloudLastError);
  const cloudUplinkBusy = useAppStore((s) => s.cloudUplinkBusy);
  const ranks = useAppStore((s) => s.arenaGlobalRanks);
  const selectedMission = useAppStore((s) => s.arenaRanksMission);
  const setSelectedMission = useAppStore((s) => s.setArenaRanksMission);
  const setArenaGlobalRanks = useAppStore((s) => s.setArenaGlobalRanks);
  const arenaRankPulseKey = useAppStore((s) => s.arenaRankPulseKey);
  const openPublicDossier = useAppStore((s) => s.openPublicDossier);
  const selfLevel = useAppStore((s) => s.userLevel);
  const selfGlobalXp = useAppStore((s) => s.globalXP);
  const gems = useAppStore((s) => s.gems);
  const activeEventModifier = useAppStore((s) => s.activeEventModifier);
  const serverTimeOffsetMs = useAppStore((s) => s.serverTimeOffsetMs);
  const duelState = useAppStore((s) => s.duelState);
  const neuralOutbreak = useAppStore((s) => s.neuralOutbreak);
  const syndicateRuntimeBuffs = useAppStore((s) => s.syndicateRuntimeBuffs);
  const consumeArenaNeuralHintCost = useAppStore((s) => s.consumeArenaNeuralHintCost);

  const feedbackClearRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const prevArenaFeedback = useRef<typeof arenaFeedback>(null);
  const arenaMissByQuestionIdRef = useRef<Map<string, number>>(new Map());
  const arenaRunPresenceRef = useRef(false);
  const [viewMode, setViewMode] = useState<"arena" | "ranks" | "hall">("arena");
  const [rankLoadedOnce, setRankLoadedOnce] = useState(false);
  const [reviewPick, setReviewPick] = useState<number | null>(null);
  const [analysisGate, setAnalysisGate] = useState(false);
  const [neuralWave, setNeuralWave] = useState(false);
  const [neuralUnlocked, setNeuralUnlocked] = useState(false);
  const [neuralHintLine, setNeuralHintLine] = useState<string | null>(null);
  const [neuralBusy, setNeuralBusy] = useState(false);
  const [neuralErr, setNeuralErr] = useState<string | null>(null);
  const [overdriveTick, setOverdriveTick] = useState(0);

  useEffect(() => {
    setReviewPick(null);
    setAnalysisGate(false);
    setNeuralWave(false);
    setNeuralUnlocked(false);
    setNeuralHintLine(null);
    setNeuralBusy(false);
    setNeuralErr(null);
  }, [run?.questionIndex, run?.outcome]);

  useEffect(() => {
    if (reviewPick === null) {
      setAnalysisGate(false);
      return;
    }
    const id = requestAnimationFrame(() => setAnalysisGate(true));
    return () => cancelAnimationFrame(id);
  }, [reviewPick]);

  useEffect(() => {
    if (arenaFeedback === "correct" && prevArenaFeedback.current !== "correct") {
      feedback.arenaCorrect();
    }
    if (arenaFeedback === "wrong" && prevArenaFeedback.current !== "wrong") {
      feedback.arenaWrong();
    }
    prevArenaFeedback.current = arenaFeedback;
  }, [arenaFeedback, feedback]);

  useEffect(() => {
    if (!run) {
      arenaRunPresenceRef.current = false;
      arenaMissByQuestionIdRef.current = new Map();
      return;
    }
    if (!arenaRunPresenceRef.current) {
      arenaRunPresenceRef.current = true;
      arenaMissByQuestionIdRef.current = new Map();
    }
  }, [run]);

  useEffect(() => {
    if (arenaFeedback !== "wrong") return;
    const r = useAppStore.getState().arenaRun;
    if (!r || r.outcome) return;
    const qs = getQuestionsForExam(r.examId);
    const cur = qs[r.questionIndex];
    const key = cur?.id ?? `__idx_${r.examId}_${r.questionIndex}`;
    const map = arenaMissByQuestionIdRef.current;
    const next = (map.get(key) ?? 0) + 1;
    map.set(key, next);
    if (next === 1) setNeuralWave(true);
  }, [arenaFeedback]);

  useEffect(() => {
    if (activeSection !== "arena") return;
    const id = window.setInterval(() => {
      const st = useAppStore.getState();
      if (st.activeSection !== "arena" || !st.arenaRun || st.arenaRun.outcome) return;
      st.tickArenaTimer();
    }, 1000);
    return () => window.clearInterval(id);
  }, [activeSection]);

  useEffect(() => {
    if (!arenaFeedback) return;
    if (feedbackClearRef.current) clearTimeout(feedbackClearRef.current);
    feedbackClearRef.current = setTimeout(() => {
      clearArenaFeedback();
      feedbackClearRef.current = null;
    }, 520);
    return () => {
      if (feedbackClearRef.current) clearTimeout(feedbackClearRef.current);
    };
  }, [arenaFeedback, clearArenaFeedback]);

  useEffect(() => {
    if (!activeEventModifier) return;
    const id = window.setInterval(() => setOverdriveTick((x) => x + 1), 1000);
    return () => window.clearInterval(id);
  }, [activeEventModifier]);

  useEffect(() => {
    if (!arenaBestNotice) return;
    const t = window.setTimeout(() => clearArenaBestNotice(), 2400);
    return () => window.clearTimeout(t);
  }, [arenaBestNotice, clearArenaBestNotice]);

  useEffect(() => {
    if (activeSection !== "arena") return;
    const teardown = import("../../lib/syncController").then((m) => m.subscribeToArenaLeaderboards());
    return () => {
      void teardown.then((off) => off());
    };
  }, [activeSection]);

  if (!run) {
    return (
      <div className="mx-auto max-w-[1240px] border border-white/[0.1] bg-surface/80 p-8 text-center font-sans text-foreground-muted">
        Kein aktiver Lauf · zurück zum Loadout
      </div>
    );
  }

  const exam = getExam(run.examId);
  const duelQuestions =
    duelState && duelState.status !== "finished" && duelState.questionIds.length > 0
      ? duelState.questionIds.map((id) => getArenaQuestionById(id)).filter((row): row is NonNullable<ReturnType<typeof getArenaQuestionById>> => !!row)
      : null;
  const questions = duelQuestions && duelQuestions.length > 0 ? duelQuestions : getQuestionsForExam(run.examId);
  const q = questions[run.questionIndex];

  const openNeuralChannel = () => {
    if (!q || neuralBusy || neuralUnlocked) return;
    setNeuralBusy(true);
    setNeuralErr(null);
    const paid = consumeArenaNeuralHintCost();
    if (!paid) {
      setNeuralErr("Keine Reserven für den Ausschnitt");
      setNeuralBusy(false);
      return;
    }
    void resolveNeuralHint(q)
      .then((line) => {
        setNeuralHintLine(line);
        setNeuralUnlocked(true);
      })
      .catch(() => {
        setNeuralErr("Uplink brach weg");
      })
      .finally(() => {
        setNeuralBusy(false);
      });
  };

  const showFifty =
    selectedPerkIds.includes("fifty_fifty") && !run.fiftyFiftyUsed && !run.outcome;
  const showSlow = selectedPerkIds.includes("slowmo") && !run.slowmoUsed && !run.outcome;

  const roundNum = String(run.questionIndex + 1).padStart(2, "0");
  const comboGhost = String(run.combo);
  const ownRankInTop = authUser ? ranks.findIndex((r) => r.user_id === authUser.id) : -1;
  void overdriveTick;
  const overdriveRemainSec = activeEventModifier
    ? Math.max(0, Math.ceil((activeEventModifier.endsAtMs - (Date.now() + serverTimeOffsetMs)) / 1000))
    : 0;
  const overdriveActiveForQuestion =
    !!activeEventModifier && overdriveRemainSec > 0 && !!q?.module && q.module === activeEventModifier.targetModule;
  const overdriveMin = String(Math.floor(overdriveRemainSec / 60)).padStart(2, "0");
  const overdriveSec = String(overdriveRemainSec % 60).padStart(2, "0");
  const mirrorModeActive = !!duelState?.mirrorMode;
  const mirrorDurationMs = Math.max(1_000, Math.floor(duelState?.ghostDurationMs ?? 1_000_000));
  const mirrorElapsedMs = duelState ? Math.max(0, Date.now() - duelState.startedAtMs) : 0;
  const mirrorProgressLive = mirrorModeActive ? Math.max(0, Math.min(1, mirrorElapsedMs / mirrorDurationMs)) : 0;
  const mirrorScoreLive = mirrorModeActive
    ? Math.max(0, Math.floor((duelState?.opponentScore ?? 0) * mirrorProgressLive))
    : 0;
  const rivalProgressDisplay = mirrorModeActive ? mirrorProgressLive : (duelState?.opponentProgress ?? 0);
  const rivalScoreDisplay = mirrorModeActive ? mirrorScoreLive : (duelState?.opponentScore ?? 0);
  const mirrorRemainSec = mirrorModeActive ? Math.max(0, Math.ceil((mirrorDurationMs - mirrorElapsedMs) / 1000)) : 0;
  const mirrorBeat = !!(
    duelState &&
    duelState.status === "finished" &&
    duelState.mirrorMode &&
    duelState.winnerUserId === authUser?.id
  );
  const activeBossModifier = getBossModifierById(duelState?.bossModifierId);
  const viralModifierId =
    neuralOutbreak.infected && !mirrorModeActive
      ? (["CHRONO_CRUNCH", "DATA_BLUR", "NEURAL_STATIC"][run.questionIndex % 3] ?? null)
      : null;
  const viralModifier = getBossModifierById(viralModifierId);
  const activeModifier = activeBossModifier ?? viralModifier;
  const dataBlurActive = !!activeBossModifier && activeBossModifier.optionBlurPx > 0 && reviewPick === null;
  const viralBlurActive = !!viralModifier && viralModifier.optionBlurPx > 0 && reviewPick === null;
  const missionFilters = (() => {
    const set = new Set<string>(["ALL", run.examId]);
    for (const row of ranks) set.add(row.mission_type);
    return Array.from(set);
  })();
  const formatOperator = (row: ArenaLeaderboardEntry) =>
    row.operator_handle?.trim() || "Unknown_Operator";

  const loadGlobalRanks = async (missionType = selectedMission) => {
    const rows = await import("../../lib/syncController").then((m) =>
      m.fetchGlobalArenaRanks(10, missionType),
    );
    setArenaGlobalRanks(rows);
    setRankLoadedOnce(true);
  };

  return (
    <div className="relative mx-auto w-full max-w-[1240px] space-y-8">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <motion.button
          type="button"
          whileTap={dockTap}
          transition={springHeavy}
          onClick={() => abandonArenaFlow()}
          className="border border-signal/35 bg-signal/[0.08] px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-signal hover-breathe hover:border-signal/50"
        >
          Abbruch zum Hub
        </motion.button>
        <p className="font-mono text-[10px] uppercase tracking-[0.25em] text-foreground-muted">
          {exam.title} · Boss Arena
        </p>
      </div>
      {duelState && duelState.status !== "finished" ? (
        <div className="relative overflow-hidden border border-fuchsia-300/35 bg-fuchsia-500/[0.08] p-3">
          {mirrorModeActive ? (
            <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.08]" aria-hidden />
          ) : null}
          <div className="flex flex-wrap items-center justify-between gap-2">
            <p className="font-mono text-[10px] font-bold uppercase tracking-[0.22em] text-fuchsia-100">
              {mirrorModeActive ? "Neural Mirror Link" : "Neural Duel Link"}
            </p>
            <p className="font-mono text-[9px] uppercase tracking-[0.16em] text-fuchsia-200/90">
              {duelState.opponentHandle} {duelState.opponentOnline ? "online" : "offline"} {mirrorModeActive ? `shadow ${String(Math.floor(mirrorRemainSec / 60)).padStart(2, "0")}:${String(mirrorRemainSec % 60).padStart(2, "0")}` : `stake ${duelState.stakeAmount} ${duelState.stakeKind}`}
            </p>
          </div>
          <div className="mt-2 grid gap-2 sm:grid-cols-2">
            <div>
              <p className="font-mono text-[8px] uppercase tracking-[0.14em] text-fuchsia-200/85">
                You {Math.round(duelState.myProgress * 100)} score {duelState.myScore}
              </p>
              <div className="mt-1 h-2 overflow-hidden border border-fuchsia-300/35 bg-black/40">
                <motion.div className="h-full bg-fuchsia-300/75" animate={{ width: `${Math.round(duelState.myProgress * 100)}%` }} />
              </div>
            </div>
            <div>
              <p className="font-mono text-[8px] uppercase tracking-[0.14em] text-cyan-200/85">
                Rival {Math.round(rivalProgressDisplay * 100)} score {rivalScoreDisplay}
              </p>
              <div className="relative mt-1 h-2 overflow-hidden border border-cyan-300/35 bg-black/40">
                <div className="pointer-events-none absolute inset-0 opacity-30 [background-image:repeating-linear-gradient(180deg,rgba(255,255,255,0.2)_0,rgba(255,255,255,0.2)_1px,transparent_1px,transparent_3px)]" />
                <motion.div
                  className="h-full bg-cyan-300/55"
                  animate={{ width: `${Math.round(rivalProgressDisplay * 100)}%` }}
                />
              </div>
            </div>
          </div>
          {activeBossModifier ? (
            <div className="mt-2 border border-fuchsia-300/35 bg-black/35 px-2 py-1.5">
              <p className="font-mono text-[8px] uppercase tracking-[0.16em] text-fuchsia-100/90">
                Modifier {activeBossModifier.shortLabel}
              </p>
              {duelState?.bountyHotZone ? (
                <motion.p
                  className="mt-1 inline-flex border border-red-300/55 bg-red-500/[0.24] px-2 py-0.5 font-mono text-[8px] font-black uppercase tracking-[0.18em] text-red-100"
                  animate={prefersReduced ? { opacity: 1 } : { opacity: [0.45, 1, 0.5], x: [0, 1.5, -1.5, 0] }}
                  transition={prefersReduced ? { duration: 0 } : { duration: 0.45, repeat: Infinity, ease: "linear" }}
                >
                  HOT ZONE x{Math.max(1, duelState?.bountyDecayStacks ?? 1)}
                </motion.p>
              ) : null}
              <div className="mt-1 flex items-center gap-2">
                {activeBossModifier.glitchTokens.map((token, idx) => (
                  <motion.span
                    key={`${token}-${idx}`}
                    className="font-mono text-[8px] uppercase tracking-[0.18em] text-fuchsia-200/90"
                    animate={
                      prefersReduced
                        ? { opacity: 0.9 }
                        : { opacity: [0.35, 1, 0.42], x: [0, 1.5, -1.5, 0], y: [0, -1, 0.5, 0] }
                    }
                    transition={prefersReduced ? { duration: 0 } : { duration: 0.42 + idx * 0.08, repeat: Infinity, ease: "linear" }}
                  >
                    {token}
                  </motion.span>
                ))}
                <span className="font-mono text-[8px] uppercase tracking-[0.16em] text-cyan-100/90">
                  {activeBossModifier.description}
                </span>
              </div>
            </div>
          ) : null}
        </div>
      ) : null}
      {neuralOutbreak.infected && !mirrorModeActive ? (
        <motion.div
          initial={prefersReduced ? false : { opacity: 0.55, y: -4 }}
          animate={prefersReduced ? { opacity: 1, y: 0 } : { opacity: [0.55, 1, 0.62], x: [0, -1.5, 1.5, 0] }}
          transition={prefersReduced ? { duration: 0 } : { duration: 0.7, repeat: Infinity, ease: "linear" }}
          className="relative overflow-hidden border border-emerald-300/45 bg-gradient-to-r from-emerald-500/[0.2] via-cyan-500/[0.14] to-black/60 px-3 py-2 shadow-[0_0_20px_rgb(16_185_129/0.2)]"
        >
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.24]" aria-hidden />
          <p className="relative font-mono text-[10px] font-black uppercase tracking-[0.22em] text-emerald-100">
            SYSTEM INFECTED
          </p>
          <p className="relative mt-1 font-mono text-[9px] uppercase tracking-[0.16em] text-emerald-100/92">
            Module {neuralOutbreak.module ?? "process"} Purge {neuralOutbreak.progress}/{Math.max(1, neuralOutbreak.target)} {activeModifier ? `Modifier ${activeModifier.shortLabel}` : ""}
          </p>
        </motion.div>
      ) : null}
      {activeEventModifier && overdriveRemainSec > 0 ? (
        <motion.div
          initial={prefersReduced ? false : { opacity: 0.55, y: -4 }}
          animate={
            prefersReduced
              ? { opacity: 1, y: 0 }
              : { opacity: [0.52, 1, 0.65, 1], x: [0, -1, 1, 0], filter: ["hue-rotate(0deg)", "hue-rotate(18deg)", "hue-rotate(0deg)"] }
          }
          transition={prefersReduced ? { duration: 0 } : { duration: 0.85, repeat: Infinity, ease: "linear" }}
          className={cn(
            "relative overflow-hidden border px-4 py-2 shadow-[0_0_22px_rgb(251_146_60/0.22)]",
            overdriveActiveForQuestion
              ? "border-orange-300/55 bg-gradient-to-r from-orange-500/22 via-amber-400/18 to-cyan-400/18"
              : "border-cyan-300/45 bg-gradient-to-r from-cyan-500/14 via-cyan-400/10 to-orange-500/10",
          )}
        >
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.18]" aria-hidden />
          <p className="relative font-mono text-[10px] font-black uppercase tracking-[0.26em] text-orange-100">
            NEURAL OVERDRIVE ACTIVE
          </p>
          <p className="relative mt-1 font-mono text-[10px] uppercase tracking-[0.2em] text-orange-100/92">
            Ziel Modul {activeEventModifier.targetModule} Zeit {overdriveMin}:{overdriveSec} XP Mult {activeEventModifier.xpMultiplier.toFixed(2)}
          </p>
        </motion.div>
      ) : null}
      {syndicateRuntimeBuffs.syndicateId ? (
        <div className="relative overflow-hidden border border-lime-300/40 bg-gradient-to-r from-lime-500/[0.14] via-cyan-500/[0.08] to-black/60 px-3 py-2">
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.16]" aria-hidden />
          <p className="relative font-mono text-[9px] uppercase tracking-[0.16em] text-lime-100/92">
            Syndicate Buff XP x{syndicateRuntimeBuffs.xpMultiplier.toFixed(2)} Time +{syndicateRuntimeBuffs.timeBonusSec}s Drop +{Math.round(syndicateRuntimeBuffs.dropRateBonus * 100)}%
          </p>
        </div>
      ) : null}

      <div className="flex flex-wrap gap-2">
        <motion.button
          type="button"
          whileTap={dockTap}
          transition={springHeavy}
          onClick={() => setViewMode("arena")}
          className={cn(
            "border px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide hover-breathe",
            viewMode === "arena"
              ? "border-white/[0.16] bg-white/[0.06] text-foreground"
              : "border-white/[0.1] bg-transparent text-foreground-muted hover:border-white/[0.14]",
          )}
        >
          Arena Feed
        </motion.button>
        <motion.button
          type="button"
          whileTap={dockTap}
          transition={springHeavy}
          onClick={() => {
            setViewMode("ranks");
            if (!rankLoadedOnce) void loadGlobalRanks(selectedMission);
            else void loadGlobalRanks(selectedMission);
          }}
          className={cn(
            "border px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide hover-breathe",
            viewMode === "ranks"
              ? "border-white/[0.16] bg-white/[0.06] text-foreground"
              : "border-white/[0.1] bg-transparent text-foreground-muted hover:border-white/[0.14]",
          )}
        >
          Global Ranks
        </motion.button>
        <motion.button
          type="button"
          whileTap={dockTap}
          transition={springHeavy}
          onClick={() => setViewMode("hall")}
          className={cn(
            "border px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide hover-breathe",
            viewMode === "hall"
              ? "border-amber-300/45 bg-amber-500/[0.08] text-amber-100"
              : "border-white/[0.1] bg-transparent text-foreground-muted hover:border-amber-300/32 hover:text-amber-100",
          )}
        >
          Hall Of Fame
        </motion.button>
      </div>

      {viewMode === "ranks" ? (
        <motion.div
          initial={prefersReduced ? false : { opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={springHeavy}
          className="border border-white/[0.1] bg-surface/85 p-6 sm:p-8"
        >
          <div className="mb-4 flex items-center justify-between gap-4">
            <div>
              <p className="font-mono text-[10px] uppercase tracking-[0.28em] text-foreground-muted">
                Arena Leaderboard
              </p>
              <h3 className="headline-cinema mt-2 text-2xl font-semibold">Top 10 Operator</h3>
            </div>
            <motion.button
              type="button"
              whileTap={dockTap}
              transition={springHeavy}
              onClick={() => void loadGlobalRanks(selectedMission)}
              className="border border-white/[0.1] bg-transparent px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-foreground-muted hover-breathe hover:border-white/[0.16] hover:text-foreground"
            >
              Aktualisieren
            </motion.button>
          </div>
          <div className="mb-4 flex flex-wrap gap-5 border-b border-white/[0.1]">
            {missionFilters.map((mission) => {
              const active = selectedMission === mission;
              return (
                <motion.button
                  key={mission}
                  type="button"
                  whileTap={dockTap}
                  transition={springHeavy}
                  onClick={() => {
                    setSelectedMission(mission);
                    void loadGlobalRanks(mission);
                  }}
                  className={cn(
                    "-mb-px border-b bg-transparent py-2 font-mono text-[11px] uppercase tracking-[0.22em] hover-breathe",
                    active
                      ? "border-foreground-muted text-titan"
                      : "border-transparent text-foreground-muted hover:border-white/[0.12] hover:text-foreground",
                  )}
                >
                  {mission === "ALL" ? "Alle Missionen" : mission}
                </motion.button>
              );
            })}
          </div>
          <div className="border border-white/[0.1]">
            {cloudUplinkBusy ? (
              <div className="px-4 py-6 font-mono text-xs uppercase tracking-wider text-foreground-muted">
                Rangliste wird synchronisiert
              </div>
            ) : ranks.length === 0 ? (
              <div className="px-4 py-6 font-mono text-xs uppercase tracking-wider text-foreground-muted">
                Keine globalen Einträge gefunden
              </div>
            ) : (
              ranks.map((row, idx) => {
                const own = !!authUser && row.user_id === authUser.id;
                const rankArtifact = getRankArtifact(row.leaderboard_level);
                const selfLife = own ? computeLifetimeXp(selfLevel, selfGlobalXp) : 0;
                const rankTitleBold = own
                  ? getPrestigeRankByLifetimeXp(selfLife).title
                  : rankArtifact.tier.replaceAll("_", " ");
                const rankTitleClass = own ? getPrestigePaletteArtifact(selfLife).accentClass : "text-foreground/88";
                const streak = row.leaderboard_streak ?? 0;
                const streakBand = getStreakFlexBand(streak);
                const streakGlow = getStreakInsetGlowMotion(rankArtifact, streakBand);
                return (
                  <motion.button
                    key={`${row.user_id}-${row.created_at}-${idx}`}
                    type="button"
                    initial={
                      arenaRankPulseKey === `${row.user_id}-${row.created_at}`
                        ? { opacity: 0.75, y: 8, backgroundColor: "rgb(200 204 210 / 0.16)" }
                        : false
                    }
                    animate={{ opacity: 1, y: 0, backgroundColor: own ? "rgb(179 24 38 / 0.07)" : "rgba(0,0,0,0)" }}
                    transition={{ type: "spring", stiffness: 280, damping: 30, mass: 1 }}
                    whileTap={dockTap}
                    onClick={() => openPublicDossier(row.user_id, row.operator_handle)}
                    className={cn(
                      "relative grid w-full grid-cols-[48px_1fr_auto] items-center gap-3 px-4 py-3 text-left hover-breathe hover:bg-white/[0.03]",
                      idx < ranks.length - 1 && "border-b border-white/[0.1]",
                      own ? "bg-signal/[0.07]" : "bg-transparent",
                      streakBand !== "none" && "ring-1 ring-toxic/25",
                    )}
                  >
                    {streakGlow && !prefersReduced ? (
                      <motion.div
                        aria-hidden
                        className="pointer-events-none absolute inset-0 z-0"
                        initial={{ opacity: 0 }}
                        animate={{
                          opacity: streakGlow.pulseOpacity,
                        }}
                        transition={{ duration: streakGlow.duration, repeat: Infinity, ease: "easeInOut" }}
                        style={{
                          boxShadow: streakGlow.boxShadow,
                        }}
                      />
                    ) : null}
                    <span
                      className={cn(
                        "relative z-10 font-mono text-xs tabular-nums",
                        own ? "text-signal" : "text-foreground-muted",
                      )}
                    >
                      #{idx + 1}
                    </span>
                    <div className="relative z-10 flex min-w-0 items-center gap-3">
                      <ArtifactPedestal
                        artifact={rankArtifact}
                        variant="compact"
                        pulseActive={arenaRankPulseKey === `${row.user_id}-${row.created_at}`}
                        className="w-[22px] shrink-0"
                      />
                      <div className="min-w-0">
                        <p
                          className={cn(
                            "truncate font-mono text-xs uppercase tracking-wide",
                            own ? "text-signal" : "text-foreground",
                          )}
                        >
                          {formatOperator(row)}
                        </p>
                        <p
                          className={cn(
                            "mt-0.5 truncate font-mono text-[11px] font-bold uppercase tracking-[0.12em]",
                            rankTitleClass,
                          )}
                        >
                          {rankTitleBold}
                        </p>
                        <p className="mt-0.5 truncate font-mono text-[10px] uppercase tracking-wider text-foreground-muted">
                          Mission {row.mission_type}
                        </p>
                      </div>
                    </div>
                    <div className="relative z-10 flex flex-col items-end gap-0.5">
                      <span
                        className={cn(
                          "font-sans text-lg font-semibold tabular-nums tracking-[-0.04em]",
                          own ? "text-signal" : "text-foreground-muted",
                        )}
                      >
                        {row.score}
                      </span>
                      {streak > 0 ? (
                        <span className="font-mono text-[10px] font-semibold uppercase tracking-wider text-toxic/95">
                          {streak}d streak
                        </span>
                      ) : null}
                    </div>
                  </motion.button>
                );
              })
            )}
          </div>
          <div className="mt-4 min-h-5 font-mono text-[10px] uppercase tracking-[0.22em] text-foreground-muted">
            {ownRankInTop >= 0
              ? `Dein Rang in den Top 10 ist #${ownRankInTop + 1}`
              : cloudLastError
                ? `Uplink Hinweis ${cloudLastError}`
                : "Du bist noch nicht in den Top 10"}
          </div>
        </motion.div>
      ) : viewMode === "hall" ? (
        <HallOfFameView />
      ) : (
      <motion.div
        animate={
          arenaFeedback === "wrong" && !prefersReduced
            ? arenaShakeKeyframes
            : { x: 0, rotate: 0 }
        }
        transition={arenaShakeTransition}
        className="relative overflow-hidden border border-white/[0.1] bg-surface/85 p-6 sm:p-8"
      >
        <span
          className="pointer-events-none absolute left-0 top-1/2 z-0 -translate-y-1/2 select-none font-sans text-[clamp(7rem,28vw,16rem)] font-bold tabular-nums leading-none text-white/[0.05]"
          aria-hidden
        >
          {roundNum}
        </span>
        <span
          className="pointer-events-none absolute bottom-2 right-2 z-0 select-none font-sans text-[clamp(5rem,18vw,11rem)] font-bold tabular-nums leading-none text-white/[0.05]"
          aria-hidden
        >
          {comboGhost}
        </span>

        {q && !run.outcome ? (
          <NeuralLinkHint
            active={neuralWave}
            unlocked={neuralUnlocked}
            hintLine={neuralHintLine}
            busy={neuralBusy}
            error={neuralErr}
            hasGemBudget={gems >= ARENA_NEURAL_GEM_COST}
            onOpenChannel={openNeuralChannel}
          />
        ) : null}

        <AnimatePresence>
          {arenaFeedback === "wrong" ? (
            <motion.div
              key="flash-red"
              initial={{ opacity: 0 }}
              animate={{ opacity: 0.38 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.28 }}
              className="pointer-events-none absolute inset-0 bg-gradient-to-br from-signal/35 via-signal/10 to-transparent mix-blend-screen"
            />
          ) : null}
          {arenaFeedback === "correct" ? (
            <motion.div
              key="flash-ok"
              initial={{ opacity: 0 }}
              animate={{ opacity: 0.28 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.35 }}
              className="pointer-events-none absolute inset-0 bg-gradient-to-tl from-white/15 via-white/5 to-transparent mix-blend-screen"
            />
          ) : null}
        </AnimatePresence>

        <div className="relative z-10 space-y-8">
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="space-y-2">
              <div className="flex items-center justify-between gap-2 font-mono text-[11px] font-medium uppercase tracking-wider text-foreground-muted">
                <span>Du</span>
                <span className="tabular-nums text-foreground">{Math.round(run.userHp)}%</span>
              </div>
              <div className="h-3 overflow-hidden border border-white/[0.1] bg-void/60">
                <motion.div
                  className="h-full bg-foreground/85"
                  initial={false}
                  animate={{ width: `${run.userHp}%` }}
                  transition={springHeavy}
                />
              </div>
            </div>
            <div className="space-y-2">
              <div className="flex items-center justify-between gap-2 font-mono text-[11px] font-medium uppercase tracking-wider text-foreground-muted">
                <span className="text-signal">IHK-Prüfung</span>
                <span className="tabular-nums text-foreground">{Math.round(run.examHp)}%</span>
              </div>
              <div className="h-3 overflow-hidden border border-white/[0.1] bg-void/60">
                <motion.div
                  className="h-full bg-signal/80"
                  initial={false}
                  animate={{ width: `${run.examHp}%` }}
                  transition={springHeavy}
                />
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center justify-center gap-2">
            <p className="font-mono text-[10px] font-medium uppercase tracking-[0.35em] text-foreground-muted">
              Countdown
            </p>
            <motion.div
              initial={false}
              animate={
                prefersReduced || run.timeRemainingSec > 30
                  ? { scale: 1 }
                  : { scale: [1, 1.03, 1] }
              }
              transition={
                prefersReduced || run.timeRemainingSec > 30
                  ? { duration: 0 }
                  : { duration: 1.1, repeat: Infinity, repeatType: "mirror", ease: "easeInOut" }
              }
              className={cn(
                "font-sans text-5xl font-semibold tabular-nums tracking-[-0.05em] sm:text-6xl",
                run.timeRemainingSec <= 30 ? "text-signal" : "text-foreground",
              )}
            >
              {formatClock(run.timeRemainingSec)}
            </motion.div>
            <p className="font-mono text-xs text-foreground-muted">
              Combo {run.combo} · Mult ×{(1 + Math.min(run.combo, 12) * 0.1).toFixed(1)}
            </p>
          </div>

          <AnimatePresence mode="wait">
            {run.outcome ? (
              <motion.div
                key="outcome"
                variants={arenaContentSwap}
                initial="initial"
                animate="animate"
                exit="exit"
                className="flex flex-col items-center gap-4 border border-white/[0.1] bg-surface-muted/40 p-8 text-center"
              >
                <AnimatePresence>
                  {arenaBestNotice ? (
                    <motion.div
                      key="best-notice"
                      initial={{ opacity: 0, y: -8 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -6 }}
                      className="border border-signal/45 bg-signal/[0.1] px-4 py-2 font-mono text-xs font-semibold uppercase tracking-[0.22em] text-signal"
                    >
                      {arenaBestNotice}
                    </motion.div>
                  ) : null}
                </AnimatePresence>
                {run.outcome === "win" ? (
                  <IconTrophy className="size-14 text-foreground-muted" aria-hidden />
                ) : (
                  <IconSkull className="size-14 text-signal" aria-hidden />
                )}
                <h3 className="headline-cinema text-2xl font-semibold">
                  {run.outcome === "win" ? "Boss besiegt" : "Run beendet"}
                </h3>
                <p className="max-w-md font-sans text-sm leading-relaxed text-foreground-muted">
                  {run.outcome === "win"
                    ? "Du hast die Prüfungssimulation geknackt · bleib scharf für den echten Termin"
                    : "Timer oder Leiste · hol dir Loadout und versuch es erneut"}
                </p>
                {duelState && duelState.status === "finished" ? (
                  duelState.mirrorMode ? (
                    <p className="font-mono text-[10px] uppercase tracking-[0.16em] text-cyan-100/90">
                      {mirrorBeat
                        ? `Shadow time broken your ${Math.ceil((duelState.myElapsedMs ?? 0) / 1000)}s mirror ${Math.ceil((duelState.ghostDurationMs ?? 0) / 1000)}s`
                        : `Shadow held your ${Math.ceil((duelState.myElapsedMs ?? 0) / 1000)}s mirror ${Math.ceil((duelState.ghostDurationMs ?? 0) / 1000)}s`}
                    </p>
                  ) : (
                    <p className="font-mono text-[10px] uppercase tracking-[0.16em] text-fuchsia-100/90">
                      Duel winner {duelState.winnerUserId === authUser?.id ? "you" : duelState.opponentHandle} your score {duelState.myScore} rival {duelState.opponentScore}
                    </p>
                  )
                ) : null}
                <motion.button
                  type="button"
                  whileTap={dockTap}
                  transition={springHeavy}
                  onClick={() => abandonArenaFlow()}
                  className="border border-white/[0.12] bg-white/[0.06] px-8 py-3 font-mono text-sm font-semibold uppercase tracking-wide text-foreground hover-breathe hover:border-white/[0.18]"
                >
                  Zurück zum Hub
                </motion.button>
              </motion.div>
            ) : q ? (
              <motion.div
                key={`q-${run.questionIndex}`}
                variants={arenaContentSwap}
                initial="initial"
                animate="animate"
                exit="exit"
                className="space-y-6"
              >
                <div>
                  <p className="font-mono text-[10px] uppercase tracking-widest text-foreground-muted">
                    {q.type === "sql_challenge" ? "SQL Challenge" : "Frage"} {run.questionIndex + 1} / {questions.length}
                  </p>
                  <h4 className="mt-2 max-w-4xl font-serif text-xl font-semibold leading-snug tracking-[-0.015em] text-foreground sm:text-2xl">
                    {q.prompt}
                  </h4>
                  <QuestionBlueprintAfterPrompt question={q} />
                </div>

                {reviewPick === null ? (
                  <>
                    <div className="flex flex-wrap gap-2">
                      {showFifty ? (
                        <motion.button
                          type="button"
                          whileTap={dockTap}
                          transition={springHeavy}
                          onClick={() => applyFiftyFifty()}
                          className="border border-signal/40 bg-signal/[0.1] px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-signal hover-breathe hover:border-signal/55"
                        >
                          50/50 aktivieren
                        </motion.button>
                      ) : null}
                      {showSlow ? (
                        <motion.button
                          type="button"
                          whileTap={dockTap}
                          transition={springHeavy}
                          onClick={() => applySlowmo()}
                          className="border border-white/[0.12] bg-transparent px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-foreground-muted hover-breathe hover:border-white/[0.18] hover:text-foreground"
                        >
                          Zeitlupe +15s
                        </motion.button>
                      ) : null}
                      {run.shieldCharges > 0 ? (
                        <span className="border border-white/[0.1] px-4 py-2 font-mono text-xs font-semibold uppercase tracking-wide text-foreground-muted">
                          Schild bereit
                        </span>
                      ) : null}
                    </div>

                    <div className="flex flex-col">
                      {(() => {
                        const visible = q.options
                          .map((opt, idx) => ({ opt, idx }))
                          .filter(({ idx }) => !run.hiddenOptionIndices.includes(idx));
                        return visible.map(({ opt, idx }, i) => {
                          const isLast = i === visible.length - 1;
                          return (
                            <motion.button
                              key={idx}
                              type="button"
                              whileTap={dockTap}
                              transition={springHeavy}
                              onClick={() => setReviewPick(idx)}
                              className={cn(
                                "question-scrollbar w-full border-0 bg-transparent px-0 py-4 text-left font-sans text-sm text-foreground transition-colors duration-700 hover-breathe hover:bg-white/[0.03]",
                                !isLast && "border-b border-white/[0.12]",
                              )}
                            >
                              <span className="font-mono text-[10px] uppercase tracking-wider text-foreground-muted">
                                {q.type === "sql_challenge" ? `Query ${idx + 1}` : `Option ${idx + 1}`}
                              </span>
                              <p
                                className={cn(
                                  "mt-1 max-h-28 overflow-auto leading-snug transition-[filter,transform,opacity] duration-200",
                                  dataBlurActive && "opacity-90",
                                )}
                              style={
                                  dataBlurActive || viralBlurActive
                                    ? {
                                        filter: `blur(${(activeBossModifier?.optionBlurPx ?? 0) + (viralModifier?.optionBlurPx ?? 0)}px)`,
                                        transform: `translateX(${((idx % 2 === 0 ? 1 : -1) * 0.6).toFixed(1)}px)`,
                                      }
                                    : undefined
                                }
                              >
                                {opt}
                              </p>
                            </motion.button>
                          );
                        });
                      })()}
                    </div>
                  </>
                ) : (
                  <div className="space-y-4">
                    <AnalysisReportBlock>
                      {q.explanation?.trim() || "Keine Kurzbegründung in der Bank hinterlegt"}
                    </AnalysisReportBlock>
                    <motion.button
                      type="button"
                      whileTap={dockTap}
                      transition={springHeavy}
                      disabled={!analysisGate}
                      onClick={() => {
                        if (reviewPick === null || !analysisGate) return;
                        submitAnswer(reviewPick);
                        setReviewPick(null);
                      }}
                      className={cn(
                        "w-full border px-4 py-3 font-mono text-xs font-bold uppercase tracking-[0.2em] transition-colors",
                        analysisGate
                          ? "border-amber-400/45 bg-amber-500/15 text-amber-100 hover:bg-amber-500/25"
                          : "cursor-not-allowed border-white/[0.08] text-foreground-muted opacity-40",
                      )}
                    >
                      {reviewPick === q.correctIndex ? "Nächste Frage" : "Erneuter Versuch"}
                    </motion.button>
                  </div>
                )}
              </motion.div>
            ) : null}
          </AnimatePresence>
        </div>
      </motion.div>
      )}
    </div>
  );
}
