import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { cn } from "../../lib/cn";
import { getGlobalFrictionData, type GlobalFrictionTile } from "../../lib/syncController";
import type { QuestionModule } from "../../data/questionSchema";

const MODULE_LABEL: Record<QuestionModule, string> = {
  networking: "Netzwerk",
  security: "Security",
  operating_systems: "Betriebssysteme",
  hardware: "Hardware",
  programming: "Programmierung",
  databases: "Datenbanken",
  testing: "Testing",
  architecture: "Architektur",
  process: "Prozess",
  wiso: "Wirtschaft",
};

function heatTone(rate: number): string {
  const t = Math.max(0, Math.min(1, rate));
  const r = Math.round(56 + (249 - 56) * t);
  const g = Math.round(189 + (115 - 189) * t);
  const b = Math.round(248 + (22 - 248) * t);
  return `rgba(${r}, ${g}, ${b}, 0.22)`;
}

function edgeTone(rate: number): string {
  const t = Math.max(0, Math.min(1, rate));
  const r = Math.round(125 + (251 - 125) * t);
  const g = Math.round(211 + (146 - 211) * t);
  const b = Math.round(252 + (60 - 252) * t);
  return `rgba(${r}, ${g}, ${b}, 0.52)`;
}

export function MatrixHeatmap() {
  const prefersReduced = !!useReducedMotion();
  const [rows, setRows] = useState<GlobalFrictionTile[]>([]);
  const [busy, setBusy] = useState(true);

  useEffect(() => {
    let alive = true;
    void getGlobalFrictionData().then((snap) => {
      if (!alive) return;
      setRows(snap.rows);
      setBusy(false);
    });
    return () => {
      alive = false;
    };
  }, []);

  const maxRate = useMemo(() => rows.reduce((m, row) => Math.max(m, row.frictionRate), 0.001), [rows]);

  return (
    <section className="relative overflow-hidden border border-white/[0.1] bg-black/50 backdrop-blur-md">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.05]" aria-hidden />
      <header className="relative flex flex-wrap items-end justify-between gap-2 border-b border-white/[0.08] px-4 py-2 sm:px-5">
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-foreground-muted">
          Matrix Heatmap
        </p>
        <p className="font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">
          Global Friction Grid
        </p>
      </header>

      <div className="relative p-3 sm:p-4">
        {busy ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-foreground-muted">
            Heatmap uplink läuft
          </p>
        ) : rows.length === 0 ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-foreground-muted">
            Keine Friction Telemetrie verfügbar
          </p>
        ) : (
          <div className="grid gap-2 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5">
            {rows.map((row) => {
              const intensity = Math.max(0.06, Math.min(1, row.frictionRate / maxRate));
              const successPct = Math.round(row.successRate * 100);
              const frictionPct = Math.round(row.frictionRate * 100);
              return (
                <motion.div
                  key={row.module}
                  initial={prefersReduced ? false : { opacity: 0, y: -8 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: prefersReduced ? 0 : 0.2, ease: [0.22, 1, 0.36, 1] }}
                  className="group relative overflow-hidden border bg-black/20 p-3"
                  style={{
                    borderColor: edgeTone(intensity),
                    backgroundColor: heatTone(intensity),
                    boxShadow: `inset 0 0 24px ${heatTone(intensity)}, 0 0 18px ${edgeTone(intensity)}`,
                  }}
                >
                  <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.13]" aria-hidden />
                  <p className="relative font-mono text-[9px] font-semibold uppercase tracking-[0.2em] text-foreground-muted">
                    {MODULE_LABEL[row.module]}
                  </p>
                  <p className="relative mt-1 font-mono text-lg font-black tabular-nums text-foreground">
                    {frictionPct}%
                  </p>
                  <p className="relative mt-1 font-mono text-[9px] uppercase tracking-[0.15em] text-foreground/85">
                    Miss {row.missCount} Success {successPct}
                  </p>

                  <div
                    className={cn(
                      "pointer-events-none absolute inset-x-2 bottom-2 z-20 border border-white/[0.12] bg-black/80 px-2 py-1.5 opacity-0 transition-opacity duration-150",
                      "group-hover:opacity-100",
                    )}
                  >
                    <p className="font-mono text-[9px] uppercase tracking-[0.14em] text-cyan-100">
                      Kritische Fragen {row.criticalQuestionCount}
                    </p>
                    <p className="mt-1 font-mono text-[9px] uppercase tracking-[0.14em] text-foreground-muted">
                      FISI Erfolg {Math.round(row.factionSuccessFisi)} FIAE Erfolg {Math.round(row.factionSuccessFiae)}
                    </p>
                    <p className="mt-1 font-mono text-[9px] uppercase tracking-[0.14em] text-foreground-muted">
                      Modul Fragen {row.questionCount} Modell Success {row.modeledSuccessCount}
                    </p>
                  </div>
                </motion.div>
              );
            })}
          </div>
        )}
      </div>
    </section>
  );
}
