export type WebLessonStep = {
  id: string;
  order: number;
  title: string;
  mission: string;
  concepts: string[];
  starterHtml: string;
  starterCss: string;
  transitionIds: string[];
  learningFlow?: LearningFlowBlock[];
};

export type LearningFlowBlock = {
  type: "learning_goal" | "core_statement" | "explanation" | "mini_example" | "exercise" | "solution" | "summary";
  title: string;
  content: string;
};

export type WebBasicsCurriculum = {
  id: "web_basics_star_wars";
  title: string;
  universe: "star_wars";
  pathLabel: string;
  steps: WebLessonStep[];
};

const BASE_TEMPLATE = {
  starterHtml:
    `<main id="hud-root">\n` +
    `  <header id="hud-header">X-Wing Control Deck</header>\n` +
    `  <section id="hud-panel">Mission data stream active</section>\n` +
    `  <button id="hud-action">Engage</button>\n` +
    `</main>`,
  starterCss:
    `#hud-root {\n` +
    `  min-height: 100vh;\n` +
    `  display: grid;\n` +
    `  place-items: center;\n` +
    `  background: radial-gradient(circle at 20% 10%, #0ea5e933, transparent 40%), #020617;\n` +
    `  color: #dbeafe;\n` +
    `  font-family: 'JetBrains Mono', monospace;\n` +
    `}\n` +
    `#hud-header {\n` +
    `  letter-spacing: 0.16em;\n` +
    `  text-transform: uppercase;\n` +
    `}\n` +
    `#hud-panel {\n` +
    `  margin-top: 12px;\n` +
    `  border: 1px solid #38bdf855;\n` +
    `  padding: 12px;\n` +
    `}\n`,
};

function buildWebLearningFlow(step: {
  title: string;
  mission: string;
  concepts: string[];
  starterHtml: string;
  starterCss: string;
}): LearningFlowBlock[] {
  const conceptsShort = step.concepts.slice(0, 3).join(" , ");
  const missionShort = step.mission.trim();
  return [
    { type: "learning_goal", title: "Lernziel", content: `Du setzt diese Mission sicher um` },
    { type: "core_statement", title: "Kernaussage", content: missionShort },
    { type: "explanation", title: "Erklaerung", content: `Fokus nur auf ${conceptsShort}` },
    { type: "mini_example", title: "Mini Beispiel", content: step.starterHtml },
    { type: "exercise", title: "Aufgabe", content: "Aendere genau einen Teil und pruefe sofort den sichtbaren Effekt" },
    { type: "solution", title: "Loesung", content: "Vergleiche mit Startercode bis Ausgabe und Ziel uebereinstimmen" },
    { type: "summary", title: "Zusammenfassung", content: "Ein klarer Schritt ist abgeschlossen" },
  ];
}

export function buildWebBasicsJediPath(): WebBasicsCurriculum {
  const steps: WebLessonStep[] = [
    {
      id: "web-step-01",
      order: 1,
      title: "Repair the X-Wing HUD",
      mission: "Baue eine klare HTML Grundstruktur",
      concepts: ["semantic tags", "id targeting", "content hierarchy"],
      starterHtml: BASE_TEMPLATE.starterHtml,
      starterCss: BASE_TEMPLATE.starterCss,
      transitionIds: ["hud-root", "hud-header", "hud-panel"],
    },
    {
      id: "web-step-02",
      order: 2,
      title: "Cantina Navigation Deck",
      mission: "Style ein Menu mit klaren Hover Zustaenden",
      concepts: ["class styling", "hover states", "typography scale"],
      starterHtml:
        `<nav id="cantina-nav">\n` +
        `  <a id="menu-home" href="#">Home</a>\n` +
        `  <a id="menu-drinks" href="#">Drinks</a>\n` +
        `  <a id="menu-music" href="#">Music</a>\n` +
        `</nav>`,
      starterCss:
        `#cantina-nav {\n  display: flex;\n  gap: 12px;\n  padding: 14px;\n  background: #0f172a;\n}\n` +
        `#cantina-nav a {\n  color: #93c5fd;\n  text-decoration: none;\n  border: 1px solid #38bdf844;\n  padding: 8px 10px;\n}\n`,
      transitionIds: ["cantina-nav", "menu-home", "menu-drinks"],
    },
    {
      id: "web-step-03",
      order: 3,
      title: "Jedi Signal Grid",
      mission: "Baue ein responsives Karten Grid",
      concepts: ["css grid", "gap rhythm", "breakpoint media query"],
      starterHtml:
        `<section id="signal-grid">\n` +
        `  <article id="signal-a">Alpha node</article>\n` +
        `  <article id="signal-b">Beta node</article>\n` +
        `  <article id="signal-c">Gamma node</article>\n` +
        `</section>`,
      starterCss:
        `#signal-grid {\n  display: grid;\n  grid-template-columns: repeat(3, minmax(0, 1fr));\n  gap: 10px;\n}\n` +
        `#signal-grid article {\n  border: 1px solid #22d3ee55;\n  padding: 12px;\n}\n`,
      transitionIds: ["signal-grid", "signal-a", "signal-b"],
    },
    {
      id: "web-step-04",
      order: 4,
      title: "Holoterminal Scanline Shader",
      mission: "Nutze Scanlines und Glow gezielt",
      concepts: ["pseudo elements", "linear gradients", "blend layering"],
      starterHtml: `<section id="holoterminal">Encrypted rebel transmission</section>`,
      starterCss:
        `#holoterminal {\n  position: relative;\n  padding: 16px;\n  border: 1px solid #22d3ee77;\n}\n` +
        `#holoterminal::after {\n  content: '';\n  position: absolute;\n  inset: 0;\n  background: repeating-linear-gradient(0deg, transparent 0 2px, #22d3ee11 2px 4px);\n}\n`,
      transitionIds: ["holoterminal"],
    },
    {
      id: "web-step-05",
      order: 5,
      title: "Reactor Status Pulse",
      mission: "Baue eine ruhige Status Animation",
      concepts: ["keyframes", "animation timing", "state colors"],
      starterHtml: `<div id="reactor-chip">Reactor stable</div>`,
      starterCss:
        `#reactor-chip {\n  display: inline-block;\n  padding: 8px 12px;\n  border: 1px solid #4ade80aa;\n  animation: pulseChip 1.4s ease-in-out infinite;\n}\n` +
        `@keyframes pulseChip {\n  0%, 100% { box-shadow: 0 0 0 #4ade8044; }\n  50% { box-shadow: 0 0 18px #4ade80aa; }\n}\n`,
      transitionIds: ["reactor-chip"],
    },
    {
      id: "web-step-06",
      order: 6,
      title: "Imperial Threat Banner",
      mission: "Erstelle ein Alert Banner mit Varianten",
      concepts: ["modifier classes", "layout spacing", "contrast safety"],
      starterHtml:
        `<aside id="threat-banner" class="severity-high">\n` +
        `  Imperial fleet incoming\n` +
        `</aside>`,
      starterCss:
        `#threat-banner {\n  padding: 12px;\n  border: 1px solid #f59e0b77;\n}\n` +
        `.severity-high {\n  background: #7f1d1d55;\n  color: #fecaca;\n}\n`,
      transitionIds: ["threat-banner"],
    },
    {
      id: "web-step-07",
      order: 7,
      title: "Droid Control Form",
      mission: "Style ein Formular mit klarem Focus",
      concepts: ["form styling", "focus ring", "input grouping"],
      starterHtml:
        `<form id="droid-form">\n` +
        `  <input id="droid-id" placeholder="Droid ID" />\n` +
        `  <button id="droid-submit">Patch</button>\n` +
        `</form>`,
      starterCss:
        `#droid-form {\n  display: flex;\n  gap: 8px;\n}\n` +
        `#droid-id:focus {\n  outline: 2px solid #22d3ee;\n  outline-offset: 2px;\n}\n`,
      transitionIds: ["droid-form", "droid-id", "droid-submit"],
    },
    {
      id: "web-step-08",
      order: 8,
      title: "Alliance Card Components",
      mission: "Baue wiederverwendbare Card Komponenten",
      concepts: ["component shells", "nested selectors", "visual rhythm"],
      starterHtml:
        `<article id="alliance-card">\n` +
        `  <h3 id="alliance-title">Alliance Unit</h3>\n` +
        `  <p id="alliance-meta">Ranked support wing</p>\n` +
        `</article>`,
      starterCss:
        `#alliance-card {\n  border: 1px solid #38bdf855;\n  padding: 14px;\n  border-radius: 10px;\n}\n` +
        `#alliance-title {\n  margin: 0;\n  color: #dbeafe;\n}\n`,
      transitionIds: ["alliance-card", "alliance-title"],
    },
    {
      id: "web-step-09",
      order: 9,
      title: "Hyperspace Layout Shift",
      mission: "Schalte Layout zwischen Zeile und Spalte",
      concepts: ["flexbox", "justify alignment", "responsive direction"],
      starterHtml:
        `<section id="hyperspace-layout">\n` +
        `  <div id="lane-a">Nav lane</div>\n` +
        `  <div id="lane-b">Telemetry lane</div>\n` +
        `</section>`,
      starterCss:
        `#hyperspace-layout {\n  display: flex;\n  gap: 10px;\n}\n` +
        `@media (max-width: 720px) {\n  #hyperspace-layout { flex-direction: column; }\n}\n`,
      transitionIds: ["hyperspace-layout", "lane-a", "lane-b"],
    },
    {
      id: "web-step-10",
      order: 10,
      title: "Jedi UI Boss Fight",
      mission: "Verbinde Struktur Styling und Motion in einer Uebung",
      concepts: ["integration pass", "visual polish", "state storytelling"],
      starterHtml:
        `<main id="boss-console">\n` +
        `  <header id="boss-title">Jedi UI Boss Fight</header>\n` +
        `  <section id="boss-feed">All systems online</section>\n` +
        `  <button id="boss-launch">Launch mission</button>\n` +
        `</main>`,
      starterCss:
        `#boss-console {\n  min-height: 100vh;\n  display: grid;\n  place-items: center;\n  color: #e0f2fe;\n  background: radial-gradient(circle at 25% 15%, #22d3ee22, transparent 45%), #030712;\n}\n` +
        `#boss-launch {\n  border: 1px solid #a78bfa99;\n  box-shadow: 0 0 18px #a78bfa55;\n}\n`,
      transitionIds: ["boss-console", "boss-title", "boss-feed", "boss-launch"],
    },
  ];

  const normalizedSteps = steps.map((step) => ({
    ...step,
    learningFlow: buildWebLearningFlow(step),
  }));

  return {
    id: "web_basics_star_wars",
    title: "Jedi UI Path",
    universe: "star_wars",
    pathLabel: "The 10 Step Jedi UI Path",
    steps: normalizedSteps,
  };
}

export function validateNoOverwhelm(step: WebLessonStep): boolean {
  return step.concepts.length <= 3;
}
