import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useRef, useState } from "react";
import type { CSSProperties } from "react";
import { buildSqlAcademyChapters, getUniverseSeed } from "../../../data/factories/sqlContentFactory";
import { SQL_UNIVERSE_ORDER } from "../../../data/universes";
import { buildJobAssignments } from "../../../data/factories/jobContentFactory";
import { useAppStore } from "../../../store/useAppStore";
import { useAcademyStore } from "../../../store/academyStore";
import { UniverseSelector } from "./UniverseSelector";
import { ChapterNav } from "./ChapterNav";
import { ExerciseHub } from "./ExerciseHub";
import { InfoCard } from "./blocks/InfoCard";
import { DiagramEngine } from "./blocks/DiagramEngine";
import { EliteSandbox } from "./blocks/EliteSandbox";
import { LanguageToggle } from "./blocks/LanguageToggle";
import { LivePreview, calculateCostScore } from "./blocks/LivePreview";
import { AchievementToast } from "./blocks/AchievementToast";
import { MasteryCertificate } from "./blocks/MasteryCertificate";
import { MasteryDashboard } from "./blocks/MasteryDashboard";
import { ProfileDashboard } from "./blocks/ProfileDashboard";
import { PortfolioShowcase } from "./PortfolioShowcase";
import { WebAcademyShell } from "./WebAcademyShell";
import { QuizHost } from "./blocks/QuizHost";
import { TaskAccordion } from "./blocks/TaskAccordion";
import { UniverseBuilder } from "./blocks/UniverseBuilder";
import { LevelUpOverlay } from "./effects/LevelUpOverlay";
import { MasteryCelebration } from "./effects/MasteryCelebration";
import { MentorTour } from "./effects/MentorTour";
import { UNIVERSE_THEMES } from "../../../styles/themes/universeThemes";
import { pushGlobalProgressWithBackoff } from "../../../services/api/SyncService";
import "./sqlAcademyReference.css";

export function resolveAcademyShellMode(track: "sql" | "web_basics" | "c_sharp"): "sql" | "web" {
  return track === "sql" ? "sql" : "web";
}

export function SqlAcademyShell() {
  const selectedUniverseId = useAppStore((s) => s.selectedUniverseId);
  const activeChapterId = useAppStore((s) => s.activeChapterId);
  const taskCompletion = useAppStore((s) => s.taskCompletion);
  const setSelectedUniverseId = useAppStore((s) => s.setSelectedUniverseId);
  const setActiveChapterId = useAppStore((s) => s.setActiveChapterId);
  const markSqlTaskCompleted = useAppStore((s) => s.markSqlTaskCompleted);
  const markTaskSolved = useAcademyStore((s) => s.markTaskSolved);
  const countChapterSolvedTasks = useAcademyStore((s) => s.countChapterSolvedTasks);
  const countChapterMasteredQuizzes = useAcademyStore((s) => s.countChapterMasteredQuizzes);
  const resetUniverseProgress = useAcademyStore((s) => s.resetUniverseProgress);
  const getChapterTimer = useAcademyStore((s) => s.getChapterTimer);
  const startChapterRun = useAcademyStore((s) => s.startChapterRun);
  const pauseChapterRun = useAcademyStore((s) => s.pauseChapterRun);
  const finishChapterRun = useAcademyStore((s) => s.finishChapterRun);
  const getUniverseMeta = useAcademyStore((s) => s.getUniverseMeta);
  const markCareerAssignmentCompleted = useAcademyStore((s) => s.markCareerAssignmentCompleted);
  const countCareerAssignmentsCompleted = useAcademyStore((s) => s.countCareerAssignmentsCompleted);
  const getCloudSnapshot = useAcademyStore((s) => s.getCloudSnapshot);
  const syncGlobalRankings = useAcademyStore((s) => s.syncGlobalRankings);
  const getLeagueTier = useAcademyStore((s) => s.getLeagueTier);
  const getPreferredDialect = useAcademyStore((s) => s.getPreferredDialect);
  const setPreferredDialect = useAcademyStore((s) => s.setPreferredDialect);
  const getPreferredTrack = useAcademyStore((s) => s.getPreferredTrack);
  const setPreferredTrack = useAcademyStore((s) => s.setPreferredTrack);
  const toastQueue = useAcademyStore((s) => s.achievementToastQueue);
  const dismissAchievementToast = useAcademyStore((s) => s.dismissAchievementToast);
  const byUniverse = useAcademyStore((s) => s.byUniverse);
  const timerByUniverse = useAcademyStore((s) => s.timerByUniverse);
  const persistenceHealthy = useAcademyStore((s) => s.persistenceHealthy);
  const lastLevelUp = useAcademyStore((s) => s.lastLevelUp);
  const [typedCore, setTypedCore] = useState("");
  const [celebrate, setCelebrate] = useState(false);
  const [certificateOpen, setCertificateOpen] = useState(false);
  const [levelOverlayOpen, setLevelOverlayOpen] = useState(false);
  const [levelOverlayPayload, setLevelOverlayPayload] = useState<{ level: number; title: string; icon: string } | null>(null);
  const [mentorTourOpen, setMentorTourOpen] = useState(false);
  const [snapshotText, setSnapshotText] = useState("");
  const [syncBadge, setSyncBadge] = useState<"idle" | "syncing" | "synced" | "retrying" | "error">("idle");
  const [learningFlowIndex, setLearningFlowIndex] = useState(0);
  const seenLevelNonceRef = useRef<number | null>(null);
  const prevPercentRef = useRef(0);

  const chapters = useMemo(() => buildSqlAcademyChapters(selectedUniverseId), [selectedUniverseId]);
  const universeSeed = useMemo(() => getUniverseSeed(selectedUniverseId), [selectedUniverseId]);
  const activeChapter = useMemo(
    () => chapters.find((chapter) => chapter.id === activeChapterId) ?? chapters[0],
    [chapters, activeChapterId],
  );
  const activeLearningFlow = activeChapter.learningFlow ?? [];
  const theme = UNIVERSE_THEMES[selectedUniverseId];
  const universeMeta = getUniverseMeta(selectedUniverseId);

  useEffect(() => {
    setTypedCore("");
    let index = 0;
    const source = activeChapter.coreStatement;
    const timer = window.setInterval(() => {
      index += 1;
      setTypedCore(source.slice(0, index));
      if (index >= source.length) window.clearInterval(timer);
    }, 15);
    return () => window.clearInterval(timer);
  }, [activeChapter.id, activeChapter.coreStatement]);

  useEffect(() => {
    setLearningFlowIndex(0);
  }, [activeChapter.id]);

  function normalizeSql(sql: string): string {
    return sql.trim().replace(/;$/, "");
  }

  function universeLabel(universeId: string): string {
    return universeId.replaceAll("_", " ");
  }

  function buildPreview(sql: string) {
    const fallbackTable = universeSeed.tables[0];
    const fromMatch = normalizeSql(sql).match(/\bFROM\s+([a-z_]+)/i);
    const tableName = fromMatch?.[1] ?? fallbackTable?.tableName ?? "charaktere";
    const table = universeSeed.tables.find((item) => item.tableName === tableName) ?? fallbackTable;
    const sourceRows = table?.rows ?? [];
    const selectClause = normalizeSql(sql).match(/\bSELECT\s+(.+?)\s+FROM\b/i)?.[1] ?? "*";
    const requested = selectClause
      .split(",")
      .map((part) => part.trim())
      .filter(Boolean);

    if (selectClause.trim().toUpperCase().startsWith("COUNT(")) {
      return {
        columns: ["total"],
        rows: [{ total: sourceRows.length }],
      };
    }

    const columns =
      requested.length === 1 && requested[0] === "*"
        ? Object.keys(sourceRows[0] ?? {})
        : requested.map((col) => col.split(/\s+AS\s+/i)[0]?.trim()).filter(Boolean);

    const rows = sourceRows.slice(0, 5).map((row) =>
      Object.fromEntries(columns.map((column) => [column, row[column] ?? null])),
    );

    return {
      columns: columns.length > 0 ? columns : Object.keys(sourceRows[0] ?? {}),
      rows,
    };
  }

  const previewExamples = (() => {
    if (activeChapter.previewBlocks && activeChapter.previewBlocks.length > 0) {
      return activeChapter.previewBlocks.map((preview, idx) => ({
        id: `preview-${activeChapter.id}-${idx + 1}`,
        title: preview.title,
        sql: preview.sql,
        ...buildPreview(preview.sql),
      }));
    }

    const sqlTasks = activeChapter.tasks.filter((task) => task.solution.type === "sql").slice(0, 2);
    if (sqlTasks.length === 0) return [];
    return sqlTasks.map((task) => ({
      id: task.id,
      title: `Example ${task.letter}`,
      sql: task.solution.content,
      ...buildPreview(task.solution.content),
    }));
  })();

  const chapterExerciseGroups =
    activeChapter.exerciseGroups ??
    [
      { id: "leicht", title: "Leicht", exercises: activeChapter.exercises.filter((row) => row.tier === "leicht") },
      { id: "mittel", title: "Mittel", exercises: activeChapter.exercises.filter((row) => row.tier === "mittel") },
      { id: "knifflig", title: "Knifflig", exercises: activeChapter.exercises.filter((row) => row.tier === "knifflig") },
    ];

  function chapterCompletionTone(chapter: (typeof chapters)[number]): "none" | "partial" | "full" {
    const solvedTasks = countChapterSolvedTasks({ universeId: selectedUniverseId, chapterId: chapter.id });
    const solvedQuizzes = countChapterMasteredQuizzes({ universeId: selectedUniverseId, chapterId: chapter.id });
    const totalTasks = chapter.tasks.length;
    const totalQuizzes = chapter.quizBlocks?.length ?? 0;
    const completed = solvedTasks + solvedQuizzes;
    const total = totalTasks + totalQuizzes;
    if (total <= 0 || completed <= 0) return "none";
    if (completed >= total) return "full";
    return "partial";
  }

  const totalCurriculumUnits = chapters.reduce((acc, chapter) => acc + chapter.tasks.length + (chapter.quizBlocks?.length ?? 0), 0);
  const solvedCurriculumUnits = chapters.reduce(
    (acc, chapter) =>
      acc +
      countChapterSolvedTasks({ universeId: selectedUniverseId, chapterId: chapter.id }) +
      countChapterMasteredQuizzes({ universeId: selectedUniverseId, chapterId: chapter.id }),
    0,
  );
  const masteryPercent = totalCurriculumUnits > 0 ? Math.min(100, Math.round((solvedCurriculumUnits / totalCurriculumUnits) * 100)) : 0;
  const solvedTaskIdSet = new Set(
    Object.values(byUniverse[selectedUniverseId] ?? {}).flatMap((chapter) => chapter.solvedTaskIds),
  );
  const solvedTasksInUniverse = chapters.flatMap((chapter) => chapter.tasks).filter((task) => solvedTaskIdSet.has(task.id));
  const categoryRules = [
    { label: "Filtering", pattern: /\bWHERE\b|\bLIKE\b|\bIN\b|\bBETWEEN\b|filter|bedingung/i },
    { label: "Joins", pattern: /\bJOIN\b|\bON\b|verbinde|join/i },
    { label: "Aggregation", pattern: /\bCOUNT\b|\bAVG\b|\bSUM\b|\bMIN\b|\bMAX\b|\bGROUP\s+BY\b|\bHAVING\b|zaehle|grupp/i },
    { label: "Performance", pattern: /\bLIMIT\b|\bORDER\s+BY\b|\bDISTINCT\b|alias|fokus|optim/i },
  ] as const;
  const solvedTaskCategoryCounts = categoryRules.map((rule) => ({
    label: rule.label,
    solved: solvedTasksInUniverse.filter((task) => rule.pattern.test(`${task.prompt} ${task.solution.content}`)).length,
    total: chapters.flatMap((chapter) => chapter.tasks).filter((task) => rule.pattern.test(`${task.prompt} ${task.solution.content}`)).length,
  }));
  const radarMetrics = solvedTaskCategoryCounts.map((item) => ({
    label: item.label,
    value: item.total > 0 ? Math.round((item.solved / item.total) * 100) : 0,
  }));
  const performanceHistory = useMemo(
    () =>
      solvedTasksInUniverse
        .slice(-20)
        .map((task) => calculateCostScore(task.solution.content, Math.max(1, universeSeed.tables[0]?.columns.length ?? 4))),
    [solvedTasksInUniverse, universeSeed.tables],
  );
  const totalProteinQueried = solvedTasksInUniverse.filter((task) =>
    /protein|eiweiss|nahrungsmittel/i.test(`${task.prompt} ${task.solution.content}`),
  ).length;
  const workoutsMastered = solvedTasksInUniverse.filter((task) =>
    /uebungen|workout|satz|wiederholung|trainingsroutine/i.test(`${task.prompt} ${task.solution.content}`),
  ).length;
  const trainingDaysSimulated = solvedTasksInUniverse.filter((task) =>
    /tag|datum|woche|day|date|trainingsroutinen/i.test(`${task.prompt} ${task.solution.content}`),
  ).length;
  const hasProgressInUniverse = solvedTasksInUniverse.length > 0 || Object.keys(byUniverse[selectedUniverseId] ?? {}).length > 0;
  const activeChapterTimer = getChapterTimer({ universeId: selectedUniverseId, chapterId: activeChapter.id });
  const heatMapSegments = useMemo(() => {
    const chapterSlice = chapters.slice(0, Math.min(6, chapters.length));
    return chapterSlice.map((chapter, index) => {
      const timer = getChapterTimer({ universeId: selectedUniverseId, chapterId: chapter.id });
      const localCurrent = timer.currentRunMs > 0 ? timer.currentRunMs : 45000 + index * 8000;
      const localPb = timer.personalBestMs ?? Math.max(12000, Math.round(localCurrent * 0.82));
      const globalSamples = Object.values(timerByUniverse).flatMap((universeTimers) => {
        const chapterTimer = universeTimers[chapter.id];
        return chapterTimer?.personalBestMs ? [chapterTimer.personalBestMs] : [];
      });
      const globalAvg =
        globalSamples.length > 0
          ? Math.round(globalSamples.reduce((acc, value) => acc + value, 0) / globalSamples.length)
          : Math.max(14000, Math.round(localCurrent * 0.9));
      return {
        id: chapter.id,
        label: `Seg ${chapter.order}`,
        currentMs: localCurrent,
        pbMs: localPb,
        globalAvgMs: globalAvg,
      };
    });
  }, [chapters, selectedUniverseId, timerByUniverse, getChapterTimer]);
  const leagueTier = getLeagueTier();
  const preferredDialect = getPreferredDialect();
  const preferredTrack = getPreferredTrack();
  const reduceMotion = useReducedMotion();
  const assignments = useMemo(() => buildJobAssignments(selectedUniverseId), [selectedUniverseId]);
  const completedCareer = countCareerAssignmentsCompleted(selectedUniverseId);
  const unlockedCareer = universeMeta.currentLevel >= 5;
  const totalGlobalXP = (Object.values(byUniverse) as Array<Record<string, { solvedTaskIds: string[]; masteredQuizIds: string[] }>>).reduce(
    (acc, _u, idx) => {
      const universeId = Object.keys(byUniverse)[idx] as keyof typeof byUniverse;
      return acc + (getUniverseMeta(universeId).totalXP ?? 0);
    },
    0,
  );
  const totalGlobalLevel = Math.max(
    1,
    ...Object.keys(byUniverse).map((key) => getUniverseMeta(key as keyof typeof byUniverse).currentLevel ?? 1),
  );
  const totalGlobalSolvedUnits = Object.values(byUniverse).reduce(
    (acc, universe) =>
      acc +
      Object.values(universe).reduce((sum, chapter) => sum + chapter.solvedTaskIds.length + chapter.masteredQuizIds.length, 0),
    0,
  );
  const totalGlobalCareer = Object.keys(byUniverse).reduce(
    (acc, key) => acc + countCareerAssignmentsCompleted(key as keyof typeof byUniverse),
    0,
  );
  const eternalLegendUniverseIds = SQL_UNIVERSE_ORDER.slice(0, 3);
  const eternalLegendUnlocked = useMemo(
    () =>
      eternalLegendUniverseIds.every((universeId) => {
        const universeChapters = buildSqlAcademyChapters(universeId);
        const totalUnits = universeChapters.reduce((acc, chapter) => acc + chapter.tasks.length + (chapter.quizBlocks?.length ?? 0), 0);
        const solvedUnits = universeChapters.reduce(
          (acc, chapter) =>
            acc +
            countChapterSolvedTasks({ universeId, chapterId: chapter.id }) +
            countChapterMasteredQuizzes({ universeId, chapterId: chapter.id }),
          0,
        );
        return totalUnits > 0 && solvedUnits >= totalUnits;
      }),
    [byUniverse, countChapterSolvedTasks, countChapterMasteredQuizzes],
  );

  function resetCurrentUniverseGains() {
    resetUniverseProgress(selectedUniverseId);
    for (const chapter of chapters) {
      for (const task of chapter.tasks) {
        if (taskCompletion[task.id]) {
          markSqlTaskCompleted(task.id, false);
        }
      }
    }
  }

  useEffect(() => {
    const prev = prevPercentRef.current;
    if (masteryPercent === 100 && prev < 100) {
      setCelebrate(true);
      setCertificateOpen(true);
    }
    prevPercentRef.current = masteryPercent;
  }, [masteryPercent]);

  useEffect(() => {
    if (!lastLevelUp) return;
    if (seenLevelNonceRef.current === lastLevelUp.nonce) return;
    seenLevelNonceRef.current = lastLevelUp.nonce;
    if (lastLevelUp.universeId !== selectedUniverseId) return;
    const levelTheme = UNIVERSE_THEMES[lastLevelUp.universeId];
    setLevelOverlayPayload({
      level: lastLevelUp.newLevel,
      title: lastLevelUp.newTitle,
      icon: levelTheme.icon,
    });
    setLevelOverlayOpen(true);
  }, [lastLevelUp, selectedUniverseId]);

  useEffect(() => {
    startChapterRun({ universeId: selectedUniverseId, chapterId: activeChapter.id });
    return () => {
      pauseChapterRun({ universeId: selectedUniverseId, chapterId: activeChapter.id });
    };
  }, [selectedUniverseId, activeChapter.id, startChapterRun, pauseChapterRun]);

  useEffect(() => {
    const onVisibility = () => {
      if (document.hidden) {
        pauseChapterRun({ universeId: selectedUniverseId, chapterId: activeChapter.id });
        return;
      }
      startChapterRun({ universeId: selectedUniverseId, chapterId: activeChapter.id });
    };
    document.addEventListener("visibilitychange", onVisibility);
    return () => document.removeEventListener("visibilitychange", onVisibility);
  }, [selectedUniverseId, activeChapter.id, startChapterRun, pauseChapterRun]);

  useEffect(() => {
    const solvedTasks = countChapterSolvedTasks({ universeId: selectedUniverseId, chapterId: activeChapter.id });
    const solvedQuizzes = countChapterMasteredQuizzes({ universeId: selectedUniverseId, chapterId: activeChapter.id });
    const chapterTotal = activeChapter.tasks.length + (activeChapter.quizBlocks?.length ?? 0);
    if (chapterTotal > 0 && solvedTasks + solvedQuizzes >= chapterTotal) {
      finishChapterRun({ universeId: selectedUniverseId, chapterId: activeChapter.id });
    }
  }, [
    selectedUniverseId,
    activeChapter.id,
    activeChapter.tasks.length,
    activeChapter.quizBlocks,
    byUniverse,
    countChapterSolvedTasks,
    countChapterMasteredQuizzes,
    finishChapterRun,
  ]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const tourFlag = window.localStorage.getItem("codesnap-academy-mentor-tour-v1");
    if (tourFlag) return;
    if (hasProgressInUniverse) return;
    setMentorTourOpen(true);
  }, [hasProgressInUniverse]);

  useEffect(() => {
    syncGlobalRankings();
    setSnapshotText(JSON.stringify(getCloudSnapshot(), null, 2));
  }, [byUniverse, selectedUniverseId, getCloudSnapshot, syncGlobalRankings]);

  useEffect(() => {
    let cancelled = false;
    const runHeartbeat = async () => {
      const snapshot = getCloudSnapshot();
      await pushGlobalProgressWithBackoff({ snapshot }, (status) => {
        if (!cancelled) setSyncBadge(status);
      });
    };
    void runHeartbeat();
    const interval = window.setInterval(() => {
      void runHeartbeat();
    }, 22000);
    return () => {
      cancelled = true;
      window.clearInterval(interval);
    };
  }, [getCloudSnapshot]);

  if (resolveAcademyShellMode(preferredTrack) === "web") {
    return (
      <div
        className="sql-academy-page"
        style={
          {
            "--academy-primary": theme.primary,
            "--academy-accent": theme.accent,
            "--academy-bg": theme.pageBg,
            "--academy-panel": theme.panelBg,
            "--academy-pattern": theme.pattern,
            "--academy-font": theme.fontFamily,
          } as CSSProperties
        }
      >
        <AnimatePresence mode="wait" initial={false}>
          <motion.section
            key={`track-shell-${preferredTrack}`}
            initial={reduceMotion ? { opacity: 1 } : { opacity: 0, filter: "blur(10px)", scale: 0.995 }}
            animate={reduceMotion ? { opacity: 1 } : { opacity: 1, filter: "blur(0px)", scale: 1 }}
            exit={reduceMotion ? { opacity: 1 } : { opacity: 0, filter: "blur(8px)", scale: 1.002 }}
            transition={{ duration: reduceMotion ? 0.01 : 0.32, ease: "easeOut" }}
            className="mx-auto w-full max-w-5xl px-4 py-8"
          >
            <header className="mb-4 rounded-xl border border-cyan-400/25 bg-slate-950/60 p-4">
              <p className="text-[10px] uppercase tracking-[0.16em] text-cyan-300">Academy Master Orchestrator</p>
              <h1 className="mt-1 text-xl font-semibold text-cyan-100">
                {preferredTrack === "c_sharp" ? "CSharp Action Bridge Shell" : "Web Basics Shell"}
              </h1>
              <p className="mt-1 text-[11px] text-cyan-200">State shift complete in high tech mode</p>
            </header>
            <WebAcademyShell track={preferredTrack === "c_sharp" ? "c_sharp" : "web_basics"} />
            <div className="mt-3 flex justify-end">
              <button
                type="button"
                className="rounded border border-fuchsia-300/45 bg-fuchsia-950/30 px-3 py-1.5 text-[10px] uppercase tracking-[0.14em] text-fuchsia-100"
                onClick={() => setPreferredTrack("sql")}
              >
                Return to SQL Shell
              </button>
            </div>
          </motion.section>
        </AnimatePresence>
      </div>
    );
  }

  return (
    <div
      className="sql-academy-page"
      style={
        {
          "--academy-primary": theme.primary,
          "--academy-accent": theme.accent,
          "--academy-bg": theme.pageBg,
          "--academy-panel": theme.panelBg,
          "--academy-pattern": theme.pattern,
          "--academy-font": theme.fontFamily,
        } as CSSProperties
      }
    >
      <MasteryCelebration active={celebrate} onDone={() => setCelebrate(false)} />
      <MentorTour
        open={mentorTourOpen}
        onDone={() => {
          setMentorTourOpen(false);
          if (typeof window !== "undefined") {
            window.localStorage.setItem("codesnap-academy-mentor-tour-v1", "seen");
          }
        }}
      />
      <LevelUpOverlay
        open={levelOverlayOpen}
        level={levelOverlayPayload?.level ?? universeMeta.currentLevel}
        title={levelOverlayPayload?.title ?? universeMeta.currentTitle}
        icon={levelOverlayPayload?.icon ?? theme.icon}
        onClose={() => setLevelOverlayOpen(false)}
      />
      <AchievementToast
        open={toastQueue.length > 0}
        label={toastQueue[0]?.label ?? ""}
        universeId={selectedUniverseId}
        onDone={dismissAchievementToast}
      />
      <MasteryCertificate
        open={certificateOpen}
        onClose={() => setCertificateOpen(false)}
        masteryPercent={masteryPercent}
        solvedUnits={solvedCurriculumUnits}
        totalUnits={totalCurriculumUnits}
        curriculumLabel="Bodybuilding Mastery Track"
        currentLevel={universeMeta.currentLevel}
        currentTitle={universeMeta.currentTitle}
        totalQueriesSolved={solvedTasksInUniverse.length}
      />
      <header className="site-header">
        <span className="header-tag">academy uplink</span>
        <h1>
          {theme.icon} SQL <span className="hl">Learning Grid</span>
        </h1>
        <p>Learning first architecture mit cyberpunk focus</p>
        <LanguageToggle />
        <ChapterNav
          chapters={chapters}
          activeChapterId={activeChapter.id}
          onSelect={setActiveChapterId}
          resolveProgressTone={chapterCompletionTone}
        />
      </header>

      <main className="content-area">
        <section className="mx-auto flex w-full max-w-4xl flex-col gap-10 py-8">
          <div id="academy-xp-dashboard" className="rounded-xl border border-cyan-500/30 bg-slate-950/50 p-4">
            <UniverseSelector selectedUniverseId={selectedUniverseId} onSelect={setSelectedUniverseId} />
            <MasteryDashboard
              trackLabel={`${theme.icon} ${universeLabel(selectedUniverseId)} mastery`}
              masteryPercent={masteryPercent}
              solvedUnits={solvedCurriculumUnits}
              totalUnits={totalCurriculumUnits}
              currentLevel={universeMeta.currentLevel}
              currentTitle={universeMeta.currentTitle}
              totalXP={universeMeta.totalXP}
              dailyStreak={universeMeta.dailyStreak}
              totalProteinQueried={totalProteinQueried}
              workoutsMastered={workoutsMastered}
              trainingDaysSimulated={trainingDaysSimulated}
              persistenceHealthy={persistenceHealthy}
              chapterAttempts={activeChapterTimer.attempts}
              chapterPersonalBestMs={activeChapterTimer.personalBestMs}
              chapterCurrentRunMs={activeChapterTimer.currentRunMs}
              heatMapSegments={heatMapSegments}
              chapterRunActive={activeChapterTimer.isRunning}
              leagueTier={leagueTier}
              eternalLegendUnlocked={eternalLegendUnlocked}
              onOpenCertificate={() => setCertificateOpen(true)}
              onResetGains={resetCurrentUniverseGains}
            />
          </div>

          <ProfileDashboard
            globalXP={totalGlobalXP}
            globalLevel={totalGlobalLevel}
            globalSolvedUnits={totalGlobalSolvedUnits}
            globalCareerCompleted={totalGlobalCareer}
            cloudSnapshotText={snapshotText}
            radarMetrics={radarMetrics}
            performanceHistory={performanceHistory}
            primaryColor={theme.primary}
            accentColor={theme.accent}
            onManualSync={() => setSnapshotText(JSON.stringify(getCloudSnapshot()))}
          />

          <PortfolioShowcase
            universeLabel={universeLabel(selectedUniverseId)}
            universeIcon={theme.icon}
            primaryColor={theme.primary}
            accentColor={theme.accent}
            masteryPercent={masteryPercent}
            solvedUnits={solvedCurriculumUnits}
            totalUnits={totalCurriculumUnits}
            level={universeMeta.currentLevel}
            title={universeMeta.currentTitle}
            totalXp={universeMeta.totalXP}
            streak={universeMeta.dailyStreak}
            careerCompleted={completedCareer}
            radarMetrics={radarMetrics}
          />

          <section id="academy-diagram-engine" className="rounded-xl border border-cyan-500/30 bg-slate-950/70 p-8">
            <h2 className="section-title text-3xl leading-tight">{activeChapter.title}</h2>
            <p className="section-subtitle mt-3 text-base leading-8">{activeChapter.subtitle}</p>
            <div className="slide mt-4">
              <div className="slide-label">Core Statement</div>
              <h4 className="text-xl leading-9">{typedCore}</h4>
            </div>
          </section>

          <section id="academy-sql-editor" className="rounded-xl border border-cyan-500/30 bg-slate-950/70 p-8">
            <div className="slide-label mb-4">Theory</div>
            {activeLearningFlow.length > 0 ? (
              <div className="mb-6 rounded-lg border border-cyan-500/20 bg-slate-900/65 p-3">
                <p className="text-[10px] uppercase tracking-[0.16em] text-cyan-200">
                  {activeLearningFlow[learningFlowIndex]?.title ?? activeLearningFlow[0]?.title}
                </p>
                <p className="mt-1 text-sm leading-7 text-slate-200">
                  {activeLearningFlow[learningFlowIndex]?.content ?? activeLearningFlow[0]?.content}
                </p>
                <div className="mt-2 flex items-center justify-between">
                  <p className="text-[10px] uppercase tracking-[0.12em] text-slate-400">
                    Schritt {Math.min(learningFlowIndex + 1, activeLearningFlow.length)}/{activeLearningFlow.length}
                  </p>
                  <div className="flex gap-2">
                    <button
                      type="button"
                      className="rounded border border-cyan-300/35 bg-slate-950/80 px-2 py-1 text-[10px] uppercase tracking-[0.1em] text-cyan-100 disabled:opacity-40"
                      onClick={() => setLearningFlowIndex((prev) => Math.max(0, prev - 1))}
                      disabled={learningFlowIndex <= 0}
                    >
                      Zurueck
                    </button>
                    <button
                      type="button"
                      className="rounded border border-cyan-300/35 bg-slate-950/80 px-2 py-1 text-[10px] uppercase tracking-[0.1em] text-cyan-100 disabled:opacity-40"
                      onClick={() => setLearningFlowIndex((prev) => Math.min(activeLearningFlow.length - 1, prev + 1))}
                      disabled={learningFlowIndex >= activeLearningFlow.length - 1}
                    >
                      Weiter
                    </button>
                  </div>
                </div>
              </div>
            ) : null}
            {activeChapter.stepBlocks && activeChapter.stepBlocks.length > 0 ? (
              <div className="mb-6 space-y-3">
                {activeChapter.stepBlocks.map((step) => (
                  <div key={`${activeChapter.id}-step-${step.step}`} className="rounded-lg border border-slate-700/80 bg-slate-900/60 p-4">
                    <p className="text-[10px] uppercase tracking-[0.18em] text-cyan-200">Step {step.step}</p>
                    <p className="mt-1 text-sm font-semibold text-slate-100">{step.title}</p>
                    <p className="mt-2 text-sm leading-7 text-slate-300">{step.body}</p>
                  </div>
                ))}
              </div>
            ) : (
              <>
                <p className="mb-3 text-base leading-8 text-slate-100">Jeder Block startet mit einer einfachen Erklaerung des Keywords</p>
                <p className="mb-6 text-base leading-8 text-slate-300">Danach siehst du warum das Keyword wichtig ist und wie es im Gym Kontext wirkt</p>
              </>
            )}
            <div className="grid gap-4 md:grid-cols-2">
              {activeChapter.conceptCards.map((card) => (
                <InfoCard key={card.id} tone="tip" title={card.title}>
                  {card.body}
                </InfoCard>
              ))}
              {activeChapter.summaryRows.slice(0, 2).map((row) => (
                <InfoCard key={row.key} tone="warning" title={row.key}>
                  {row.desc}
                </InfoCard>
              ))}
              {(activeChapter.noteBlocks ?? []).map((note, index) => (
                <InfoCard
                  key={`${activeChapter.id}-note-${index}`}
                  tone={note.tone === "warn" ? "warning" : note.tone}
                  title={note.title}
                >
                  {note.body}
                </InfoCard>
              ))}
            </div>
            <DiagramEngine chapter={activeChapter} universeSeed={universeSeed} universeId={selectedUniverseId} />
          </section>

          <section className="rounded-xl border border-cyan-500/30 bg-slate-950/70 p-8">
            <div className="slide-label mb-4">Live Preview Examples</div>
            <p className="mb-6 text-base leading-8 text-slate-300">
              Erst Theorie dann Preview So siehst du den SQL Befehl mit voller Bedeutung
            </p>
            <div className="space-y-4">
              {previewExamples.map((preview) => (
                <LivePreview
                  key={preview.id}
                  title={preview.title}
                  sql={preview.sql}
                  columns={preview.columns}
                  rows={preview.rows}
                  querySuccessful={preview.rows.length >= 0 && preview.columns.length > 0}
                  universeId={selectedUniverseId}
                  radarMetrics={radarMetrics}
                  successfulTasksCount={solvedTasksInUniverse.length}
                />
              ))}
            </div>
          </section>

          {activeChapter.quizBlocks && activeChapter.quizBlocks.length > 0 ? (
            <section className="rounded-xl border border-cyan-500/30 bg-slate-950/70 p-8">
              <div className="slide-label mb-4">Theory Check</div>
              <div className="space-y-4">
                {activeChapter.quizBlocks.map((quiz) => (
                  <QuizHost key={quiz.id} quiz={quiz} chapterId={activeChapter.id} universeId={selectedUniverseId} />
                ))}
              </div>
            </section>
          ) : null}

          <section className="rounded-xl border border-cyan-500/30 bg-slate-950/70 p-8">
            <div className="tasks-header">Tasks</div>
            <p className="mb-6 text-base leading-8 text-slate-300">
              Gehe Aufgabe fuer Aufgabe und oeffne die Loesung nur wenn du einen Check brauchst
            </p>
            <div className="space-y-3">
              {activeChapter.tasks.map((task) => {
                const sql =
                  task.solution.type === "sql"
                    ? task.solution.content
                    : `SELECT * FROM ${universeSeed.tables[0]?.tableName ?? "charaktere"} LIMIT 3;`;
                const explanation =
                  task.solution.type === "sql"
                    ? "Diese Query setzt den Lernschritt direkt auf die aktive Tabelle um"
                    : task.solution.content;
                const preview = buildPreview(sql);
                return (
                  <TaskAccordion
                    key={task.id}
                    chapterId={activeChapter.id}
                    taskId={task.id}
                    universeId={selectedUniverseId}
                    letter={task.letter}
                    prompt={task.prompt}
                    sql={sql}
                    explanation={explanation}
                    columns={preview.columns}
                    rows={preview.rows}
                    querySuccessful={preview.rows.length >= 0 && preview.columns.length > 0}
                    radarMetrics={radarMetrics}
                    successfulTasksCount={solvedTasksInUniverse.length}
                    completed={Boolean(taskCompletion[task.id])}
                    onToggleComplete={() => {
                      const next = !taskCompletion[task.id];
                      markSqlTaskCompleted(task.id, next);
                      markTaskSolved({
                        universeId: selectedUniverseId,
                        chapterId: activeChapter.id,
                        taskId: task.id,
                        solved: next,
                      });
                    }}
                  />
                );
              })}
            </div>
          </section>

          {activeChapter.id === "chapter-12" ? (
            <section className="rounded-xl border border-cyan-500/30 bg-slate-950/70 p-6">
              <h3 className="section-title text-xl">Übungsaufgaben</h3>
              <div className="mt-4">
                <ExerciseHub groups={chapterExerciseGroups} />
              </div>
            </section>
          ) : null}

          <EliteSandbox
            unlocked={universeMeta.currentLevel >= 10 || masteryPercent >= 50}
            preferredDialect={preferredDialect}
            onDialectChange={setPreferredDialect}
            preferredTrack={preferredTrack}
            onTrackChange={setPreferredTrack}
          />

          <UniverseBuilder universeId={selectedUniverseId} />

          <section className="rounded-xl border border-amber-400/30 bg-slate-950/70 p-6">
            <div className="slide-label mb-3">Career Mode</div>
            {!unlockedCareer ? (
              <p className="text-sm text-amber-100">Career assignments unlock at level 5</p>
            ) : (
              <div className="space-y-3">
                {assignments.map((assignment) => {
                  const done = universeMeta.careerCompletedIds.includes(assignment.id);
                  return (
                    <article key={assignment.id} className="rounded-lg border border-amber-300/30 bg-slate-900/65 p-3">
                      <p className="text-sm font-semibold text-amber-100">{assignment.title}</p>
                      <p className="mt-1 text-[10px] uppercase tracking-[0.14em] text-amber-200">
                        {assignment.taskType === "migration"
                          ? "Architect challenge migration"
                          : assignment.taskType === "transaction"
                            ? "Recover restore transaction challenge"
                            : assignment.taskType === "security"
                              ? "Rls defense challenge"
                              : assignment.taskType === "procedural"
                                ? "Advanced logic procedure challenge"
                            : "Career query challenge"}
                      </p>
                      <p className="mt-1 text-xs text-slate-200">{assignment.ticket}</p>
                      <p className="mt-1 text-xs text-slate-300">Acceptance {assignment.acceptance}</p>
                      <p className="mt-1 text-xs text-slate-300">Hint {assignment.sqlHint}</p>
                      {typeof assignment.targetCostThreshold === "number" ? (
                        <p className="mt-1 text-xs text-emerald-200">Target Cost under {assignment.targetCostThreshold}</p>
                      ) : null}
                      {assignment.migrationScriptExample ? (
                        <p className="mt-1 text-xs text-slate-300">Migration script {assignment.migrationScriptExample}</p>
                      ) : null}
                      {assignment.requiredCommands?.length ? (
                        <p className="mt-1 text-xs text-cyan-200">Required {assignment.requiredCommands.join(" | ")}</p>
                      ) : null}
                      <button
                        type="button"
                        className="mt-2 rounded-md border border-amber-300/50 bg-amber-950/25 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-amber-100"
                        onClick={() => markCareerAssignmentCompleted({ universeId: selectedUniverseId, assignmentId: assignment.id })}
                        disabled={done}
                      >
                        {done ? "Ticket resolved" : "Mark ticket resolved"}
                      </button>
                    </article>
                  );
                })}
                <p className="text-xs text-amber-200">Completed {completedCareer}/{assignments.length}</p>
              </div>
            )}
          </section>
          <footer className="rounded-xl border border-cyan-500/25 bg-slate-950/60 px-4 py-2">
            <div className="flex items-center justify-between gap-3">
              <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Global Sync Heartbeat</p>
              <span
                className={`rounded border px-2 py-0.5 text-[10px] uppercase tracking-[0.12em] ${
                  syncBadge === "synced"
                    ? "border-emerald-300/55 bg-emerald-950/35 text-emerald-100"
                    : syncBadge === "syncing" || syncBadge === "retrying"
                      ? "border-amber-300/55 bg-amber-950/35 text-amber-100"
                      : syncBadge === "error"
                        ? "border-rose-300/55 bg-rose-950/35 text-rose-100"
                        : "border-cyan-300/40 bg-cyan-950/25 text-cyan-100"
                }`}
              >
                {syncBadge === "syncing"
                  ? "Syncing"
                  : syncBadge === "retrying"
                    ? "Sync retry"
                    : syncBadge === "synced"
                      ? "Synced"
                      : syncBadge === "error"
                        ? "Sync offline"
                        : "Sync idle"}
              </span>
            </div>
          </footer>
        </section>
    </main>
  </div>
  );
}
