const SYNDICATE_VAULT_THRESHOLDS = [800, 2400, 5400, 9800, 15800] as const;

function syndicateBuffByTier(tierRaw: number): string {
  const tier = Math.max(0, Math.floor(tierRaw));
  if (tier >= 5) return "OMEGA STACK +18% TEAM XP";
  if (tier >= 4) return "PHANTOM STACK +14% TEAM XP";
  if (tier >= 3) return "NOVA STACK +10% TEAM XP";
  if (tier >= 2) return "ECHO STACK +6% TEAM XP";
  if (tier >= 1) return "LINK STACK +3% TEAM XP";
  return "NO STACK LOCKED";
}

function syndicateMissionLineByTier(tierRaw: number): string {
  const tier = Math.max(0, Math.floor(tierRaw));
  if (tier >= 4) return "Mission Silent Breach 120 clean hits this cycle";
  if (tier >= 2) return "Mission Grid Burn 75 precision hits this cycle";
  return "Mission Link Warmup 40 precision hits this cycle";
}

function nextSyndicateThreshold(vaultXpRaw: number): number {
  const xp = Math.max(0, Math.floor(vaultXpRaw));
  const next = SYNDICATE_VAULT_THRESHOLDS.find((threshold) => xp < threshold);
  return next ?? SYNDICATE_VAULT_THRESHOLDS[SYNDICATE_VAULT_THRESHOLDS.length - 1];
}

export function generateTechnoSyndicateName(seed = Date.now()): string {
  const left = ["NEON", "VECTOR", "CIPHER", "NOVA", "SPECTRAL", "OMEGA", "QUANTUM", "AXIOM"];
  const right = ["LOOM", "GRID", "NODE", "FANG", "VAULT", "SIGIL", "SWARM", "ECHO"];
  const serial = String(Math.abs(seed) % 997).padStart(3, "0");
  const l = left[Math.abs(seed) % left.length] ?? "NEON";
  const r = right[Math.floor(Math.abs(seed / 7)) % right.length] ?? "NODE";
  return `${l} ${r} ${serial}`;
}

