function normalizePublicQuestionRow(row: PublicQuestionRow): QuestionBankEntry | null {
  if (!isExamId(row.exam_id)) return null;
  const candidate = {
    id: row.id,
    slug: row.slug ?? row.id,
    examId: row.exam_id,
    careerPaths:
      Array.isArray(row.career_paths) && row.career_paths.length > 0
        ? row.career_paths.filter((entry): entry is CareerPath => entry === "FISI" || entry === "FIAE")
        : ["FISI", "FIAE"],
    module: row.module ?? "process",
    type: row.question_type,
    difficulty: row.difficulty,
    tags: Array.isArray(row.tags) ? row.tags : [],
    source: row.source ?? undefined,
    imagePath: row.image_path ?? undefined,
    imageUrl: row.image_url ?? undefined,
    codeSnippet: row.code_snippet ?? undefined,
    version: row.version,
    isPublished: row.is_published,
    explanation: row.explanation ?? undefined,
    hint: row.hint?.trim() ? row.hint.trim() : undefined,
    prompt: row.prompt,
    payload: row.payload,
  };
  return isQuestionBankEntry(candidate) ? candidate : null;
}

function strongestFlashcardTag(progress: CloudProgressPayload | null): string | null {
  const entries = progress?.flashcardProgress;
  if (!entries) return null;
  const counts = new Map<string, number>();
  for (const key of Object.keys(entries)) {
    const tag = key.split(":")[0] || key.split("/")[0] || key;
    counts.set(tag, (counts.get(tag) ?? 0) + 1);
  }
  let winner: string | null = null;
  let best = 0;
  for (const [tag, count] of counts) {
    if (count > best) {
      best = count;
      winner = tag;
    }
  }
  return winner;
}

function markPending(): void {
  try {
    if (typeof localStorage !== "undefined") localStorage.setItem(PENDING_LS_KEY, "1");
  } catch {
    /* private mode */
  }
}

function clearPending(): void {
  try {
    if (typeof localStorage !== "undefined") localStorage.removeItem(PENDING_LS_KEY);
  } catch {
    /* private mode */
  }
}

export function hasPendingProgressSync(): boolean {
  try {
    return typeof localStorage !== "undefined" && localStorage.getItem(PENDING_LS_KEY) === "1";
  } catch {
    return false;
  }
}

function buildProgressPayload(): CloudProgressPayload {
  const s = useAppStore.getState();
  const d = s.dailyGrind;
  return {
    userLevel: s.userLevel,
    globalXP: s.globalXP,
    globalXpToNext: s.globalXpToNext,
    gems: s.gems,
    flashcardProgress: s.flashcardProgress,
    flashcardTotalReviews: s.flashcardTotalReviews,
    dailyStreakDays: d.streakDays,
    dailyGoalMetYmd: d.dailyGoalMetYmd,
    dailyLedgerYmd: d.ledgerYmd,
    unlockedAchievements: [...s.unlockedAchievementIds],
    seasonArtifacts: [...s.seasonLegacyArtifacts],
    helpdeskClears: s.helpdeskClears,
    legacyPoints: s.legacyPoints,
    legacyTranscendCount: s.legacyTranscendCount,
    legacyXpBoostMultiplier: s.legacyXpBoostMultiplier,
  };
}

function sanitizeSeasonArtifacts(input: unknown): SeasonLegacyArtifact[] {
  if (!Array.isArray(input)) return [];
  return input
    .map((row): SeasonLegacyArtifact | null => {
      if (!row || typeof row !== "object") return null;
      const r = row as Record<string, unknown>;
      const rank = Number(r.rank);
      const winner = r.winnerFaction;
      if (
        typeof r.seasonKey !== "string" ||
        (rank !== 1 && rank !== 2 && rank !== 3) ||
        (winner !== "FISI" && winner !== "FIAE" && winner !== "TIE") ||
        typeof r.label !== "string" ||
        typeof r.closedAt !== "string"
      ) {
        return null;
      }
      return {
        seasonKey: r.seasonKey,
        rank: rank as 1 | 2 | 3,
        winnerFaction: winner,
        label: r.label,
        closedAt: r.closedAt,
      };
    })
    .filter((row): row is SeasonLegacyArtifact => !!row)
    .slice(-24);
}

function mergeDailyGrindFromCloud(cloud: CloudProgressPayload, local: DailyGrindState): DailyGrindState {
  const streak =
    typeof cloud.dailyStreakDays === "number" && Number.isFinite(cloud.dailyStreakDays)
      ? Math.max(0, Math.floor(cloud.dailyStreakDays))
      : local.streakDays;
  const goalYmd =
    cloud.dailyGoalMetYmd === undefined
      ? local.dailyGoalMetYmd
      : (cloud.dailyGoalMetYmd as string | null);
  const ledgerYmd =
    cloud.dailyLedgerYmd === undefined
      ? local.ledgerYmd
      : (cloud.dailyLedgerYmd as string | null);
  return {
    ...local,
    streakDays: streak,
    dailyGoalMetYmd: goalYmd,
    ledgerYmd: ledgerYmd ?? local.ledgerYmd,
  };
}

function leaderboardStreakFromProgress(p: unknown): number {
  if (!p || typeof p !== "object") return 0;
  const s = (p as Record<string, unknown>).dailyStreakDays;
  return typeof s === "number" && Number.isFinite(s) ? Math.max(0, Math.floor(s)) : 0;
}

function isCloudProgressPayload(v: unknown): v is CloudProgressPayload {
  if (!v || typeof v !== "object") return false;
  const x = v as Record<string, unknown>;
  if (
    !(
      typeof x.userLevel === "number" &&
      typeof x.globalXP === "number" &&
      typeof x.globalXpToNext === "number" &&
      typeof x.gems === "number" &&
      typeof x.flashcardTotalReviews === "number" &&
      !!x.flashcardProgress &&
      typeof x.flashcardProgress === "object"
    )
  ) {
    return false;
  }
  if (x.unlockedAchievements !== undefined) {
    if (!Array.isArray(x.unlockedAchievements) || x.unlockedAchievements.length > 64) return false;
    if (!x.unlockedAchievements.every((e) => typeof e === "string" && e.length < 96)) return false;
  }
  if (x.seasonArtifacts !== undefined) {
    if (!Array.isArray(x.seasonArtifacts) || x.seasonArtifacts.length > 48) return false;
    for (const row of x.seasonArtifacts) {
      if (!row || typeof row !== "object") return false;
      const r = row as Record<string, unknown>;
      const rank = Number(r.rank);
      if (
        typeof r.seasonKey !== "string" ||
        (rank !== 1 && rank !== 2 && rank !== 3) ||
        (r.winnerFaction !== "FISI" && r.winnerFaction !== "FIAE" && r.winnerFaction !== "TIE") ||
        typeof r.label !== "string" ||
        typeof r.closedAt !== "string"
      ) {
        return false;
      }
    }
  }
  if (x.helpdeskClears !== undefined) {
    const h = x.helpdeskClears;
    if (typeof h !== "number" || !Number.isFinite(h) || h < 0 || h > 50000) return false;
  }
  if (x.legacyPoints !== undefined) {
    const p = x.legacyPoints;
    if (typeof p !== "number" || !Number.isFinite(p) || p < 0 || p > 500000) return false;
  }
  if (x.legacyTranscendCount !== undefined) {
    const c = x.legacyTranscendCount;
    if (typeof c !== "number" || !Number.isFinite(c) || c < 0 || c > 200) return false;
  }
  if (x.legacyXpBoostMultiplier !== undefined) {
    const b = x.legacyXpBoostMultiplier;
    if (typeof b !== "number" || !Number.isFinite(b) || b < 1 || b > 1.6) return false;
  }
  return true;
}

/**
 * Schreibt XP/Flashcard-Stats nach Supabase (Upsert), wenn Client und Session bereit sind
 * Setzt bei Fehler ein lokales Pending-Flag für spätere Retries
 */
export async function flushProgressDeltaSync(): Promise<boolean> {
  const sb = getSupabase();
  const { authUser, authReady } = useAppStore.getState();
  if (!sb || !authReady || !authUser) return false;

  const progress = buildProgressPayload();
  const { error } = await sb.from(SYNC_TABLE).upsert(
    {
      user_id: authUser.id,
      progress,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "user_id" },
  );

  if (error) {
    markPending();
    useAppStore.setState({
      cloudLastError: error.message,
      syncStatus: useAppStore.getState().syncStatus === "offline" ? "offline" : "cloud-outdated",
    });
    return false;
  }

  clearPending();
  const st = useAppStore.getState();
  if (st.authUser && st.syncStatus !== "offline") {
    useAppStore.setState({ cloudLastError: null, syncStatus: "cloud-synced" });
  }
  return true;
}

/** Lädt den Progress-Datensatz des aktuellen Users aus codesnap_progress_sync */
export async function fetchCloudProgress(): Promise<CloudProgressPayload | null> {
  const sb = getSupabase();
  const { authUser, authReady } = useAppStore.getState();
  if (!sb || !authReady || !authUser) return null;

  const { data, error } = await sb
    .from(SYNC_TABLE)
    .select("progress")
    .eq("user_id", authUser.id)
    .maybeSingle();

  if (error) {
    useAppStore.setState({
      cloudLastError: error.message,
      syncStatus: "cloud-outdated",
    });
    return null;
  }

  const raw = data?.progress;
  if (!raw || !isCloudProgressPayload(raw)) return null;
  return raw;
}

/** Merge-Strategie Local/Cloud nach Login oder Session-Restore */
export async function syncCloudToLocal(): Promise<"hydrated" | "pushed" | "noop"> {
  const before = useAppStore.getState();
  if (!before.authUser || !before.authReady || !getSupabase()) return "noop";

  useAppStore.setState({ cloudUplinkBusy: true, cloudLastError: null });
  const cloud = await fetchCloudProgress();
  if (!cloud) {
    useAppStore.setState({ cloudUplinkBusy: false });
    await flushPendingProgressSync();
    return "noop";
  }

  const local = useAppStore.getState();
  const cloudXp = cloud.globalXP;
  const localXp = local.globalXP;
  const cloudArtifacts = sanitizeSeasonArtifacts(cloud.seasonArtifacts);
  const localArtifacts = local.seasonLegacyArtifacts;
  const mergedArtifacts = new Map<string, SeasonLegacyArtifact>();
  for (const row of [...localArtifacts, ...cloudArtifacts]) {
    mergedArtifacts.set(`${row.seasonKey}#${row.rank}`, row);
  }
  const mergedArtifactRows = [...mergedArtifacts.values()].slice(-24);
  const localSig = localArtifacts.map((x) => `${x.seasonKey}#${x.rank}`).join("|");
  const mergedSig = mergedArtifactRows.map((x) => `${x.seasonKey}#${x.rank}`).join("|");
  if (localSig !== mergedSig) {
    useAppStore.setState({ seasonLegacyArtifacts: mergedArtifactRows });
  }
  const cloudLegacyPoints =
    typeof cloud.legacyPoints === "number" && Number.isFinite(cloud.legacyPoints)
      ? Math.max(0, Math.floor(cloud.legacyPoints))
      : local.legacyPoints;
  const cloudLegacyCount =
    typeof cloud.legacyTranscendCount === "number" && Number.isFinite(cloud.legacyTranscendCount)
      ? Math.max(0, Math.floor(cloud.legacyTranscendCount))
      : local.legacyTranscendCount;
  const cloudLegacyBoost =
    typeof cloud.legacyXpBoostMultiplier === "number" && Number.isFinite(cloud.legacyXpBoostMultiplier)
      ? Math.max(1, Math.min(1.6, cloud.legacyXpBoostMultiplier))
      : Math.max(1, 1 + cloudLegacyCount * 0.05);
  if (
    cloudLegacyPoints > local.legacyPoints ||
    cloudLegacyCount > local.legacyTranscendCount ||
    cloudLegacyBoost > local.legacyXpBoostMultiplier
  ) {
    useAppStore.getState().applyLegacySnapshot({
      points: Math.max(local.legacyPoints, cloudLegacyPoints),
      count: Math.max(local.legacyTranscendCount, cloudLegacyCount),
    });
  }

  if (localXp === 0 || cloudXp > localXp) {
    const mergedDaily = mergeDailyGrindFromCloud(cloud, local.dailyGrind);
    const cloudAch = sanitizeAchievementIds(cloud.unlockedAchievements ?? []);
    const mergedAch = [...new Set([...local.unlockedAchievementIds, ...cloudAch])];
    const cloudHd =
      typeof cloud.helpdeskClears === "number" && Number.isFinite(cloud.helpdeskClears)
        ? Math.max(0, Math.min(50000, Math.floor(cloud.helpdeskClears)))
        : 0;
    useAppStore.setState({
      userLevel: cloud.userLevel,
      globalXP: cloud.globalXP,
      globalXpToNext: cloud.globalXpToNext,
      gems: cloud.gems,
      flashcardProgress: cloud.flashcardProgress,
      flashcardTotalReviews: cloud.flashcardTotalReviews,
      dailyGrind: mergedDaily,
      unlockedAchievementIds: mergedAch,
      seasonLegacyArtifacts: mergedArtifactRows,
      helpdeskClears: Math.max(local.helpdeskClears, cloudHd),
      legacyPoints: Math.max(local.legacyPoints, cloudLegacyPoints),
      legacyTranscendCount: Math.max(local.legacyTranscendCount, cloudLegacyCount),
      legacyXpBoostMultiplier: Math.max(local.legacyXpBoostMultiplier, cloudLegacyBoost),
      progress: {
        ...local.progress,
        level: cloud.userLevel,
        xpCurrent: cloud.globalXP,
        xpToNext: cloud.globalXpToNext,
        streakDays: mergedDaily.streakDays,
      },
      syncStatus: "cloud-synced",
      cloudUplinkBusy: false,
      cloudRestoreNotice: "Cloud-Spielstand synchronisiert",
    });
    window.setTimeout(() => {
      const s = useAppStore.getState();
      if (s.cloudRestoreNotice === "Cloud-Spielstand synchronisiert") {
        useAppStore.setState({ cloudRestoreNotice: null });
      }
    }, 2200);
    clearPending();
    return "hydrated";
  }

  useAppStore.setState({ cloudUplinkBusy: false });
  if (localXp > cloudXp) {
    await flushProgressDeltaSync();
    return "pushed";
  }
  await flushPendingProgressSync();
  return "noop";
}

/** Debounced Hintergrund-Sync nach XP- oder Karten-Änderungen */
export function scheduleBackgroundProgressSync(debounceMs = DEFAULT_DEBOUNCE_MS): void {
  if (typeof window === "undefined") return;
  if (debounceId) window.clearTimeout(debounceId);
  debounceId = window.setTimeout(() => {
    debounceId = null;
    void flushProgressDeltaSync();
  }, debounceMs);
}

/** Nach Login oder App-Start: ausstehenden Sync erneut anstoßen */
export async function flushPendingProgressSync(): Promise<void> {
  if (!hasPendingProgressSync()) return;
  await flushProgressDeltaSync();
}

