export async function fetchGlobalArenaRanks(
  limit = 10,
  missionType?: string,
): Promise<ArenaLeaderboardEntry[]> {
  const sb = getSupabase();
  if (!sb) return [];
  useAppStore.setState({ cloudUplinkBusy: true, cloudLastError: null });
  let query = sb
    .from(LEADERBOARD_TABLE)
    .select("user_id,score,mission_type,created_at")
    .order("score", { ascending: false })
    .order("created_at", { ascending: true })
    .limit(limit);
  if (missionType && missionType !== "ALL") {
    query = query.eq("mission_type", missionType);
  }
  const { data, error } = await query;
  useAppStore.setState({ cloudUplinkBusy: false });
  if (error || !data) {
    if (error) {
      useAppStore.setState({
        cloudLastError: error.message,
        syncStatus: useAppStore.getState().syncStatus === "offline" ? "offline" : "cloud-outdated",
      });
    }
    return [];
  }
  const rows = data as Array<{
    user_id: string;
    score: number;
    mission_type: string;
    created_at: string;
  }>;
  const userIds = Array.from(new Set(rows.map((r) => r.user_id)));
  let handleMap = new Map<string, string>();
  if (userIds.length > 0) {
    const { data: profiles } = await sb
      .from(OPERATOR_PROFILE_TABLE)
      .select("user_id,handle")
      .in("user_id", userIds);
    if (profiles) {
      handleMap = new Map(profiles.map((p) => [p.user_id as string, p.handle as string]));
    }
  }
  const levelMap = new Map<string, number>();
  const streakMap = new Map<string, number>();
  if (userIds.length > 0) {
    const { data: progressRows } = await sb
      .from(SYNC_TABLE)
      .select("user_id,progress")
      .in("user_id", userIds);
    if (progressRows) {
      for (const row of progressRows as Array<{ user_id: string; progress: { userLevel?: number } | null }>) {
        levelMap.set(row.user_id, Math.max(0, Math.floor(row.progress?.userLevel ?? 0)));
        streakMap.set(row.user_id, leaderboardStreakFromProgress(row.progress));
      }
    }
  }
  return rows.map((r) => ({
    ...r,
    operator_handle: handleMap.get(r.user_id) ?? null,
    leaderboard_level: levelMap.get(r.user_id) ?? 0,
    leaderboard_streak: streakMap.get(r.user_id) ?? 0,
  }));
}

