/** Phase 71 — Content Forge: bevorzugt RPC, mit sicherem Upsert-Fallback */
export async function rpcUpsertQuestionFromForge(input: ForgeQuestionInput): Promise<{ ok: boolean; error?: string }> {
  if (!useAppStore.getState().isAdmin) {
    return { ok: false, error: "Zugriff verweigert Admin-Kernel erforderlich" };
  }
  const sb = getSupabase();
  const { authUser, authReady } = useAppStore.getState();
  if (!sb || !authReady || !authUser) {
    return { ok: false, error: "Uplink nicht aktiv" };
  }

  const payload =
    input.type === "sql_challenge"
      ? {
          prompt: input.prompt,
          starterSql: input.starterSql ?? "",
          options: input.options,
          correctIndex: input.correctIndex,
        }
      : {
          options: input.options,
          correctIndex: input.correctIndex,
        };

  const rpc = await sb.rpc("rpc_upsert_question", {
    input_id: input.id,
    input_slug: input.slug,
    input_exam_id: input.examId,
    input_career_paths: ["FISI", "FIAE"],
    input_module: input.module,
    input_question_type: input.type,
    input_prompt: input.prompt,
    input_payload: payload,
    input_explanation: input.explanation ?? null,
    input_hint: input.hint ?? null,
    input_difficulty: input.difficulty,
    input_tags: input.tags,
    input_image_url: input.imageUrl ?? null,
    input_code_snippet: input.codeSnippet ?? null,
    input_source: `Forge IHK ${Math.max(0, Math.min(100, Math.floor(input.ihkScore)))}`,
    input_is_published: true,
  });

  const rpcMissing =
    !!rpc.error &&
    ((rpc.error.message ?? "").toLowerCase().includes("function") ||
      rpc.error.code === "42883" ||
      rpc.error.code === "PGRST202");

  if (rpc.error && !rpcMissing) {
    return { ok: false, error: rpc.error.message };
  }

  if (rpcMissing) {
    const fallback = await sb.from(QUESTION_BANK_TABLE).upsert(
      {
        id: input.id,
        slug: input.slug,
        exam_id: input.examId,
        career_paths: ["FISI", "FIAE"],
        module: input.module,
        question_type: input.type,
        prompt: input.prompt,
        payload,
        explanation: input.explanation ?? null,
        hint: input.hint ?? null,
        difficulty: input.difficulty,
        tags: input.tags,
        image_url: input.imageUrl ?? null,
        code_snippet: input.codeSnippet ?? null,
        source: `Forge IHK ${Math.max(0, Math.min(100, Math.floor(input.ihkScore)))}`,
        version: 1,
        is_published: true,
        updated_at: new Date().toISOString(),
      },
      { onConflict: "id" },
    );
    if (fallback.error) return { ok: false, error: fallback.error.message };
  }

  await hydrateQuestionBank(true);
  void emitNexusActivityEvent({
    kind: input.hint?.trim() ? "NEW_HINT" : "FORGE_DROP",
    label: `${input.slug} ${input.module} ${input.difficulty}`,
  });
  return { ok: true };
}

function normalizeNexusActivityPayload(raw: unknown): NexusActivityEventPayload | null {
  if (!raw || typeof raw !== "object") return null;
  const row = raw as Record<string, unknown>;
  const kind = row.kind;
  const label = row.label;
  if (
    kind !== "NEW_RANK" &&
    kind !== "NEW_HINT" &&
    kind !== "FACTION_GAIN" &&
    kind !== "FORGE_DROP" &&
    kind !== "GLOBAL_OVERDRIVE" &&
    kind !== "LORE_UNLOCK" &&
    kind !== "CHALLENGE_INIT" &&
    kind !== "CHALLENGE_ACCEPT" &&
    kind !== "DUEL_RESULT" &&
    kind !== "GLOBAL_BOSS_GHOST" &&
    kind !== "SYSTEM_INFECTED" &&
    kind !== "NEURAL_PURGE" &&
    kind !== "SYSTEM_CURED" &&
    kind !== "SYNDICATE_FOUNDED" &&
    kind !== "SYNDICATE_ASCENSION" &&
    kind !== "SECTOR_CAPTURED" &&
    kind !== "COUNCIL_PROPOSAL" &&
    kind !== "COUNCIL_DECREE" &&
    kind !== "NEXUS_SINGULARITY" &&
    kind !== "LAUNCH_INIT"
  ) {
    return null;
  }
  if (typeof label !== "string" || label.trim().length === 0) return null;
  return {
    kind,
    label: label.trim().slice(0, 220),
    userId: typeof row.userId === "string" ? row.userId : undefined,
    handle: typeof row.handle === "string" ? row.handle : undefined,
    routeHint: row.routeHint === "public_dossier" ? "public_dossier" : undefined,
    meta: row.meta && typeof row.meta === "object" ? (row.meta as Record<string, string | number | boolean | null>) : undefined,
  };
}

function parseOverdriveFromActivity(event: NexusActivityEventPayload): OverdriveEventModifier | null {
  if (event.kind !== "GLOBAL_OVERDRIVE") return null;
  const m = event.meta;
  if (!m) return null;
  const directive = typeof m.directive === "string" ? m.directive : "START_OVERDRIVE";
  if (directive !== "START_OVERDRIVE") return null;
  const target = m.targetModule;
  const endsAtMs = Number(m.endsAtMs);
  const startedAtMs = Number(m.startedAtMs);
  const xpMultiplier = Number(m.xpMultiplier);
  const eventId = typeof m.eventId === "string" ? m.eventId : "";
  if (
    target !== "networking" &&
    target !== "security" &&
    target !== "operating_systems" &&
    target !== "hardware" &&
    target !== "programming" &&
    target !== "databases" &&
    target !== "testing" &&
    target !== "architecture" &&
    target !== "process" &&
    target !== "wiso"
  ) {
    return null;
  }
  if (!Number.isFinite(endsAtMs) || !Number.isFinite(startedAtMs) || !Number.isFinite(xpMultiplier)) return null;
  return {
    id: eventId || `overdrive-${target}-${Math.floor(startedAtMs / 60000)}`,
    source: "broadcast",
    label: event.label,
    targetModule: target,
    xpMultiplier: Math.max(1, Math.min(4, xpMultiplier)),
    startedAtMs: Math.floor(startedAtMs),
    endsAtMs: Math.floor(endsAtMs),
  };
}

function applyGlobalOverdriveDirective(event: NexusActivityEventPayload): void {
  if (event.kind !== "GLOBAL_OVERDRIVE" || !event.meta) return;
  const meta = event.meta;
  const directive = typeof meta.directive === "string" ? meta.directive : "START_OVERDRIVE";
  const state = useAppStore.getState();

  if (directive === "DROP_RATE") {
    const scale = Number(meta.dropScale);
    if (Number.isFinite(scale)) {
      state.setRaidDropRateScale(Math.max(0, Math.min(3, scale)));
    }
    return;
  }

  if (directive === "ALL_STOP") {
    state.setActiveEventModifier(null);
    state.clearSystemPulse();
    state.clearNexusActivity();
    globalOverdriveLastEmitId = "";
    return;
  }

  const overdrive = parseOverdriveFromActivity(event);
  if (!overdrive) return;
  const now = Date.now() + state.serverTimeOffsetMs;
  if (now >= overdrive.endsAtMs) return;
  const current = state.activeEventModifier;
  if (!current || current.endsAtMs < overdrive.endsAtMs) {
    state.setActiveEventModifier(overdrive);
    state.pushSystemPulseEvent({
      kind: "GLOBAL_LIVE_EVENT",
      headline: `OVERDRIVE ${overdrive.targetModule.toUpperCase()} ACTIVE`,
    });
  }
}

function awardOutbreakAntivirusArtifact(outbreakId: string): void {
  if (!outbreakId) return;
  const state = useAppStore.getState();
  if (state.claimedOutbreakRewardIds.includes(outbreakId)) return;
  const module = state.neuralOutbreak.module ?? "process";
  const artifact = {
    id: `antivirus-${outbreakId}-${Math.random().toString(36).slice(2, 8)}`,
    label: `Antivirus Sigil ${module.toUpperCase()}`,
    rarity: "mythic" as const,
    module,
    eventId: outbreakId,
    receivedAt: new Date().toISOString(),
  };
  useAppStore.setState({
    raidArtifacts: [artifact, ...state.raidArtifacts].slice(0, 24),
  });
  state.claimOutbreakReward(outbreakId);
  state.pushSystemPulseEvent({
    kind: "SYSTEM_ANNOUNCEMENT",
    message: `DIAG NEURAL PURGE COMPLETE ANTIVIRUS ARTIFACT SYNCED`,
  });
}

function applyOutbreakDirective(event: NexusActivityEventPayload): void {
  const meta = event.meta ?? {};
  if (event.kind === "SYSTEM_INFECTED") {
    const snap = normalizeOutbreakRow({
      infected: true,
      outbreak_id: typeof meta.outbreakId === "string" ? meta.outbreakId : null,
      module: meta.module,
      progress: meta.progress,
      target: meta.target,
      hot_zone_boss_id: typeof meta.hotZoneBossId === "string" ? meta.hotZoneBossId : null,
    });
    applyOutbreakSnapshotToStore(snap);
    return;
  }
  if (event.kind === "NEURAL_PURGE") {
    const snap = normalizeOutbreakRow({
      infected: true,
      outbreak_id: typeof meta.outbreakId === "string" ? meta.outbreakId : null,
      module: meta.module,
      progress: meta.progress,
      target: meta.target,
      hot_zone_boss_id: typeof meta.hotZoneBossId === "string" ? meta.hotZoneBossId : null,
    });
    applyOutbreakSnapshotToStore(snap);
    return;
  }
  if (event.kind === "SYSTEM_CURED") {
    const outbreakId = typeof meta.outbreakId === "string" ? meta.outbreakId : "";
    applyOutbreakSnapshotToStore({
      infected: false,
      outbreakId,
      module: null,
      progress: Math.max(0, Math.floor(Number(meta.progress ?? 0))),
      target: Math.max(0, Math.floor(Number(meta.target ?? 0))),
      hotZoneBossId: null,
    });
    awardOutbreakAntivirusArtifact(outbreakId);
  }
}

type ChallengePayload = {
  duelId: string;
  fromUserId: string;
  fromHandle: string;
  toUserId: string;
  toHandle: string;
  examId: ExamId;
  questionIds: string[];
  stakeKind: "gems" | "xp";
  stakeAmount: number;
  createdAtMs: number;
};

function parseChallengePayload(meta: Record<string, string | number | boolean | null> | undefined): ChallengePayload | null {
  if (!meta) return null;
  const duelId = typeof meta.duelId === "string" ? meta.duelId : "";
  const fromUserId = typeof meta.fromUserId === "string" ? meta.fromUserId : "";
  const fromHandle = typeof meta.fromHandle === "string" ? meta.fromHandle : "Unknown_Operator";
  const toUserId = typeof meta.toUserId === "string" ? meta.toUserId : "";
  const toHandle = typeof meta.toHandle === "string" ? meta.toHandle : "Unknown_Operator";
  const examIdRaw = meta.examId;
  const examId: ExamId | null =
    examIdRaw === "AP1" || examIdRaw === "AP2" || examIdRaw === "WISO" ? examIdRaw : null;
  const questionIdsRaw = typeof meta.questionIdsCsv === "string" ? meta.questionIdsCsv : "";
  const questionIds = questionIdsRaw
    .split("|")
    .map((x) => x.trim())
    .filter(Boolean);
  const stakeKind = meta.stakeKind === "xp" ? "xp" : "gems";
  const stakeAmount = Math.max(1, Math.floor(Number(meta.stakeAmount ?? 12)));
  const createdAtMs = Math.max(0, Math.floor(Number(meta.createdAtMs ?? Date.now())));
  if (!duelId || !fromUserId || !toUserId || !examId || questionIds.length === 0) return null;
  return {
    duelId,
    fromUserId,
    fromHandle,
    toUserId,
    toHandle,
    examId,
    questionIds,
    stakeKind,
    stakeAmount,
    createdAtMs,
  };
}

function startDuelFromAcceptedChallenge(input: ChallengePayload): void {
  const self = useAppStore.getState().authUser?.id;
  if (!self) return;
  const existing = useAppStore.getState().duelState;
  if (existing && existing.duelId === input.duelId && existing.status !== "finished") return;
  const iAmChallenger = self === input.fromUserId;
  const opponentUserId = iAmChallenger ? input.toUserId : input.fromUserId;
  const opponentHandle = iAmChallenger ? input.toHandle : input.fromHandle;
  useAppStore.getState().setDuelState({
    duelId: input.duelId,
    examId: input.examId,
    questionIds: input.questionIds,
    opponentUserId,
    opponentHandle,
    stakeKind: input.stakeKind,
    stakeAmount: input.stakeAmount,
    myScore: 0,
    opponentScore: 0,
    myProgress: 0,
    opponentProgress: 0,
    myDone: false,
    opponentDone: false,
    opponentOnline: false,
    winnerUserId: null,
    startedAtMs: Date.now(),
    myElapsedMs: 0,
    status: "live",
  });
  useAppStore.getState().setSelectedExamId(input.examId);
  const startArena = useAppStore.getState().startArena;
  startArena();
  void openDuelRealtimeChannel(input.duelId, opponentUserId);
}

function applyDuelDirective(event: NexusActivityEventPayload): void {
  if (event.kind === "CHALLENGE_INIT") {
    const parsed = parseChallengePayload(event.meta);
    if (!parsed) return;
    const self = useAppStore.getState().authUser?.id;
    if (!self || parsed.toUserId !== self) return;
    useAppStore.getState().pushDuelChallenge({
      duelId: parsed.duelId,
      fromUserId: parsed.fromUserId,
      fromHandle: parsed.fromHandle,
      toUserId: parsed.toUserId,
      toHandle: parsed.toHandle,
      examId: parsed.examId,
      questionIds: parsed.questionIds,
      stakeKind: parsed.stakeKind,
      stakeAmount: parsed.stakeAmount,
      createdAtMs: parsed.createdAtMs,
    });
    return;
  }
  if (event.kind === "CHALLENGE_ACCEPT") {
    const parsed = parseChallengePayload(event.meta);
    if (!parsed) return;
    const self = useAppStore.getState().authUser?.id;
    if (!self) return;
    if (self !== parsed.fromUserId && self !== parsed.toUserId) return;
    startDuelFromAcceptedChallenge(parsed);
    return;
  }
  if (event.kind === "DUEL_RESULT") {
    const meta = event.meta;
    if (!meta) return;
    const duelId = typeof meta.duelId === "string" ? meta.duelId : "";
    const winnerUserId = typeof meta.winnerUserId === "string" ? meta.winnerUserId : "";
    if (!duelId || !winnerUserId) return;
    const duel = useAppStore.getState().duelState;
    if (!duel || duel.duelId !== duelId) return;
    useAppStore.getState().patchDuelState({ status: "finished", winnerUserId });
  }
}

async function getOrCreateNexusEmitChannel(sb: SupabaseClient): Promise<RealtimeChannel> {
  if (nexusActivityEmitChannel) return nexusActivityEmitChannel;
  nexusActivityEmitChannel = sb.channel("nexus-activity-emit", {
    config: { broadcast: { self: false, ack: false } },
  });
  await nexusActivityEmitChannel.subscribe();
  return nexusActivityEmitChannel;
}

export async function emitNexusActivityEvent(event: NexusActivityEventPayload): Promise<void> {
  const sb = getSupabase();
  const state = useAppStore.getState();
  const selfId = state.authUser?.id;
  const ownEvent = !!selfId && event.userId === selfId;
  if (ownEvent && state.ghostModeEnabled) return;
  if (!sb) return;

  const payload: NexusActivityEventPayload = {
    ...event,
    userId: event.userId ?? selfId ?? undefined,
    handle: event.handle ?? state.operatorHandle ?? undefined,
  };
  state.pushNexusActivity(payload);
  applyGlobalOverdriveDirective(payload);
  applyDuelDirective(payload);
  applyOutbreakDirective(payload);
  if (payload.kind === "SYNDICATE_ASCENSION" || payload.kind === "SYNDICATE_FOUNDED") {
    void refreshSyndicateRuntimeBuffs();
  }
  if (payload.kind === "COUNCIL_DECREE" || payload.kind === "COUNCIL_PROPOSAL") {
    void refreshCouncilRuntimeOverride();
  }
  if (payload.kind === "LAUNCH_INIT") {
    void refreshLaunchRuntimeState();
  }
  const channel = await getOrCreateNexusEmitChannel(sb);
  await channel.send({
    type: "broadcast",
    event: "nexus_activity",
    payload,
  });
}

