export async function refreshGlobalLoreStateAndPulse(): Promise<void> {
  const totalGlobalXp = await fetchGlobalTotalXp();
  const unlockedLoreIds = resolveUnlockedLoreIds(totalGlobalXp);
  const state = useAppStore.getState();
  const prevIds = new Set(state.globalLore.unlockedLoreIds);
  state.setGlobalLore({ totalGlobalXp, unlockedLoreIds });
  const newlyUnlocked = unlockedLoreIds.filter((id) => !prevIds.has(id));
  if (newlyUnlocked.length === 0) return;
  if (!state.isAdmin) return;
  const newest = newlyUnlocked.at(-1);
  if (!newest) return;
  if (newest === globalLoreLastAnnouncedId) return;
  globalLoreLastAnnouncedId = newest;
  await emitNexusActivityEvent({
    kind: "LORE_UNLOCK",
    label: `FRAGMENT ${newest.toUpperCase()} FREIGEGEBEN`,
    meta: {
      fragmentId: newest,
      totalGlobalXp,
    },
  });
}

export function startGlobalLoreWatcher(): () => void {
  const tick = () => {
    void refreshGlobalLoreStateAndPulse();
  };
  tick();
  if (typeof window !== "undefined") {
    if (globalLoreWatcherTimer) window.clearInterval(globalLoreWatcherTimer);
    globalLoreWatcherTimer = window.setInterval(tick, 95_000);
  }
  return () => {
    if (globalLoreWatcherTimer) {
      window.clearInterval(globalLoreWatcherTimer);
      globalLoreWatcherTimer = null;
    }
  };
}

/** Phase 65 — saisonale Fraktionswerte aus Snapshot-Zeile, Legacy-RPC nur als Fallback */
export async function fetchFactionXpWarTotals(): Promise<FactionXpWarTotals | null> {
  const sb = getSupabase();
  if (!sb) return null;
  const snap = await sb
    .from(FACTION_XP_WAR_TOTALS_TABLE)
    .select("fisi_total_xp,fiae_total_xp")
    .eq("id", 1)
    .maybeSingle();
  if (!snap.error && snap.data) {
    const row = snap.data as { fisi_total_xp?: unknown; fiae_total_xp?: unknown };
    return {
      fisiXp: Math.max(0, Math.floor(Number(row.fisi_total_xp ?? 0))),
      fiaeXp: Math.max(0, Math.floor(Number(row.fiae_total_xp ?? 0))),
    };
  }

  const legacy = await sb.rpc("get_faction_xp_war_totals");
  if (legacy.error) return null;
  const rows = (legacy.data ?? []) as Array<{ career_path?: string; total_xp?: number | string }>;
  let fisi = 0;
  let fiae = 0;
  for (const row of rows) {
    const xp = Math.max(0, Math.floor(Number(row.total_xp ?? 0)));
    if (row.career_path === "FISI") fisi = xp;
    if (row.career_path === "FIAE") fiae = xp;
  }
  return { fisiXp: fisi, fiaeXp: fiae };
}

const FACTION_WAR_LS_KEY = "codesnap-faction-war-totals-v1";

function readFactionWarCache(): { fisi: number; fiae: number } | null {
  try {
    if (typeof localStorage === "undefined") return null;
    const raw = localStorage.getItem(FACTION_WAR_LS_KEY);
    if (!raw) return null;
    const p = JSON.parse(raw) as { fisi?: unknown; fiae?: unknown };
    if (typeof p.fisi !== "number" || typeof p.fiae !== "number") return null;
    return { fisi: Math.max(0, Math.floor(p.fisi)), fiae: Math.max(0, Math.floor(p.fiae)) };
  } catch {
    return null;
  }
}

function writeFactionWarCache(fisi: number, fiae: number): void {
  try {
    if (typeof localStorage === "undefined") return;
    localStorage.setItem(FACTION_WAR_LS_KEY, JSON.stringify({ fisi, fiae, at: Date.now() }));
  } catch {
    /* private mode */
  }
}

function applyFactionWarTotalsToApp(
  fisi: number,
  fiae: number,
  opts?: { isInitial?: boolean; forcePulse?: boolean },
): void {
  const prevFisi = useAppStore.getState().factionFisiXp;
  const prevFiae = useAppStore.getState().factionFiaeXp;
  writeFactionWarCache(fisi, fiae);
  const poolPrev = prevFisi + prevFiae;
  const delta = Math.abs(fisi - prevFisi) + Math.abs(fiae - prevFiae);
  const threshold = Math.max(2800, Math.floor(poolPrev * 0.006));
  let pulseKey: string | null = null;
  if (
    opts?.forcePulse ||
    (!opts?.isInitial && poolPrev > 800 && delta >= threshold)
  ) {
    pulseKey = `fw-${Date.now()}`;
  }
  useAppStore.setState({
    factionFisiXp: fisi,
    factionFiaeXp: fiae,
    ...(pulseKey ? { factionWarPulseKey: pulseKey } : {}),
  });
  if (pulseKey && typeof window !== "undefined") {
    window.setTimeout(() => {
      if (useAppStore.getState().factionWarPulseKey === pulseKey) {
        useAppStore.setState({ factionWarPulseKey: null });
      }
    }, 920);
  }
}

/** Phase 64 — Snapshot-Zeile bevorzugt, sonst RPC; Cache für Offline */
export async function fetchFactionXpWarTotalsLive(opts?: { isInitial?: boolean }): Promise<void> {
  const cached = readFactionWarCache();
  if (cached && opts?.isInitial) {
    useAppStore.setState({ factionFisiXp: cached.fisi, factionFiaeXp: cached.fiae });
  }
  const sb = getSupabase();
  if (!sb) {
    if (cached) {
      useAppStore.setState({ factionFisiXp: cached.fisi, factionFiaeXp: cached.fiae });
    }
    return;
  }
  const { data, error } = await sb
    .from(FACTION_XP_WAR_TOTALS_TABLE)
    .select("fisi_total_xp,fiae_total_xp")
    .eq("id", 1)
    .maybeSingle();
  if (!error && data) {
    const row = data as { fisi_total_xp?: unknown; fiae_total_xp?: unknown };
    const fisi = Math.max(0, Math.floor(Number(row.fisi_total_xp ?? 0)));
    const fiae = Math.max(0, Math.floor(Number(row.fiae_total_xp ?? 0)));
    applyFactionWarTotalsToApp(fisi, fiae, { isInitial: opts?.isInitial });
    return;
  }
  const rpc = await fetchFactionXpWarTotals();
  if (rpc) {
    applyFactionWarTotalsToApp(rpc.fisiXp, rpc.fiaeXp, { isInitial: opts?.isInitial });
  } else if (cached) {
    useAppStore.setState({ factionFisiXp: cached.fisi, factionFiaeXp: cached.fiae });
  }
}

/**
 * Phase 64 — Realtime auf faction_xp_war_totals; initiales Live-Fetch + LS-Cache
 * Teardown beim Unmount (zusammen mit System-Pulse-Ingest)
 */
export function subscribeFactionXpWarTotals(): () => void {
  const sb = getSupabase();
  if (!sb) return () => undefined;

  void fetchFactionXpWarTotalsLive({ isInitial: true });

  if (factionWarRealtimeChannel) {
    void factionWarRealtimeChannel.unsubscribe();
    factionWarRealtimeChannel = null;
    factionRealtimeStatus = "idle";
  }

  factionWarRealtimeChannel = sb
    .channel("faction-xp-war-live")
    .on(
      "postgres_changes",
      {
        event: "*",
        schema: "public",
        table: FACTION_XP_WAR_TOTALS_TABLE,
        filter: "id=eq.1",
      },
      (payload: { new?: Record<string, unknown> }) => {
        const row = payload.new;
        if (!row) return;
        const fisi = Math.max(0, Math.floor(Number(row.fisi_total_xp ?? 0)));
        const fiae = Math.max(0, Math.floor(Number(row.fiae_total_xp ?? 0)));
        applyFactionWarTotalsToApp(fisi, fiae, { isInitial: false });
      },
    )
    .subscribe((status) => {
      factionRealtimeStatus = status === "SUBSCRIBED" ? "subscribed" : status === "CHANNEL_ERROR" ? "error" : "idle";
    });

  return () => {
    if (factionWarRealtimeChannel) {
      void factionWarRealtimeChannel.unsubscribe();
      factionWarRealtimeChannel = null;
      factionRealtimeStatus = "idle";
    }
  };
}

