export async function fetchBossRaidRankboard(limit = 18): Promise<BossRaidRankboardRow[]> {
  const sb = getSupabase();
  if (!sb) return [];
  const lim = Math.max(3, Math.min(60, Math.floor(limit)));
  const [rankRes, handleRes, titleMap] = await Promise.all([
    sb
      .from(BOSS_RAID_RANKBOARD_VIEW)
      .select("user_id,wins,best_score,best_time_ms,last_win_at")
      .order("wins", { ascending: false })
      .order("best_score", { ascending: false })
      .order("best_time_ms", { ascending: true })
      .order("last_win_at", { ascending: false })
      .limit(lim),
    sb.from(OPERATOR_PROFILE_TABLE).select("user_id,handle"),
    fetchBossRaidTitlesMap(),
  ]);
  if (rankRes.error || !Array.isArray(rankRes.data)) return [];
  const handleMap = new Map<string, string>();
  if (!handleRes.error && Array.isArray(handleRes.data)) {
    for (const row of handleRes.data as Array<{ user_id?: unknown; handle?: unknown }>) {
      const uid = typeof row.user_id === "string" ? row.user_id : "";
      const h = typeof row.handle === "string" ? row.handle.trim() : "";
      if (uid && h) handleMap.set(uid, h);
    }
  }
  return rankRes.data.map((row) => {
    const userId = typeof row.user_id === "string" ? row.user_id : "";
    const wins = Math.max(0, Math.floor(Number(row.wins ?? 0)));
    const bestScore = Math.max(0, Math.floor(Number(row.best_score ?? 0)));
    const bestTimeMs = Math.max(0, Math.floor(Number(row.best_time_ms ?? 0)));
    const lastWinAt = typeof row.last_win_at === "string" ? row.last_win_at : new Date(0).toISOString();
    return {
      userId,
      handle: handleMap.get(userId) ?? "Unknown_Operator",
      wins,
      bestScore,
      bestTimeMs,
      lastWinAt,
      title: titleMap.get(userId) ?? null,
    };
  });
}

function currentUtcWeekDateIso(): string {
  const now = new Date();
  const d = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate());
  const day = new Date(d).getUTCDay();
  const mondayOffset = (day + 6) % 7;
  const monday = new Date(d - mondayOffset * 24 * 60 * 60 * 1000);
  return `${monday.getUTCFullYear()}-${String(monday.getUTCMonth() + 1).padStart(2, "0")}-${String(monday.getUTCDate()).padStart(2, "0")}`;
}

