export async function fetchCouncilChamberState(): Promise<{ proposals: CouncilProposal[]; power: CouncilPowerRow[] }> {
  const sb = getSupabase();
  const self = useAppStore.getState().authUser?.id;
  if (!sb || !self) return { proposals: [], power: [] };

  const proposalsRes = await sb
    .from(COUNCIL_PROPOSALS_TABLE)
    .select("id,title,target_module,xp_boost_multiplier,drop_scale_delta,status,proposer_syndicate_name,starts_at,ends_at")
    .order("created_at", { ascending: false })
    .limit(12);
  const voteRes = await sb
    .from(COUNCIL_VOTES_TABLE)
    .select("proposal_id,syndicate_id,voter_user_id,vote_choice,vote_weight")
    .in(
      "proposal_id",
      ((proposalsRes.data ?? []) as Array<{ id?: unknown }>)
        .map((row) => (typeof row.id === "string" ? row.id : ""))
        .filter(Boolean),
    );
  const sectorsRes = await sb.from(SECTORS_TABLE).select("owner_syndicate_id,owner_name");

  const votes = (voteRes.data ?? []) as Array<Record<string, unknown>>;
  const proposals: CouncilProposal[] = ((proposalsRes.data ?? []) as Array<Record<string, unknown>>)
    .map((row) => {
      const id = typeof row.id === "string" ? row.id : "";
      if (!id) return null;
      const moduleRaw = row.target_module;
      const targetModule: QuestionModule | null =
        moduleRaw === "networking" ||
        moduleRaw === "security" ||
        moduleRaw === "operating_systems" ||
        moduleRaw === "hardware" ||
        moduleRaw === "programming" ||
        moduleRaw === "databases" ||
        moduleRaw === "testing" ||
        moduleRaw === "architecture" ||
        moduleRaw === "process" ||
        moduleRaw === "wiso"
          ? moduleRaw
          : null;
      if (!targetModule) return null;
      const supportWeight = votes
        .filter((v) => v.proposal_id === id && v.vote_choice === "support")
        .reduce((sum, v) => sum + Math.max(0, Math.floor(Number(v.vote_weight ?? 0))), 0);
      const rejectWeight = votes
        .filter((v) => v.proposal_id === id && v.vote_choice === "reject")
        .reduce((sum, v) => sum + Math.max(0, Math.floor(Number(v.vote_weight ?? 0))), 0);
      const myVoteRow = votes.find((v) => v.proposal_id === id && v.voter_user_id === self);
      return {
        id,
        title: typeof row.title === "string" ? row.title : "Council Motion",
        targetModule,
        xpBoostMultiplier: Math.max(1, Number(row.xp_boost_multiplier ?? 1)),
        dropScaleDelta: Math.max(0, Number(row.drop_scale_delta ?? 0)),
        status:
          row.status === "active" || row.status === "passed" || row.status === "rejected" || row.status === "expired"
            ? row.status
            : "active",
        proposerSyndicateName:
          typeof row.proposer_syndicate_name === "string" && row.proposer_syndicate_name.trim()
            ? row.proposer_syndicate_name
            : "SYNDICATE",
        startsAt: typeof row.starts_at === "string" ? row.starts_at : new Date(0).toISOString(),
        endsAt: typeof row.ends_at === "string" ? row.ends_at : new Date(0).toISOString(),
        supportWeight,
        rejectWeight,
        myVote:
          myVoteRow?.vote_choice === "support" || myVoteRow?.vote_choice === "reject"
            ? (myVoteRow.vote_choice as "support" | "reject")
            : null,
      } as CouncilProposal;
    })
    .filter((row): row is CouncilProposal => !!row);

  const powerMap = new Map<string, CouncilPowerRow>();
  for (const row of (sectorsRes.data ?? []) as Array<Record<string, unknown>>) {
    const sid = typeof row.owner_syndicate_id === "string" ? row.owner_syndicate_id : null;
    if (!sid) continue;
    const ownerName =
      typeof row.owner_name === "string" && row.owner_name.trim().length > 0 ? row.owner_name.trim() : "SYNDICATE";
    const prev = powerMap.get(sid);
    powerMap.set(sid, {
      syndicateId: sid,
      syndicateName: ownerName,
      sectors: (prev?.sectors ?? 0) + 1,
    });
  }
  const power = [...powerMap.values()].sort((a, b) => b.sectors - a.sectors || a.syndicateName.localeCompare(b.syndicateName));
  return { proposals, power };
}

