export async function reportNeuralPurgeContribution(
  module: QuestionModule,
  pointsRaw: number,
): Promise<void> {
  const state = useAppStore.getState();
  const outbreak = state.neuralOutbreak;
  if (!outbreak.infected || !outbreak.outbreakId || outbreak.module !== module) return;
  const sb = getSupabase();
  if (!sb) return;
  const points = Math.max(1, Math.min(6, Math.floor(pointsRaw)));
  const { data, error } = await sb.rpc("advance_neural_purge", {
    p_module: module,
    p_points: points,
  });
  if (error || !data) return;
  const row = data as Record<string, unknown>;
  const snap = normalizeOutbreakRow({
    infected: !!row.infected,
    outbreak_id: row.outbreak_id,
    module: row.module,
    progress: row.progress,
    target: row.target,
    hot_zone_boss_id: row.hot_zone_boss_id,
  });
  applyOutbreakSnapshotToStore(snap);
  if (snap.infected) {
    await emitNexusActivityEvent({
      kind: "NEURAL_PURGE",
      label: `NEURAL PURGE ${Math.max(0, Math.floor(snap.progress))}/${Math.max(1, Math.floor(snap.target))}`,
      meta: {
        outbreakId: snap.outbreakId ?? outbreak.outbreakId,
        module: snap.module ?? module,
        progress: snap.progress,
        target: snap.target,
        hotZoneBossId: snap.hotZoneBossId,
      },
    });
    return;
  }
  const outbreakId = typeof row.outbreak_id === "string" ? row.outbreak_id : outbreak.outbreakId;
  if (!outbreakId) return;
  await emitNexusActivityEvent({
    kind: "SYSTEM_CURED",
    label: `NEURAL PURGE COMPLETE ${outbreakId}`,
    meta: {
      outbreakId,
      module,
      progress: snap.progress,
      target: snap.target,
    },
  });
}

