/** Phase 62/65 — Kohorten-Telemetrie für Overseer (Misses + saisonale Fraktionswerte) */
export type AdminCmdTelemetrySnapshot = {
  activeOperators: number;
  ingestPerMinute: number;
  serverLoadPct: number;
  painPoints: AdminCmdPainRow[];
  factionFisiXp: number;
  factionFiaeXp: number;
};

export type GlobalFrictionTile = {
  module: QuestionModule;
  missCount: number;
  questionCount: number;
  criticalQuestionCount: number;
  modeledSuccessCount: number;
  successRate: number;
  frictionRate: number;
  factionSuccessFisi: number;
  factionSuccessFiae: number;
};

export type GlobalFrictionSnapshot = {
  loadedAtMs: number;
  rows: GlobalFrictionTile[];
};

let globalFrictionSessionCache: GlobalFrictionSnapshot | null = null;
const GLOBAL_FRICTION_SESSION_KEY = "codesnap-global-friction-v1";

function normalizeModule(value: unknown): QuestionModule | null {
  if (
    value === "networking" ||
    value === "security" ||
    value === "operating_systems" ||
    value === "hardware" ||
    value === "programming" ||
    value === "databases" ||
    value === "testing" ||
    value === "architecture" ||
    value === "process" ||
    value === "wiso"
  ) {
    return value;
  }
  return null;
}

function readGlobalFrictionSessionCache(): GlobalFrictionSnapshot | null {
  if (globalFrictionSessionCache) return globalFrictionSessionCache;
  try {
    if (typeof sessionStorage === "undefined") return null;
    const raw = sessionStorage.getItem(GLOBAL_FRICTION_SESSION_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as GlobalFrictionSnapshot | null;
    if (!parsed || typeof parsed.loadedAtMs !== "number" || !Array.isArray(parsed.rows)) return null;
    globalFrictionSessionCache = parsed;
    return parsed;
  } catch {
    return null;
  }
}

function writeGlobalFrictionSessionCache(snapshot: GlobalFrictionSnapshot): void {
  globalFrictionSessionCache = snapshot;
  try {
    if (typeof sessionStorage !== "undefined") {
      sessionStorage.setItem(GLOBAL_FRICTION_SESSION_KEY, JSON.stringify(snapshot));
    }
  } catch {
    /* ignore */
  }
}

/** Phase 73 — globale Friktionsdaten als Session-schonender Snapshot */
export async function getGlobalFrictionData(forceRefresh = false): Promise<GlobalFrictionSnapshot> {
  if (!forceRefresh) {
    const cached = readGlobalFrictionSessionCache();
    if (cached) return cached;
  }

  const sb = getSupabase();
  const { authUser, authReady } = useAppStore.getState();
  if (!sb || !authReady || !authUser) {
    return { loadedAtMs: Date.now(), rows: [] };
  }

  const rpc = await sb.rpc("get_global_friction_telemetry");
  type RpcRow = { module?: unknown; miss_count?: unknown; question_count?: unknown; critical_questions?: unknown };
  let aggRows: RpcRow[] = [];

  if (!rpc.error && Array.isArray(rpc.data)) {
    aggRows = rpc.data as RpcRow[];
  } else {
    const [bankRes, missRes] = await Promise.all([
      sb.from(QUESTION_BANK_TABLE).select("id,module").eq("is_published", true),
      sb.rpc("get_top_question_misses"),
    ]);
    const bankRows = (bankRes.data ?? []) as Array<{ id?: string; module?: unknown }>;
    const byQuestion = new Map<string, QuestionModule>();
    const questionCountByModule = new Map<QuestionModule, number>();
    for (const row of bankRows) {
      if (typeof row.id !== "string") continue;
      const mod = normalizeModule(row.module);
      if (!mod) continue;
      byQuestion.set(row.id, mod);
      questionCountByModule.set(mod, (questionCountByModule.get(mod) ?? 0) + 1);
    }
    const misses = (missRes.data ?? []) as Array<{ question_id?: unknown; miss_count?: unknown }>;
    const missByModule = new Map<QuestionModule, number>();
    const criticalByModule = new Map<QuestionModule, number>();
    for (const row of misses) {
      if (typeof row.question_id !== "string") continue;
      const mod = byQuestion.get(row.question_id);
      if (!mod) continue;
      const miss = Math.max(0, Math.floor(Number(row.miss_count ?? 0)));
      missByModule.set(mod, (missByModule.get(mod) ?? 0) + miss);
      if (miss >= 3) criticalByModule.set(mod, (criticalByModule.get(mod) ?? 0) + 1);
    }
    aggRows = [...questionCountByModule.entries()].map(([module, questionCount]) => ({
      module,
      miss_count: missByModule.get(module) ?? 0,
      question_count: questionCount,
      critical_questions: criticalByModule.get(module) ?? 0,
    }));
  }

  const facRes = await sb
    .from(FACTION_XP_WAR_TOTALS_TABLE)
    .select("fisi_total_xp,fiae_total_xp")
    .eq("id", 1)
    .maybeSingle();
  const fac = facRes.data as { fisi_total_xp?: unknown; fiae_total_xp?: unknown } | null;
  const fisi = Math.max(0, Math.floor(Number(fac?.fisi_total_xp ?? 0)));
  const fiae = Math.max(0, Math.floor(Number(fac?.fiae_total_xp ?? 0)));
  const totalFaction = Math.max(1, fisi + fiae);
  const factionSuccessFisi = (fisi / totalFaction) * 100;
  const factionSuccessFiae = (fiae / totalFaction) * 100;

  const activeCount = await sb.rpc("get_admin_active_operator_count");
  const activeOperators = Math.max(1, parseAdminActiveOperatorCount(activeCount.data));

  const rows: GlobalFrictionTile[] = aggRows
    .map((row) => {
      const module = normalizeModule(row.module);
      if (!module) return null;
      const missCount = Math.max(0, Math.floor(Number(row.miss_count ?? 0)));
      const questionCount = Math.max(1, Math.floor(Number(row.question_count ?? 1)));
      const criticalQuestionCount = Math.max(0, Math.floor(Number(row.critical_questions ?? 0)));
      const modeledAttempts = Math.max(questionCount * activeOperators, missCount + 1);
      const modeledSuccessCount = Math.max(0, modeledAttempts - missCount);
      const successRate = modeledSuccessCount / modeledAttempts;
      const frictionRate = missCount / modeledAttempts;
      return {
        module,
        missCount,
        questionCount,
        criticalQuestionCount,
        modeledSuccessCount,
        successRate,
        frictionRate,
        factionSuccessFisi,
        factionSuccessFiae,
      };
    })
    .filter((row): row is GlobalFrictionTile => !!row)
    .sort((a, b) => b.frictionRate - a.frictionRate);

  const avg = rows.length > 0 ? rows.reduce((acc, row) => acc + row.frictionRate, 0) / rows.length : 0;
  useAppStore.getState().setGlobalFrictionAvg(avg);
  const snapshot: GlobalFrictionSnapshot = { loadedAtMs: Date.now(), rows };
  writeGlobalFrictionSessionCache(snapshot);
  return snapshot;
}

function overdriveLabel(module: QuestionModule, frictionRate: number): string {
  const pct = Math.round(frictionRate * 100);
  return `NEURAL OVERDRIVE ${module.toUpperCase()} FRICTION ${pct}`;
}

async function evaluateAndEmitGlobalOverdrive(): Promise<void> {
  const state = useAppStore.getState();
  const now = Date.now() + state.serverTimeOffsetMs;
  const current = state.activeEventModifier;
  if (current && now < current.endsAtMs) return;
  if (current && now >= current.endsAtMs) {
    state.setActiveEventModifier(null);
  }

  const cached = await getGlobalFrictionData();
  const stale = now - cached.loadedAtMs > 10 * 60 * 1000;
  const snap = stale ? await getGlobalFrictionData(true) : cached;
  const top = snap.rows[0];
  if (!top || top.frictionRate < OVERDRIVE_FRICTION_THRESHOLD) return;
  if (!state.isAdmin) return;

  const bucket = Math.floor(now / OVERDRIVE_DURATION_MS);
  const eventId = `overdrive-${top.module}-${bucket}`;
  if (eventId === globalOverdriveLastEmitId) return;
  globalOverdriveLastEmitId = eventId;
  const startsAtMs = now;
  const endsAtMs = startsAtMs + OVERDRIVE_DURATION_MS;
  const mod: OverdriveEventModifier = {
    id: eventId,
    source: "friction",
    label: overdriveLabel(top.module, top.frictionRate),
    targetModule: top.module,
    xpMultiplier: 1.45,
    startedAtMs: startsAtMs,
    endsAtMs,
  };
  state.setActiveEventModifier(mod);
  state.pushSystemPulseEvent({
    kind: "GLOBAL_LIVE_EVENT",
    headline: `OVERDRIVE ${top.module.toUpperCase()} ACTIVE`,
  });
  await emitNexusActivityEvent({
    kind: "GLOBAL_OVERDRIVE",
    label: mod.label,
    meta: {
      directive: "START_OVERDRIVE",
      eventId: mod.id,
      targetModule: mod.targetModule,
      xpMultiplier: mod.xpMultiplier,
      startedAtMs: mod.startedAtMs,
      endsAtMs: mod.endsAtMs,
    },
  });
}

/** Phase 74 — Heatmap-getriebener Auto-Raid Controller */
export function startGlobalOverdriveController(): () => void {
  const tick = () => {
    void evaluateAndEmitGlobalOverdrive();
  };
  tick();
  if (typeof window !== "undefined") {
    if (globalOverdriveControllerTimer) window.clearInterval(globalOverdriveControllerTimer);
    globalOverdriveControllerTimer = window.setInterval(tick, 92_000);
  }
  return () => {
    if (globalOverdriveControllerTimer) {
      window.clearInterval(globalOverdriveControllerTimer);
      globalOverdriveControllerTimer = null;
    }
  };
}

