function maybeFinalizeDuelFromState(): void {
  const s = useAppStore.getState();
  const duel = s.duelState;
  if (!duel || duel.status === "finished") return;
  if (!duel.myDone || !duel.opponentDone) return;
  const self = s.authUser?.id;
  if (!self) return;
  const winnerUserId =
    duel.myScore === duel.opponentScore
      ? self
      : duel.myScore > duel.opponentScore
        ? self
        : duel.opponentUserId;
  s.patchDuelState({ status: "finished", winnerUserId });
  if (winnerUserId === self) {
    if (duel.stakeKind === "gems") {
      useAppStore.setState({ gems: s.gems + duel.stakeAmount });
    } else {
      s.awardGlobalXp(Math.max(1, duel.stakeAmount));
    }
  }
  void emitNexusActivityEvent({
    kind: "DUEL_RESULT",
    label: `DUEL ${duel.duelId} WINNER ${winnerUserId === self ? "SELF" : duel.opponentHandle.toUpperCase()}`,
    meta: {
      duelId: duel.duelId,
      winnerUserId,
    },
  });
}

async function openDuelRealtimeChannel(duelId: string, opponentUserId: string): Promise<void> {
  const sb = getSupabase();
  const self = useAppStore.getState().authUser?.id;
  if (!sb || !self) return;
  if (duelRealtimeChannel && duelRealtimeChannelId === duelId) return;
  if (duelRealtimeChannel) {
    void duelRealtimeChannel.unsubscribe();
    duelRealtimeChannel = null;
    duelRealtimeChannelId = "";
  }
  duelRealtimeChannelId = duelId;
  const ch = sb.channel(`duel-${duelId}`, {
    config: { presence: { key: self }, broadcast: { self: false, ack: false } },
  });
  duelRealtimeChannel = ch;
  ch.on("presence", { event: "sync" }, () => {
    const presence = ch.presenceState<Record<string, unknown>>();
    const online = Object.keys(presence).includes(opponentUserId);
    useAppStore.getState().patchDuelState({ opponentOnline: online });
  });
  ch.on("broadcast", { event: "duel_progress" }, (payload: { payload?: Record<string, unknown> }) => {
    const p = payload.payload ?? {};
    const incomingDuelId = typeof p.duelId === "string" ? p.duelId : "";
    if (incomingDuelId !== duelId) return;
    const fromUserId = typeof p.fromUserId === "string" ? p.fromUserId : "";
    if (!fromUserId || fromUserId === self) return;
    const score = Math.max(0, Math.floor(Number(p.score ?? 0)));
    const progress = Math.max(0, Math.min(1, Number(p.progress ?? 0)));
    const done = !!p.done;
    useAppStore.getState().patchDuelState({
      opponentScore: score,
      opponentProgress: progress,
      opponentDone: done,
      opponentOnline: true,
    });
    maybeFinalizeDuelFromState();
  });
  ch.subscribe((status) => {
    if (status === "SUBSCRIBED") {
      void ch.track({ userId: self, duelId });
    }
  });
}

export async function publishDuelProgress(input: {
  duelId: string;
  score: number;
  progress: number;
  done: boolean;
}): Promise<void> {
  const sb = getSupabase();
  const self = useAppStore.getState().authUser?.id;
  if (!sb || !self) return;
  if (!duelRealtimeChannel || duelRealtimeChannelId !== input.duelId) {
    const duel = useAppStore.getState().duelState;
    if (!duel) return;
    await openDuelRealtimeChannel(duel.duelId, duel.opponentUserId);
  }
  if (!duelRealtimeChannel) return;
  await duelRealtimeChannel.send({
    type: "broadcast",
    event: "duel_progress",
    payload: {
      duelId: input.duelId,
      fromUserId: self,
      score: Math.max(0, Math.floor(input.score)),
      progress: Math.max(0, Math.min(1, input.progress)),
      done: !!input.done,
    },
  });
  if (input.done) {
    useAppStore.getState().patchDuelState({ myDone: true });
    maybeFinalizeDuelFromState();
  }
}

