async function fetchMirrorGhostProfile(examId: ExamId, mode: MirrorMode): Promise<MirrorGhostProfile | null> {
  const sb = getSupabase();
  const self = useAppStore.getState().authUser?.id;
  if (!sb) return null;
  const base = sb
    .from(ARENA_GHOSTS_TABLE)
    .select("id,user_id,score,duration_ms,question_count,boss_label,created_at")
    .eq("exam_id", examId)
    .order("score", { ascending: false })
    .order("duration_ms", { ascending: true })
    .order("created_at", { ascending: false })
    .limit(1);
  const res =
    mode === "personal_best" && self
      ? await base.eq("user_id", self).maybeSingle()
      : mode === "global_boss"
        ? await base.eq("is_global_boss", true).maybeSingle()
        : await base.gte("created_at", new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString()).maybeSingle();
  const row = (res.data ?? null) as
    | {
        id?: unknown;
        user_id?: unknown;
        score?: unknown;
        duration_ms?: unknown;
        question_count?: unknown;
        boss_label?: unknown;
      }
    | null;
  if (!row) return null;
  const ghostId = typeof row.id === "string" ? row.id : "";
  if (!ghostId) return null;
  const ownerUserId = typeof row.user_id === "string" ? row.user_id : "";
  return {
    id: ghostId,
    ownerUserId,
    score: Math.max(0, Math.floor(Number(row.score ?? 0))),
    durationMs: Math.max(1_000, Math.floor(Number(row.duration_ms ?? 60_000))),
    questionCount: Math.max(1, Math.floor(Number(row.question_count ?? 10))),
    bossLabel: typeof row.boss_label === "string" ? row.boss_label.trim() : null,
  };
}

export async function startMirrorDuel(mode: MirrorMode): Promise<{ ok: boolean; error?: string }> {
  const state = useAppStore.getState();
  const examId = state.selectedExamId;
  const questions = getQuestionsForExam(examId).slice(0, 14);
  if (questions.length < 6) return { ok: false, error: "Zu wenige Fragen für Neural Mirror" };
  const ghost =
    (await fetchMirrorGhostProfile(examId, mode)) ??
    ({
      id: "",
      ownerUserId: "",
      score: Math.max(400, questions.length * 80),
      durationMs: Math.max(45_000, questions.length * 5_000),
      questionCount: questions.length,
      bossLabel: null,
    } satisfies MirrorGhostProfile);
  if (mode === "global_boss" && !ghost.bossLabel) {
    return { ok: false, error: "DIAG NO GLOBAL BOSS GHOST ONLINE" };
  }
  const bounty =
    mode === "global_boss"
      ? (await fetchActiveFactionBounties()).find((row) => row.bossGhostId === ghost.id) ?? null
      : null;
  const activeModifierId = bounty?.modifierId ?? (mode === "global_boss" ? "NEURAL_STATIC" : undefined);
  const modifier = getBossModifierById(activeModifierId);
  const modifierIntensity = (modifier?.xpExponentBoost ?? 0) * (bounty?.isHotZone ? 2 : 1);
  const bountyBonusGems = (bounty?.bonusGems ?? 0) * (bounty?.isHotZone ? 2 : 1);
  const duelId = `mirror-${mode}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  useAppStore.getState().setDuelState({
    duelId,
    examId,
    questionIds: questions.map((q) => q.id),
    opponentUserId: `ghost-${mode}`,
    opponentHandle:
      mode === "weekly_top"
        ? "Neural_Mirror_Weekly"
        : mode === "personal_best"
          ? "Neural_Mirror_Personal"
          : `Global_Boss_${ghost.bossLabel ?? "Unknown"}`,
    stakeKind: "xp",
    stakeAmount: 0,
    myScore: 0,
    opponentScore: ghost.score,
    myProgress: 0,
    opponentProgress: 0,
    myDone: false,
    opponentDone: false,
    opponentOnline: true,
    winnerUserId: null,
    startedAtMs: Date.now(),
    myElapsedMs: 0,
    ghostDurationMs: ghost.durationMs,
    bossGhostId: mode === "global_boss" ? ghost.id : undefined,
    bossModifierId: modifier?.id,
    modifierIntensity,
    bountyTargetFaction: bounty?.targetFaction,
    bountyBonusGems,
    bountyDecayStacks: bounty?.decayStacks ?? 0,
    bountyHotZone: !!bounty?.isHotZone,
    mirrorMode: mode,
    status: "live",
  });
  useAppStore.getState().setSelectedExamId(examId);
  useAppStore.getState().startArena();
  if (mode === "global_boss" && modifier?.timeScale && modifier.timeScale < 1) {
    const run = useAppStore.getState().arenaRun;
    if (run) {
      useAppStore.setState({
        arenaRun: {
          ...run,
          timeRemainingSec: Math.max(18, Math.floor(run.timeRemainingSec * modifier.timeScale)),
        },
      });
    }
  }
  return { ok: true };
}

export async function issueDuelChallenge(
  targetUserId: string,
  targetHandle: string,
  opts?: { examId?: ExamId; stakeKind?: "gems" | "xp"; stakeAmount?: number },
): Promise<{ ok: boolean; error?: string }> {
  const state = useAppStore.getState();
  const self = state.authUser?.id;
  if (!self) return { ok: false, error: "Uplink nicht aktiv" };
  if (!targetUserId || targetUserId === self) return { ok: false, error: "Ungültiges Ziel" };
  const examId = opts?.examId ?? state.selectedExamId;
  const qIds = getQuestionsForExam(examId)
    .slice(0, 14)
    .map((q) => q.id);
  if (qIds.length < 6) return { ok: false, error: "Zu wenige Fragen für Duell" };
  const duelId = `duel-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  const stakeKind = opts?.stakeKind ?? "gems";
  const stakeAmount = Math.max(1, Math.floor(opts?.stakeAmount ?? 10));
  const fromHandle = (state.operatorHandle ?? state.progress.displayName ?? "Unknown_Operator").trim();
  await emitNexusActivityEvent({
    kind: "CHALLENGE_INIT",
    userId: self,
    handle: fromHandle,
    label: `${fromHandle.toUpperCase()} VS ${targetHandle.toUpperCase()} ${examId}`,
    meta: {
      duelId,
      fromUserId: self,
      fromHandle,
      toUserId: targetUserId,
      toHandle: targetHandle,
      examId,
      questionIdsCsv: qIds.join("|"),
      stakeKind,
      stakeAmount,
      createdAtMs: Date.now() + state.serverTimeOffsetMs,
    },
  });
  return { ok: true };
}

export async function acceptDuelChallenge(duelId: string): Promise<{ ok: boolean; error?: string }> {
  const state = useAppStore.getState();
  const self = state.authUser?.id;
  if (!self) return { ok: false, error: "Uplink nicht aktiv" };
  const challenge = state.duelInbox.find((row) => row.duelId === duelId);
  if (!challenge) return { ok: false, error: "Duell nicht gefunden" };
  await emitNexusActivityEvent({
    kind: "CHALLENGE_ACCEPT",
    userId: self,
    handle: (state.operatorHandle ?? state.progress.displayName ?? "Unknown_Operator").trim(),
    label: `LINK ${challenge.fromHandle.toUpperCase()} ${challenge.toHandle.toUpperCase()} ${challenge.examId}`,
    meta: {
      duelId: challenge.duelId,
      fromUserId: challenge.fromUserId,
      fromHandle: challenge.fromHandle,
      toUserId: challenge.toUserId,
      toHandle: challenge.toHandle,
      examId: challenge.examId,
      questionIdsCsv: challenge.questionIds.join("|"),
      stakeKind: challenge.stakeKind,
      stakeAmount: challenge.stakeAmount,
      createdAtMs: challenge.createdAtMs,
    },
  });
  useAppStore.setState({ duelInbox: state.duelInbox.filter((row) => row.duelId !== duelId) });
  return { ok: true };
}

export async function fetchAdminCmdTelemetry(): Promise<AdminCmdTelemetrySnapshot> {
  const sb = getSupabase();
  const { authUser, authReady, isAdmin } = useAppStore.getState();
  if (!sb || !authReady || !authUser || !isAdmin) {
    return { activeOperators: 0, ingestPerMinute: 0, serverLoadPct: 0, painPoints: [], factionFisiXp: 0, factionFiaeXp: 0 };
  }
  const [activeRes, missRes, facRes, metricsRes] = await Promise.all([
    sb.rpc("get_admin_active_operator_count"),
    sb.rpc("get_top_question_misses"),
    sb.rpc("get_admin_runtime_metrics"),
    sb
      .from(FACTION_XP_WAR_TOTALS_TABLE)
      .select("fisi_total_xp,fiae_total_xp")
      .eq("id", 1)
      .maybeSingle(),
  ]);
  const active = activeRes.error ? 0 : parseAdminActiveOperatorCount(activeRes.data);
  const facRow = facRes.data as { fisi_total_xp?: unknown; fiae_total_xp?: unknown } | null;
  const factionFisiXp = Math.max(0, Math.floor(Number(facRow?.fisi_total_xp ?? 0)));
  const factionFiaeXp = Math.max(0, Math.floor(Number(facRow?.fiae_total_xp ?? 0)));

  let rows: Array<{
    question_id?: string;
    miss_count?: number | string;
    slug?: string;
    prompt?: string;
  }> = [];
  if (!missRes.error) {
    rows = (missRes.data ?? []) as typeof rows;
  } else {
    const fb = await sb.rpc("get_admin_top_question_misses");
    if (!fb.error && fb.data) {
      const legacy = (fb.data ?? []) as Array<{ question_id?: string; miss_count?: number | string }>;
      rows = legacy.map((r) => ({
        question_id: r.question_id,
        miss_count: r.miss_count,
        slug: typeof r.question_id === "string" ? r.question_id : "",
        prompt: "",
      }));
    }
  }

  const painPoints = mapMissRowsToPainPoints(rows);
  const metricsRow = firstRpcRow(metricsRes.data);
  const ingestPerMinute = Math.max(0, Math.floor(Number(metricsRow?.ingest_per_minute ?? 0)));
  const serverLoadPct = Math.max(0, Math.min(100, Number(metricsRow?.server_load_pct ?? 0)));
  return { activeOperators: active, ingestPerMinute, serverLoadPct, painPoints, factionFisiXp, factionFiaeXp };
}

export async function broadcastSystemAnnouncement(rawBody: string): Promise<{ ok: boolean; error?: string }> {
  if (!useAppStore.getState().isAdmin) {
    return { ok: false, error: "Zugriff verweigert Admin-Kernel erforderlich" };
  }
  const body = rawBody.trim().replace(/\.\s*$/, "");
  if (!body) {
    return { ok: false, error: "Leerer Broadcast abgewiesen" };
  }
  const sb = getSupabase();
  const { authUser, authReady } = useAppStore.getState();
  if (!sb || !authReady || !authUser) {
    return { ok: false, error: "Uplink nicht aktiv" };
  }
  const { error } = await sb.from(SYSTEM_ANNOUNCEMENTS_TABLE).insert({ body });
  if (error) {
    return { ok: false, error: error.message };
  }
  useAppStore.getState().pushSystemPulseEvent({ kind: "SYSTEM_ANNOUNCEMENT", message: body });
  return { ok: true };
}

