export async function completeIdentityOnboarding(input: {
  handle: string;
  careerPath: CareerPath;
}): Promise<{ ok: boolean; error?: string }> {
  const sb = getSupabase();
  const { authUser, authReady } = useAppStore.getState();
  if (!sb || !authReady || !authUser) return { ok: false, error: "Uplink nicht aktiv" };

  useAppStore.setState({ cloudUplinkBusy: true, cloudLastError: null });

  const handleRes = await setOperatorHandle(input.handle);
  if (!handleRes.ok) {
    useAppStore.setState({ cloudUplinkBusy: false });
    return { ok: false, error: handleRes.error };
  }

  const { error } = await sb.from(PROFILES_TABLE).upsert(
    {
      id: authUser.id,
      onboarding_completed: true,
      career_path: input.careerPath,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "id" },
  );

  if (error) {
    useAppStore.setState({ cloudUplinkBusy: false, cloudLastError: error.message, syncStatus: "cloud-outdated" });
    return { ok: false, error: error.message };
  }

  const prior = useAppStore.getState();
  const handleForPulse = (handleRes.handle ?? input.handle).trim().replace(/\s+/g, "_").toUpperCase();
  if (!prior.operatorWelcomePulseEmitted) {
    prior.pushSystemPulseEvent({
      kind: "SYSTEM_ANNOUNCEMENT",
      message: `NEW OPERATOR ${handleForPulse} LINKED TO THE NEXUS`,
    });
  }

  useAppStore.setState({
    cloudUplinkBusy: false,
    cloudLastError: null,
    onboardingCompleted: true,
    careerPath: input.careerPath,
    onboardingHandleDraft: handleRes.handle ?? input.handle,
    operatorWelcomePulseEmitted: true,
    welcomeProtocolSeen: false,
  });
  await flushProgressDeltaSync();
  return { ok: true };
}

export function subscribeToArenaLeaderboards(): () => void {
  const sb = getSupabase();
  if (!sb) return () => undefined;
  if (arenaRealtimeChannel) {
    void arenaRealtimeChannel.unsubscribe();
    arenaRealtimeChannel = null;
    arenaRealtimeStatus = "idle";
  }
  const triggerRefetch = (pulseKey: string) => {
    const mission = useAppStore.getState().arenaRanksMission;
    void fetchGlobalArenaRanks(10, mission).then((rows) => {
      useAppStore.getState().setArenaGlobalRanks(rows);
      useAppStore.getState().setArenaRankPulseKey(pulseKey);
      window.setTimeout(() => {
        if (useAppStore.getState().arenaRankPulseKey === pulseKey) {
          useAppStore.getState().setArenaRankPulseKey(null);
        }
      }, 900);
    });
  };
  arenaRealtimeChannel = sb
    .channel("arena-leaderboards-live")
    .on(
      "postgres_changes",
      { event: "INSERT", schema: "public", table: LEADERBOARD_TABLE },
      (payload: { new?: { user_id?: string; created_at?: string } }) => {
        const next = payload?.new;
        const key = `${next?.user_id ?? "u"}-${next?.created_at ?? Date.now()}`;
        triggerRefetch(key);
      },
    )
    .on(
      "postgres_changes",
      { event: "UPDATE", schema: "public", table: LEADERBOARD_TABLE },
      (payload: { new?: { user_id?: string; created_at?: string } }) => {
        const next = payload?.new;
        const key = `${next?.user_id ?? "u"}-${next?.created_at ?? Date.now()}`;
        triggerRefetch(key);
      },
    )
    .subscribe((status) => {
      arenaRealtimeStatus = status === "SUBSCRIBED" ? "subscribed" : status === "CHANNEL_ERROR" ? "error" : "idle";
    });
  return () => {
    if (arenaRealtimeChannel) {
      void arenaRealtimeChannel.unsubscribe();
      arenaRealtimeChannel = null;
      arenaRealtimeStatus = "idle";
    }
  };
}

function scheduleSystemPulseIngest(fn: () => void): void {
  if (typeof window === "undefined") return;
  if (systemPulseDebounceTimer) window.clearTimeout(systemPulseDebounceTimer);
  systemPulseDebounceTimer = window.setTimeout(() => {
    systemPulseDebounceTimer = null;
    fn();
  }, 420);
}

function parsePulseProgressFields(v: unknown): { level: number; streak: number; globalXP: number } | null {
  if (!v || typeof v !== "object") return null;
  const o = v as Record<string, unknown>;
  if (typeof o.userLevel !== "number" || typeof o.globalXP !== "number") return null;
  return {
    level: Math.max(0, Math.floor(o.userLevel)),
    globalXP: Math.max(0, Math.floor(o.globalXP)),
    streak: typeof o.dailyStreakDays === "number" ? Math.max(0, Math.floor(o.dailyStreakDays)) : 0,
  };
}

async function resolveOperatorHandleUpper(sb: SupabaseClient, userId: string): Promise<string> {
  const { data } = await sb.from(OPERATOR_PROFILE_TABLE).select("handle").eq("user_id", userId).maybeSingle();
  const raw = (data?.handle as string | undefined)?.trim() || "UNKNOWN";
  const up = raw.replace(/\s+/g, "_").toUpperCase();
  return up.length > 0 ? up : "UNKNOWN";
}

function isSelfPulseUser(userId: string): boolean {
  const self = useAppStore.getState().authUser?.id;
  return !!self && userId === self;
}

async function ingestProgressPulseFromRow(userId: string, progressRaw: unknown): Promise<void> {
  const parsed = parsePulseProgressFields(progressRaw);
  if (!parsed) return;
  const prev = progressPulseSnapshots.get(userId);
  progressPulseSnapshots.set(userId, { level: parsed.level, streak: parsed.streak });
  if (isSelfPulseUser(userId)) return;
  const sb = getSupabase();
  if (!sb) return;
  const handle = await resolveOperatorHandleUpper(sb, userId);
  const push = useAppStore.getState().pushSystemPulseEvent;
  if (prev) {
    if (parsed.level > prev.level) {
      const life = computeLifetimeXp(parsed.level, parsed.globalXP);
      const rank = getPrestigeRankByLifetimeXp(life);
      push({
        kind: "PROMOTION",
        handle,
        rankTitle: rank.title,
      });
    }
    const milestones = [7, 14, 30] as const;
    let crossed = 0;
    for (const m of milestones) {
      if (parsed.streak >= m && prev.streak < m) crossed = m;
    }
    if (crossed > 0) {
      push({ kind: "STREAK_MILESTONE", handle, days: crossed });
    }
  }
}

async function ingestLatestArenaMissionPulse(): Promise<void> {
  const rows = await fetchArenaRecentPulse(1);
  const row = rows[0];
  if (!row) return;
  const key = `${row.user_id}-${row.created_at}`;
  if (key === lastArenaIngestKey) return;
  lastArenaIngestKey = key;
  if (isSelfPulseUser(row.user_id)) return;
  const handle = (row.operator_handle || "UNKNOWN").trim().replace(/\s+/g, "_").toUpperCase() || "UNKNOWN";
  useAppStore.getState().pushSystemPulseEvent({
    kind: "MISSION_SOLVED",
    handle,
    ticketId: row.mission_type,
    score: row.score,
  });
}

function resolveFactionLeading(fisiPct: number, fiaePct: number): "FISI" | "FIAE" | "TIE" {
  if (fisiPct > fiaePct + 0.02) return "FISI";
  if (fiaePct > fisiPct + 0.02) return "FIAE";
  return "TIE";
}

async function maybePushFactionShiftPulse(opts?: { forceSnapshot?: boolean }): Promise<void> {
  const fac = await fetchFactionXpWarTotals();
  if (!fac || fac.fisiXp + fac.fiaeXp <= 0) return;
  const t = fac.fisiXp + fac.fiaeXp;
  const fp = (fac.fisiXp / t) * 100;
  const ap = 100 - fp;
  const push = useAppStore.getState().pushSystemPulseEvent;
  if (lastFactionPulsePct === null) {
    lastFactionPulsePct = { f: fp, a: ap };
    if (opts?.forceSnapshot) {
      push({
        kind: "FACTION_SHIFT",
        leading: resolveFactionLeading(fp, ap),
        fisiPct: fp,
        fiaePct: ap,
      });
    }
    return;
  }
  if (opts?.forceSnapshot) return;
  if (Math.abs(fp - lastFactionPulsePct.f) < 0.35) return;
  lastFactionPulsePct = { f: fp, a: ap };
  push({
    kind: "FACTION_SHIFT",
    leading: resolveFactionLeading(fp, ap),
    fisiPct: fp,
    fiaePct: ap,
  });
}

async function seedSystemPulseFromRecentActivity(): Promise<void> {
  const sb = getSupabase();
  if (!sb) return;
  const rows = await fetchArenaRecentPulse(3);
  const selfId = useAppStore.getState().authUser?.id;
  const filtered = selfId ? rows.filter((r) => r.user_id !== selfId) : rows;
  const push = useAppStore.getState().pushSystemPulseEvent;
  for (const row of [...filtered].reverse()) {
    const handle = (row.operator_handle || "UNKNOWN").trim().replace(/\s+/g, "_").toUpperCase() || "UNKNOWN";
    push({
      kind: "MISSION_SOLVED",
      handle,
      ticketId: row.mission_type,
      score: row.score,
    });
  }
  await maybePushFactionShiftPulse({ forceSnapshot: true });
  const newest = rows[0];
  if (newest) lastArenaIngestKey = `${newest.user_id}-${newest.created_at}`;
}

/**
 * Phase 43–45 — Realtime-Ingest: Progress, Arena, Faction-Poll, System-Broadcasts
 * Einmal beim Dashboard-Einstieg starten, Teardown beim Unmount
 */
export function subscribeSystemPulseIngest(): () => void {
  const sb = getSupabase();
  if (!sb) return () => undefined;

  if (systemPulseIngestChannel) {
    void systemPulseIngestChannel.unsubscribe();
    systemPulseIngestChannel = null;
    pulseRealtimeStatus = "idle";
  }

  const onProgressUpdate = (payload: { new?: Record<string, unknown>; old?: Record<string, unknown> }) => {
    const uidRaw = payload.new?.user_id ?? payload.old?.user_id;
    const prog = payload.new?.progress;
    if (typeof uidRaw !== "string") return;
    scheduleSystemPulseIngest(() => void ingestProgressPulseFromRow(uidRaw, prog));
  };

  const onArenaInsert = () => {
    scheduleSystemPulseIngest(() => void ingestLatestArenaMissionPulse());
  };

  const onSystemAnnouncementInsert = (payload: { new?: Record<string, unknown> }) => {
    const raw = payload.new?.body;
    if (typeof raw !== "string") return;
    const message = raw.trim().replace(/\.\s*$/, "");
    if (!message) return;
    useAppStore.getState().pushSystemPulseEvent({ kind: "SYSTEM_ANNOUNCEMENT", message });
  };

  systemPulseIngestChannel = sb
    .channel("system-pulse-ingest")
    .on(
      "postgres_changes",
      { event: "UPDATE", schema: "public", table: SYNC_TABLE },
      (payload: { new?: Record<string, unknown> }) => onProgressUpdate(payload),
    )
    .on(
      "postgres_changes",
      { event: "INSERT", schema: "public", table: LEADERBOARD_TABLE },
      () => onArenaInsert(),
    )
    .on(
      "postgres_changes",
      { event: "INSERT", schema: "public", table: SYSTEM_ANNOUNCEMENTS_TABLE },
      (payload: { new?: Record<string, unknown> }) => onSystemAnnouncementInsert(payload),
    )
    .subscribe((status) => {
      pulseRealtimeStatus = status === "SUBSCRIBED" ? "subscribed" : status === "CHANNEL_ERROR" ? "error" : "idle";
    });

  void seedSystemPulseFromRecentActivity();

  if (typeof window !== "undefined") {
    systemPulseFactionPoll = window.setInterval(() => {
      void maybePushFactionShiftPulse();
    }, 88_000);
  }

  return () => {
    if (systemPulseDebounceTimer) {
      window.clearTimeout(systemPulseDebounceTimer);
      systemPulseDebounceTimer = null;
    }
    if (systemPulseFactionPoll) {
      window.clearInterval(systemPulseFactionPoll);
      systemPulseFactionPoll = null;
    }
    if (systemPulseIngestChannel) {
      void systemPulseIngestChannel.unsubscribe();
      systemPulseIngestChannel = null;
      pulseRealtimeStatus = "idle";
    }
  };
}

/** Phase 72 — globaler Broadcast Kanal für Social Pulse */
export function subscribeNexusActivityBus(): () => void {
  const sb = getSupabase();
  if (!sb) return () => undefined;

  if (nexusActivityChannel) {
    void nexusActivityChannel.unsubscribe();
    nexusActivityChannel = null;
  }

  nexusActivityChannel = sb
    .channel("nexus-activity")
    .on("broadcast", { event: "nexus_activity" }, (payload: { payload?: unknown }) => {
      const normalized = normalizeNexusActivityPayload(payload.payload);
      if (!normalized) return;
      const selfId = useAppStore.getState().authUser?.id;
      const ownEvent = !!selfId && normalized.userId === selfId;
      if (ownEvent) return;
      const state = useAppStore.getState();
      state.pushNexusActivity(normalized);
      applyGlobalOverdriveDirective(normalized);
      applyDuelDirective(normalized);
      applyOutbreakDirective(normalized);
      if (normalized.kind === "SYNDICATE_ASCENSION" || normalized.kind === "SYNDICATE_FOUNDED") {
        void refreshSyndicateRuntimeBuffs();
      }
      if (normalized.kind === "COUNCIL_DECREE" || normalized.kind === "COUNCIL_PROPOSAL") {
        void refreshCouncilRuntimeOverride();
      }
      if (normalized.kind === "LAUNCH_INIT") {
        void refreshLaunchRuntimeState();
      }
    })
    .subscribe();

  void maybeAutoRotateWeeklyBossPool();
  void refreshSyndicateRuntimeBuffs();
  void refreshCouncilRuntimeOverride();
  void refreshLaunchRuntimeState();

  return () => {
    if (nexusActivityChannel) {
      void nexusActivityChannel.unsubscribe();
      nexusActivityChannel = null;
    }
    if (nexusActivityEmitChannel) {
      void nexusActivityEmitChannel.unsubscribe();
      nexusActivityEmitChannel = null;
    }
    if (duelRealtimeChannel) {
      void duelRealtimeChannel.unsubscribe();
      duelRealtimeChannel = null;
      duelRealtimeChannelId = "";
    }
  };
}

export async function setOperatorHandle(handleRaw: string): Promise<{ ok: boolean; error?: string; handle?: string }> {
  const sb = getSupabase();
  const { authUser, authReady } = useAppStore.getState();
  if (!sb || !authReady || !authUser) return { ok: false, error: "Uplink nicht aktiv" };
  const normalized = handleRaw.trim().replace(/\s+/g, "_");
  if (!/^[A-Za-z0-9_]{3,24}$/.test(normalized)) {
    return { ok: false, error: "Handle benötigt 3-24 Zeichen aus A-Z 0-9 _" };
  }
  useAppStore.setState({ cloudUplinkBusy: true, cloudLastError: null });
  const { error } = await sb.from(OPERATOR_PROFILE_TABLE).upsert(
    {
      user_id: authUser.id,
      handle: normalized,
      updated_at: new Date().toISOString(),
    },
    { onConflict: "user_id" },
  );
  useAppStore.setState({ cloudUplinkBusy: false });
  if (error) {
    useAppStore.setState({ cloudLastError: error.message, syncStatus: "cloud-outdated" });
    return { ok: false, error: error.message };
  }
  useAppStore.setState({ operatorHandle: normalized });
  return { ok: true, handle: normalized };
}

