import { motion } from "framer-motion";
import { useMemo, useState } from "react";
import type { QuestionModule, QuestionType } from "../../data/questionSchema";
import { cn } from "../../lib/cn";
import type { ArenaQuestion } from "../../lib/questionContent";
import { rpcUpsertQuestionFromForge } from "../../lib/syncController";
import { QuestionBlueprintAfterPrompt } from "../blocks/QuestionBlueprintAfterPrompt";

const MODULE_CHOICES: Array<{ id: QuestionModule; label: string }> = [
  { id: "networking", label: "Netzwerk" },
  { id: "programming", label: "Programmierung" },
  { id: "wiso", label: "Wirtschaftslehre" },
  { id: "security", label: "Security" },
  { id: "databases", label: "Datenbanken" },
  { id: "process", label: "Prozess" },
];

function slugify(raw: string): string {
  return raw
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 72);
}

export function QuestionForgeView() {
  const [prompt, setPrompt] = useState("");
  const [optA, setOptA] = useState("");
  const [optB, setOptB] = useState("");
  const [optC, setOptC] = useState("");
  const [optD, setOptD] = useState("");
  const [correctIndex, setCorrectIndex] = useState<0 | 1 | 2 | 3>(0);
  const [hint, setHint] = useState("");
  const [explanation, setExplanation] = useState("");
  const [tagsRaw, setTagsRaw] = useState("ihk,forge");
  const [module, setModule] = useState<QuestionModule>("programming");
  const [type, setType] = useState<QuestionType>("multiple_choice");
  const [examId, setExamId] = useState<"AP1" | "AP2" | "WISO">("AP1");
  const [difficulty, setDifficulty] = useState<"easy" | "medium" | "hard">("medium");
  const [starterSql, setStarterSql] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [codeSnippet, setCodeSnippet] = useState("");
  const [ihkScore, setIhkScore] = useState(70);
  const [busy, setBusy] = useState(false);
  const [status, setStatus] = useState<null | { kind: "ok" | "err"; text: string }>(null);

  const options = useMemo(
    () => [optA.trim(), optB.trim(), optC.trim(), optD.trim()] as [string, string, string, string],
    [optA, optB, optC, optD],
  );
  const promptTrim = prompt.trim();
  const slug = slugify(promptTrim || "forge-question");
  const id = `forge-${examId.toLowerCase()}-${slug || "item"}`;
  const tags = useMemo(() => {
    const base = tagsRaw
      .split(",")
      .map((x) => x.trim().toLowerCase())
      .filter(Boolean);
    const withIhk = [...base, `ihk_score_${Math.max(0, Math.min(100, Math.floor(ihkScore)))}`];
    return Array.from(new Set(withIhk));
  }, [ihkScore, tagsRaw]);
  const canSave = promptTrim.length > 10 && options.every((x) => x.length > 0);

  const previewQuestion: ArenaQuestion = {
    id,
    slug,
    type,
    prompt: promptTrim || "Vorschau Prompt",
    options: (options.every((x) => x) ? options : ["Option A", "Option B", "Option C", "Option D"]) as [
      string,
      string,
      string,
      string,
    ],
    correctIndex,
    explanation: explanation.trim() || undefined,
    contextCode: starterSql.trim() || undefined,
    tags,
    difficulty,
    imageUrl: imageUrl.trim() || undefined,
    codeSnippet: codeSnippet.trim() || undefined,
    hint: hint.trim() || undefined,
  };

  const save = async () => {
    if (!canSave || busy) return;
    setBusy(true);
    setStatus(null);
    const res = await rpcUpsertQuestionFromForge({
      id,
      slug,
      examId,
      module,
      type,
      difficulty,
      prompt: promptTrim,
      options,
      correctIndex,
      hint: hint.trim() || undefined,
      explanation: explanation.trim() || undefined,
      tags,
      starterSql: starterSql.trim() || undefined,
      imageUrl: imageUrl.trim() || undefined,
      codeSnippet: codeSnippet.trim() || undefined,
      ihkScore: Math.max(0, Math.min(100, Math.floor(ihkScore))),
    });
    if (res.ok) {
      setStatus({ kind: "ok", text: `Question synced ${id}` });
    } else {
      setStatus({ kind: "err", text: res.error ?? "Forge Sync fehlgeschlagen" });
    }
    setBusy(false);
  };

  return (
    <section className="border border-white/[0.12] bg-black/35 p-3 sm:p-4">
      <div className="mb-2 flex items-end justify-between gap-2 border-b border-white/[0.1] pb-2">
        <div>
          <p className="font-mono text-[9px] font-bold uppercase tracking-[0.26em] text-cyan-200/80">
            Content Forge
          </p>
          <h3 className="font-mono text-[13px] font-bold uppercase tracking-[0.08em] text-foreground">
            Question Builder
          </h3>
        </div>
        <motion.button
          type="button"
          whileTap={{ scale: 0.96, y: 1 }}
          disabled={!canSave || busy}
          onClick={() => void save()}
          className={cn(
            "border px-3 py-1.5 font-mono text-[10px] font-bold uppercase tracking-[0.18em]",
            !canSave || busy
              ? "cursor-not-allowed border-white/[0.1] text-foreground-muted opacity-50"
              : "border-cyan-300/45 bg-cyan-500/10 text-cyan-100 hover:bg-cyan-500/16",
          )}
        >
          {busy ? "Syncing" : "Push Question"}
        </motion.button>
      </div>

      <div className="grid gap-3 lg:grid-cols-[1.05fr_0.95fr]">
        <div className="space-y-2">
          <div className="grid gap-2 sm:grid-cols-3">
            <select
              value={examId}
              onChange={(e) => setExamId(e.target.value as "AP1" | "AP2" | "WISO")}
              className="border border-white/[0.12] bg-black/60 px-2 py-1 font-mono text-[10px] uppercase tracking-[0.14em] text-foreground"
            >
              <option value="AP1">AP1</option>
              <option value="AP2">AP2</option>
              <option value="WISO">WISO</option>
            </select>
            <select
              value={module}
              onChange={(e) => setModule(e.target.value as QuestionModule)}
              className="border border-white/[0.12] bg-black/60 px-2 py-1 font-mono text-[10px] uppercase tracking-[0.14em] text-foreground"
            >
              {MODULE_CHOICES.map((m) => (
                <option key={m.id} value={m.id}>
                  {m.label}
                </option>
              ))}
            </select>
            <select
              value={difficulty}
              onChange={(e) => setDifficulty(e.target.value as "easy" | "medium" | "hard")}
              className="border border-white/[0.12] bg-black/60 px-2 py-1 font-mono text-[10px] uppercase tracking-[0.14em] text-foreground"
            >
              <option value="easy">Easy</option>
              <option value="medium">Medium</option>
              <option value="hard">Hard</option>
            </select>
          </div>

          <textarea
            rows={3}
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="Prompt"
            className="w-full border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60"
          />

          <div className="grid gap-2 sm:grid-cols-2">
            <input value={optA} onChange={(e) => setOptA(e.target.value)} placeholder="Option A" className="border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
            <input value={optB} onChange={(e) => setOptB(e.target.value)} placeholder="Option B" className="border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
            <input value={optC} onChange={(e) => setOptC(e.target.value)} placeholder="Option C" className="border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
            <input value={optD} onChange={(e) => setOptD(e.target.value)} placeholder="Option D" className="border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
          </div>

          <div className="grid gap-2 sm:grid-cols-3">
            <select
              value={String(correctIndex)}
              onChange={(e) => setCorrectIndex(Number(e.target.value) as 0 | 1 | 2 | 3)}
              className="border border-white/[0.12] bg-black/60 px-2 py-1 font-mono text-[10px] uppercase tracking-[0.14em] text-foreground"
            >
              <option value="0">Lösung A</option>
              <option value="1">Lösung B</option>
              <option value="2">Lösung C</option>
              <option value="3">Lösung D</option>
            </select>
            <select
              value={type}
              onChange={(e) => setType(e.target.value as QuestionType)}
              className="border border-white/[0.12] bg-black/60 px-2 py-1 font-mono text-[10px] uppercase tracking-[0.14em] text-foreground"
            >
              <option value="multiple_choice">MCQ</option>
              <option value="sql_challenge">SQL</option>
            </select>
            <label className="flex items-center gap-2 border border-white/[0.12] bg-black/60 px-2 py-1 font-mono text-[10px] uppercase tracking-[0.14em] text-foreground">
              IHK {ihkScore}
              <input
                type="range"
                min={0}
                max={100}
                value={ihkScore}
                onChange={(e) => setIhkScore(Number(e.target.value))}
                className="w-full accent-cyan-300"
              />
            </label>
          </div>

          <input value={hint} onChange={(e) => setHint(e.target.value)} placeholder="Neural Link Hint" className="w-full border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
          <input value={tagsRaw} onChange={(e) => setTagsRaw(e.target.value)} placeholder="Tags comma separated" className="w-full border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
          <textarea rows={2} value={explanation} onChange={(e) => setExplanation(e.target.value)} placeholder="Kurzbegründung" className="w-full border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
          <input value={imageUrl} onChange={(e) => setImageUrl(e.target.value)} placeholder="Image URL optional" className="w-full border border-white/[0.12] bg-black/60 px-2 py-1.5 font-sans text-sm text-foreground placeholder:text-foreground-muted/60" />
          <textarea
            rows={2}
            value={codeSnippet}
            onChange={(e) => setCodeSnippet(e.target.value)}
            placeholder="Code Snippet optional"
            className="w-full border border-white/[0.12] bg-black/60 px-2 py-1.5 font-mono text-xs text-foreground placeholder:text-foreground-muted/60"
          />
          {type === "sql_challenge" ? (
            <textarea
              rows={2}
              value={starterSql}
              onChange={(e) => setStarterSql(e.target.value)}
              placeholder="Starter SQL optional"
              className="w-full border border-white/[0.12] bg-black/60 px-2 py-1.5 font-mono text-xs text-foreground placeholder:text-foreground-muted/60"
            />
          ) : null}
          {status ? (
            <p className={cn("font-mono text-[10px] uppercase tracking-[0.16em]", status.kind === "ok" ? "text-cyan-200" : "text-signal")}>
              {status.text}
            </p>
          ) : null}
        </div>

        <div className="border border-white/[0.1] bg-black/28 p-3">
          <p className="font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">Live Preview</p>
          <h4 className="mt-2 font-serif text-lg font-semibold text-foreground">{previewQuestion.prompt}</h4>
          <QuestionBlueprintAfterPrompt question={previewQuestion} className="mt-2" />
          <div className="mt-3 space-y-1">
            {previewQuestion.options.map((opt, idx) => (
              <div
                key={`${idx}-${opt}`}
                className={cn(
                  "border px-2 py-1.5 font-sans text-sm",
                  idx === previewQuestion.correctIndex
                    ? "border-cyan-300/35 bg-cyan-500/10 text-cyan-100"
                    : "border-white/[0.1] bg-black/20 text-foreground",
                )}
              >
                {opt}
              </div>
            ))}
          </div>
          {previewQuestion.hint ? (
            <p className="mt-3 border border-cyan-300/25 bg-cyan-500/[0.08] px-2 py-1.5 font-mono text-[10px] uppercase tracking-[0.14em] text-cyan-100">
              Hint {previewQuestion.hint}
            </p>
          ) : null}
        </div>
      </div>
    </section>
  );
}
