import type { StateCreator } from "zustand";
import { SYNTHESIS_RECIPES } from "../../data/synthesisRecipes";
import type { AppState } from "../useAppStore";

export interface AdminSlice {
  isAdmin: boolean;
  setIsAdmin: (next: boolean) => void;
  seedDevMaterials: () => number;
  resetCraftingInventory: () => void;
}

const DEV_MATERIAL_SEED_LIST: string[] = SYNTHESIS_RECIPES.flatMap((recipe) =>
  recipe.input.flatMap((material) => Array.from({ length: material.amount }, () => material.itemId)),
);

export const createAdminSlice: StateCreator<AppState, [], [], AdminSlice> = (set, get) => ({
  isAdmin: false,
  setIsAdmin: (next) => set({ isAdmin: !!next }),
  seedDevMaterials: () => {
    const added = get().addInventoryItems(DEV_MATERIAL_SEED_LIST);
    return added;
  },
  resetCraftingInventory: () => {
    get().clearCraftingInventory();
  },
});
