import { cn } from "../../lib/cn";

type BlueprintCodeBlockProps = {
  code: string;
  caption?: string;
  className?: string;
};

export function BlueprintCodeBlock({ code, caption, className }: BlueprintCodeBlockProps) {
  const trimmed = code.trim();
  if (!trimmed) return null;
  return (
    <div className={cn("mt-4", className)}>
      {caption ? (
        <p className="mb-1.5 font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-cyan-400/90">{caption}</p>
      ) : null}
      <pre
        className={cn(
          "question-scrollbar max-h-64 overflow-auto px-3 py-2.5 font-mono text-[11px] leading-relaxed text-cyan-50/95",
          "border border-cyan-500/25 bg-cyan-950/30",
          "shadow-[inset_0_0_0_1px_rgb(6_182_212_/0.14)]",
        )}
      >
        <code>{trimmed}</code>
      </pre>
    </div>
  );
}
