import { motion, useMotionValue, useReducedMotion, useTransform, type MotionValue } from "framer-motion";
import { useMemo, type CSSProperties } from "react";
import { cn } from "../../lib/cn";
import type { RankArtifact } from "../../lib/rankEngine";

type ArtifactPedestalProps = {
  artifact: RankArtifact;
  variant?: "hero" | "compact";
  tiltX?: MotionValue<number>;
  tiltY?: MotionValue<number>;
  pulseActive?: boolean;
  className?: string;
};

export function ArtifactPedestal({
  artifact,
  variant = "hero",
  tiltX,
  tiltY,
  pulseActive = false,
  className,
}: ArtifactPedestalProps) {
  const prefersReduced = useReducedMotion();
  const fallbackTiltX = useMotionValue(0);
  const fallbackTiltY = useMotionValue(0);
  const isHero = variant === "hero";
  const particleCount = isHero ? 8 : pulseActive ? 4 : 2;
  const auraOpacity = isHero ? 1 : pulseActive ? 0.88 : artifact.compactAuraOpacity;

  const reflectionTransform = useTransform(
    [tiltX ?? fallbackTiltX, tiltY ?? fallbackTiltY],
    ([x, y]) => {
      const tiltHorizontal = Number(y);
      const tiltVertical = Number(x);
      return `translate3d(${tiltHorizontal * 0.55}px, ${tiltVertical * -0.45}px, 0) rotate(${tiltHorizontal * 0.18}deg)`;
    },
  );

  const particles = useMemo(
    () =>
      Array.from({ length: particleCount }, (_, index) => {
        const progress = particleCount <= 1 ? 0.5 : index / (particleCount - 1);
        const left = 10 + progress * 78;
        const delay = `${(index * 0.47).toFixed(2)}s`;
        const duration = `${(isHero ? 5.6 : 7.1) + (index % 3) * 0.9}s`;
        const size = `${isHero ? 2 + (index % 3) : 1 + (index % 2)}px`;
        return { left: `${left}%`, delay, duration, size, opacity: isHero ? 0.68 : pulseActive ? 0.56 : 0.28 };
      }),
    [isHero, particleCount, pulseActive],
  );

  const ambientShadow = isHero
    ? `0 22px 40px ${artifact.shadowColor}, inset 0 -16px 32px rgba(0, 0, 0, 0.24), inset 0 1px 0 rgba(255, 255, 255, 0.08)`
    : `0 8px 18px ${artifact.shadowColor}, inset 0 -6px 12px rgba(0, 0, 0, 0.2)`;

  const auraClass =
    artifact.pulseMode === "threat"
      ? "artifact-pedestal-threat"
      : artifact.pulseMode === "breathe"
        ? "artifact-pedestal-breathe"
        : "";

  return (
    <div
      className={cn(
        "relative isolate flex aspect-square items-center justify-center overflow-hidden border border-white/[0.1] bg-void/60",
        isHero ? "w-full [perspective:1200px]" : "w-full",
        className,
      )}
      style={{ boxShadow: ambientShadow }}
    >
      <motion.div
        className={cn("pointer-events-none absolute inset-[-16%] rounded-[34%] opacity-90", !prefersReduced && auraClass)}
        style={{
          opacity: auraOpacity,
          background: `radial-gradient(circle at 50% 52%, ${artifact.auraColor} 0%, ${artifact.auraSecondaryColor} 34%, transparent 72%)`,
          filter: isHero ? "blur(24px)" : "blur(12px)",
        }}
        animate={
          prefersReduced || (!isHero && !pulseActive)
            ? undefined
            : artifact.pulseMode === "threat"
              ? { scale: [0.98, 1.04, 0.98], opacity: [auraOpacity * 0.92, auraOpacity * 1.16, auraOpacity * 0.92] }
              : isHero
                ? { scale: [0.99, 1.03, 0.99], opacity: [auraOpacity * 0.9, auraOpacity * 1.08, auraOpacity * 0.9] }
                : { opacity: [auraOpacity, Math.min(1, auraOpacity + 0.16), auraOpacity] }
        }
        transition={
          prefersReduced || (!isHero && !pulseActive)
            ? undefined
            : { duration: artifact.pulseMode === "threat" ? 2.4 : 4.8, repeat: Infinity, ease: "easeInOut" }
        }
      />
      <div
        className="pointer-events-none absolute inset-[12%] rounded-[30%]"
        style={{
          background: `radial-gradient(circle at 50% 58%, ${artifact.pedestalTone} 0%, rgba(0, 0, 0, 0.18) 58%, transparent 76%)`,
          filter: isHero ? "blur(10px)" : "blur(6px)",
        }}
      />
      <div
        className={cn(
          "pointer-events-none absolute inset-[9%] overflow-hidden rounded-[28%] border border-white/[0.08]",
          isHero ? "backdrop-blur-[10px]" : "backdrop-blur-[5px]",
        )}
        style={{
          background: `linear-gradient(160deg, ${artifact.glassTint} 0%, rgba(255, 255, 255, 0.02) 38%, rgba(255, 255, 255, 0.01) 100%)`,
        }}
      >
        <motion.div
          className="artifact-pedestal-glass pointer-events-none absolute inset-y-0 left-[-26%] w-[58%] rounded-full"
          style={{
            transform: reflectionTransform,
            background:
              "linear-gradient(90deg, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.18) 48%, rgba(255, 255, 255, 0.02) 100%)",
            filter: isHero ? "blur(10px)" : "blur(5px)",
            opacity: isHero ? 0.8 : pulseActive ? 0.62 : 0.34,
          }}
          animate={
            prefersReduced || (!isHero && !pulseActive)
              ? undefined
              : { x: ["0%", "48%", "0%"], opacity: isHero ? [0.46, 0.8, 0.46] : [0.28, 0.56, 0.28] }
          }
          transition={
            prefersReduced || (!isHero && !pulseActive) ? undefined : { duration: isHero ? 7.8 : 4.6, repeat: Infinity, ease: "easeInOut" }
          }
        />
      </div>
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-30" />
      <div className="pointer-events-none absolute inset-0 scanlines opacity-[0.08]" />
      <div className="pointer-events-none absolute inset-x-1 top-1 h-px bg-white/[0.18]" />
      <motion.div
        className="pointer-events-none absolute inset-[6%] border"
        style={{ borderColor: artifact.auraSecondaryColor }}
        animate={
          prefersReduced || (!isHero && !pulseActive)
            ? undefined
            : { opacity: artifact.pulseMode === "threat" ? [0.34, 0.78, 0.34] : [0.24, 0.54, 0.24] }
        }
        transition={
          prefersReduced || (!isHero && !pulseActive) ? undefined : { duration: isHero ? 4.4 : 2.8, repeat: Infinity, ease: "easeInOut" }
        }
      />
      <div className="pointer-events-none absolute inset-0 ring-1 ring-white/[0.06]" />
      <div className="pointer-events-none absolute inset-[16%] rounded-[26%] border border-white/[0.04]" />
      <div className="pointer-events-none absolute inset-0">
        {particles.map((particle, index) => (
          <span
            key={`${artifact.tier}-${variant}-${index}`}
            className="artifact-pedestal-particle pointer-events-none absolute bottom-[10%] rounded-full"
            style={
              {
                left: particle.left,
                width: particle.size,
                height: particle.size,
                opacity: particle.opacity,
                background: artifact.particleColor,
                boxShadow: `0 0 10px ${artifact.auraColor}`,
                animationDelay: particle.delay,
                animationDuration: particle.duration,
              } as CSSProperties
            }
          />
        ))}
      </div>
      <img
        src={artifact.assetPath}
        alt={artifact.tier}
        width={isHero ? 160 : 22}
        height={isHero ? 160 : 22}
        loading="eager"
        fetchPriority="high"
        decoding="async"
        className={cn("relative z-10 aspect-square object-contain", isHero ? "w-full p-2" : "w-full p-[2px]")}
      />
    </div>
  );
}
