import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import type { QuestionModule } from "../../data/questionSchema";
import { fetchSectorDominanceMap, type SectorDominanceRow } from "../../lib/syncController";

const MODULE_LABEL: Record<QuestionModule, string> = {
  networking: "NET",
  security: "SEC",
  operating_systems: "OPS",
  hardware: "HWD",
  programming: "PRG",
  databases: "DB",
  testing: "TST",
  architecture: "ARC",
  process: "PRC",
  wiso: "WISO",
};

function ownerTone(mine: boolean): string {
  if (mine) return "rgba(34,197,94,0.28)";
  return "rgba(56,189,248,0.22)";
}

export function WorldSectorMap() {
  const prefersReduced = !!useReducedMotion();
  const [busy, setBusy] = useState(true);
  const [rows, setRows] = useState<SectorDominanceRow[]>([]);

  useEffect(() => {
    let alive = true;
    void fetchSectorDominanceMap()
      .then((next) => {
        if (!alive) return;
        setRows(next);
      })
      .finally(() => {
        if (!alive) return;
        setBusy(false);
      });
    return () => {
      alive = false;
    };
  }, []);

  const maxInfluence = useMemo(
    () => Math.max(1, ...rows.map((row) => Math.max(1, row.influence))),
    [rows],
  );

  return (
    <section className="relative overflow-hidden border border-sky-300/25 bg-black/55 backdrop-blur-md">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.08]" aria-hidden />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.18]" aria-hidden />
      <header className="relative flex flex-wrap items-end justify-between gap-2 border-b border-sky-300/25 px-4 py-2 sm:px-5">
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-sky-100/90">
          World Sector Map
        </p>
        <p className="font-mono text-[9px] uppercase tracking-[0.2em] text-sky-200/75">
          Tactical Grid Hologram
        </p>
      </header>
      <div className="relative p-3 sm:p-4">
        {busy ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-sky-100/78">Sector uplink läuft</p>
        ) : rows.length === 0 ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-sky-100/78">Keine Sektordaten verfügbar</p>
        ) : (
          <div className="grid grid-cols-2 gap-2 sm:grid-cols-3 lg:grid-cols-5">
            {rows.map((row, idx) => {
              const strength = Math.max(0.2, Math.min(1, row.influence / maxInfluence));
              return (
                <motion.article
                  key={row.module}
                  initial={prefersReduced ? false : { opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: prefersReduced ? 0 : 0.2, delay: prefersReduced ? 0 : idx * 0.02 }}
                  className="relative overflow-hidden border border-sky-300/35 bg-black/30 p-3"
                  style={{
                    boxShadow: `inset 0 0 22px ${ownerTone(row.mine)}, 0 0 18px rgba(56,189,248,${0.12 + strength * 0.28})`,
                  }}
                >
                  <div className="pointer-events-none absolute inset-0 bg-[linear-gradient(120deg,transparent,rgba(56,189,248,0.12),transparent)]" />
                  <p className="relative font-mono text-[9px] font-bold uppercase tracking-[0.22em] text-sky-100">
                    {MODULE_LABEL[row.module]}
                  </p>
                  <p className="relative mt-1 truncate font-mono text-[8px] uppercase tracking-[0.14em] text-sky-100/85">
                    {row.ownerName}
                  </p>
                  <p className="relative mt-1 font-mono text-[8px] uppercase tracking-[0.14em] text-sky-200/82">
                    INF {row.influence}
                  </p>
                  {row.mine ? (
                    <span className="relative mt-1 inline-flex border border-emerald-300/45 bg-emerald-500/[0.2] px-1.5 py-0.5 font-mono text-[8px] uppercase tracking-[0.14em] text-emerald-100">
                      Owned
                    </span>
                  ) : null}
                </motion.article>
              );
            })}
          </div>
        )}
      </div>
    </section>
  );
}
