import type { CSharpMission } from "../../data/factories/csharpFactory";
import { addInventoryItem, applyShieldIntegrityListener, clampShieldValue } from "./CSharpActionHandler";
import { createDroid, type BaseDroid, type DroidKind } from "./DroidModels";

export type DroidDiagnostic = {
  model: string;
  powerLevel: number;
  type: "BattleDroid" | "ProtocolDroid";
};

export type MissionRuntimeState = {
  systemStatus: string;
  inventoryItems: string[];
  shieldValue: number;
  droid: DroidDiagnostic | null;
  droidArmy: DroidDiagnostic[];
  cssVariables: Record<string, string>;
};

export type MissionActionInput =
  | { type: "trigger" }
  | { type: "add_inventory"; item: string }
  | { type: "set_shield"; value: number }
  | { type: "instantiate_droid"; model: string; powerLevel: number }
  | { type: "set_droid_power"; value: number }
  | { type: "add_droid"; kind: DroidKind; model: string; powerLevel: number }
  | { type: "execute_army" };

export type MissionActionResult = {
  valid: boolean;
  state: MissionRuntimeState;
  html: string;
};

export interface IMissionHandler {
  validate(action: MissionActionInput): boolean;
  executeAction(input: {
    action: MissionActionInput;
    mission: CSharpMission;
    state: MissionRuntimeState;
  }): MissionActionResult;
}

class DroidModel {
  private _powerLevel: number;
  readonly model: string;

  constructor(model: string, powerLevel: number) {
    this.model = model.trim() || "R2 Unit";
    this._powerLevel = 0;
    this.powerLevel = powerLevel;
  }

  get powerLevel(): number {
    return this._powerLevel;
  }

  set powerLevel(value: number) {
    this._powerLevel = clampShieldValue(value);
  }
}

function bindStatus(template: string, status: string): string {
  return template.replace("{{SYSTEM_STATUS}}", status);
}

function bindInventory(template: string, items: string[]): string {
  const rows = items.map((item) => `  <li>${item}</li>`).join("\n");
  return template.replace("{{KYBER_LIST}}", `<ul id="kyber-inventory">\n${rows}\n</ul>`);
}

function bindShield(template: string, shieldValue: number): string {
  return template.replace("{{SHIELD_VALUE}}", String(shieldValue));
}

function bindDroid(template: string, droid: DroidDiagnostic | null): string {
  if (!droid) {
    return template.replace("{{DROID_DIAGNOSTIC}}", "<p id=\"droid-empty\">No droid linked</p>");
  }
  return template.replace(
    "{{DROID_DIAGNOSTIC}}",
    `<article id="droid-diagnostic"><p>Droid ${droid.model}</p><p>PowerLevel ${droid.powerLevel}</p></article>`,
  );
}

function bindDroidArmy(template: string, droids: DroidDiagnostic[]): string {
  if (droids.length === 0) {
    return template.replace("{{DROID_DIAGNOSTIC}}", "<p id=\"droid-empty\">Registry empty</p>");
  }
  const rows = droids
    .map((droid) => `<li>${droid.model} ${droid.type} power ${droid.powerLevel}</li>`)
    .join("");
  return template.replace("{{DROID_DIAGNOSTIC}}", `<ul id="droid-registry">${rows}</ul>`);
}

class StatusBindingStrategy implements IMissionHandler {
  validate(action: MissionActionInput): boolean {
    return action.type === "trigger";
  }
  executeAction(input: { action: MissionActionInput; mission: CSharpMission; state: MissionRuntimeState }): MissionActionResult {
    if (!this.validate(input.action)) return { valid: false, state: input.state, html: input.mission.starterHtml };
    const state = { ...input.state, systemStatus: input.mission.activeStatus };
    return { valid: true, state, html: bindStatus(input.mission.starterHtml, state.systemStatus) };
  }
}

class InventoryListStrategy implements IMissionHandler {
  validate(action: MissionActionInput): boolean {
    return action.type === "add_inventory";
  }
  executeAction(input: { action: MissionActionInput; mission: CSharpMission; state: MissionRuntimeState }): MissionActionResult {
    if (input.action.type !== "add_inventory") return { valid: false, state: input.state, html: input.mission.starterHtml };
    const next = addInventoryItem({ items: input.state.inventoryItems, item: input.action.item });
    const state = { ...input.state, inventoryItems: next.items };
    return { valid: true, state, html: bindInventory(input.mission.starterHtml, state.inventoryItems) };
  }
}

class ShieldIntegrityStrategy implements IMissionHandler {
  validate(action: MissionActionInput): boolean {
    return action.type === "set_shield";
  }
  executeAction(input: { action: MissionActionInput; mission: CSharpMission; state: MissionRuntimeState }): MissionActionResult {
    if (input.action.type !== "set_shield") return { valid: false, state: input.state, html: input.mission.starterHtml };
    const shield = applyShieldIntegrityListener({
      shieldValue: input.action.value,
      existingCssVariables: input.state.cssVariables,
    });
    const state = {
      ...input.state,
      shieldValue: shield.shieldValue,
      cssVariables: shield.cssVariables,
      systemStatus: shield.critical ? "Critical Red" : "Shield Stable",
    };
    return { valid: true, state, html: bindShield(input.mission.starterHtml, state.shieldValue) };
  }
}

class DroidEncapsulationStrategy implements IMissionHandler {
  validate(action: MissionActionInput): boolean {
    return action.type === "instantiate_droid" || action.type === "set_droid_power";
  }
  executeAction(input: { action: MissionActionInput; mission: CSharpMission; state: MissionRuntimeState }): MissionActionResult {
    if (!this.validate(input.action)) return { valid: false, state: input.state, html: input.mission.starterHtml };
    if (input.action.type === "instantiate_droid") {
      const model = new DroidModel(input.action.model, input.action.powerLevel);
      const state = {
        ...input.state,
        droid: { model: model.model, powerLevel: model.powerLevel, type: "ProtocolDroid" as const },
      };
      return { valid: true, state, html: bindDroid(input.mission.starterHtml, state.droid) };
    }
    const current: DroidDiagnostic = input.state.droid ?? { model: "R2 Unit", powerLevel: 0, type: "ProtocolDroid" };
    if (input.action.type !== "set_droid_power") return { valid: false, state: input.state, html: input.mission.starterHtml };
    const model = new DroidModel(current.model, current.powerLevel);
    model.powerLevel = input.action.value;
    const state = {
      ...input.state,
      droid: { model: model.model, powerLevel: model.powerLevel, type: current.type ?? "ProtocolDroid" },
    };
    return { valid: true, state, html: bindDroid(input.mission.starterHtml, state.droid) };
  }
}

function droidTypeName(kind: DroidKind): "BattleDroid" | "ProtocolDroid" {
  return kind === "battle" ? "BattleDroid" : "ProtocolDroid";
}

class DroidFactoryStrategy implements IMissionHandler {
  validate(action: MissionActionInput): boolean {
    return action.type === "add_droid" || action.type === "execute_army";
  }
  executeAction(input: { action: MissionActionInput; mission: CSharpMission; state: MissionRuntimeState }): MissionActionResult {
    if (input.action.type === "add_droid") {
      const nextDroid = createDroid(input.action.kind, input.action.model, input.action.powerLevel);
      const type = droidTypeName(input.action.kind);
      const nextArmy = [...input.state.droidArmy, { model: nextDroid.model, powerLevel: nextDroid.powerLevel, type }];
      const state = { ...input.state, droidArmy: nextArmy };
      return { valid: true, state, html: bindDroidArmy(input.mission.starterHtml, nextArmy) };
    }
    if (input.action.type === "execute_army") {
      const instances: BaseDroid[] = input.state.droidArmy.map((row) =>
        createDroid(row.type === "BattleDroid" ? "battle" : "protocol", row.model, row.powerLevel),
      );
      const effects = instances.map((droid) => droid.ExecuteFunction());
      const cssVariables = { ...input.state.cssVariables };
      for (const effect of effects) cssVariables[effect.cssVariable] = effect.cssValue;
      const state = { ...input.state, cssVariables, systemStatus: effects.map((effect) => effect.message).join(" | ") };
      return { valid: true, state, html: bindDroidArmy(input.mission.starterHtml, input.state.droidArmy) };
    }
    return { valid: false, state: input.state, html: input.mission.starterHtml };
  }
}

const STATUS_STRATEGY = new StatusBindingStrategy();
const INVENTORY_STRATEGY = new InventoryListStrategy();
const SHIELD_STRATEGY = new ShieldIntegrityStrategy();
const DROID_STRATEGY = new DroidEncapsulationStrategy();
const DROID_FACTORY_STRATEGY = new DroidFactoryStrategy();

export function resolveMissionHandler(mission: CSharpMission): IMissionHandler {
  if (mission.missionType === "status_binding") return STATUS_STRATEGY;
  if (mission.missionType === "inventory_list") return INVENTORY_STRATEGY;
  if (mission.missionType === "shield_integrity") return SHIELD_STRATEGY;
  if (mission.missionType === "droid_encapsulation") return DROID_STRATEGY;
  return DROID_FACTORY_STRATEGY;
}
