import { AnimatePresence, motion } from "framer-motion";
import { useMemo } from "react";
import { formatNexusActivityLine, type NexusActivityItem } from "../../../types/nexusActivity";
import { useAppStore } from "../../../store/useAppStore";

function buildFallbackItems(): NexusActivityItem[] {
  const now = Date.now();
  return [
    {
      id: "mock-syn-1",
      ts: now - 2_000,
      kind: "FORGE_DROP",
      handle: "Operator_One",
      label: "Operator_One synthesized Neural Link",
    },
    {
      id: "mock-syn-2",
      ts: now - 1_000,
      kind: "SYNDICATE_ASCENSION",
      handle: "Operator_Two",
      label: "Operator_Two secured sector uplink",
    },
  ];
}

export function ActivityStream() {
  const entries = useAppStore((s) => s.nexusActivity);
  const items = useMemo(() => (entries.length > 0 ? entries : buildFallbackItems()), [entries]);

  return (
    <section className="relative overflow-hidden rounded-2xl border border-cyan/35 bg-black/60 p-3 sm:p-4">
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20" aria-hidden />
      <div className="pointer-events-none absolute inset-0 bg-[linear-gradient(to_bottom,rgba(0,255,255,0.08)_1px,transparent_1px)] bg-[size:100%_4px] opacity-30" />
      <header className="mb-2 flex items-center justify-between">
        <p className="font-mono text-[10px] uppercase tracking-[0.25em] text-cyan">Nexus Activity Stream</p>
        <span className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">Live ticker</span>
      </header>
      <div className="space-y-1.5">
        <AnimatePresence initial={false}>
          {items.slice(0, 8).map((entry) => (
            <motion.div
              key={entry.id}
              initial={{ opacity: 0, y: 6 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -6 }}
              transition={{ duration: 0.18, ease: [0.22, 1, 0.36, 1] }}
              className="rounded-md border border-cyan/20 bg-cyan/10 px-2.5 py-1.5 font-mono text-[10px] uppercase tracking-[0.12em] text-cyan-100"
            >
              {formatNexusActivityLine(entry)}
            </motion.div>
          ))}
        </AnimatePresence>
      </div>
    </section>
  );
}
