import { useCallback, useMemo } from "react";
import { runHaptic, type HapticPattern } from "../lib/haptics";
import {
  playUiClick,
  playUiError,
  playUiKeyMechanical,
  playUiSubBassHum,
  playUiSuccess,
  playUiSwoosh,
  resumeAudioContext,
  triggerAudioCue,
} from "../lib/webAudioUi";
import { useAppStore } from "../store/useAppStore";

export function useFeedback() {
  const enabled = useAppStore((s) => s.feedbackEnabled);
  const bump = useAppStore((s) => s.bumpAudioActivity);

  const fire = useCallback(
    (opts: { sound?: () => void; haptic?: HapticPattern }) => {
      if (!enabled) return;
      resumeAudioContext();
      if (opts.sound) {
        opts.sound();
        bump();
      }
      if (opts.haptic) runHaptic(opts.haptic);
    },
    [enabled, bump],
  );

  return useMemo(
    () => ({
      menuTap: () => fire({ sound: playUiClick, haptic: "light" }),
      flip: () => fire({ sound: playUiSwoosh, haptic: "light" }),
      arenaCorrect: () => fire({ sound: playUiSuccess, haptic: "success" }),
      arenaWrong: () => fire({ sound: playUiError, haptic: "error" }),
      cardGraded: () => fire({ sound: playUiSuccess, haptic: "medium" }),
      /** Terminal-Tastatur — nur Sound, sehr leise */
      terminalKey: () => {
        if (!enabled) return;
        resumeAudioContext();
        playUiKeyMechanical();
        bump();
      },
      /** Elite-Login Abschluss: Erfolgston + tiefer Puls */
      dossierSyncedElite: () => fire({ sound: playUiSuccess, haptic: "bass" }),
      dossierSubBassHum: () => fire({ sound: playUiSubBassHum, haptic: "bass" }),
      artifactClick: () => fire({ sound: playUiKeyMechanical, haptic: "medium" }),
      hoverTick: () => {
        if (!enabled) return;
        resumeAudioContext();
        triggerAudioCue("HOVER");
        bump();
      },
    }),
    [enabled, bump, fire],
  );
}
