import type { AccentKey } from "../types/accent";

export type ExamId = "AP1" | "AP2" | "WISO";

export interface ExamDefinition {
  id: ExamId;
  title: string;
  tagline: string;
  durationMin: number;
  passRatePercent: number;
  accent: AccentKey;
}

export const EXAMS: ExamDefinition[] = [
  {
    id: "AP1",
    title: "AP1",
    tagline: "Fachinformatiker Anwendungsentwicklung — Teil 1",
    durationMin: 90,
    passRatePercent: 62,
    accent: "cyan",
  },
  {
    id: "AP2",
    title: "AP2",
    tagline: "Abschlussprojekt & Dokumentation",
    durationMin: 120,
    passRatePercent: 58,
    accent: "magenta",
  },
  {
    id: "WISO",
    title: "WISO",
    tagline: "Wirtschafts- und Sozialkunde",
    durationMin: 60,
    passRatePercent: 71,
    accent: "toxic",
  },
];

export function getExam(id: ExamId): ExamDefinition {
  const found = EXAMS.find((e) => e.id === id);
  if (!found) throw new Error(`Unknown exam ${id}`);
  return found;
}
