import ammoDrop from "../data/ammo_drop.json";
import masterQuestions from "../data/master_questions.json";
import { isQuestionBankEntry, type MasterQuestionSeed, type QuestionBankEntry } from "../data/questionSchema";

export type ImportIssue = {
  kind: "invalid" | "duplicate_id" | "duplicate_slug" | "duplicate_prompt";
  id?: string;
  slug?: string;
  message: string;
};

export type ImportResult = {
  valid: QuestionBankEntry[];
  issues: ImportIssue[];
};

function promptFingerprint(prompt: string): string {
  return prompt.toLowerCase().replace(/\s+/g, " ").trim();
}

export function parseQuestionSeed(input: unknown): ImportResult {
  if (!Array.isArray(input)) {
    return {
      valid: [],
      issues: [{ kind: "invalid", message: "Master-Seed ist kein Array" }],
    };
  }

  const ids = new Set<string>();
  const slugs = new Set<string>();
  const prompts = new Set<string>();
  const valid: QuestionBankEntry[] = [];
  const issues: ImportIssue[] = [];

  for (const raw of input) {
    if (!isQuestionBankEntry(raw)) {
      issues.push({ kind: "invalid", message: "Ein Eintrag verletzt das kanonische Fragen-Schema" });
      continue;
    }
    if (ids.has(raw.id)) {
      issues.push({ kind: "duplicate_id", id: raw.id, slug: raw.slug, message: `Doppelte id ${raw.id}` });
      continue;
    }
    if (slugs.has(raw.slug)) {
      issues.push({ kind: "duplicate_slug", id: raw.id, slug: raw.slug, message: `Doppelter slug ${raw.slug}` });
      continue;
    }
    const fingerprint = promptFingerprint(raw.prompt);
    if (prompts.has(fingerprint)) {
      issues.push({ kind: "duplicate_prompt", id: raw.id, slug: raw.slug, message: `Nahezu doppelter Prompt ${raw.id}` });
      continue;
    }
    ids.add(raw.id);
    slugs.add(raw.slug);
    prompts.add(fingerprint);
    valid.push(raw);
  }

  return { valid, issues };
}

export function loadMasterQuestionSeed(): ImportResult {
  return parseQuestionSeed(masterQuestions as MasterQuestionSeed);
}

/**
 * Phase 42 — Ammo Drop: Slug dedupe (letzter gewinnt), danach harte id Eindeutigkeit
 * Phase 48 — optionales Feld `explanation` wird mit validiert und von injectAmmoDropMasterSeed nach Supabase geschrieben
 */
export function parseAmmoDropSeed(input: unknown): ImportResult {
  if (!Array.isArray(input)) {
    return {
      valid: [],
      issues: [{ kind: "invalid", message: "Ammo-Drop ist kein Array" }],
    };
  }

  const bySlug = new Map<string, QuestionBankEntry>();
  const issues: ImportIssue[] = [];

  for (const raw of input) {
    if (!isQuestionBankEntry(raw)) {
      issues.push({ kind: "invalid", message: "Ein Ammo-Eintrag verletzt das kanonische Fragen-Schema" });
      continue;
    }
    bySlug.set(raw.slug, raw);
  }

  const merged = [...bySlug.values()];
  const ids = new Set<string>();
  const valid: QuestionBankEntry[] = [];

  for (const row of merged) {
    if (ids.has(row.id)) {
      issues.push({
        kind: "duplicate_id",
        id: row.id,
        slug: row.slug,
        message: `Doppelte id ${row.id} nach Slug-Dedupe`,
      });
      continue;
    }
    ids.add(row.id);
    valid.push(row);
  }

  return { valid, issues };
}

export function loadAmmoDropSeed(): ImportResult {
  return parseAmmoDropSeed(ammoDrop as MasterQuestionSeed);
}
