import { useMemo } from "react";

type Segment = {
  id: string;
  label: string;
  currentMs: number;
  pbMs: number;
  globalAvgMs: number;
};

type EfficiencyHeatMapProps = {
  segments: Segment[];
};

function pctDelta(currentMs: number, baselineMs: number): number {
  if (baselineMs <= 0) return 0;
  return ((currentMs - baselineMs) / baselineMs) * 100;
}

function toneByDelta(delta: number): string {
  if (delta <= 0) return "bg-cyan-400/55 border-cyan-300/55";
  if (delta <= 20) return "bg-cyan-300/35 border-cyan-300/45";
  if (delta <= 40) return "bg-amber-300/40 border-amber-300/50";
  return "bg-amber-400/60 border-amber-300/65";
}

export function EfficiencyHeatMap({ segments }: EfficiencyHeatMapProps) {
  const totalMs = useMemo(() => segments.reduce((acc, segment) => acc + segment.currentMs, 0), [segments]);
  return (
    <div className="mt-3 rounded-md border border-cyan-400/25 bg-slate-950/65 p-2">
      <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-200">Time Loss Heat Map</p>
      <div className="mt-2 grid grid-cols-1 gap-2 sm:grid-cols-2">
        {segments.map((segment) => {
          const baseline = Math.max(1, Math.round((segment.pbMs + segment.globalAvgMs) / 2));
          const delta = pctDelta(segment.currentMs, baseline);
          const width = totalMs > 0 ? Math.max(8, Math.round((segment.currentMs / totalMs) * 100)) : 8;
          return (
            <div key={segment.id} className={`rounded border px-2 py-1.5 ${toneByDelta(delta)}`}>
              <p className="text-[10px] uppercase tracking-[0.12em] text-slate-100">{segment.label}</p>
              <div className="mt-1 h-1.5 w-full overflow-hidden rounded-full bg-slate-900/70">
                <div className="h-full bg-gradient-to-r from-cyan-300 to-amber-300" style={{ width: `${width}%` }} />
              </div>
              <p className="mt-1 text-[10px] text-slate-100">
                Run {Math.round(segment.currentMs / 1000)}s | PB {Math.round(segment.pbMs / 1000)}s | Avg {Math.round(segment.globalAvgMs / 1000)}s
              </p>
            </div>
          );
        })}
      </div>
    </div>
  );
}
