import type { SqlUniverseId } from "../../../../data/universes";
import { detectSqlInjectionRisk, generateSqlMentorAdvice, type MentorRadarMetric } from "../../../../services/ai/SqlMentorService";

type PreviewRow = Record<string, string | number | null>;

type LivePreviewProps = {
  title: string;
  sql: string;
  columns: string[];
  rows: PreviewRow[];
  querySuccessful?: boolean;
  universeId?: SqlUniverseId;
  radarMetrics?: MentorRadarMetric[];
  successfulTasksCount?: number;
};

type ExplainStep = {
  node: "Table Scan" | "Index Scan" | "Filter" | "Sort";
  cost: number;
  detail: string;
};

type IntegrityDiagnostic = {
  type: "FOREIGN_KEY" | "UNIQUE";
  risk: "high" | "medium";
  summary: string;
  detail: string;
};

type TriggerSignal = {
  active: boolean;
  source: "INSERT" | "UPDATE" | null;
  linkLabel: string;
};

const SQL_KEYWORDS = new Set([
  "SELECT",
  "FROM",
  "WHERE",
  "ORDER",
  "BY",
  "LIMIT",
  "JOIN",
  "ON",
  "GROUP",
  "HAVING",
  "AS",
  "ASC",
  "DESC",
  "COUNT",
  "AVG",
  "SUM",
  "MIN",
  "MAX",
  "DISTINCT",
  "IN",
  "LIKE",
  "AND",
  "OR",
]);

function renderSql(sql: string) {
  const tokens = sql.split(/(\s+|,|\(|\)|;)/g).filter((token) => token.length > 0);
  return tokens.map((token, index) => {
    const normalized = token.trim().toUpperCase();
    if (SQL_KEYWORDS.has(normalized)) {
      return (
        <span key={`${token}-${index}`} className="text-cyan-300">
          {token}
        </span>
      );
    }
    if (/^\d+$/.test(token.trim())) {
      return (
        <span key={`${token}-${index}`} className="text-amber-300">
          {token}
        </span>
      );
    }
    if (/^'.*'$/.test(token.trim())) {
      return (
        <span key={`${token}-${index}`} className="text-emerald-300">
          {token}
        </span>
      );
    }
    return <span key={`${token}-${index}`}>{token}</span>;
  });
}

function hasIndexSignal(sql: string): boolean {
  return /\bCREATE\s+(?:UNIQUE\s+)?INDEX\b|\bUNIQUE\b|\bPRIMARY\s+KEY\b/i.test(sql);
}

export function calculateCostScore(sql: string, columnCount: number): number {
  const clean = sql.toUpperCase();
  const joins = (clean.match(/\bJOIN\b/g) ?? []).length;
  const wheres = (clean.match(/\bWHERE\b/g) ?? []).length;
  const groups = (clean.match(/\bGROUP\s+BY\b/g) ?? []).length;
  const orders = (clean.match(/\bORDER\s+BY\b/g) ?? []).length;
  const indexBonus = hasIndexSignal(sql) ? 16 : 0;
  const cost = 8 + columnCount * 2 + joins * 14 + wheres * 8 + groups * 10 + orders * 6 - indexBonus;
  return Math.max(1, Math.min(100, cost));
}

export function buildExplainSteps(sql: string, baseCost: number): ExplainStep[] {
  const clean = sql.toUpperCase();
  const indexReady = hasIndexSignal(sql) || /\bWHERE\b.+\bID\b/i.test(sql);
  const hasSort = /\bORDER\s+BY\b/.test(clean);
  const hasFilter = /\bWHERE\b|\bHAVING\b/.test(clean);
  const scanCost = Math.max(8, Math.round(baseCost * (indexReady ? 0.32 : 0.62)));
  const steps: ExplainStep[] = [
    {
      node: indexReady ? "Index Scan" : "Table Scan",
      cost: scanCost,
      detail: indexReady ? "Key lookup path active" : "Full relation walk active",
    },
  ];
  if (hasFilter) {
    steps.push({ node: "Filter", cost: Math.max(4, Math.round(baseCost * 0.18)), detail: "Predicate pruning stage" });
  }
  if (hasSort) {
    steps.push({ node: "Sort", cost: Math.max(3, Math.round(baseCost * 0.14)), detail: "Order materialization stage" });
  }
  return steps;
}

function explainTone(node: ExplainStep["node"]): string {
  if (node === "Table Scan") return "border-rose-400/55 bg-rose-950/35 text-rose-100";
  if (node === "Index Scan") return "border-emerald-400/55 bg-emerald-950/35 text-emerald-100";
  if (node === "Filter") return "border-cyan-300/45 bg-cyan-950/30 text-cyan-100";
  return "border-amber-300/45 bg-amber-950/30 text-amber-100";
}

function totalExplainCost(steps: ExplainStep[]): number {
  return steps.reduce((acc, step) => acc + step.cost, 0);
}

function explainBottleneck(steps: ExplainStep[]): ExplainStep | null {
  if (steps.length === 0) return null;
  return [...steps].sort((a, b) => b.cost - a.cost)[0] ?? null;
}

function calculateLegacyCostScore(sql: string, columnCount: number): number {
  const clean = sql.toUpperCase();
  const joins = (clean.match(/\bJOIN\b/g) ?? []).length;
  const wheres = (clean.match(/\bWHERE\b/g) ?? []).length;
  const groups = (clean.match(/\bGROUP\s+BY\b/g) ?? []).length;
  const orders = (clean.match(/\bORDER\s+BY\b/g) ?? []).length;
  const cost = 8 + columnCount * 2 + joins * 14 + wheres * 8 + groups * 10 + orders * 6;
  return Math.min(100, cost);
}

function isMigrationSql(sql: string): boolean {
  return /\bALTER\s+TABLE\b|\bCREATE\s+TABLE\b|\bDROP\s+COLUMN\b|\bADD\s+COLUMN\b/i.test(sql);
}

function schemaHealth(sql: string): { normalizationLevel: number; redundancyScore: number; tone: string } {
  const clean = sql.toUpperCase();
  const joins = (clean.match(/\bJOIN\b/g) ?? []).length;
  const addColumn = (clean.match(/\bADD\s+COLUMN\b/g) ?? []).length;
  const hasForeignKey = /\bFOREIGN\s+KEY\b/.test(clean);
  const hasNotNull = /\bNOT\s+NULL\b/.test(clean);
  const hasDefault = /\bDEFAULT\b/.test(clean);
  const normalizationLevel = Math.max(1, Math.min(5, 2 + joins + (hasForeignKey ? 1 : 0)));
  const redundancyRaw = 68 - joins * 9 - addColumn * 3 - (hasNotNull ? 10 : 0) - (hasDefault ? 6 : 0);
  const redundancyScore = Math.max(5, Math.min(95, redundancyRaw));
  const tone = redundancyScore <= 25 ? "Lean schema flow" : redundancyScore <= 55 ? "Balanced migration pulse" : "Redundancy hotspot";
  return { normalizationLevel, redundancyScore, tone };
}

export function detectIntegrityDiagnostics(sql: string): IntegrityDiagnostic[] {
  const clean = sql.toUpperCase();
  const diagnostics: IntegrityDiagnostic[] = [];
  const writesData = /\bINSERT\b|\bUPDATE\b/.test(clean);
  const hasIdField = /\b[A-Z_]+_ID\b/.test(clean);
  const hasJoinCheck = /\bJOIN\b|\bEXISTS\b|\bREFERENCES\b/.test(clean);
  const hasUniqueSignal = /\bUNIQUE\b|\bON\s+CONFLICT\b|\bPRIMARY\s+KEY\b/.test(clean);
  if (writesData && hasIdField && !hasJoinCheck) {
    diagnostics.push({
      type: "FOREIGN_KEY",
      risk: "high",
      summary: "Foreign key violation risk",
      detail: "Write path uses relation ids without parent validation orphan rows can break integrity",
    });
  }
  if (writesData && /\bEMAIL\b|\bUSERNAME\b|\bCODE\b/.test(clean) && !hasUniqueSignal) {
    diagnostics.push({
      type: "UNIQUE",
      risk: "medium",
      summary: "Unique constraint collision risk",
      detail: "Natural key write detected without uniqueness guard duplicate records can poison analytics",
    });
  }
  return diagnostics;
}

export function detectTriggerSignal(sql: string): TriggerSignal {
  const clean = sql.toUpperCase();
  if (/\bINSERT\b/.test(clean)) {
    return {
      active: true,
      source: "INSERT",
      linkLabel: "Triggered insert audit log sync",
    };
  }
  if (/\bUPDATE\b/.test(clean)) {
    return {
      active: true,
      source: "UPDATE",
      linkLabel: "Triggered update shadow history write",
    };
  }
  return {
    active: false,
    source: null,
    linkLabel: "",
  };
}

export function LivePreview({
  title,
  sql,
  columns,
  rows,
  querySuccessful = true,
  universeId = "bodybuilding",
  radarMetrics = [],
  successfulTasksCount = 0,
}: LivePreviewProps) {
  const costScore = calculateCostScore(sql, columns.length);
  const baselineCost = calculateLegacyCostScore(sql, columns.length);
  const explainSteps = buildExplainSteps(sql, costScore);
  const explainTotal = totalExplainCost(explainSteps);
  const bottleneck = explainBottleneck(explainSteps);
  const impactTone = costScore >= 70 ? "text-rose-300" : costScore >= 40 ? "text-amber-300" : "text-emerald-300";
  const mentorAdvice =
    querySuccessful && (costScore > 50 || successfulTasksCount >= 5)
      ? generateSqlMentorAdvice({ sql, costScore, radar: radarMetrics, universeId, successfulTasks: successfulTasksCount })
      : null;
  const migrationMode = isMigrationSql(sql);
  const health = migrationMode ? schemaHealth(sql) : null;
  const integrityDiagnostics = detectIntegrityDiagnostics(sql);
  const injectionShield = detectSqlInjectionRisk(sql);
  const triggerSignal = detectTriggerSignal(sql);

  return (
    <section className="overflow-hidden rounded-xl border border-cyan-500/40 bg-slate-950/80">
      <div className="flex items-center gap-3 border-b border-cyan-400/20 px-4 py-2">
        <div className="flex items-center gap-1.5">
          <span className="h-2.5 w-2.5 rounded-full bg-rose-500" />
          <span className="h-2.5 w-2.5 rounded-full bg-amber-400" />
          <span className="h-2.5 w-2.5 rounded-full bg-emerald-500" />
        </div>
        <p
          className="text-xs uppercase tracking-[0.2em] text-cyan-200/90"
          style={{ fontFamily: '"JetBrains Mono", monospace' }}
        >
          {title}
        </p>
      </div>

      <div className="grid grid-cols-1 gap-0 md:grid-cols-2">
        <div className="border-b border-cyan-400/20 p-4 md:border-b-0 md:border-r">
          <p
            className="mb-2 text-[10px] uppercase tracking-[0.18em] text-cyan-300/90"
            style={{ fontFamily: '"JetBrains Mono", monospace' }}
          >
            SQL Query
          </p>
          <pre
            className="overflow-x-auto text-sm text-slate-100"
            style={{ fontFamily: '"JetBrains Mono", monospace' }}
          >
            <code>{renderSql(sql)}</code>
          </pre>
        </div>

        <div className="p-4">
          <p
            className="mb-2 text-[10px] uppercase tracking-[0.18em] text-cyan-300/90"
            style={{ fontFamily: '"JetBrains Mono", monospace' }}
          >
            Result Grid
          </p>
          <div className="overflow-x-auto rounded-lg border border-cyan-500/30 bg-slate-900/80">
            <table
              className="w-full border-collapse text-xs text-slate-100"
              style={{ fontFamily: '"JetBrains Mono", monospace' }}
            >
              <thead>
                <tr className="bg-cyan-950/60">
                  {columns.map((column) => (
                    <th key={column} className="border-b border-cyan-500/30 px-3 py-2 text-left font-semibold">
                      {column}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {rows.map((row, rowIndex) => (
                  <tr key={`row-${rowIndex}`} className="odd:bg-slate-900 even:bg-slate-950">
                    {columns.map((column) => (
                      <td key={`${rowIndex}-${column}`} className="border-b border-cyan-500/20 px-3 py-2">
                        {String(row[column] ?? "NULL")}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <p
            className="mt-2 text-[11px] text-cyan-200/80"
            style={{ fontFamily: '"JetBrains Mono", monospace' }}
          >
            {rows.length} Zeilen
          </p>
          <div className="mt-2 rounded-md border border-cyan-400/30 bg-slate-950/70 px-3 py-2">
            <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
              Performance Impact
            </p>
            <p className={`mt-1 text-xs font-semibold ${impactTone}`} style={{ fontFamily: '"JetBrains Mono", monospace' }}>
              Cost Score {costScore}
            </p>
            <p className="mt-1 text-[10px] text-cyan-200" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
              Delta {Math.max(0, baselineCost - costScore)} from index and constraint signals
            </p>
            <div className="mt-2 rounded border border-fuchsia-300/30 bg-slate-950/75 px-2 py-2">
              <p className="text-[10px] uppercase tracking-[0.14em] text-fuchsia-200" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                Explain Analyze Sim
              </p>
              <div className="mt-2 space-y-1.5">
                {explainSteps.map((step) => (
                  <div key={`${step.node}-${step.detail}`} className={`rounded border px-2 py-1 ${explainTone(step.node)}`}>
                    <p className="text-[10px] uppercase tracking-[0.1em]">{step.node}</p>
                    <p className="mt-0.5 text-[10px]">{step.detail} | Cost {step.cost}</p>
                  </div>
                ))}
              </div>
              <p className="mt-1 text-[10px] text-fuchsia-100" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                Plan Cost {explainTotal} {bottleneck ? `| Bottleneck ${bottleneck.node}` : ""}
              </p>
            </div>
            {querySuccessful && mentorAdvice ? (
              <div className="mt-2 rounded border border-amber-300/30 bg-amber-950/20 px-2 py-2">
                <p className="text-[10px] uppercase tracking-[0.14em] text-amber-200" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  Mentor Advice
                </p>
                <p className="mt-1 text-[11px] text-amber-100" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  {mentorAdvice}
                </p>
              </div>
            ) : null}
            {health ? (
              <div className="mt-2 rounded border border-cyan-300/35 bg-cyan-950/20 px-2 py-2">
                <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-100" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  Schema Health
                </p>
                <p className="mt-1 text-[11px] text-cyan-50" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  Normalization Level L{health.normalizationLevel} | Redundancy Score {health.redundancyScore}
                </p>
                <p className="mt-1 text-[10px] uppercase tracking-[0.1em] text-cyan-200" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  {health.tone}
                </p>
              </div>
            ) : null}
            {integrityDiagnostics.length > 0 ? (
              <div className="mt-2 rounded border border-rose-300/35 bg-rose-950/20 px-2 py-2">
                <p className="text-[10px] uppercase tracking-[0.14em] text-rose-100" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  Integrity Violation Diagnostics
                </p>
                <div className="mt-1 space-y-1">
                  {integrityDiagnostics.map((diagnostic) => (
                    <div key={`${diagnostic.type}-${diagnostic.summary}`} className="rounded border border-rose-300/35 bg-slate-950/50 px-2 py-1">
                      <p className="text-[10px] uppercase tracking-[0.1em] text-rose-100">
                        {diagnostic.type === "FOREIGN_KEY" ? "Foreign Key Risk" : "Unique Risk"} | {diagnostic.risk}
                      </p>
                      <p className="mt-0.5 text-[10px] text-rose-50">{diagnostic.summary}</p>
                      <p className="mt-0.5 text-[10px] text-rose-100/90">{diagnostic.detail}</p>
                    </div>
                  ))}
                </div>
              </div>
            ) : null}
            {injectionShield.detected ? (
              <div className="mt-2 animate-pulse rounded border border-rose-300/60 bg-rose-950/35 px-2 py-2">
                <p className="text-[10px] uppercase tracking-[0.14em] text-rose-100" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  Critical Warning
                </p>
                <p className="mt-1 text-[10px] text-rose-50" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  {injectionShield.summary}
                </p>
                <p className="mt-1 text-[10px] text-rose-100/90" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  {injectionShield.guidance}
                </p>
              </div>
            ) : null}
            {triggerSignal.active ? (
              <div className="mt-2 rounded border border-blue-300/55 bg-blue-950/30 px-2 py-2 shadow-[0_0_18px_rgb(56_189_248_/_0.35)]">
                <p className="text-[10px] uppercase tracking-[0.14em] text-blue-100" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  Automated Reaction
                </p>
                <p className="mt-1 text-[10px] text-blue-50" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  {triggerSignal.source} event linked
                </p>
                <p className="mt-1 text-[10px] uppercase tracking-[0.1em] text-blue-200" style={{ fontFamily: '"JetBrains Mono", monospace' }}>
                  {triggerSignal.linkLabel}
                </p>
              </div>
            ) : null}
          </div>
        </div>
      </div>
    </section>
  );
}
