import { motion, useReducedMotion } from "framer-motion";
import { cn } from "../../lib/cn";
import type { AccentKey } from "../../types/accent";

const strokeMap: Record<AccentKey, string> = {
  cyan: "rgb(255 255 255 / 0.88)",
  magenta: "rgb(179 24 38)",
  toxic: "rgb(255 255 255 / 0.42)",
};

export interface CircularStatRingProps {
  label: string;
  value: number;
  max: number;
  accent: AccentKey;
  size?: number;
  strokeWidth?: number;
  centerLabel: string;
  sublabel?: string;
}

export function CircularStatRing({
  label,
  value,
  max,
  accent,
  size = 92,
  strokeWidth = 6,
  centerLabel,
  sublabel,
}: CircularStatRingProps) {
  const prefersReduced = useReducedMotion();
  const r = (size - strokeWidth) / 2;
  const c = 2 * Math.PI * r;
  const clamped = max <= 0 ? 0 : Math.min(1, value / max);
  const offset = c * (1 - clamped);

  return (
    <div
      className="relative flex flex-col items-center gap-2"
      style={{ width: size, minWidth: size }}
    >
      <p className="font-sans text-[10px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
        {label}
      </p>
      <div className="relative" style={{ width: size, height: size }}>
        <svg
          width={size}
          height={size}
          viewBox={`0 0 ${size} ${size}`}
          className="rotate-[-90deg]"
          aria-hidden
        >
          <circle
            cx={size / 2}
            cy={size / 2}
            r={r}
            stroke="rgb(255 255 255 / 0.08)"
            strokeWidth={strokeWidth}
            fill="none"
          />
          <motion.circle
            cx={size / 2}
            cy={size / 2}
            r={r}
            stroke={strokeMap[accent]}
            strokeWidth={strokeWidth}
            strokeLinecap="round"
            fill="none"
            strokeDasharray={c}
            initial={{ strokeDashoffset: prefersReduced ? offset : c }}
            animate={{ strokeDashoffset: offset }}
            transition={
              prefersReduced
                ? { duration: 0.01 }
                : { duration: 1.05, ease: [0.16, 1, 0.3, 1] }
            }
          />
        </svg>
        <div className="pointer-events-none absolute inset-0 flex flex-col items-center justify-center text-center">
          <span
            className={cn(
              "font-sans text-xl font-semibold tracking-[-0.04em] text-foreground",
              accent === "magenta" && "text-signal",
              accent === "toxic" && "text-foreground-muted",
            )}
          >
            {centerLabel}
          </span>
          {sublabel ? (
            <span className="font-sans text-[10px] text-foreground-muted">{sublabel}</span>
          ) : null}
        </div>
      </div>
    </div>
  );
}
