import type { ArenaQuestion } from "../../lib/questionContent";
import { resolveQuestionBlueprintImageSrc } from "../../lib/questionContent";
import { BlueprintCodeBlock } from "./BlueprintCodeBlock";
import { BlueprintViewer } from "./BlueprintViewer";
import { cn } from "../../lib/cn";

type QuestionBlueprintAfterPromptProps = {
  question: ArenaQuestion;
  className?: string;
};

export function QuestionBlueprintAfterPrompt({ question, className }: QuestionBlueprintAfterPromptProps) {
  const src = resolveQuestionBlueprintImageSrc(question);
  const snippet = question.codeSnippet?.trim();
  const starter = question.contextCode?.trim();

  return (
    <div className={cn("space-y-0", className)}>
      {src ? <BlueprintViewer src={src} /> : null}
      {snippet ? <BlueprintCodeBlock code={snippet} caption="Blueprint-Fragment" /> : null}
      {starter ? <BlueprintCodeBlock code={starter} caption="Starter SQL" /> : null}
    </div>
  );
}
