import type { StateCreator } from "zustand";
import type { ExamId } from "../../data/exams";
import { getExam } from "../../data/exams";
import { getArenaQuestionById, getQuestionsForExam } from "../../data/mockQuestions";
import type { AppState, ArenaRunState, DuelChallenge, DuelState } from "../useAppStore";

export interface ArenaSlice {
  arenaRun: ArenaRunState | null;
  arenaFeedback: null | "correct" | "wrong";
  arenaBestScores: Record<string, number>;
  arenaBestNotice: string | null;
  arenaGlobalRanks: Array<{
    user_id: string;
    score: number;
    mission_type: string;
    created_at: string;
    operator_handle: string | null;
    leaderboard_level: number;
    leaderboard_streak: number;
  }>;
  arenaRanksMission: string;
  arenaRankPulseKey: string | null;
  setArenaGlobalRanks: (
    ranks: Array<{
      user_id: string;
      score: number;
      mission_type: string;
      created_at: string;
      operator_handle: string | null;
      leaderboard_level: number;
      leaderboard_streak: number;
    }>,
  ) => void;
  setArenaRanksMission: (mission: string) => void;
  setArenaRankPulseKey: (key: string | null) => void;
  openLoadout: () => void;
  startArena: () => void;
  abandonArenaFlow: () => void;
  clearArenaFeedback: () => void;
  clearArenaBestNotice: () => void;
  submitAnswer: (optionIndex: number) => void;
  applyFiftyFifty: () => void;
  applySlowmo: () => void;
  tickArenaTimer: () => void;
  duelInbox: DuelChallenge[];
  pushDuelChallenge: (next: DuelChallenge) => void;
  clearDuelInbox: () => void;
  duelState: DuelState | null;
  setDuelState: (next: DuelState | null) => void;
  patchDuelState: (patch: Partial<DuelState>) => void;
  ghostModeEnabled: boolean;
  setGhostModeEnabled: (next: boolean) => void;
  bossGhostArmed: boolean;
  setBossGhostArmed: (next: boolean) => void;
}

function initialRun(examId: ExamId): ArenaRunState {
  const exam = getExam(examId);
  const durationSec = Math.min(exam.durationMin * 60, 180);
  return {
    examId,
    startedAtMs: Date.now(),
    timeRemainingSec: durationSec,
    userHp: 100,
    examHp: 100,
    combo: 0,
    questionIndex: 0,
    fiftyFiftyUsed: false,
    slowmoUsed: false,
    shieldCharges: 0,
    hiddenOptionIndices: [],
    outcome: null,
  };
}

export const createArenaSlice: StateCreator<AppState, [], [], ArenaSlice> = (set, get) => ({
  arenaRun: null,
  arenaFeedback: null,
  arenaBestScores: {},
  arenaBestNotice: null,
  arenaGlobalRanks: [],
  arenaRanksMission: "ALL",
  arenaRankPulseKey: null,
  setArenaGlobalRanks: (ranks) => set({ arenaGlobalRanks: ranks }),
  setArenaRanksMission: (mission) => set({ arenaRanksMission: mission }),
  setArenaRankPulseKey: (key) => set({ arenaRankPulseKey: key }),

  openLoadout: () =>
    set({
      activeSection: "loadout",
      arenaRun: null,
      arenaFeedback: null,
      moreMenuOpen: false,
    }),

  startArena: () => {
    const examId = get().selectedExamId;
    const perks = get().selectedPerkIds;
    const shieldCharges = perks.includes("shield") ? 1 : 0;
    const timeBonusSec = Math.max(0, Math.floor(get().syndicateRuntimeBuffs.timeBonusSec));
    const seeded = initialRun(examId);
    set({
      activeSection: "arena",
      arenaRun: {
        ...seeded,
        shieldCharges,
        timeRemainingSec: seeded.timeRemainingSec + timeBonusSec,
      },
      arenaFeedback: null,
      moreMenuOpen: false,
    });
  },

  abandonArenaFlow: () =>
    set({
      activeSection: "command",
      arenaRun: null,
      arenaFeedback: null,
      duelState: null,
    }),

  clearArenaFeedback: () => set({ arenaFeedback: null }),
  clearArenaBestNotice: () => set({ arenaBestNotice: null }),

  applyFiftyFifty: () => {
    const run = get().arenaRun;
    const perks = get().selectedPerkIds;
    if (!run || run.fiftyFiftyUsed || !perks.includes("fifty_fifty")) return;
    const qs = getQuestionsForExam(run.examId);
    const q = qs[run.questionIndex];
    if (!q) return;
    const wrong = [0, 1, 2, 3].filter((i) => i !== q.correctIndex);
    const pick = wrong.sort(() => Math.random() - 0.5).slice(0, 2);
    set({
      arenaRun: {
        ...run,
        fiftyFiftyUsed: true,
        hiddenOptionIndices: pick,
      },
    });
  },

  applySlowmo: () => {
    const run = get().arenaRun;
    const perks = get().selectedPerkIds;
    if (!run || run.slowmoUsed || !perks.includes("slowmo")) return;
    set({
      arenaRun: {
        ...run,
        slowmoUsed: true,
        timeRemainingSec: run.timeRemainingSec + 15,
      },
    });
  },

  tickArenaTimer: () => {
    const run = get().arenaRun;
    if (!run || run.outcome) return;
    const outbreakTickPenalty = get().neuralOutbreak.infected && run.timeRemainingSec % 4 === 0 ? 1 : 0;
    const drain = 1 + outbreakTickPenalty;
    if (run.timeRemainingSec <= drain) {
      set({
        arenaRun: { ...run, timeRemainingSec: 0, outcome: "lose" },
      });
      return;
    }
    set({
      arenaRun: { ...run, timeRemainingSec: run.timeRemainingSec - drain },
    });
  },
  duelInbox: [],
  pushDuelChallenge: (next) =>
    set((s) => {
      const filtered = s.duelInbox.filter((row) => row.duelId !== next.duelId);
      return { duelInbox: [next, ...filtered].slice(0, 8) };
    }),
  clearDuelInbox: () => set({ duelInbox: [] }),
  duelState: null,
  setDuelState: (next) => set({ duelState: next }),
  patchDuelState: (patch) =>
    set((s) => {
      if (!s.duelState) return {};
      return { duelState: { ...s.duelState, ...patch } };
    }),

  submitAnswer: (optionIndex) => {
    const run = get().arenaRun;
    if (!run || run.outcome) return;
    const elapsedMs = Math.max(0, Date.now() - run.startedAtMs);
    const duel = get().duelState;
    const duelQuestions =
      duel && duel.status !== "finished" && duel.questionIds.length > 0
        ? duel.questionIds
            .map((id) => getArenaQuestionById(id))
            .filter((row): row is NonNullable<ReturnType<typeof getArenaQuestionById>> => !!row)
        : null;
    const qs = duelQuestions && duelQuestions.length > 0 ? duelQuestions : getQuestionsForExam(run.examId);
    const q = qs[run.questionIndex];
    if (!q) return;
    const outbreak = get().neuralOutbreak;
    const shouldContributePurge = !!outbreak.infected && !!q.module && q.module === outbreak.module;
    const purgeModule = shouldContributePurge && q.module ? q.module : null;
    const sectorModule = q.module ?? null;

    const correct = optionIndex === q.correctIndex;
    if (correct) {
      const comboNext = run.combo + 1;
      const dmg = Math.min(22, 10 + comboNext * 2);
      const examHp = Math.max(0, run.examHp - dmg);
      const nextIndex = run.questionIndex + 1;
      const clearedAll = nextIndex >= qs.length;
      const duelProgress = Math.max(0, Math.min(1, nextIndex / Math.max(1, qs.length)));

      if (examHp <= 0 || clearedAll) {
        const score = Math.max(0, Math.floor(comboNext * 140 + run.userHp * 12 + run.timeRemainingSec * 5));
        const markBossGhost = get().isAdmin && get().bossGhostArmed;
        const prevBest = get().arenaBestScores[run.examId] ?? 0;
        const isPersonalBest = score > prevBest;
        set({
          arenaRun: { ...run, examHp: 0, combo: comboNext, outcome: "win" },
          arenaFeedback: "correct",
          arenaBestScores: isPersonalBest
            ? { ...get().arenaBestScores, [run.examId]: score }
            : get().arenaBestScores,
          arenaBestNotice: isPersonalBest ? "Neuer persönlicher Bestwert" : null,
        });
        let bossGhostVictory = false;
        let bossGhostLabel: string | undefined;
        let bossGhostId: string | undefined;
        let modifierIntensity = 0;
        let bountyBonusGems = 0;
        if (duel && duel.status !== "finished") {
          if (duel.mirrorMode) {
            const myUserId = get().authUser?.id ?? null;
            const ghostDurationMs = Math.max(1_000, Math.floor(duel.ghostDurationMs ?? 1_000_000));
            const beatGhost = score > duel.opponentScore || (score === duel.opponentScore && elapsedMs < ghostDurationMs);
            bossGhostVictory = duel.mirrorMode === "global_boss" && beatGhost;
            bossGhostLabel = duel.opponentHandle;
            bossGhostId = duel.bossGhostId;
            modifierIntensity = Math.max(0, Math.floor(duel.modifierIntensity ?? 0));
            if (
              bossGhostVictory &&
              duel.bountyTargetFaction &&
              duel.bountyBonusGems &&
              get().careerPath === duel.bountyTargetFaction
            ) {
              bountyBonusGems = Math.max(1, Math.floor(duel.bountyBonusGems));
            }
            get().patchDuelState({
              myDone: true,
              myProgress: 1,
              myScore: score,
              myElapsedMs: elapsedMs,
              opponentProgress: Math.max(0, Math.min(1, elapsedMs / ghostDurationMs)),
              opponentDone: true,
              winnerUserId: beatGhost ? myUserId : duel.opponentUserId,
              status: "finished",
            });
          } else {
            get().patchDuelState({ myDone: true, myProgress: 1, myScore: score, myElapsedMs: elapsedMs });
            void import("../../lib/syncController").then((m) =>
              m.publishDuelProgress({
                duelId: duel.duelId,
                score,
                progress: 1,
                done: true,
              }),
            );
          }
        }
        get().addXp(120, {
          module: q.module,
          bossGhostVictory,
          bossLabel: bossGhostLabel,
          modifierIntensity,
        });
        if (bountyBonusGems > 0) {
          set({ gems: get().gems + bountyBonusGems });
          get().pushSystemPulseEvent({
            kind: "SYSTEM_ANNOUNCEMENT",
            message: `DIAG BOUNTY CONTRACT FULFILLED BONUS GEMS ${bountyBonusGems}`,
          });
        }
        get().maybeDropRaidArtifact(q.module);
        void import("../../lib/syncController").then((m) => {
          m.uplinkArenaScore({
            score,
            missionType: run.examId,
          });
          m.recordArenaGhostRun({
            examId: run.examId,
            score,
            durationMs: elapsedMs,
            questionCount: qs.length,
            won: true,
            markAsGlobalBoss: markBossGhost,
          });
          if (bossGhostVictory && bossGhostId) {
            m.recordBossRaidLadderWin({
              bossGhostId,
              score,
              durationMs: elapsedMs,
              winnerFaction: get().careerPath,
            });
          }
          if (purgeModule) {
            m.reportNeuralPurgeContribution(purgeModule, 1);
          }
          if (sectorModule) {
            m.reportSectorInfluenceFromAnswer(sectorModule, 1);
          }
        });
        if (markBossGhost) get().setBossGhostArmed(false);
        get().registerDailyGrindActivity("arena_win", 1);
        return;
      }

      set({
        arenaRun: {
          ...run,
          examHp,
          combo: comboNext,
          questionIndex: nextIndex,
          hiddenOptionIndices: [],
        },
        arenaFeedback: "correct",
      });
      get().maybeDropRaidArtifact(q.module);
      if (duel && duel.status !== "finished") {
        const scoreLive = Math.max(0, Math.floor(comboNext * 90 + examHp * 3 + duelProgress * 100));
        get().patchDuelState({ myProgress: duelProgress, myScore: scoreLive, myElapsedMs: elapsedMs });
        if (!duel.mirrorMode) {
          void import("../../lib/syncController").then((m) =>
            m.publishDuelProgress({
              duelId: duel.duelId,
              score: scoreLive,
              progress: duelProgress,
              done: false,
            }),
          );
        }
      }
      if (purgeModule) {
        void import("../../lib/syncController").then((m) => m.reportNeuralPurgeContribution(purgeModule, 1));
      }
      if (sectorModule) {
        void import("../../lib/syncController").then((m) => m.reportSectorInfluenceFromAnswer(sectorModule, 1));
      }
      get().tryUnlockAchievements();
      return;
    }

    let userHp = run.userHp - 14;
    let shieldCharges = run.shieldCharges;
    if (shieldCharges > 0) {
      userHp = run.userHp;
      shieldCharges = 0;
    }

    const combo = 0;
    if (userHp <= 0) {
      const score = Math.max(0, Math.floor(run.combo * 70 + run.examHp * 2 + (run.questionIndex / Math.max(1, qs.length)) * 100));
      set({
        arenaRun: {
          ...run,
          userHp: 0,
          combo,
          shieldCharges,
          outcome: "lose",
        },
        arenaFeedback: "wrong",
      });
      if (duel && duel.status !== "finished") {
        if (duel.mirrorMode) {
          get().patchDuelState({
            myDone: true,
            myProgress: Math.max(0, Math.min(1, run.questionIndex / Math.max(1, qs.length))),
            myScore: score,
            myElapsedMs: elapsedMs,
            opponentDone: true,
            winnerUserId: duel.opponentUserId,
            status: "finished",
          });
        } else {
          get().patchDuelState({
            myDone: true,
            myScore: score,
            myElapsedMs: elapsedMs,
          });
          void import("../../lib/syncController").then((m) =>
            m.publishDuelProgress({
              duelId: duel.duelId,
              score,
              progress: Math.max(0, Math.min(1, run.questionIndex / Math.max(1, qs.length))),
              done: true,
            }),
          );
        }
      }
      void import("../../lib/syncController").then((m) =>
        m.recordArenaQuestionMiss({ questionId: q.id, examId: run.examId }),
      );
      void import("../../lib/syncController").then((m) =>
        m.recordArenaGhostRun({
          examId: run.examId,
          score,
          durationMs: elapsedMs,
          questionCount: qs.length,
          won: false,
        }),
      );
      get().tryUnlockAchievements();
      return;
    }

    set({
      arenaRun: {
        ...run,
        userHp,
        combo,
        shieldCharges,
      },
      arenaFeedback: "wrong",
    });
    if (duel && duel.status !== "finished") {
      const progress = Math.max(0, Math.min(1, run.questionIndex / Math.max(1, qs.length)));
      const scoreLive = Math.max(0, Math.floor(run.combo * 75 + run.examHp * 2 + progress * 100));
      get().patchDuelState({ myProgress: progress, myScore: scoreLive, myElapsedMs: elapsedMs });
      if (!duel.mirrorMode) {
        void import("../../lib/syncController").then((m) =>
          m.publishDuelProgress({
            duelId: duel.duelId,
            score: scoreLive,
            progress,
            done: false,
          }),
        );
      }
    }
    void import("../../lib/syncController").then((m) =>
      m.recordArenaQuestionMiss({ questionId: q.id, examId: run.examId }),
    );
    get().tryUnlockAchievements();
  },

  ghostModeEnabled: false,
  setGhostModeEnabled: (next) => set({ ghostModeEnabled: !!next }),
  bossGhostArmed: false,
  setBossGhostArmed: (next) => set({ bossGhostArmed: !!next }),
});
