import { DEFAULT_ACADEMY_LOCALE, academyStrings, type AcademyLocale } from "./academyStrings";
import { useAcademyStore } from "../store/academyStore";

export function useTranslation(localeOverride?: AcademyLocale) {
  const storeLocale = useAcademyStore((s) => s.locale);
  const locale = localeOverride ?? storeLocale ?? DEFAULT_ACADEMY_LOCALE;
  return academyStrings[locale] ?? academyStrings[DEFAULT_ACADEMY_LOCALE];
}
