import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { cn } from "../../lib/cn";
import { springHeavy } from "../../motion/variants";
import type { SeasonHistoryEntry } from "../../lib/syncController";
import { useAppStore } from "../../store/useAppStore";

function formatClosedAt(iso: string): string {
  const d = new Date(iso);
  if (!Number.isFinite(d.getTime())) return "Zeitstempel unbekannt";
  return d.toLocaleString("de-DE", {
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function winnerBadge(winner: SeasonHistoryEntry["winnerFaction"]): string {
  if (winner === "FISI") return "Siegerfraktion FISI";
  if (winner === "FIAE") return "Siegerfraktion FIAE";
  return "Siegerfraktion Unentschieden";
}

const RANK_STYLE: Record<1 | 2 | 3, { medal: string; frame: string; glow: string }> = {
  1: {
    medal: "PLATIN",
    frame: "border-amber-300/45 bg-amber-500/[0.08]",
    glow: "shadow-[inset_0_0_24px_rgb(251_191_36_/0.22),0_0_28px_rgb(251_191_36_/0.16)]",
  },
  2: {
    medal: "GOLD",
    frame: "border-yellow-300/40 bg-yellow-500/[0.08]",
    glow: "shadow-[inset_0_0_18px_rgb(253_224_71_/0.2),0_0_20px_rgb(253_224_71_/0.14)]",
  },
  3: {
    medal: "SILBER",
    frame: "border-slate-300/35 bg-slate-400/[0.06]",
    glow: "shadow-[inset_0_0_16px_rgb(203_213_225_/0.14),0_0_16px_rgb(203_213_225_/0.1)]",
  },
};

export function HallOfFameView() {
  const prefersReduced = useReducedMotion();
  const openPublicDossier = useAppStore((s) => s.openPublicDossier);
  const [rows, setRows] = useState<SeasonHistoryEntry[]>([]);
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    setBusy(true);
    void import("../../lib/syncController")
      .then((m) => m.fetchSeasonHistory(14))
      .then((data) => setRows(data))
      .finally(() => setBusy(false));
  }, []);

  const heroesTotal = useMemo(() => rows.reduce((acc, row) => acc + row.top.filter((x) => x.userId).length, 0), [rows]);

  return (
    <motion.div
      initial={prefersReduced ? false : { opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={springHeavy}
      className="border border-white/[0.1] bg-surface/88 p-6 sm:p-8"
    >
      <div className="mb-5 border border-amber-300/25 bg-gradient-to-r from-amber-500/[0.09] via-slate-200/[0.08] to-amber-500/[0.09] px-5 py-4 shadow-[inset_0_0_30px_rgb(255_255_255_/0.05),0_0_24px_rgb(251_191_36_/0.11)]">
        <p className="font-mono text-[10px] uppercase tracking-[0.3em] text-amber-100/85">Hall Of Fame</p>
        <h3 className="headline-cinema mt-2 text-2xl font-semibold text-amber-50 sm:text-3xl">Ewige Helden</h3>
        <p className="mt-2 font-mono text-[11px] uppercase tracking-[0.18em] text-foreground-muted">
          Saisons {rows.length} · Geehrte Operator {heroesTotal}
        </p>
      </div>

      {busy ? (
        <div className="border border-white/[0.1] px-4 py-8 font-mono text-xs uppercase tracking-[0.2em] text-foreground-muted">
          Historie wird geladen
        </div>
      ) : rows.length === 0 ? (
        <div className="border border-white/[0.1] px-4 py-8 font-mono text-xs uppercase tracking-[0.2em] text-foreground-muted">
          Noch keine abgeschlossene Saison archiviert
        </div>
      ) : (
        <div className="space-y-5">
          {rows.map((season) => (
            <section
              key={season.seasonKey}
              className="border border-white/[0.1] bg-black/40 p-4 shadow-[inset_0_0_18px_rgb(255_255_255_/0.03)] sm:p-5"
            >
              <div className="mb-4 flex flex-wrap items-center justify-between gap-2 border-b border-white/[0.08] pb-3">
                <div>
                  <p className="font-mono text-[10px] uppercase tracking-[0.26em] text-foreground-muted">{season.seasonLabel}</p>
                  <p className="mt-1 font-mono text-[11px] uppercase tracking-[0.2em] text-amber-100/80">
                    {winnerBadge(season.winnerFaction)}
                  </p>
                </div>
                <div className="text-right font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
                  <p>Abschluss {formatClosedAt(season.closedAt)}</p>
                  <p>
                    FISI {season.fisiTotalXp} · FIAE {season.fiaeTotalXp}
                  </p>
                </div>
              </div>

              <div className="grid gap-3 sm:grid-cols-3">
                {season.top.map((hero) => {
                  const style = RANK_STYLE[hero.rank];
                  const canOpen = !!hero.userId;
                  return (
                    <motion.button
                      key={`${season.seasonKey}-${hero.rank}-${hero.userId ?? "void"}`}
                      type="button"
                      whileTap={{ scale: 0.97, y: 2 }}
                      transition={springHeavy}
                      disabled={!canOpen}
                      onClick={() => {
                        if (!hero.userId) return;
                        openPublicDossier(hero.userId, hero.handle);
                      }}
                      className={cn(
                        "border p-4 text-left",
                        style.frame,
                        style.glow,
                        canOpen ? "hover-breathe" : "cursor-default opacity-85",
                      )}
                    >
                      <p className="font-mono text-[10px] font-bold uppercase tracking-[0.24em] text-foreground-muted">
                        Platz {hero.rank} · {style.medal}
                      </p>
                      <p className="mt-3 truncate font-sans text-lg font-semibold tracking-[-0.03em] text-foreground">
                        {hero.handle}
                      </p>
                      <p className="mt-1 font-mono text-[11px] uppercase tracking-[0.2em] text-foreground-muted">
                        Score {hero.score}
                      </p>
                    </motion.button>
                  );
                })}
              </div>
            </section>
          ))}
        </div>
      )}
    </motion.div>
  );
}
