import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useMemo, useState } from "react";
import { useAppStore } from "../../store/useAppStore";

type WelcomeStep = {
  key: string;
  title: string;
  line: string;
  accent: string;
};

const STEPS: WelcomeStep[] = [
  {
    key: "intro",
    title: "Welcome to the Nexus",
    line: "Dein Operator-Profil ist online und der globale Datenstrom ist stabilisiert",
    accent: "from-cyan-400/28 via-cyan-300/12 to-transparent",
  },
  {
    key: "factions",
    title: "Faction Protocol",
    line: "FISI kontrolliert Infrastruktur FIAE kontrolliert Code beides speist den War-Core",
    accent: "from-fuchsia-400/24 via-cyan-300/10 to-transparent",
  },
  {
    key: "void",
    title: "V O I D Core Sync",
    line: "Der Core reagiert auf globale Friktion Overdrive und deine Eingaben im Command Deck",
    accent: "from-amber-300/26 via-fuchsia-300/12 to-transparent",
  },
];

export function WelcomeProtocol() {
  const prefersReduced = !!useReducedMotion();
  const welcomeProtocolSeen = useAppStore((s) => s.welcomeProtocolSeen);
  const completeWelcomeProtocol = useAppStore((s) => s.completeWelcomeProtocol);
  const setActiveSection = useAppStore((s) => s.setActiveSection);
  const [stepIdx, setStepIdx] = useState(0);

  const step = STEPS[stepIdx] ?? STEPS[0];
  const progress = useMemo(() => Math.round(((stepIdx + 1) / STEPS.length) * 100), [stepIdx]);

  if (welcomeProtocolSeen) return null;

  return (
    <AnimatePresence>
      <motion.div
        key="welcome-protocol"
        className="fixed inset-0 z-[380] overflow-hidden bg-black/94"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
      >
        <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.08]" />
        <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.22]" />
        <div className={`pointer-events-none absolute inset-0 bg-gradient-to-br ${step.accent}`} />

        <div className="relative mx-auto flex min-h-dvh w-full max-w-4xl items-center justify-center px-6 py-10">
          <motion.section
            initial={prefersReduced ? false : { opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: prefersReduced ? 0 : 0.24, ease: [0.22, 1, 0.36, 1] }}
            className="w-full border border-cyan-200/28 bg-black/72 p-6 shadow-[0_0_36px_rgb(34_211_238/0.14)] sm:p-8"
          >
            <p className="font-mono text-[10px] uppercase tracking-[0.34em] text-cyan-200/88">Global Vanguard</p>
            <h2 className="mt-3 headline-cinema text-4xl font-semibold text-cyan-50 sm:text-6xl">{step.title}</h2>
            <p className="mt-4 max-w-2xl font-sans text-sm leading-relaxed text-cyan-100/84 sm:text-base">{step.line}</p>

            <div className="mt-6">
              <div className="h-2 overflow-hidden border border-cyan-200/24 bg-black/60">
                <motion.div
                  className="h-full bg-gradient-to-r from-cyan-300 via-fuchsia-300 to-cyan-200"
                  animate={{ width: `${progress}%` }}
                  transition={{ duration: prefersReduced ? 0 : 0.28, ease: "easeOut" }}
                />
              </div>
              <p className="mt-1 font-mono text-[9px] uppercase tracking-[0.16em] text-cyan-100/72">
                Step {stepIdx + 1} von {STEPS.length}
              </p>
            </div>

            <div className="mt-7 flex flex-wrap gap-2">
              <button
                type="button"
                onClick={() => {
                  if (stepIdx <= 0) return;
                  setStepIdx((v) => Math.max(0, v - 1));
                }}
                className="border border-cyan-300/32 bg-cyan-500/10 px-3 py-1.5 font-mono text-[10px] uppercase tracking-[0.16em] text-cyan-100 hover:bg-cyan-500/20"
              >
                Zurück
              </button>
              <button
                type="button"
                onClick={() => {
                  if (stepIdx < STEPS.length - 1) {
                    setStepIdx((v) => Math.min(STEPS.length - 1, v + 1));
                    return;
                  }
                  completeWelcomeProtocol();
                  setActiveSection("command");
                }}
                className="border border-fuchsia-300/45 bg-fuchsia-500/18 px-3 py-1.5 font-mono text-[10px] font-bold uppercase tracking-[0.16em] text-fuchsia-100 hover:bg-fuchsia-500/28"
              >
                {stepIdx < STEPS.length - 1 ? "Weiter" : "Enter Command Deck"}
              </button>
              <button
                type="button"
                onClick={() => {
                  completeWelcomeProtocol();
                  setActiveSection("command");
                }}
                className="border border-white/20 bg-white/5 px-3 py-1.5 font-mono text-[10px] uppercase tracking-[0.16em] text-white/85 hover:bg-white/10"
              >
                Überspringen
              </button>
            </div>
          </motion.section>
        </div>
      </motion.div>
    </AnimatePresence>
  );
}
