import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useAppStore } from "../../store/useAppStore";

export function LevelUpOverlay() {
  const activeNotification = useAppStore((s) => s.activeNotification);
  const dismissLevelUp = useAppStore((s) => s.dismissLevelUp);
  const prefersReduced = useReducedMotion();
  const active = activeNotification?.kind === "level_up" ? activeNotification : null;

  return (
    <AnimatePresence>
      {active ? (
        <motion.div
          key={active.id}
          data-print-hide
          role="dialog"
          aria-modal="true"
          aria-labelledby="level-up-title"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[130] grid place-items-center bg-[#030611]/90 px-4 backdrop-blur-xl"
          onClick={dismissLevelUp}
        >
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-40" />
          <div
            className="pointer-events-none absolute inset-0"
            style={{
              background:
                "repeating-linear-gradient(180deg, rgba(34,211,238,0.06) 0px, rgba(34,211,238,0.06) 1px, transparent 2px, transparent 4px)",
            }}
          />

          <motion.div
            initial={{ y: 36, opacity: 0, scale: 0.92 }}
            animate={{ y: 0, opacity: 1, scale: 1 }}
            exit={{ y: 20, opacity: 0, scale: 0.96 }}
            transition={
              prefersReduced
                ? { duration: 0.1 }
                : { type: "spring", stiffness: 240, damping: 24, mass: 0.9 }
            }
            onClick={(event) => event.stopPropagation()}
            className="relative w-full max-w-2xl overflow-hidden rounded-3xl border border-cyan-400/40 bg-[#050b1b]/90 p-8 ring-1 ring-fuchsia-400/35 md:p-10"
          >
            <div className="pointer-events-none absolute -inset-28 bg-[radial-gradient(circle_at_25%_20%,rgba(34,211,238,0.22),transparent_55%),radial-gradient(circle_at_80%_15%,rgba(217,70,239,0.24),transparent_48%)]" />

            <div className="relative space-y-6 text-center">
              <motion.p
                initial={{ opacity: 0, letterSpacing: "0.5em" }}
                animate={{ opacity: 1, letterSpacing: "0.36em" }}
                className="font-mono text-[11px] font-semibold uppercase text-cyan-200/90"
              >
                Nexus Progress Signal
              </motion.p>

              <motion.h2
                id="level-up-title"
                initial={{ opacity: 0 }}
                animate={
                  prefersReduced
                    ? { opacity: 1 }
                    : {
                        opacity: [1, 0.72, 1, 0.86, 1],
                        x: [0, -1, 2, -2, 0],
                      }
                }
                transition={{ duration: 0.45, repeat: prefersReduced ? 0 : 5, repeatDelay: 0.22 }}
                className="font-display text-5xl font-black uppercase tracking-[0.14em] text-transparent sm:text-6xl"
                style={{
                  backgroundImage: "linear-gradient(90deg, rgb(34 211 238) 0%, rgb(217 70 239) 45%, rgb(99 102 241) 100%)",
                  WebkitBackgroundClip: "text",
                  backgroundClip: "text",
                  textShadow: "0 0 26px rgba(34,211,238,0.36), 0 0 34px rgba(217,70,239,0.28)",
                }}
              >
                Level Up
              </motion.h2>

              <div className="mx-auto grid max-w-xl gap-3 md:grid-cols-3">
                <div className="rounded-2xl border border-cyan-300/35 bg-black/35 p-3">
                  <p className="font-mono text-[10px] uppercase tracking-[0.26em] text-cyan-200/70">From</p>
                  <p className="mt-1 font-display text-3xl font-bold text-cyan-100">{active.fromLevel}</p>
                </div>
                <div className="rounded-2xl border border-fuchsia-300/35 bg-black/35 p-3">
                  <p className="font-mono text-[10px] uppercase tracking-[0.26em] text-fuchsia-200/75">To</p>
                  <p className="mt-1 font-display text-3xl font-bold text-fuchsia-100">{active.level}</p>
                </div>
                <div className="rounded-2xl border border-indigo-300/35 bg-black/35 p-3">
                  <p className="font-mono text-[10px] uppercase tracking-[0.26em] text-indigo-200/75">Skill Points</p>
                  <p className="mt-1 font-display text-3xl font-bold text-indigo-100">+{active.skillPointsGained}</p>
                </div>
              </div>

              <div className="mx-auto h-2 w-full max-w-xl overflow-hidden rounded-full border border-cyan-300/30 bg-black/40">
                <motion.div
                  initial={{ width: "0%" }}
                  animate={{ width: "100%" }}
                  transition={{ duration: prefersReduced ? 0.12 : 2.4, ease: "easeOut" }}
                  className="h-full bg-[linear-gradient(90deg,rgba(34,211,238,0.95),rgba(217,70,239,0.95),rgba(99,102,241,0.95))]"
                />
              </div>

              <motion.button
                type="button"
                whileTap={{ scale: 0.97 }}
                onClick={dismissLevelUp}
                className="mx-auto mt-2 inline-flex min-w-52 items-center justify-center rounded-2xl border border-cyan-300/50 bg-[linear-gradient(180deg,rgba(34,211,238,0.22),rgba(217,70,239,0.12))] px-6 py-3 font-mono text-xs font-semibold uppercase tracking-[0.24em] text-cyan-50 ring-1 ring-cyan-200/35"
              >
                Continue
              </motion.button>
            </div>
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}
