import { useEffect, useRef } from "react";
import { useAppStore } from "../store/useAppStore";

/**
 * Keeps overlay triggers resilient when levels change outside award flow
 * and auto-dismisses active queue entry after animation window
 */
export function useLevelUpOverlayTrigger(): void {
  const currentLevel = useAppStore((s) => s.currentLevel);
  const pendingLevelUps = useAppStore((s) => s.pendingLevelUps);
  const activeNotification = useAppStore((s) => s.activeNotification);
  const enqueueLevelUpNotice = useAppStore((s) => s.enqueueLevelUpNotice);
  const dismissLevelUp = useAppStore((s) => s.dismissLevelUp);
  const prevLevelRef = useRef(currentLevel);

  useEffect(() => {
    const prev = prevLevelRef.current;
    if (currentLevel > prev) {
      const hasCurrentQueued = pendingLevelUps.some((entry) => entry.level === currentLevel && entry.fromLevel === prev);
      if (!hasCurrentQueued) {
        enqueueLevelUpNotice({
          level: currentLevel,
          fromLevel: prev,
          gemsGained: 0,
          skillPointsGained: Math.max(0, currentLevel - prev),
        });
      }
    }
    prevLevelRef.current = currentLevel;
  }, [currentLevel, pendingLevelUps, enqueueLevelUpNotice]);

  useEffect(() => {
    if (!activeNotification || activeNotification.kind !== "level_up") return;
    const timer = window.setTimeout(() => dismissLevelUp(), 3800);
    return () => window.clearTimeout(timer);
  }, [activeNotification, dismissLevelUp]);
}
