import { useCallback, useMemo } from "react";
import { computeHexLayout, realmHexCoordinates, tileKey } from "../../lib/hexLayout";
import { useAppStore } from "../../store/useAppStore";
import type { RealmFactionId } from "../../types/faction";
import { HexCell } from "./HexCell";

const HEX_SIZE = 26;

export function HexGridBoard() {
  const realmTiles = useAppStore((s) => s.realmTiles);
  const selectedFaction = useAppStore((s) => s.selectedFaction);
  const faction: RealmFactionId = selectedFaction ?? "humans";

  const { hexes, boxW, boxH } = useMemo(
    () => computeHexLayout(realmHexCoordinates(), HEX_SIZE),
    [],
  );

  const onPress = useCallback((q: number, r: number) => {
    useAppStore.getState().tryOpenRealmBuildMenu(q, r);
  }, []);

  return (
    <div
      className="relative mx-auto mt-24 w-full max-w-4xl overflow-visible rounded-3xl border border-border-glass bg-surface/40 p-4 sm:mt-28 sm:p-6"
      style={{ minHeight: boxH + 48 }}
    >
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-15" />
      <div
        className="relative mx-auto"
        style={{ width: boxW, height: boxH, maxWidth: "100%" }}
      >
        {hexes.map(({ q, r, px, py }) => {
          const key = tileKey(q, r);
          const tile = realmTiles[key] ?? { structure: "empty" as const };
          return (
            <HexCell
              key={key}
              q={q}
              r={r}
              structure={tile.structure}
              faction={faction}
              pixelLeft={px}
              pixelTop={py}
              cellSizePx={HEX_SIZE}
              onPress={onPress}
            />
          );
        })}
      </div>
    </div>
  );
}
