/**
 * Phase 52 — globale Live-Events (UTC-Fenster, Server-validiert)
 * UI-Kopien ohne Satzzeichen am Ende
 */

export type GlobalEventId = "HAPPY_HOUR" | "FACTION_FRENZY";

export type GlobalEventWindowUtc = {
  /** Inklusiver Start [Minuten seit Mitternacht UTC 0..1440) */
  startMinuteUtc: number;
  /** Exklusives Ende (gleicher Kalendertag UTC, start < end) */
  endMinuteUtc: number;
};

export type GlobalEventDefinition = {
  id: GlobalEventId;
  /** Header — kurz, fett */
  headlineShort: string;
  /** Unterzeile im Header */
  tagline: string;
  /** System-Pulse Zeile */
  pulseLine: string;
  xpMultiplier: number;
  factionPointsMultiplier: number;
  window: GlobalEventWindowUtc;
};

/** Höhere Priorität zuerst bei Überlappung */
export const GLOBAL_EVENT_PRIORITY: readonly GlobalEventId[] = ["FACTION_FRENZY", "HAPPY_HOUR"];

export const GLOBAL_EVENTS: Record<GlobalEventId, GlobalEventDefinition> = {
  HAPPY_HOUR: {
    id: "HAPPY_HOUR",
    headlineShort: "HAPPY HOUR",
    tagline: "XP x1.5",
    pulseLine: "GLOBAL LIVE · HAPPY HOUR · XP x1.5",
    xpMultiplier: 1.5,
    factionPointsMultiplier: 1,
    window: { startMinuteUtc: 16 * 60, endMinuteUtc: 17 * 60 },
  },
  FACTION_FRENZY: {
    id: "FACTION_FRENZY",
    headlineShort: "FACTION FRENZY",
    tagline: "Doppelte Fraktionspunkte",
    pulseLine: "GLOBAL LIVE · FACTION FRENZY · DOPPELTE FRAKTIONSPUNKTE",
    xpMultiplier: 1,
    factionPointsMultiplier: 2,
    window: { startMinuteUtc: 18 * 60, endMinuteUtc: 18 * 60 + 30 },
  },
};
