import type { StateCreator } from "zustand";
import { buildSqlAcademyChapters } from "../../data/factories/sqlContentFactory";
import type { SqlUniverseId } from "../../data/universes";
import { verifySqlQuery } from "../../lib/utils/sqlVerifier";
import type { AppState } from "../useAppStore";

const SQL_REALM_STORAGE_KEY = "codesnap-realm-sql";

type SqlRealmPersisted = {
  selectedUniverseId: SqlUniverseId;
  activeChapterId: string;
  unlockedChapters: string[];
  taskCompletion: Record<string, boolean>;
};

function defaultSqlRealmState(): SqlRealmPersisted {
  const chapters = buildSqlAcademyChapters("star_wars");
  return {
    selectedUniverseId: "star_wars",
    activeChapterId: chapters[0]?.id ?? "chapter-01",
    unlockedChapters: [chapters[0]?.id ?? "chapter-01"],
    taskCompletion: {},
  };
}

function readSqlRealmPersisted(): SqlRealmPersisted {
  if (typeof window === "undefined") return defaultSqlRealmState();
  try {
    const raw = window.localStorage.getItem(SQL_REALM_STORAGE_KEY);
    if (!raw) return defaultSqlRealmState();
    const parsed = JSON.parse(raw) as Partial<SqlRealmPersisted>;
    const fallback = defaultSqlRealmState();
    const selectedUniverseId =
      parsed.selectedUniverseId &&
      (parsed.selectedUniverseId === "star_wars" ||
        parsed.selectedUniverseId === "nutrition" ||
        parsed.selectedUniverseId === "cs_tactical" ||
        parsed.selectedUniverseId === "anime" ||
        parsed.selectedUniverseId === "warzone" ||
        parsed.selectedUniverseId === "wow" ||
        parsed.selectedUniverseId === "bodybuilding")
        ? parsed.selectedUniverseId
        : fallback.selectedUniverseId;
    const activeChapterId = typeof parsed.activeChapterId === "string" ? parsed.activeChapterId : fallback.activeChapterId;
    const unlockedChapters = Array.isArray(parsed.unlockedChapters)
      ? parsed.unlockedChapters.filter((x): x is string => typeof x === "string")
      : fallback.unlockedChapters;
    const taskCompletion =
      parsed.taskCompletion && typeof parsed.taskCompletion === "object"
        ? Object.fromEntries(
            Object.entries(parsed.taskCompletion).filter(
              (entry): entry is [string, boolean] => typeof entry[0] === "string" && typeof entry[1] === "boolean",
            ),
          )
        : fallback.taskCompletion;
    return {
      selectedUniverseId,
      activeChapterId,
      unlockedChapters: unlockedChapters.length > 0 ? unlockedChapters : fallback.unlockedChapters,
      taskCompletion,
    };
  } catch {
    return defaultSqlRealmState();
  }
}

function writeSqlRealmPersisted(input: SqlRealmPersisted): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(SQL_REALM_STORAGE_KEY, JSON.stringify(input));
  } catch {
    /* private mode */
  }
}

export interface SqlSlice {
  selectedUniverseId: SqlUniverseId;
  activeChapterId: string;
  unlockedChapters: string[];
  taskCompletion: Record<string, boolean>;
  setSelectedUniverseId: (universeId: SqlUniverseId) => void;
  setActiveChapterId: (chapterId: string) => void;
  unlockChapter: (chapterId: string) => void;
  markSqlTaskCompleted: (taskId: string, completed?: boolean) => void;
  completeSqlExerciseWithVerification: (taskId: string, userSql: string, solutionSql: string) => boolean;
}

export const createSqlSlice: StateCreator<AppState, [], [], SqlSlice> = (set, get) => {
  const persisted = readSqlRealmPersisted();
  return {
    selectedUniverseId: persisted.selectedUniverseId,
    activeChapterId: persisted.activeChapterId,
    unlockedChapters: persisted.unlockedChapters,
    taskCompletion: persisted.taskCompletion,
    setSelectedUniverseId: (universeId) =>
      set(() => {
        const chapters = buildSqlAcademyChapters(universeId);
        const firstChapterId = chapters[0]?.id ?? "chapter-01";
        const next = {
          selectedUniverseId: universeId,
          activeChapterId: firstChapterId,
          unlockedChapters: [firstChapterId],
          taskCompletion: {},
        };
        writeSqlRealmPersisted(next);
        return next;
      }),
    setActiveChapterId: (chapterId) =>
      set((s) => {
        const next = {
          selectedUniverseId: s.selectedUniverseId,
          activeChapterId: chapterId,
          unlockedChapters: s.unlockedChapters,
          taskCompletion: s.taskCompletion,
        };
        writeSqlRealmPersisted(next);
        return { activeChapterId: chapterId };
      }),
    unlockChapter: (chapterId) =>
      set((s) => {
        if (s.unlockedChapters.includes(chapterId)) return {};
        const unlocked = [...s.unlockedChapters, chapterId];
        writeSqlRealmPersisted({
          selectedUniverseId: s.selectedUniverseId,
          activeChapterId: s.activeChapterId,
          unlockedChapters: unlocked,
          taskCompletion: s.taskCompletion,
        });
        return { unlockedChapters: unlocked };
      }),
    markSqlTaskCompleted: (taskId, completed = true) =>
      set((s) => {
        const taskCompletion = { ...s.taskCompletion, [taskId]: completed };
        writeSqlRealmPersisted({
          selectedUniverseId: s.selectedUniverseId,
          activeChapterId: s.activeChapterId,
          unlockedChapters: s.unlockedChapters,
          taskCompletion,
        });
        return { taskCompletion };
      }),
    completeSqlExerciseWithVerification: (taskId, userSql, solutionSql) => {
      const isValid = verifySqlQuery(userSql, solutionSql);
      if (!isValid) return false;
      set((s) => {
        const taskCompletion = { ...s.taskCompletion, [taskId]: true };
        writeSqlRealmPersisted({
          selectedUniverseId: s.selectedUniverseId,
          activeChapterId: s.activeChapterId,
          unlockedChapters: s.unlockedChapters,
          taskCompletion,
        });
        return { taskCompletion };
      });
      get().addXp(26, { module: "databases" });
      return true;
    },
  };
};
