import type { StateCreator } from "zustand";
import type { LinkPulseStatus } from "../../lib/connectivity";
import { getAuthEmailRedirectUrl } from "../../lib/siteUrl";
import { getSupabase } from "../../lib/supabase";
import type { AppState, AuthUserBrief, CloudSyncStatus } from "../useAppStore";
import {
  fetchVaultFromCloud,
  hydrateCloudSessionState,
  hydrateQuestionBankOnly,
  pushVaultToCloud,
} from "../../lib/services/syncService";

let __cloudAuthListenerBound = false;

export interface AuthSlice {
  authUser: AuthUserBrief | null;
  authReady: boolean;
  syncStatus: CloudSyncStatus;
  linkPulseStatus: LinkPulseStatus;
  swNeedRefresh: boolean;
  setSwNeedRefresh: (next: boolean) => void;
  cloudUplinkBusy: boolean;
  cloudAuthPending: boolean;
  cloudLastError: string | null;
  cloudRestoreNotice: string | null;
  initCloudAuth: () => void;
  signInWithEmail: (email: string, password: string) => Promise<{ ok: boolean; error?: string }>;
  signUpWithEmail: (email: string, password: string) => Promise<{ ok: boolean; error?: string }>;
  signOutCloud: () => Promise<void>;
  pushToCloud: () => Promise<boolean>;
  fetchFromCloud: () => Promise<boolean>;
}

export const createAuthSlice: StateCreator<AppState, [], [], AuthSlice> = (set, get) => ({
  authUser: null,
  authReady: false,
  syncStatus: "offline" as CloudSyncStatus,
  linkPulseStatus: "online",
  swNeedRefresh: false,
  setSwNeedRefresh: (next) => set({ swNeedRefresh: next }),
  cloudUplinkBusy: false,
  cloudAuthPending: false,
  cloudLastError: null,
  cloudRestoreNotice: null,

  initCloudAuth: () => {
    const sb = getSupabase();
    if (!sb) {
      void hydrateQuestionBankOnly();
      set({
        authReady: true,
        authUser: null,
        syncStatus: "offline",
        cloudUplinkBusy: false,
        cloudAuthPending: false,
        cloudRestoreNotice: null,
        onboardingVisible: false,
      });
      return;
    }
    void sb.auth
      .getSession()
      .then(({ data: { session } }) => {
        void hydrateQuestionBankOnly();
        set({
          authUser: session?.user
            ? { id: session.user.id, email: session.user.email ?? null }
            : null,
          authReady: true,
          syncStatus: session?.user ? "cloud-outdated" : "offline",
          cloudAuthPending: false,
        });
        if (session?.user) {
          void hydrateCloudSessionState();
        }
      })
      .catch(() => {
        set({
          authReady: true,
          authUser: null,
          syncStatus: "offline",
          cloudAuthPending: false,
          cloudRestoreNotice: null,
          onboardingVisible: false,
        });
      });
    if (!__cloudAuthListenerBound) {
      __cloudAuthListenerBound = true;
      sb.auth.onAuthStateChange((_event, session) => {
        set({
          authUser: session?.user
            ? { id: session.user.id, email: session.user.email ?? null }
            : null,
          syncStatus: session?.user ? "cloud-outdated" : "offline",
          cloudUplinkBusy: false,
          cloudAuthPending: false,
        });
        void hydrateQuestionBankOnly();
        if (session?.user) {
          void hydrateCloudSessionState();
        } else {
          set({
            isAdmin: false,
            activeEventModifier: null,
            ghostModeEnabled: false,
            syndicateRuntimeBuffs: {
              syndicateId: null,
              role: null,
              unlockedNodeIds: [],
              xpMultiplier: 1,
              timeBonusSec: 0,
              dropRateBonus: 0,
            },
            councilRuntime: {
              active: false,
              proposalId: null,
              targetModule: null,
              xpBoostMultiplier: 1,
              dropScaleDelta: 0,
              label: "",
              expiresAt: null,
            },
            legacyPoints: 0,
            legacyTranscendCount: 0,
            legacyXpBoostMultiplier: 1,
            singularitySequence: {
              active: false,
              seasonTag: "",
              gainedLegacyPoints: 0,
            },
            duelInbox: [],
            duelState: null,
            onboardingVisible: false,
            onboardingCompleted: false,
            onboardingStep: "boot",
            onboardingHandleDraft: "",
            careerPath: null,
          });
        }
      });
    }
  },

  signInWithEmail: async (email, password) => {
    const sb = getSupabase();
    if (!sb) return { ok: false, error: "Uplink nicht konfiguriert" };
    set({ cloudAuthPending: true, cloudLastError: null });
    try {
      const { error } = await sb.auth.signInWithPassword({
        email: email.trim(),
        password,
      });
      if (error) return { ok: false, error: error.message };
      return { ok: true };
    } finally {
      set({ cloudAuthPending: false });
    }
  },

  signUpWithEmail: async (email, password) => {
    const sb = getSupabase();
    if (!sb) return { ok: false, error: "Uplink nicht konfiguriert" };
    set({ cloudAuthPending: true, cloudLastError: null });
    try {
      const { error } = await sb.auth.signUp({
        email: email.trim(),
        password,
        options: { emailRedirectTo: getAuthEmailRedirectUrl() },
      });
      if (error) return { ok: false, error: error.message };
      return { ok: true };
    } finally {
      set({ cloudAuthPending: false });
    }
  },

  signOutCloud: async () => {
    const sb = getSupabase();
    if (sb) await sb.auth.signOut();
    set({
      authUser: null,
      syncStatus: "offline",
      cloudLastError: null,
      cloudUplinkBusy: false,
      cloudAuthPending: false,
      cloudRestoreNotice: null,
      ammoDropImportFeed: [],
      systemPulse: [],
      activeEventModifier: null,
      nexusActivity: [],
      globalLore: { totalGlobalXp: 0, unlockedLoreIds: [] },
      globalFrictionAvg: 0,
      neuralOutbreak: {
        infected: false,
        outbreakId: null,
        module: null,
        progress: 0,
        target: 0,
        hotZoneBossId: null,
      },
      claimedOutbreakRewardIds: [],
      syndicateRuntimeBuffs: {
        syndicateId: null,
        role: null,
        unlockedNodeIds: [],
        xpMultiplier: 1,
        timeBonusSec: 0,
        dropRateBonus: 0,
      },
      councilRuntime: {
        active: false,
        proposalId: null,
        targetModule: null,
        xpBoostMultiplier: 1,
        dropScaleDelta: 0,
        label: "",
        expiresAt: null,
      },
      duelInbox: [],
      duelState: null,
      bossGhostArmed: false,
      factionWarPulseKey: null,
      isAdmin: false,
      ghostModeEnabled: false,
      onboardingVisible: false,
      onboardingCompleted: false,
      onboardingStep: "boot",
      onboardingHandleDraft: "",
      careerPath: null,
      operatorWelcomePulseEmitted: false,
      welcomeProtocolSeen: true,
      linkPulseStatus: "online",
      serverTimeOffsetMs: 0,
      globalLiveEvent: null,
      launchPulse: {
        active: false,
        xpMultiplier: 1,
        startsAtMs: 0,
        endsAtMs: 0,
        message: "WELCOME TO THE NEXUS",
      },
      swNeedRefresh: false,
      mockExam: null,
    });
  },

  pushToCloud: async () => {
    const sb = getSupabase();
    const user = get().authUser;
    if (!sb || !user) {
      set({ syncStatus: "offline", cloudLastError: null });
      return false;
    }
    set({ cloudUplinkBusy: true, cloudLastError: null });
    const pushed = await pushVaultToCloud(user.id, () => get());
    if (!pushed.ok) {
      set({
        cloudUplinkBusy: false,
        syncStatus: "cloud-outdated",
        cloudLastError: pushed.error ?? "Cloud Push fehlgeschlagen",
      });
      return false;
    }
    set({ cloudUplinkBusy: false, syncStatus: "cloud-synced", cloudLastError: null });
    return true;
  },

  fetchFromCloud: async () => {
    const sb = getSupabase();
    const user = get().authUser;
    if (!sb || !user) return false;
    set({ cloudUplinkBusy: true, cloudLastError: null });
    const pulled = await fetchVaultFromCloud(user.id);
    set({ cloudUplinkBusy: false });
    if (!pulled.ok) {
      set({ cloudLastError: pulled.error ?? "Cloud Pull fehlgeschlagen", syncStatus: "cloud-outdated" });
      return false;
    }
    if (!pulled.didImport) {
      set({ syncStatus: "cloud-synced", cloudLastError: null });
      return true;
    }
    set({ syncStatus: "cloud-synced", cloudLastError: null });
    void Promise.resolve().then(() => {
      window.location.reload();
    });
    return true;
  },
});
