/**
 * UI-Sounds per Web Audio API — keine externen Assets, geringe Latenz
 * Phase 68: zentraler Cue-Player mit Kompressor und Ambient-Terminal-Hum
 */

import { AUDIO_MANIFEST, type AudioCueId } from "../data/audioManifest";

let ctx: AudioContext | null = null;
let masterGain: GainNode | null = null;
let limiter: DynamicsCompressorNode | null = null;
let ambientNodes:
  | {
      osc: OscillatorNode;
      noise: AudioBufferSourceNode;
      lfo: OscillatorNode;
      lfoGain: GainNode;
      gain: GainNode;
    }
  | null = null;
let hotZoneNodes:
  | {
      noise: AudioBufferSourceNode;
      bp: BiquadFilterNode;
      gain: GainNode;
      lfo: OscillatorNode;
      lfoGain: GainNode;
    }
  | null = null;
const lastCueAt = new Map<AudioCueId, number>();

export function getAudioRuntimeHealth(): {
  contextState: "none" | AudioContextState;
  ambientActive: boolean;
  hotZoneStaticActive: boolean;
  masterReady: boolean;
} {
  return {
    contextState: ctx ? ctx.state : "none",
    ambientActive: !!ambientNodes,
    hotZoneStaticActive: !!hotZoneNodes,
    masterReady: !!masterGain && !!limiter,
  };
}

function getCtx(): AudioContext | null {
  if (typeof window === "undefined") return null;
  if (!ctx) {
    try {
      ctx = new AudioContext({ latencyHint: "interactive" });
    } catch {
      return null;
    }
  }
  if (!masterGain || !limiter) {
    masterGain = ctx.createGain();
    limiter = ctx.createDynamicsCompressor();
    limiter.threshold.value = -12;
    limiter.knee.value = 10;
    limiter.ratio.value = 8;
    limiter.attack.value = 0.003;
    limiter.release.value = 0.18;
    masterGain.gain.value = 0.74;
    masterGain.connect(limiter);
    limiter.connect(ctx.destination);
  }
  return ctx;
}

export function resumeAudioContext(): void {
  const c = getCtx();
  if (c && c.state === "suspended") void c.resume();
}

function connectDest(node: AudioNode, c: AudioContext): void {
  if (!masterGain) getCtx();
  if (masterGain) node.connect(masterGain);
  else node.connect(c.destination);
}

function canPlayCue(id: AudioCueId): boolean {
  const def = AUDIO_MANIFEST[id];
  const now = performance.now();
  const prev = lastCueAt.get(id) ?? 0;
  if (now - prev < def.cooldownMs) return false;
  lastCueAt.set(id, now);
  return true;
}

function withCueGain(c: AudioContext, id: AudioCueId): GainNode {
  const g = c.createGain();
  g.gain.value = AUDIO_MANIFEST[id].gain;
  return g;
}

function playCueClick(c: AudioContext): void {
  const t = c.currentTime;
  const osc = c.createOscillator();
  const g = withCueGain(c, "CLICK");
  const env = c.createGain();
  osc.type = "sine";
  osc.frequency.setValueAtTime(2050, t);
  osc.frequency.exponentialRampToValueAtTime(1180, t + 0.03);
  env.gain.setValueAtTime(0.0001, t);
  env.gain.exponentialRampToValueAtTime(1, t + 0.004);
  env.gain.exponentialRampToValueAtTime(0.0001, t + 0.05);
  osc.connect(env);
  env.connect(g);
  connectDest(g, c);
  osc.start(t);
  osc.stop(t + 0.055);
}

function playCueHover(c: AudioContext): void {
  const t = c.currentTime;
  const osc = c.createOscillator();
  const g = withCueGain(c, "HOVER");
  const env = c.createGain();
  osc.type = "triangle";
  osc.frequency.setValueAtTime(760, t);
  osc.frequency.exponentialRampToValueAtTime(980, t + 0.05);
  env.gain.setValueAtTime(0.0001, t);
  env.gain.exponentialRampToValueAtTime(0.5, t + 0.01);
  env.gain.exponentialRampToValueAtTime(0.0001, t + 0.07);
  osc.connect(env);
  env.connect(g);
  connectDest(g, c);
  osc.start(t);
  osc.stop(t + 0.08);
}

function playCueLevelUp(c: AudioContext): void {
  const t = c.currentTime;
  const notes = [392, 523.25, 659.25, 783.99];
  notes.forEach((hz, i) => {
    const osc = c.createOscillator();
    const env = c.createGain();
    const g = withCueGain(c, "LEVEL_UP");
    const st = t + i * 0.05;
    osc.type = "triangle";
    osc.frequency.setValueAtTime(hz, st);
    env.gain.setValueAtTime(0.0001, st);
    env.gain.exponentialRampToValueAtTime(0.62, st + 0.016);
    env.gain.exponentialRampToValueAtTime(0.0001, st + 0.14);
    osc.connect(env);
    env.connect(g);
    connectDest(g, c);
    osc.start(st);
    osc.stop(st + 0.16);
  });
}

function playCueWarPulse(c: AudioContext): void {
  const t = c.currentTime;
  const osc = c.createOscillator();
  const lp = c.createBiquadFilter();
  const env = c.createGain();
  const g = withCueGain(c, "WAR_PULSE");
  osc.type = "sawtooth";
  osc.frequency.setValueAtTime(86, t);
  osc.frequency.exponentialRampToValueAtTime(52, t + 0.28);
  lp.type = "lowpass";
  lp.frequency.setValueAtTime(220, t);
  lp.frequency.exponentialRampToValueAtTime(130, t + 0.28);
  env.gain.setValueAtTime(0.0001, t);
  env.gain.exponentialRampToValueAtTime(0.7, t + 0.04);
  env.gain.exponentialRampToValueAtTime(0.0001, t + 0.32);
  osc.connect(lp);
  lp.connect(env);
  env.connect(g);
  connectDest(g, c);
  osc.start(t);
  osc.stop(t + 0.34);
}

function playCueWhir(c: AudioContext): void {
  const t = c.currentTime;
  const dur = 0.13;
  const n = Math.floor(c.sampleRate * dur);
  const buf = c.createBuffer(1, n, c.sampleRate);
  const ch = buf.getChannelData(0);
  for (let i = 0; i < n; i += 1) {
    const x = i / n;
    const env = (1 - x) * (1 - x);
    ch[i] = (Math.random() * 2 - 1) * env;
  }
  const src = c.createBufferSource();
  src.buffer = buf;
  const bp = c.createBiquadFilter();
  bp.type = "bandpass";
  bp.Q.value = 1.1;
  bp.frequency.setValueAtTime(700, t);
  bp.frequency.exponentialRampToValueAtTime(3600, t + dur);
  const env = c.createGain();
  const g = withCueGain(c, "WHIR");
  env.gain.setValueAtTime(0.0001, t);
  env.gain.exponentialRampToValueAtTime(0.9, t + 0.02);
  env.gain.exponentialRampToValueAtTime(0.0001, t + dur);
  src.connect(bp);
  bp.connect(env);
  env.connect(g);
  connectDest(g, c);
  src.start(t);
  src.stop(t + dur + 0.01);
}

export function triggerAudioCue(id: AudioCueId): void {
  const c = getCtx();
  if (!c) return;
  resumeAudioContext();
  if (!canPlayCue(id)) return;
  if (id === "CLICK") playCueClick(c);
  else if (id === "HOVER") playCueHover(c);
  else if (id === "LEVEL_UP") playCueLevelUp(c);
  else if (id === "WAR_PULSE") playCueWarPulse(c);
  else playCueWhir(c);
}

function createNoiseSource(c: AudioContext): AudioBufferSourceNode {
  const dur = 1.8;
  const n = Math.floor(c.sampleRate * dur);
  const buf = c.createBuffer(1, n, c.sampleRate);
  const ch = buf.getChannelData(0);
  for (let i = 0; i < n; i += 1) ch[i] = (Math.random() * 2 - 1) * 0.22;
  const src = c.createBufferSource();
  src.buffer = buf;
  src.loop = true;
  return src;
}

export function setAmbientTerminalAudioEnabled(enabled: boolean): void {
  const c = getCtx();
  if (!c) return;
  resumeAudioContext();
  if (enabled) {
    if (ambientNodes) return;
    const gain = c.createGain();
    gain.gain.setValueAtTime(0.0001, c.currentTime);
    const lp = c.createBiquadFilter();
    lp.type = "lowpass";
    lp.frequency.value = 540;

    const osc = c.createOscillator();
    osc.type = "triangle";
    osc.frequency.value = 58;

    const noise = createNoiseSource(c);
    const hp = c.createBiquadFilter();
    hp.type = "highpass";
    hp.frequency.value = 180;

    const lfo = c.createOscillator();
    lfo.type = "sine";
    lfo.frequency.value = 0.12;
    const lfoGain = c.createGain();
    lfoGain.gain.value = 0.012;

    lfo.connect(lfoGain);
    lfoGain.connect(gain.gain);
    osc.connect(lp);
    lp.connect(gain);
    noise.connect(hp);
    hp.connect(gain);
    connectDest(gain, c);

    osc.start();
    noise.start();
    lfo.start();
    gain.gain.exponentialRampToValueAtTime(0.043, c.currentTime + 0.45);
    ambientNodes = { osc, noise, lfo, lfoGain, gain };
    return;
  }
  if (!ambientNodes) return;
  const t = c.currentTime;
  ambientNodes.gain.gain.cancelScheduledValues(t);
  ambientNodes.gain.gain.setValueAtTime(Math.max(0.0001, ambientNodes.gain.gain.value), t);
  ambientNodes.gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.28);
  ambientNodes.osc.stop(t + 0.3);
  ambientNodes.noise.stop(t + 0.3);
  ambientNodes.lfo.stop(t + 0.3);
  ambientNodes = null;
  setAmbientHotZoneEscalationEnabled(false);
}

export function setAmbientHotZoneEscalationEnabled(enabled: boolean): void {
  const c = getCtx();
  if (!c) return;
  resumeAudioContext();
  if (enabled) {
    if (hotZoneNodes) return;
    const noise = createNoiseSource(c);
    const bp = c.createBiquadFilter();
    bp.type = "bandpass";
    bp.frequency.value = 2450;
    bp.Q.value = 0.9;
    const gain = c.createGain();
    gain.gain.setValueAtTime(0.0001, c.currentTime);
    const lfo = c.createOscillator();
    lfo.type = "square";
    lfo.frequency.value = 1.8;
    const lfoGain = c.createGain();
    lfoGain.gain.value = 0.011;
    lfo.connect(lfoGain);
    lfoGain.connect(gain.gain);
    noise.connect(bp);
    bp.connect(gain);
    connectDest(gain, c);
    noise.start();
    lfo.start();
    gain.gain.exponentialRampToValueAtTime(0.018, c.currentTime + 0.22);
    hotZoneNodes = { noise, bp, gain, lfo, lfoGain };
    return;
  }
  if (!hotZoneNodes) return;
  const t = c.currentTime;
  hotZoneNodes.gain.gain.cancelScheduledValues(t);
  hotZoneNodes.gain.gain.setValueAtTime(Math.max(0.0001, hotZoneNodes.gain.gain.value), t);
  hotZoneNodes.gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.24);
  hotZoneNodes.noise.stop(t + 0.26);
  hotZoneNodes.lfo.stop(t + 0.26);
  hotZoneNodes = null;
}

/** Legacy wrapper — mechanischer Tastaturimpuls */
export function playUiKeyMechanical(): void {
  triggerAudioCue("HOVER");
}

/** Legacy wrapper — UI-Klick */
export function playUiClick(): void {
  triggerAudioCue("CLICK");
}

/** Legacy wrapper — kurzer Whir/Swoosh */
export function playUiSwoosh(): void {
  triggerAudioCue("WHIR");
}

/** Legacy wrapper — Erfolg/Level-Anhebung */
export function playUiSuccess(): void {
  triggerAudioCue("LEVEL_UP");
}

/** Legacy wrapper — starker Pulse */
export function playUiError(): void {
  triggerAudioCue("WAR_PULSE");
}

/** Legacy wrapper — tiefer Hum */
export function playUiSubBassHum(): void {
  triggerAudioCue("WAR_PULSE");
}
