function buildSummaryRows(universeName: string, chapter: (typeof CHAPTER_TITLES)[number]): SqlSummaryRow[] {
  return [
    { key: "Keyword", desc: `${chapter.keyword} bedeutet ${chapter.keywordMeaning}` },
    { key: "Warum", desc: chapter.keywordWhy },
    { key: "Bild", desc: chapter.metaphor },
    { key: "Kontext", desc: `Dieses Kapitel arbeitet im ${universeName} Datenset` },
  ];
}

function buildConceptCards(order: number, tableNames: string[], chapter: (typeof CHAPTER_TITLES)[number]): SqlInfoCard[] {
  const cards: SqlInfoCard[] = [
    {
      id: `chapter-${order}-card-1`,
      title: `Keyword zuerst ${chapter.keyword}`,
      body: `${chapter.keywordMeaning} ${chapter.keywordWhy}`,
    },
    {
      id: `chapter-${order}-card-2`,
      title: "Bodybuilding Bild",
      body: chapter.metaphor,
    },
    {
      id: `chapter-${order}-card-3`,
      title: "Tabellenfokus",
      body: `Du trainierst heute mit den Tabellen ${tableNames.join(" ")}`,
    },
  ];

  if (order === 1) {
    cards.push({
      id: "chapter-1-card-diagram",
      title: "DB DBMS DBS",
      body: "Diagramm zeigt den Fluss zwischen Daten Speicher und SQL Zugriff",
      diagram: "dbs-flow",
    });
  }

  if (order === 2) {
    cards.push({
      id: "chapter-2-card-diagram",
      title: "Tabellen Anatomie",
      body: "Diagramm erklärt Zeilen Spalten und Primärschlüssel",
      diagram: "table-anatomy",
    });
  }

  if (order === 3) {
    cards.push({
      id: "chapter-3-card-diagram",
      title: "Filter Logik",
      body: "Diagramm zeigt den Weg von Tabelle ueber Tuersteher Filter bis zum Ergebnis",
      diagram: "filter-logic",
    });
  }

  if (order === 4) {
    cards.push({
      id: "chapter-4-card-diagram",
      title: "WHERE Tuersteher",
      body: "Diagramm zeigt wie WHERE nur passende Zeilen durchlaesst",
      diagram: "filter-logic",
    });
  }

  return cards;
}

