function replaceTables(input: string, tableMap: Record<string, string>): string {
  return Object.entries(tableMap).reduce((acc, [from, to]) => acc.replaceAll(from, to), input);
}

function buildUniverseExercises(universeId: SqlUniverseId, tableNames: string[]): SqlExercise[] {
  if (universeId === "star_wars") return STAR_WARS_EXERCISES;
  if (universeId === "anime") return ANIME_EXERCISES;
  if (
    tableNames[0] === "nahrungsmittel" &&
    tableNames[1] === "uebungen" &&
    tableNames[2] === "trainingsroutinen"
  ) {
    return BODYBUILDING_EXERCISES;
  }

  const tableMap = {
    charaktere: tableNames[0] ?? "charaktere",
    planeten: tableNames[1] ?? "planeten",
    raumschiffe: tableNames[2] ?? "raumschiffe",
  };

  return EXERCISE_POOL.map((exercise) => ({
    ...exercise,
    challenge: replaceTables(exercise.challenge, tableMap),
    starterHint: replaceTables(exercise.starterHint, tableMap),
    solutionSql: replaceTables(exercise.solutionSql, tableMap),
  }));
}

function buildExerciseGroups(exercises: SqlExercise[]): SqlExerciseGroup[] {
  return [
    { id: "leicht", title: "Leicht", exercises: exercises.filter((exercise) => exercise.tier === "leicht") },
    { id: "mittel", title: "Mittel", exercises: exercises.filter((exercise) => exercise.tier === "mittel") },
    { id: "knifflig", title: "Knifflig", exercises: exercises.filter((exercise) => exercise.tier === "knifflig") },
  ];
}

function chapterExercises(order: number, universeExercises: SqlExercise[]) {
  if (order === 12) return universeExercises;
  const start = (order - 1) * 2;
  const base = universeExercises.slice(start, start + 2);
  const bonus = universeExercises[20 + ((order - 1) % 10)];
  return bonus ? [...base, bonus] : base;
}

