import { motion, useReducedMotion } from "framer-motion";
import { useMemo, useState } from "react";

type SpeedrunTrackerProps = {
  currentRunMs: number;
  personalBestMs: number | null;
};

export function SpeedrunTracker({ currentRunMs, personalBestMs }: SpeedrunTrackerProps) {
  const [ghostEnabled, setGhostEnabled] = useState(true);
  const reduceMotion = useReducedMotion();
  const targetMs = useMemo(() => Math.max(15000, personalBestMs ?? 60000), [personalBestMs]);
  const runProgress = Math.min(100, Math.max(0, (currentRunMs / targetMs) * 100));
  const ghostProgress = personalBestMs ? Math.min(100, Math.max(0, (personalBestMs / targetMs) * 100)) : 0;

  return (
    <div className="mt-3 rounded-md border border-cyan-400/25 bg-slate-950/65 p-2">
      <div className="mb-1 flex items-center justify-between">
        <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-200">Speedrun Tracker</p>
        <button
          type="button"
          className="rounded border border-cyan-300/40 bg-cyan-950/25 px-2 py-0.5 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
          onClick={() => setGhostEnabled((prev) => !prev)}
        >
          {ghostEnabled ? "Ghost on" : "Ghost off"}
        </button>
      </div>
      <div className="relative h-2.5 overflow-hidden rounded-full border border-cyan-300/30 bg-slate-900/80">
        {ghostEnabled && personalBestMs ? (
          <motion.div
            className="absolute inset-y-0 left-0 border-r border-fuchsia-200/70 bg-fuchsia-500/20"
            style={{ width: `${ghostProgress}%` }}
            initial={false}
            animate={reduceMotion ? { opacity: 0.7 } : { opacity: [0.55, 0.85, 0.55] }}
            transition={reduceMotion ? { duration: 0 } : { duration: 1.6, repeat: Infinity, ease: "easeInOut" }}
          />
        ) : null}
        <motion.div
          className="h-full bg-gradient-to-r from-cyan-400 to-emerald-300"
          initial={false}
          animate={{ width: `${runProgress}%` }}
          transition={reduceMotion ? { duration: 0 } : { duration: 0.35, ease: "easeOut" }}
        />
      </div>
      <p className="mt-1 text-[10px] text-cyan-200">
        Run {Math.floor(currentRunMs / 1000)}s {personalBestMs ? `| PB ${Math.floor(personalBestMs / 1000)}s` : "| PB pending"}
      </p>
    </div>
  );
}
