export type DossierMemoryState<TPayload> = {
  publicDossierCachedUserId: string | null;
  publicDossierLastFetchedAt: number | null;
  publicDossierCachedPayload: TPayload | null;
};

const PUBLIC_DOSSIER_CACHE_MS = 60_000;

export function dossierMemoryHit<TPayload extends { userId: string }>(
  state: DossierMemoryState<TPayload>,
  userId: string,
): boolean {
  return (
    state.publicDossierCachedUserId === userId &&
    state.publicDossierLastFetchedAt != null &&
    state.publicDossierCachedPayload?.userId === userId &&
    Date.now() - state.publicDossierLastFetchedAt < PUBLIC_DOSSIER_CACHE_MS
  );
}
