import type { SqlUniverseId } from "../../data/universes";

export type MentorRadarMetric = {
  label: string;
  value: number;
};

export type SqlMentorInput = {
  sql: string;
  costScore: number;
  radar: MentorRadarMetric[];
  universeId: SqlUniverseId;
  successfulTasks?: number;
};

export type InjectionShieldResult = {
  detected: boolean;
  severity: "none" | "high";
  summary: string;
  guidance: string;
};

const TONE_BY_UNIVERSE: Record<SqlUniverseId, string> = {
  star_wars: "Jedi",
  nutrition: "Coach",
  cs_tactical: "Analyst",
  anime: "Sensei",
  warzone: "Commander",
  wow: "Archivist",
  bodybuilding: "Mentor",
};

function normalizeRadar(radar: MentorRadarMetric[]): MentorRadarMetric[] {
  return radar.map((metric) => ({ ...metric, value: Math.max(0, Math.min(100, metric.value)) }));
}

function pickStrongest(radar: MentorRadarMetric[]): MentorRadarMetric | null {
  if (radar.length === 0) return null;
  return [...radar].sort((a, b) => b.value - a.value)[0] ?? null;
}

function pickWeakest(radar: MentorRadarMetric[]): MentorRadarMetric | null {
  if (radar.length === 0) return null;
  return [...radar].sort((a, b) => a.value - b.value)[0] ?? null;
}

function detectHeavyJoins(sql: string): boolean {
  return (sql.toUpperCase().match(/\bJOIN\b/g) ?? []).length >= 2;
}

function detectWeakFiltering(sql: string): boolean {
  const clean = sql.toUpperCase();
  return !/\bWHERE\b/.test(clean) && !/\bHAVING\b/.test(clean);
}

function detectWideSelect(sql: string): boolean {
  return /\bSELECT\s+\*/i.test(sql);
}

function lookupMetric(radar: MentorRadarMetric[], label: "Joins" | "Filtering" | "Performance"): number {
  return radar.find((metric) => metric.label.toLowerCase() === label.toLowerCase())?.value ?? 0;
}

function joinAdvice(tone: string, joinsRadar: number, heavyJoins: boolean): string {
  if (!heavyJoins) return `${tone} signal join graph stable keep relation paths explicit and short`;
  if (joinsRadar >= 75) return `${tone} signal you mastered Joins but this query is heavy on memory try a subquery and prune join paths`;
  return `${tone} signal join pressure detected remove unnecessary JOINs and prefilter rows before joining`;
}

function filteringAdvice(tone: string, filteringRadar: number, weakFiltering: boolean): string {
  if (!weakFiltering) return `${tone} signal filtering path is controlled keep these predicates tight`;
  if (filteringRadar >= 70) return `${tone} signal filtering mastery is high add one strict WHERE branch to cut scanned rows`;
  return `${tone} signal filtering is your next gain add WHERE conditions before ORDER BY and GROUP BY`;
}

function performanceAdvice(tone: string, performanceRadar: number, wideSelect: boolean): string {
  if (!wideSelect) return `${tone} signal projection is focused keep selected columns minimal`;
  if (performanceRadar >= 70) return `${tone} signal strong performance instincts detected replace SELECT star with explicit columns`;
  return `${tone} signal cost can drop fast limit SELECT columns and apply LIMIT during diagnostics`;
}

function deepDiveReview(sql: string, strongest: MentorRadarMetric | null): string {
  const hasAlias = /\bAS\b/i.test(sql);
  const hasExplicitColumns = !/\bSELECT\s+\*/i.test(sql);
  const hasSchemaSignal = /\bJOIN\b|\bGROUP\s+BY\b|\bALTER\s+TABLE\b/i.test(sql);
  const strongestSignal = strongest?.label ?? "core SQL";
  const bestPracticeLine = hasAlias && hasExplicitColumns
    ? "Best Practices strong aliasing and explicit projection keep this style for maintainable reviews"
    : "Best Practices add explicit columns and alias names to improve readability across teams";
  const schemaLine = hasSchemaSignal
    ? "Schema Design signal detected keep relationships normalized and document key constraints"
    : "Schema Design next step map table relationships and define migration-safe keys";
  return `Elite Coach deep dive unlocked after five wins focus ${strongestSignal} ${bestPracticeLine} ${schemaLine}`;
}

export function detectSqlInjectionRisk(sql: string): InjectionShieldResult {
  const clean = sql.trim();
  const patterns = [
    /\bOR\s+1\s*=\s*1\b/i,
    /'\s*OR\s*'1'\s*=\s*'1/i,
    /--/,
    /;\s*DROP\s+TABLE\b/i,
    /\bUNION\s+SELECT\b/i,
  ];
  const matched = patterns.some((pattern) => pattern.test(clean));
  if (!matched) {
    return {
      detected: false,
      severity: "none",
      summary: "Injection shield clean query signature",
      guidance: "Use prepared statements and bound parameters for every external input path",
    };
  }
  return {
    detected: true,
    severity: "high",
    summary: "Injection shield critical warning unsafe dynamic predicate detected",
    guidance: "Switch to parameterized inputs and never concatenate raw user values into SQL clauses",
  };
}

export function generateSqlMentorAdvice(input: SqlMentorInput): string {
  const radar = normalizeRadar(input.radar);
  const strongest = pickStrongest(radar);
  const weakest = pickWeakest(radar);
  const cost = Math.max(0, Math.min(100, input.costScore));
  const tone = TONE_BY_UNIVERSE[input.universeId];
  const coachTone = `${tone} Elite Coach`;
  const injection = detectSqlInjectionRisk(input.sql);

  if (injection.detected) {
    return `${coachTone} ${injection.summary} ${injection.guidance}`;
  }

  if ((input.successfulTasks ?? 0) >= 5) {
    return deepDiveReview(input.sql, strongest);
  }

  if (cost <= 35) {
    if (strongest) return `${coachTone} signal clean query and stable flow your ${strongest.label} mastery is visible`;
    return `${coachTone} signal clean query and stable flow keep this pacing`;
  }

  if (cost <= 50) {
    if (weakest) return `${coachTone} signal balanced query keep momentum and sharpen ${weakest.label} for faster execution`;
    return `${coachTone} signal balanced query you can still tighten selected columns`;
  }

  const joinsRadar = lookupMetric(radar, "Joins");
  const filteringRadar = lookupMetric(radar, "Filtering");
  const performanceRadar = lookupMetric(radar, "Performance");
  const hasJoinPressure = detectHeavyJoins(input.sql);
  const weakFiltering = detectWeakFiltering(input.sql);
  const wideSelect = detectWideSelect(input.sql);

  if (hasJoinPressure) return joinAdvice(coachTone, joinsRadar, hasJoinPressure);
  if (weakFiltering) return filteringAdvice(coachTone, filteringRadar, weakFiltering);
  if (wideSelect) return performanceAdvice(coachTone, performanceRadar, wideSelect);
  if (weakest) return `${coachTone} readout cost spike detected reduce selected columns and tune ${weakest.label} with tighter clauses`;
  if (strongest) return `${coachTone} readout stable query shape keep building on ${strongest.label} precision`;
  return `${coachTone} readout cost spike detected limit SELECT columns and add strict WHERE filters`;
}
