import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect } from "react";
import { achievementTierClasses, isAchievementId, ACHIEVEMENTS } from "../../data/achievementSchema";
import { useAppStore } from "../../store/useAppStore";

export function AchievementToast() {
  const prefersReduced = useReducedMotion();
  const activeNotification = useAppStore((s) => s.activeNotification);
  const dismissActiveNotification = useAppStore((s) => s.dismissActiveNotification);

  const achievement =
    activeNotification?.kind === "achievement" && isAchievementId(activeNotification.achievementId)
      ? ACHIEVEMENTS[activeNotification.achievementId]
      : null;

  useEffect(() => {
    if (!achievement) return;
    const timer = window.setTimeout(() => dismissActiveNotification(), 3400);
    return () => window.clearTimeout(timer);
  }, [achievement, dismissActiveNotification]);

  const tierClasses = achievement ? achievementTierClasses(achievement.tier) : null;

  return (
    <div className="pointer-events-none fixed right-4 top-4 z-[420] flex max-w-[min(92vw,21rem)] flex-col items-end gap-2">
      <AnimatePresence mode="wait">
        {achievement && tierClasses ? (
          <motion.div
            key={activeNotification?.id}
            initial={prefersReduced ? { opacity: 0 } : { opacity: 0, x: 28, y: -10 }}
            animate={{ opacity: 1, x: 0, y: 0 }}
            exit={prefersReduced ? { opacity: 0 } : { opacity: 0, x: 16, y: -6 }}
            transition={{ type: "spring", stiffness: 260, damping: 24, mass: 0.82 }}
            className={`pointer-events-auto relative w-full overflow-hidden border bg-black/90 px-4 py-3 ${tierClasses.frame} ${tierClasses.glow}`}
          >
            <div className="pointer-events-none absolute inset-0 noise-overlay opacity-25" />
            <p className="relative font-mono text-[9px] font-semibold uppercase tracking-[0.26em] text-cyan-200/85">
              Achievement Unlocked
            </p>
            <div className="relative mt-2 flex items-start gap-3">
              <div className={`mt-0.5 size-2 rounded-full ${tierClasses.icon} bg-current shadow-[0_0_10px_currentColor]`} />
              <div className="min-w-0">
                <p className="font-mono text-xs font-bold uppercase tracking-[0.12em] text-foreground/95">
                  {achievement.title}
                </p>
                <p className="mt-1 line-clamp-3 font-mono text-[10px] leading-snug text-foreground-muted">
                  {achievement.requirement}
                </p>
              </div>
            </div>
            <motion.button
              type="button"
              whileTap={{ scale: 0.98 }}
              onClick={dismissActiveNotification}
              className="relative mt-3 w-full border border-cyan-300/25 bg-cyan-500/8 py-1.5 font-mono text-[9px] font-semibold uppercase tracking-[0.2em] text-cyan-100"
            >
              Continue
            </motion.button>
          </motion.div>
        ) : null}
      </AnimatePresence>
    </div>
  );
}
