export type DroidKind = "battle" | "protocol";

export type DroidExecution = {
  model: string;
  kind: DroidKind;
  message: string;
  cssVariable: string;
  cssValue: string;
};

export type DroidSkill = "Stealth" | "Overload" | "Diplomacy";

export type DroidSkillExecution = {
  model: string;
  skill: DroidSkill;
  message: string;
  cssVariable: string;
  cssValue: string;
};

export interface IDroidAbility {
  PerformSkill(skill: DroidSkill): DroidSkillExecution;
  listSkills(): DroidSkill[];
}

export abstract class BaseDroid {
  readonly model: string;
  protected _powerLevel: number;

  constructor(model: string, powerLevel: number) {
    this.model = model.trim() || "Unit";
    this._powerLevel = 0;
    this.powerLevel = powerLevel;
  }

  get powerLevel(): number {
    return this._powerLevel;
  }

  set powerLevel(value: number) {
    this._powerLevel = Math.max(0, Math.min(100, Math.round(value)));
  }

  abstract get kind(): DroidKind;
  abstract ExecuteFunction(): DroidExecution;
}

export class BattleDroid extends BaseDroid implements IDroidAbility {
  override get kind(): DroidKind {
    return "battle";
  }

  override ExecuteFunction(): DroidExecution {
    return {
      model: this.model,
      kind: this.kind,
      message: `${this.model} enters combat stance`,
      cssVariable: "--droid-battle-glow",
      cssValue: "0 0 20px rgba(239,68,68,0.75)",
    };
  }

  listSkills(): DroidSkill[] {
    return ["Stealth", "Overload"];
  }

  PerformSkill(skill: DroidSkill): DroidSkillExecution {
    if (skill === "Stealth") {
      return {
        model: this.model,
        skill,
        message: `${this.model} activates stealth cloak`,
        cssVariable: "--droid-skill-stealth",
        cssValue: "0 0 24px rgba(20,184,166,0.78)",
      };
    }
    return {
      model: this.model,
      skill: "Overload",
      message: `${this.model} charges overload pulse`,
      cssVariable: "--droid-skill-overload",
      cssValue: "0 0 24px rgba(239,68,68,0.82)",
    };
  }
}

export class ProtocolDroid extends BaseDroid implements IDroidAbility {
  override get kind(): DroidKind {
    return "protocol";
  }

  override ExecuteFunction(): DroidExecution {
    return {
      model: this.model,
      kind: this.kind,
      message: `${this.model} opens diplomacy channel`,
      cssVariable: "--droid-protocol-glow",
      cssValue: "0 0 20px rgba(56,189,248,0.72)",
    };
  }

  listSkills(): DroidSkill[] {
    return ["Stealth", "Diplomacy"];
  }

  PerformSkill(skill: DroidSkill): DroidSkillExecution {
    if (skill === "Stealth") {
      return {
        model: this.model,
        skill,
        message: `${this.model} enters silent protocol mode`,
        cssVariable: "--droid-skill-stealth",
        cssValue: "0 0 24px rgba(45,212,191,0.72)",
      };
    }
    return {
      model: this.model,
      skill: "Diplomacy",
      message: `${this.model} opens diplomacy relay`,
      cssVariable: "--droid-skill-diplomacy",
      cssValue: "0 0 24px rgba(56,189,248,0.8)",
    };
  }
}

export function hasDroidAbility(droid: BaseDroid): droid is BaseDroid & IDroidAbility {
  return typeof (droid as unknown as IDroidAbility).PerformSkill === "function";
}

export function createDroid(kind: DroidKind, model: string, powerLevel: number): BaseDroid {
  if (kind === "battle") return new BattleDroid(model, powerLevel);
  return new ProtocolDroid(model, powerLevel);
}
