import { useMemo, useState, type DragEvent } from "react";

type BuilderColumnType = "INT" | "BIGINT" | "VARCHAR(50)" | "VARCHAR(100)";

type BuilderColumn = {
  name: string;
  sqlType: BuilderColumnType;
};

type BuilderTable = {
  tableName: string;
  columns: BuilderColumn[];
};

type BuilderTask = {
  id: string;
  prompt: string;
  sql: string;
};

const COLUMN_SNIPPETS: BuilderColumn[] = [
  { name: "id", sqlType: "INT" },
  { name: "name", sqlType: "VARCHAR(100)" },
  { name: "created_at", sqlType: "BIGINT" },
  { name: "category", sqlType: "VARCHAR(50)" },
];

const TASK_SNIPPETS: BuilderTask[] = [
  { id: "task-select", prompt: "Show all rows", sql: "SELECT * FROM table_name LIMIT 5;" },
  { id: "task-filter", prompt: "Filter by category", sql: "SELECT * FROM table_name WHERE category = 'A';" },
  { id: "task-agg", prompt: "Count grouped rows", sql: "SELECT category, COUNT(*) AS total FROM table_name GROUP BY category;" },
];

type UniverseBuilderProps = {
  universeId: string;
};

export function UniverseBuilder({ universeId }: UniverseBuilderProps) {
  const [tables, setTables] = useState<BuilderTable[]>([{ tableName: "custom_table", columns: [{ name: "id", sqlType: "INT" }] }]);
  const [tasks, setTasks] = useState<BuilderTask[]>([]);
  const [activeTableIndex, setActiveTableIndex] = useState(0);

  const payload = useMemo(
    () => ({
      factoryPayloadVersion: 1,
      universeSeed: {
        universeId,
        universeName: "Creator Universe",
        accentClass: "from-cyan-500/40 to-fuchsia-500/40",
        tables: tables.map((table) => ({
          tableName: table.tableName,
          columns: table.columns,
          rows: [],
        })),
      },
      tasks: tasks.map((task, index) => ({
        id: `creator-task-${index + 1}`,
        letter: ["A", "B", "C", "D"][index % 4],
        prompt: task.prompt,
        solution: { type: "sql", content: task.sql },
      })),
    }),
    [tables, tasks, universeId],
  );

  function onDropColumn(event: DragEvent<HTMLDivElement>, tableIndex: number) {
    event.preventDefault();
    const raw = event.dataTransfer.getData("application/codesnap-column");
    if (!raw) return;
    const column = JSON.parse(raw) as BuilderColumn;
    setTables((prev) =>
      prev.map((table, idx) =>
        idx === tableIndex ? { ...table, columns: [...table.columns, { ...column, name: `${column.name}_${table.columns.length + 1}` }] } : table,
      ),
    );
  }

  function onDropTask(event: DragEvent<HTMLDivElement>) {
    event.preventDefault();
    const raw = event.dataTransfer.getData("application/codesnap-task");
    if (!raw) return;
    const task = JSON.parse(raw) as BuilderTask;
    setTasks((prev) => [...prev, { ...task, id: `${task.id}-${prev.length + 1}` }]);
  }

  return (
    <section className="rounded-xl border border-cyan-400/35 bg-slate-950/75 p-4">
      <p className="text-[10px] uppercase tracking-[0.16em] text-cyan-300">Creator Mode</p>
      <h3 className="mt-2 text-lg font-semibold text-cyan-100">Universe Builder</h3>
      <p className="mt-1 text-xs text-slate-300">Drag snippets into tables and tasks then export JSON for sqlContentFactory injection</p>

      <div className="mt-4 grid gap-3 md:grid-cols-2">
        <div className="rounded-lg border border-cyan-400/25 bg-slate-900/60 p-3">
          <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Column Snippets</p>
          <div className="mt-2 flex flex-wrap gap-2">
            {COLUMN_SNIPPETS.map((column) => (
              <button
                key={`${column.name}-${column.sqlType}`}
                type="button"
                draggable
                onDragStart={(event) => event.dataTransfer.setData("application/codesnap-column", JSON.stringify(column))}
                className="rounded-md border border-cyan-300/30 bg-cyan-950/35 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
              >
                {column.name} {column.sqlType}
              </button>
            ))}
          </div>
          <p className="mt-4 text-[10px] uppercase tracking-[0.14em] text-fuchsia-300">Task Snippets</p>
          <div className="mt-2 flex flex-wrap gap-2">
            {TASK_SNIPPETS.map((task) => (
              <button
                key={task.id}
                type="button"
                draggable
                onDragStart={(event) => event.dataTransfer.setData("application/codesnap-task", JSON.stringify(task))}
                className="rounded-md border border-fuchsia-300/30 bg-fuchsia-950/35 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-fuchsia-100"
              >
                {task.prompt}
              </button>
            ))}
          </div>
        </div>

        <div className="rounded-lg border border-cyan-400/25 bg-slate-900/60 p-3">
          <div className="flex items-center justify-between gap-2">
            <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Tables</p>
            <button
              type="button"
              className="rounded-md border border-emerald-300/40 bg-emerald-950/30 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-emerald-100"
              onClick={() =>
                setTables((prev) => [...prev, { tableName: `custom_table_${prev.length + 1}`, columns: [{ name: "id", sqlType: "INT" }] }])
              }
            >
              Add Table
            </button>
          </div>
          <div className="mt-2 space-y-2">
            {tables.map((table, index) => (
              <div
                key={`${table.tableName}-${index}`}
                onDragOver={(event) => event.preventDefault()}
                onDrop={(event) => onDropColumn(event, index)}
                className={`rounded-md border p-2 ${activeTableIndex === index ? "border-cyan-300/60 bg-cyan-950/25" : "border-cyan-300/25 bg-slate-950/55"}`}
                onClick={() => setActiveTableIndex(index)}
              >
                <p className="text-[10px] uppercase tracking-[0.12em] text-cyan-200">{table.tableName}</p>
                <div className="mt-1 flex flex-wrap gap-1">
                  {table.columns.map((column, colIndex) => (
                    <span key={`${column.name}-${colIndex}`} className="rounded border border-cyan-300/30 bg-slate-900/60 px-1.5 py-0.5 text-[10px] text-cyan-100">
                      {column.name}:{column.sqlType}
                    </span>
                  ))}
                </div>
              </div>
            ))}
          </div>

          <div onDragOver={(event) => event.preventDefault()} onDrop={onDropTask} className="mt-3 rounded-md border border-fuchsia-300/30 bg-slate-950/55 p-2">
            <p className="text-[10px] uppercase tracking-[0.12em] text-fuchsia-200">Drop Tasks Here</p>
            <div className="mt-1 space-y-1">
              {tasks.map((task) => (
                <p key={task.id} className="text-[10px] text-slate-200">
                  {task.prompt}
                </p>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="mt-4 rounded-lg border border-cyan-400/25 bg-slate-950/70 p-3">
        <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-300">Factory JSON Output</p>
        <pre className="mt-2 max-h-64 overflow-auto whitespace-pre-wrap text-[10px] text-cyan-100">{JSON.stringify(payload, null, 2)}</pre>
      </div>
    </section>
  );
}
