import type { ExamId } from "../../data/exams";
import { getArenaQuestionById, getRandomMockExamQuestions, type ArenaQuestion } from "../../data/mockQuestions";
import { getSupabase } from "../supabase";

export type MockExamSubmitPayload = {
  examId: "MOCK_EXAM";
  scorePercent: number;
  totalQuestions: number;
  correctAnswers: number;
  durationMs: number;
};

export function getMockExamQuestions(minCount = 30, maxCount = 40): ArenaQuestion[] {
  return getRandomMockExamQuestions(minCount, maxCount);
}

export function getChallengeQuestionSet(ids: string[]): ArenaQuestion[] {
  const normalized = ids.map((x) => x.trim()).filter(Boolean);
  const rows = normalized.map((id) => getArenaQuestionById(id)).filter((q): q is ArenaQuestion => !!q);
  const uniq = new Map<string, ArenaQuestion>();
  for (const row of rows) {
    if (!uniq.has(row.id)) uniq.set(row.id, row);
  }
  return [...uniq.values()];
}

/**
 * Cloud-first fetch for published exam data, with safe local fallback
 * Uses existing question-bank schema without mutating any persisted state
 */
export async function fetchPublishedExamQuestions(examId: ExamId, limit = 64): Promise<ArenaQuestion[]> {
  const sb = getSupabase();
  if (!sb) return getRandomMockExamQuestions(30, 40);
  const { data, error } = await sb
    .from("ihk_question_bank")
    .select("id,slug,type,prompt,payload,difficulty,tags,module,image_path,image_url,code_snippet,hint,explanation")
    .eq("is_published", true)
    .eq("exam_id", examId)
    .limit(Math.max(1, Math.floor(limit)));
  if (error || !Array.isArray(data)) {
    return getRandomMockExamQuestions(30, 40);
  }
  const mapped: ArenaQuestion[] = [];
  for (const row of data as Array<Record<string, unknown>>) {
    const payload = row.payload as { options?: unknown; correctIndex?: unknown } | null;
    if (
      !row.id ||
      !row.slug ||
      !row.type ||
      !row.prompt ||
      !payload ||
      !Array.isArray(payload.options) ||
      payload.options.length !== 4 ||
      typeof payload.correctIndex !== "number"
    ) {
      continue;
    }
    const options = payload.options;
    if (!options.every((x) => typeof x === "string")) continue;
    const correctIndex = payload.correctIndex;
    if (correctIndex < 0 || correctIndex > 3) continue;
    mapped.push({
      id: String(row.id),
      slug: String(row.slug),
      type: row.type === "sql_challenge" ? "sql_challenge" : "multiple_choice",
      prompt: String(row.prompt),
      options: options as [string, string, string, string],
      correctIndex: correctIndex as 0 | 1 | 2 | 3,
      explanation: typeof row.explanation === "string" ? row.explanation : undefined,
      tags: Array.isArray(row.tags) ? row.tags.filter((x): x is string => typeof x === "string") : [],
      module: typeof row.module === "string" ? (row.module as ArenaQuestion["module"]) : undefined,
      difficulty:
        row.difficulty === "hard" || row.difficulty === "medium" || row.difficulty === "easy"
          ? row.difficulty
          : "medium",
      imagePath: typeof row.image_path === "string" ? row.image_path : undefined,
      imageUrl: typeof row.image_url === "string" ? row.image_url : undefined,
      codeSnippet: typeof row.code_snippet === "string" ? row.code_snippet : undefined,
      hint: typeof row.hint === "string" ? row.hint : undefined,
    });
  }
  return mapped.length > 0 ? mapped : getRandomMockExamQuestions(30, 40);
}

/**
 * Submit mock exam summary to cloud leaderboard channel
 * Failure is non-fatal and returns false to keep UX stable
 */
export async function submitMockExamResult(payload: MockExamSubmitPayload): Promise<boolean> {
  const sb = getSupabase();
  if (!sb) return false;
  const {
    data: { session },
  } = await sb.auth.getSession();
  if (!session?.user) return false;
  const score = Math.max(0, Math.floor(payload.scorePercent * 10));
  const { error } = await sb.from("arena_leaderboards").insert({
    user_id: session.user.id,
    score,
    mission_type: payload.examId,
  });
  return !error;
}
