export type DailyMissionKind = "arena_win" | "flashcard_reviews" | "sql_checkpoint";

/** Matches store `CareerPath` — kept local to avoid circular imports with `useAppStore`. */
export type DailyCareerPath = "FISI" | "FIAE" | null;

export interface DailyMissionDef {
  id: string;
  title: string;
  subtitle: string;
  kind: DailyMissionKind;
  target: number;
}

/** Local calendar day YYYY-MM-DD */
export function localCalendarYmd(d = new Date()): string {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

export function parseYmd(ymd: string): Date | null {
  const m = /^(\d{4})-(\d{2})-(\d{2})$/.exec(ymd);
  if (!m) return null;
  const y = Number(m[1]);
  const mo = Number(m[2]) - 1;
  const da = Number(m[3]);
  const dt = new Date(y, mo, da);
  if (dt.getFullYear() !== y || dt.getMonth() !== mo || dt.getDate() !== da) return null;
  return dt;
}

export function addCalendarDays(ymd: string, delta: number): string {
  const base = parseYmd(ymd);
  if (!base) return ymd;
  base.setDate(base.getDate() + delta);
  return localCalendarYmd(base);
}

function mulberry32(seed: number) {
  return () => {
    let t = (seed += 0x6d2b79f5);
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function seedFromYmdCareer(ymd: string, career: DailyCareerPath): number {
  const tag = career ?? "MIX";
  let h = 2166136261;
  for (const c of `${ymd}|${tag}`) {
    h ^= c.charCodeAt(0);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
}

