/** Three missions for the given local day and career path (FISI / FIAE / mixed). */
export function buildDailyMissionsForDay(ymd: string, careerPath: DailyCareerPath): DailyMissionDef[] {
  const pool = careerPath === "FIAE" ? POOL_FIAE : careerPath === "FISI" ? POOL_FISI : [...POOL_FISI, ...POOL_FIAE];
  const rand = mulberry32(seedFromYmdCareer(ymd, careerPath));
  const idxs: number[] = [];
  while (idxs.length < 3) {
    const i = Math.floor(rand() * pool.length);
    if (!idxs.includes(i)) idxs.push(i);
  }
  return idxs.map((pi, slot) => ({
    ...pool[pi],
    id: `dg-${ymd}-slot${slot}-${pool[pi].kind}`,
  }));
}

export function yesterdayYmd(todayYmd: string): string {
  return addCalendarDays(todayYmd, -1);
}

/** If the last goal-met day is strictly before yesterday, the chain is broken. */
export function isStreakChainBroken(todayYmd: string, dailyGoalMetYmd: string | null): boolean {
  if (!dailyGoalMetYmd) return false;
  const y = yesterdayYmd(todayYmd);
  return dailyGoalMetYmd < y;
}
