import { SYNTHESIS_RECIPES, SYNTHESIS_RECIPES_BY_ID, type SynthesisMaterialRequirement } from "../../data/synthesisRecipes";

export interface SynthesisInventorySnapshot {
  inventory: string[];
}

export interface SynthesisCraftResult {
  recipeId: string;
  success: boolean;
  consumedMaterials: SynthesisMaterialRequirement[];
  producedItemId: string | null;
  producedAmount: number;
  roll: number;
  successRate: number;
}

export interface MissingMaterial {
  itemId: string;
  required: number;
  available: number;
}

export function getCraftableRecipeIds(snapshot: SynthesisInventorySnapshot): string[] {
  return SYNTHESIS_RECIPES.filter((recipe) => getMissingMaterials(snapshot, recipe.input).length === 0).map((r) => r.id);
}

export function getMissingMaterials(
  snapshot: SynthesisInventorySnapshot,
  materials: SynthesisMaterialRequirement[],
): MissingMaterial[] {
  const counts = countItems(snapshot.inventory);
  return materials
    .map((requirement) => {
      const available = counts.get(requirement.itemId) ?? 0;
      return {
        itemId: requirement.itemId,
        required: requirement.amount,
        available,
      };
    })
    .filter((row) => row.available < row.required);
}

export function runSynthesisAttempt(
  recipeId: string,
  snapshot: SynthesisInventorySnapshot,
  random: () => number = Math.random,
): SynthesisCraftResult {
  const recipe = SYNTHESIS_RECIPES_BY_ID[recipeId];
  if (!recipe) {
    throw new Error(`Unknown synthesis recipe ${recipeId}`);
  }
  const missing = getMissingMaterials(snapshot, recipe.input);
  if (missing.length > 0) {
    throw new Error(`Missing materials for ${recipeId}`);
  }
  const roll = clampRoll(random());
  const success = recipe.type === "static" ? true : roll < recipe.successRate;
  return {
    recipeId,
    success,
    consumedMaterials: recipe.input,
    producedItemId: success ? recipe.output.itemId : null,
    producedAmount: success ? recipe.output.amount : 0,
    roll,
    successRate: recipe.successRate,
  };
}

function countItems(items: string[]): Map<string, number> {
  const map = new Map<string, number>();
  for (const item of items) {
    const next = (map.get(item) ?? 0) + 1;
    map.set(item, next);
  }
  return map;
}

function clampRoll(value: number): number {
  if (!Number.isFinite(value)) return 0.999999;
  if (value < 0) return 0;
  if (value > 0.999999) return 0.999999;
  return value;
}
