export type CSharpMission = {
  id: string;
  order: number;
  title: string;
  mission: string;
  missionType: "status_binding" | "inventory_list" | "shield_integrity" | "droid_encapsulation" | "droid_factory";
  concepts: string[];
  starterHtml: string;
  starterCss: string;
  transitionIds: string[];
  statusVarName: string;
  initialStatus: string;
  activeStatus: string;
  learningFlow?: LearningFlowBlock[];
};

export type LearningFlowBlock = {
  type: "learning_goal" | "core_statement" | "explanation" | "mini_example" | "exercise" | "solution" | "summary";
  title: string;
  content: string;
};

function buildCSharpLearningFlow(mission: {
  title: string;
  mission: string;
  concepts: string[];
  statusVarName: string;
  initialStatus: string;
  activeStatus: string;
}): LearningFlowBlock[] {
  const conceptsShort = mission.concepts.slice(0, 3).join(" , ");
  const missionShort = mission.mission.trim();
  return [
    { type: "learning_goal", title: "Lernziel", content: "Du setzt diese Mission sicher um" },
    { type: "core_statement", title: "Kernaussage", content: missionShort },
    { type: "explanation", title: "Erklaerung", content: `Fokus nur auf ${conceptsShort}` },
    {
      type: "mini_example",
      title: "Mini Beispiel",
      content: `${mission.statusVarName} von ${mission.initialStatus} nach ${mission.activeStatus}`,
    },
    { type: "exercise", title: "Aufgabe", content: "Fuehre genau eine Aktion aus und pruefe den sichtbaren State Wechsel" },
    { type: "solution", title: "Loesung", content: "Der neue Status wird direkt in der UI sichtbar gebunden" },
    { type: "summary", title: "Zusammenfassung", content: "Ein klarer Schritt ist abgeschlossen" },
  ];
}

