import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useState } from "react";
import { IconTrophy } from "../icons/ThinLineIcons";
import type { BossRaidRankboardRow } from "../../lib/syncController";
import { useAppStore } from "../../store/useAppStore";

function formatMs(ms: number): string {
  const secs = Math.max(0, Math.floor(ms / 1000));
  const min = Math.floor(secs / 60);
  const rest = secs % 60;
  return `${String(min).padStart(2, "0")}:${String(rest).padStart(2, "0")}`;
}

export function BossRankboard() {
  const prefersReduced = !!useReducedMotion();
  const [rows, setRows] = useState<BossRaidRankboardRow[]>([]);
  const [busy, setBusy] = useState(false);
  const openPublicDossier = useAppStore((s) => s.openPublicDossier);

  useEffect(() => {
    setBusy(true);
    void import("../../lib/syncController")
      .then((m) => m.fetchBossRaidRankboard(18))
      .then((next) => setRows(next))
      .finally(() => setBusy(false));
  }, []);

  return (
    <section className="relative overflow-hidden rounded-3xl border border-amber-300/38 bg-gradient-to-br from-amber-500/[0.11] via-black/40 to-amber-500/[0.08] p-6 ring-1 ring-amber-200/20">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.05]" aria-hidden />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.13]" aria-hidden />
      <div className="relative space-y-4">
        <div className="flex flex-wrap items-end justify-between gap-3">
          <div className="space-y-1">
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-amber-200/95">
              Boss Raid Ladder
            </p>
            <h3 className="font-display text-2xl font-bold uppercase tracking-wide text-amber-50">
              Eternal Hunter Board
            </h3>
          </div>
          <span className="border border-amber-200/30 bg-amber-500/[0.16] px-3 py-1 font-mono text-[10px] uppercase tracking-[0.18em] text-amber-100">
            Ranked {rows.length}
          </span>
        </div>

        {busy ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-amber-100/85">
            Ladder uplink synchronisiert
          </p>
        ) : rows.length === 0 ? (
          <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-amber-100/85">
            Noch kein Boss Raid Sieg registriert
          </p>
        ) : (
          <div className="grid gap-2">
            {rows.map((row, idx) => (
              <motion.button
                key={`${row.userId}-${idx}`}
                type="button"
                initial={prefersReduced ? false : { opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: prefersReduced ? 0 : 0.18, delay: prefersReduced ? 0 : idx * 0.03 }}
                onClick={() => openPublicDossier(row.userId, row.handle)}
                className="group grid grid-cols-[auto_1fr_auto] items-center gap-3 border border-amber-200/20 bg-black/35 px-3 py-2 text-left hover:border-amber-200/35 hover:bg-black/45"
              >
                <div className="flex min-w-[2.4rem] items-center justify-center border border-amber-200/30 bg-amber-500/[0.12] px-2 py-1 font-mono text-[10px] font-black uppercase tracking-[0.12em] text-amber-100">
                  #{idx + 1}
                </div>
                <div className="space-y-0.5">
                  <p className="truncate font-mono text-[10px] font-semibold uppercase tracking-[0.16em] text-amber-50">
                    {row.handle}
                  </p>
                  <p className="font-mono text-[9px] uppercase tracking-[0.14em] text-amber-100/80">
                    Wins {row.wins} Best Score {row.bestScore} Best Time {formatMs(row.bestTimeMs)}
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  {row.title ? (
                    <span className="border border-amber-200/35 bg-amber-500/[0.18] px-2 py-1 font-mono text-[8px] font-bold uppercase tracking-[0.16em] text-amber-100">
                      {row.title}
                    </span>
                  ) : null}
                  <IconTrophy className="size-4 text-amber-200/80 group-hover:text-amber-100" aria-hidden />
                </div>
              </motion.button>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}
