const SQL_KEYWORDS = new Set([
  "select",
  "from",
  "where",
  "group",
  "by",
  "having",
  "order",
  "asc",
  "desc",
  "limit",
  "offset",
  "join",
  "inner",
  "left",
  "right",
  "full",
  "outer",
  "on",
  "as",
  "and",
  "or",
  "not",
  "in",
  "is",
  "null",
  "like",
  "ilike",
  "between",
  "exists",
  "with",
  "union",
  "all",
  "case",
  "when",
  "then",
  "else",
  "end",
  "insert",
  "into",
  "values",
  "update",
  "set",
  "delete",
  "begin",
  "commit",
  "rollback",
  "count",
  "sum",
  "avg",
  "min",
  "max",
  "distinct",
  "over",
  "partition",
  "row_number",
]);

function tokenizeSql(input: string): string[] {
  const tokens: string[] = [];
  let idx = 0;
  while (idx < input.length) {
    const ch = input[idx];

    if (/\s/.test(ch)) {
      idx += 1;
      continue;
    }

    if (ch === "'" || ch === '"') {
      const quote = ch;
      let value = quote;
      idx += 1;
      while (idx < input.length) {
        const next = input[idx];
        value += next;
        idx += 1;
        if (next === quote) {
          if (input[idx] === quote && quote === "'") {
            value += input[idx];
            idx += 1;
            continue;
          }
          break;
        }
      }
      tokens.push(value);
      continue;
    }

    const multi = input.slice(idx, idx + 2);
    if (multi === ">=" || multi === "<=" || multi === "!=" || multi === "<>") {
      tokens.push(multi);
      idx += 2;
      continue;
    }

    if ("(),=*+-/%;<>.".includes(ch)) {
      tokens.push(ch);
      idx += 1;
      continue;
    }

    const match = input.slice(idx).match(/^[A-Za-z_][A-Za-z0-9_]*/);
    if (match) {
      tokens.push(match[0]);
      idx += match[0].length;
      continue;
    }

    const num = input.slice(idx).match(/^\d+(\.\d+)?/);
    if (num) {
      tokens.push(num[0]);
      idx += num[0].length;
      continue;
    }

    tokens.push(ch);
    idx += 1;
  }

  while (tokens.length > 0 && tokens[tokens.length - 1] === ";") {
    tokens.pop();
  }
  return tokens;
}

function normalizeTokens(tokens: string[]): string[] {
  return tokens.map((token) => {
    if (token.startsWith("'") || token.startsWith('"')) return token;
    if (/^[A-Za-z_][A-Za-z0-9_]*$/.test(token)) {
      const lower = token.toLowerCase();
      if (SQL_KEYWORDS.has(lower)) return lower.toUpperCase();
      return lower;
    }
    return token;
  });
}

export function verifySqlQuery(userSql: string, solutionSql: string): boolean {
  const userTokens = normalizeTokens(tokenizeSql(userSql));
  const solutionTokens = normalizeTokens(tokenizeSql(solutionSql));
  if (userTokens.length !== solutionTokens.length) return false;
  for (let i = 0; i < userTokens.length; i += 1) {
    if (userTokens[i] !== solutionTokens[i]) return false;
  }
  return true;
}
