import { motion, useReducedMotion } from "framer-motion";
import { REALM_FACTIONS, type RealmFactionId } from "../../types/faction";
import { cn } from "../../lib/cn";
import { itemReveal, staggerContainer } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";

const pulseByFaction: Record<RealmFactionId, { ring: string }> = {
  humans: { ring: "border-cyber-cyan/70 ring-1 ring-white/10" },
  orcs: { ring: "border-magenta/70 ring-1 ring-white/10" },
  dwarves: { ring: "border-toxic/70 ring-1 ring-white/10" },
};

export function FactionSelect() {
  const prefersReduced = useReducedMotion();
  const selectedFaction = useAppStore((s) => s.selectedFaction);
  const setSelectedFaction = useAppStore((s) => s.setSelectedFaction);
  const enterRealmBoard = useAppStore((s) => s.enterRealmBoard);

  return (
    <motion.div
      variants={staggerContainer}
      initial="initial"
      animate="animate"
      className="space-y-8"
    >
      <motion.div variants={itemReveal} className="space-y-2 text-center">
        <p className="font-sans text-[11px] font-semibold uppercase tracking-[0.32em] text-toxic">
          RealmQuest
        </p>
        <h2 className="font-display text-3xl font-bold uppercase tracking-wide text-foreground sm:text-4xl">
          Wähl dein Haus
        </h2>
        <p className="mx-auto max-w-xl font-sans text-sm text-foreground-muted sm:text-base">
          Menschen, Orks oder Zwerge — jedes Haus gibt dir andere Buffs im späteren Kampagnenlauf
        </p>
      </motion.div>
      <motion.div
        variants={itemReveal}
        className="grid grid-cols-1 gap-5 sm:grid-cols-3"
      >
        {REALM_FACTIONS.map((f) => {
          const selected = selectedFaction === f.id;
          const pulse = pulseByFaction[f.id];
          return (
            <motion.button
              key={f.id}
              type="button"
              layout
              onClick={() => setSelectedFaction(f.id)}
              whileTap={{
                scale: 0.94,
                transition: { type: "spring", stiffness: 520, damping: 22 },
              }}
              className={cn(
                "relative overflow-hidden rounded-2xl border bg-surface-muted/70 p-6 text-left backdrop-blur-xl",
                "border-border-glass transition-colors",
                selected && pulse.ring,
              )}
              animate={
                selected && !prefersReduced ? { scale: [1, 1.02, 1] } : { scale: 1 }
              }
              transition={
                selected && !prefersReduced
                  ? { duration: 1.25, repeat: Infinity, ease: "easeInOut" }
                  : { duration: 0.2 }
              }
            >
              <div className="pointer-events-none absolute inset-0 noise-overlay opacity-25 mix-blend-overlay" />
              <div
                className={cn(
                  "pointer-events-none absolute -inset-1 rounded-2xl opacity-0 transition-opacity",
                  f.id === "humans" && "bg-gradient-to-br from-cyber-cyan/20 to-transparent",
                  f.id === "orcs" && "bg-gradient-to-br from-magenta/25 to-transparent",
                  f.id === "dwarves" && "bg-gradient-to-br from-toxic/20 to-transparent",
                  selected && "opacity-100",
                )}
              />
              <div className="relative space-y-2">
                <p
                  className={cn(
                    "font-display text-2xl font-bold uppercase tracking-wide",
                    f.id === "humans" && "text-cyber-cyan text-glow-cyan",
                    f.id === "orcs" && "text-magenta text-glow-magenta",
                    f.id === "dwarves" && "text-toxic",
                  )}
                >
                  {f.title}
                </p>
                <p className="font-sans text-sm leading-relaxed text-foreground-muted">
                  {f.blurb}
                </p>
              </div>
              {selected ? (
                <motion.span
                  layoutId="faction-lock-strip"
                  className="absolute bottom-3 right-3 rounded-full border border-border-glass bg-surface/90 px-2 py-0.5 font-mono text-[9px] uppercase tracking-wider text-foreground"
                  initial={{ opacity: 0, y: 6 }}
                  animate={{ opacity: 1, y: 0 }}
                >
                  Eingerastet
                </motion.span>
              ) : null}
            </motion.button>
          );
        })}
      </motion.div>
      {selectedFaction ? (
        <motion.div variants={itemReveal} className="flex justify-center pt-6">
          <motion.button
            type="button"
            whileHover={{ scale: 1.04 }}
            whileTap={{ scale: 0.97 }}
            onClick={() => enterRealmBoard()}
            className="rounded-full border border-toxic/40 bg-toxic/15 px-10 py-3 font-display text-sm font-bold uppercase tracking-wide text-toxic ring-1 ring-white/10"
          >
            Ins Grid starten
          </motion.button>
        </motion.div>
      ) : null}
    </motion.div>
  );
}
