import { motion, useReducedMotion } from "framer-motion";
import { useAcademyStore } from "../../../../store/academyStore";
import { useTranslation } from "../../../../i18n/useTranslation";

export function LanguageToggle() {
  const locale = useAcademyStore((s) => s.locale);
  const setLocale = useAcademyStore((s) => s.setLocale);
  const reduceMotion = useReducedMotion();
  const t = useTranslation();

  return (
    <div className="mt-4 inline-flex items-center gap-2 rounded-md border border-cyan-400/35 bg-slate-950/70 p-1">
      {(["de", "en"] as const).map((nextLocale) => {
        const active = locale === nextLocale;
        const label = nextLocale === "de" ? t.ui.localeDe : t.ui.localeEn;
        return (
          <button
            key={nextLocale}
            type="button"
            onClick={() => setLocale(nextLocale)}
            className={`relative overflow-hidden rounded px-2 py-1 text-[10px] font-semibold uppercase tracking-[0.14em] ${
              active ? "text-slate-950" : "text-cyan-200"
            }`}
          >
            {active ? (
              <motion.span
                className="absolute inset-0 rounded bg-cyan-300"
                layoutId="academy-locale-pill"
                transition={reduceMotion ? { duration: 0 } : { duration: 0.22, ease: "easeOut" }}
              />
            ) : null}
            <span className="relative z-10">{label}</span>
          </button>
        );
      })}
      <span
        className="inline-flex items-center gap-1 rounded border border-cyan-300/35 bg-cyan-950/25 px-2 py-1 text-[9px] uppercase tracking-[0.14em] text-cyan-200"
        style={{ fontFamily: '"JetBrains Mono", monospace' }}
      >
        <span className="h-1.5 w-1.5 animate-pulse rounded-full bg-cyan-300 shadow-[0_0_8px_rgb(0_229_255_/_0.6)]" />
        {t.ui.localeActive} {locale.toUpperCase()}
      </span>
    </div>
  );
}
