import type { RealtimeChannel } from "@supabase/supabase-js";
import { getSupabase } from "../supabase";
import {
  fetchCodesnapServerNowMs,
  resolveActiveGlobalLiveEvent,
  type ResolvedGlobalLiveEvent,
} from "../globalEventEngine";

export type GlobalEventSnapshot = {
  serverTimeOffsetMs: number;
  globalLiveEvent: ResolvedGlobalLiveEvent | null;
};

/**
 * Fetch current global event using server-clock RPC alignment
 */
export async function fetchGlobalEventSnapshot(): Promise<GlobalEventSnapshot> {
  const sb = getSupabase();
  if (!sb) {
    return { serverTimeOffsetMs: 0, globalLiveEvent: null };
  }
  const serverMs = await fetchCodesnapServerNowMs(sb);
  if (serverMs == null) {
    return { serverTimeOffsetMs: 0, globalLiveEvent: null };
  }
  return {
    serverTimeOffsetMs: serverMs - Date.now(),
    globalLiveEvent: resolveActiveGlobalLiveEvent(serverMs),
  };
}

/**
 * Subscribe to global event related realtime updates
 * Caller owns unsubscribe lifecycle
 */
export function subscribeGlobalEventUpdates(onChange: () => void): (() => void) | null {
  const sb = getSupabase();
  if (!sb) return null;

  const channels: RealtimeChannel[] = [];

  const seasonChannel = sb
    .channel("codesnap-global-events")
    .on(
      "postgres_changes",
      { event: "*", schema: "public", table: "season_history" },
      () => {
        onChange();
      },
    )
    .subscribe();
  channels.push(seasonChannel);

  const factionChannel = sb
    .channel("codesnap-faction-war")
    .on(
      "postgres_changes",
      { event: "*", schema: "public", table: "faction_xp_war_totals_live" },
      () => {
        onChange();
      },
    )
    .subscribe();
  channels.push(factionChannel);

  return () => {
    for (const channel of channels) {
      void sb.removeChannel(channel);
    }
  };
}
