import type { StateCreator } from "zustand";
import { applySm2, computeNextReviewTimestamp, flashRatingToSm2, selectDueFlashcardIds, SM2_DEFAULT_STATE } from "../../lib/sm2";
import { MAX_EQUIPPED_PERKS } from "../../data/perks";
import { computeLifetimeXp } from "../../lib/xpCurve";
import {
  DEFAULT_TERMINAL_THEME_ID,
  getTerminalThemeById,
  isTerminalThemeUnlocked,
  prestigeRankIndexFromLifetimeXp,
} from "../../data/terminalThemes";
import { markBootCompletedSession, readBootCompletedSession } from "../../lib/services/bootService";
import type { AppState, UserProgress } from "../useAppStore";

const initialProgress: UserProgress = {
  displayName: "Nico",
  level: 12,
  xpCurrent: 1840,
  xpToNext: 2400,
  streakDays: 0,
};

export interface CoreSlice {
  progress: AppState["progress"];
  operatorHandle: AppState["operatorHandle"];
  onboardingCompleted: AppState["onboardingCompleted"];
  onboardingVisible: AppState["onboardingVisible"];
  onboardingStep: AppState["onboardingStep"];
  onboardingHandleDraft: AppState["onboardingHandleDraft"];
  careerPath: AppState["careerPath"];
  setOnboardingStep: AppState["setOnboardingStep"];
  setOnboardingHandleDraft: AppState["setOnboardingHandleDraft"];
  setCareerPath: AppState["setCareerPath"];
  beginOnboarding: AppState["beginOnboarding"];
  finishOnboarding: AppState["finishOnboarding"];
  operatorWelcomePulseEmitted: AppState["operatorWelcomePulseEmitted"];
  welcomeProtocolSeen: AppState["welcomeProtocolSeen"];
  completeWelcomeProtocol: AppState["completeWelcomeProtocol"];
  flashcardProgress: AppState["flashcardProgress"];
  flashcardTotalReviews: AppState["flashcardTotalReviews"];
  getDueFlashcardQueue: AppState["getDueFlashcardQueue"];
  answerFlashcard: AppState["answerFlashcard"];
  feedbackEnabled: AppState["feedbackEnabled"];
  toggleFeedbackEnabled: AppState["toggleFeedbackEnabled"];
  audioActivityTick: AppState["audioActivityTick"];
  bumpAudioActivity: AppState["bumpAudioActivity"];
  ammoDropImportFeed: AppState["ammoDropImportFeed"];
  appendAmmoDropImportLog: AppState["appendAmmoDropImportLog"];
  clearAmmoDropImportLog: AppState["clearAmmoDropImportLog"];
  events: AppState["events"];
  legacyPoints: AppState["legacyPoints"];
  legacyTranscendCount: AppState["legacyTranscendCount"];
  legacyXpBoostMultiplier: AppState["legacyXpBoostMultiplier"];
  applyLegacySnapshot: AppState["applyLegacySnapshot"];
  rigTerminalThemeId: AppState["rigTerminalThemeId"];
  rigScanlineDial: AppState["rigScanlineDial"];
  setRigTerminalThemeId: AppState["setRigTerminalThemeId"];
  setRigScanlineDial: AppState["setRigScanlineDial"];
  hasBooted: AppState["hasBooted"];
  completeSystemBoot: AppState["completeSystemBoot"];
  selectedExamId: AppState["selectedExamId"];
  setSelectedExamId: AppState["setSelectedExamId"];
  selectedPerkIds: AppState["selectedPerkIds"];
  togglePerk: AppState["togglePerk"];
  seasonLegacyArtifacts: AppState["seasonLegacyArtifacts"];
  helpdeskClears: AppState["helpdeskClears"];
  recordHelpdeskDiagnosticClear: AppState["recordHelpdeskDiagnosticClear"];
}

export const createCoreSlice: StateCreator<AppState, [], [], CoreSlice> = (set, get) => ({
  progress: initialProgress,
  operatorHandle: null,
  onboardingCompleted: false,
  onboardingVisible: false,
  onboardingStep: "boot",
  onboardingHandleDraft: "",
  careerPath: null,
  setOnboardingStep: (step) => set({ onboardingStep: step }),
  setOnboardingHandleDraft: (value) => set({ onboardingHandleDraft: value }),
  setCareerPath: (value) => set({ careerPath: value }),
  beginOnboarding: () =>
    set({
      onboardingVisible: true,
      onboardingStep: "boot",
      onboardingHandleDraft: get().operatorHandle ?? "",
    }),
  finishOnboarding: () =>
    set({
      onboardingCompleted: true,
      onboardingVisible: false,
      onboardingStep: "arrival",
    }),
  operatorWelcomePulseEmitted: false,
  welcomeProtocolSeen: true,
  completeWelcomeProtocol: () => set({ welcomeProtocolSeen: true }),
  flashcardProgress: {},
  flashcardTotalReviews: 0,
  getDueFlashcardQueue: () => selectDueFlashcardIds(get().flashcardProgress),
  answerFlashcard: (quality) => {
    const queue = get().getDueFlashcardQueue();
    const id = queue[0];
    if (!id) return;
    const xpMap = { again: 4, hard: 8, good: 15, easy: 22 } as const;
    const xp = xpMap[quality];
    const raw = get().flashcardProgress[id];
    const prev = raw ? { ef: raw.ef, interval: raw.interval, repetitions: raw.repetitions } : SM2_DEFAULT_STATE;
    const sm2q = flashRatingToSm2(quality);
    const nextSm2 = applySm2(prev, sm2q);
    const nextReviewDate = computeNextReviewTimestamp(nextSm2.interval);
    set({
      flashcardProgress: {
        ...get().flashcardProgress,
        [id]: { ...nextSm2, nextReviewDate },
      },
      flashcardTotalReviews: get().flashcardTotalReviews + 1,
    });
    get().awardGlobalXp(xp);
    get().registerDailyGrindActivity("flashcard_reviews", 1);
  },
  feedbackEnabled: true,
  toggleFeedbackEnabled: () => set((s) => ({ feedbackEnabled: !s.feedbackEnabled })),
  audioActivityTick: 0,
  bumpAudioActivity: () => set((s) => ({ audioActivityTick: s.audioActivityTick + 1 })),
  ammoDropImportFeed: [],
  appendAmmoDropImportLog: (line) =>
    set((s) => ({
      ammoDropImportFeed: [...s.ammoDropImportFeed, line].slice(-120),
    })),
  clearAmmoDropImportLog: () => set({ ammoDropImportFeed: [] }),
  events: {
    raidDropRateScale: 1,
    globalLore: { totalGlobalXp: 0, unlockedLoreIds: [] },
    globalFrictionAvg: 0,
    claimedOutbreakRewardIds: [],
  },
  legacyPoints: 0,
  legacyTranscendCount: 0,
  legacyXpBoostMultiplier: 1,
  applyLegacySnapshot: (next) =>
    set({
      legacyPoints: Math.max(0, Math.floor(next.points)),
      legacyTranscendCount: Math.max(0, Math.floor(next.count)),
      legacyXpBoostMultiplier: Math.max(1, Math.min(1.6, 1 + Math.max(0, Math.floor(next.count)) * 0.05)),
    }),
  rigTerminalThemeId: DEFAULT_TERMINAL_THEME_ID,
  rigScanlineDial: 50,
  setRigTerminalThemeId: (id) => {
    const life = computeLifetimeXp(get().userLevel, get().globalXP);
    const pIdx = prestigeRankIndexFromLifetimeXp(life);
    const theme = getTerminalThemeById(id);
    if (!theme || !isTerminalThemeUnlocked(theme, pIdx)) return;
    set({ rigTerminalThemeId: id });
  },
  setRigScanlineDial: (value) => {
    const n = Math.max(0, Math.min(100, Math.round(Number(value) || 0)));
    set({ rigScanlineDial: n });
  },
  hasBooted: readBootCompletedSession(),
  completeSystemBoot: () => {
    markBootCompletedSession();
    set({ hasBooted: true });
    get().reconcileDailyLedger();
  },
  selectedExamId: "AP1",
  setSelectedExamId: (id) => set({ selectedExamId: id }),
  selectedPerkIds: [],
  togglePerk: (id) => {
    const current = get().selectedPerkIds;
    if (current.includes(id)) {
      set({ selectedPerkIds: current.filter((p) => p !== id) });
      return;
    }
    if (current.length >= MAX_EQUIPPED_PERKS) return;
    set({ selectedPerkIds: [...current, id] });
  },
  seasonLegacyArtifacts: [],
  helpdeskClears: 0,
  recordHelpdeskDiagnosticClear: () => {
    set({ helpdeskClears: get().helpdeskClears + 1 });
    get().tryUnlockAchievements();
  },
});
