import { useEffect } from "react";
import { useAppStore } from "../store/useAppStore";

const REFRESH_MS = 42_000;

/** Phase 52 — periodischer Server-Zeit-Check für Live-Events (leichtgewichtig) */
export function useGlobalLiveEventTick() {
  const hasBooted = useAppStore((s) => s.hasBooted);
  const authReady = useAppStore((s) => s.authReady);
  const authUser = useAppStore((s) => s.authUser);
  const refreshGlobalLiveEvent = useAppStore((s) => s.refreshGlobalLiveEvent);

  useEffect(() => {
    if (!hasBooted || !authReady || !authUser) return;
    void refreshGlobalLiveEvent();
    const id = window.setInterval(() => {
      void refreshGlobalLiveEvent();
    }, REFRESH_MS);
    const onVis = () => {
      if (document.visibilityState === "visible") void refreshGlobalLiveEvent();
    };
    document.addEventListener("visibilitychange", onVis);
    return () => {
      window.clearInterval(id);
      document.removeEventListener("visibilitychange", onVis);
    };
  }, [authReady, authUser, hasBooted, refreshGlobalLiveEvent]);
}
