type LeagueTier = "Bronze" | "Silver" | "Gold" | "Platinum" | "Diamond" | "Master";

type LeagueBadgeProps = {
  league: LeagueTier;
};

const STYLE_BY_LEAGUE: Record<LeagueTier, { border: string; bg: string; text: string; glow: string }> = {
  Bronze: {
    border: "border-amber-700/60",
    bg: "bg-amber-950/35",
    text: "text-amber-200",
    glow: "shadow-[0_0_8px_rgb(217_119_6_/_0.3)]",
  },
  Silver: {
    border: "border-slate-400/60",
    bg: "bg-slate-900/55",
    text: "text-slate-200",
    glow: "shadow-[0_0_10px_rgb(148_163_184_/_0.3)]",
  },
  Gold: {
    border: "border-yellow-400/70",
    bg: "bg-yellow-950/35",
    text: "text-yellow-200",
    glow: "shadow-[0_0_12px_rgb(250_204_21_/_0.35)]",
  },
  Platinum: {
    border: "border-cyan-300/70",
    bg: "bg-cyan-950/25",
    text: "text-cyan-100",
    glow: "shadow-[0_0_14px_rgb(103_232_249_/_0.35)]",
  },
  Diamond: {
    border: "border-fuchsia-300/70",
    bg: "bg-fuchsia-950/30",
    text: "text-fuchsia-100",
    glow: "shadow-[0_0_16px_rgb(217_70_239_/_0.42)]",
  },
  Master: {
    border: "border-cyan-300/80",
    bg: "bg-slate-900/65",
    text: "text-cyan-50",
    glow: "shadow-[0_0_18px_rgb(34_211_238_/_0.45)]",
  },
};

export function LeagueBadge({ league }: LeagueBadgeProps) {
  const style = STYLE_BY_LEAGUE[league];
  return (
    <div className={`inline-flex items-center gap-2 rounded-md border px-2.5 py-1.5 ${style.border} ${style.bg} ${style.glow}`}>
      <span className="text-[10px] uppercase tracking-[0.16em] text-slate-300">League</span>
      <span className={`text-[11px] font-semibold uppercase tracking-[0.14em] ${style.text}`}>{league}</span>
    </div>
  );
}
