import { cn } from "../../lib/cn";
import { CODESNAP_LOGO_PATH } from "../../lib/brandAssets";

export function CodeSnapLogo({
  className,
  heightClass = "h-9",
}: {
  className?: string;
  /** Feste Höhe für scharfe SVG-Darstellung */
  heightClass?: string;
}) {
  return (
    <img
      src={CODESNAP_LOGO_PATH}
      alt="CodeSnap"
      width={512}
      height={512}
      decoding="async"
      draggable={false}
      className={cn("w-auto max-w-[min(200px,42vw)] object-contain", heightClass, className)}
      style={{ imageRendering: "auto" }}
    />
  );
}
