import { motion, useReducedMotion } from "framer-motion";
import { useMemo, useState } from "react";
import { buildWebBasicsJediPath } from "../../../../data/factories/webBasicsFactory";
import { buildCSharpActionContracts, simulateCSharpClickEvent } from "../../../../services/logic/CSharpActionHandler";
import { createDroid, hasDroidAbility, type BaseDroid, type DroidKind, type DroidSkill } from "../../../../services/logic/DroidModels";
import { useTranslation } from "../../../../i18n/useTranslation";

type EliteSandboxProps = {
  unlocked: boolean;
  preferredDialect?: SqlDialect;
  onDialectChange?: (dialect: SqlDialect) => void;
  preferredTrack?: "sql" | "web_basics" | "c_sharp";
  onTrackChange?: (track: "sql" | "web_basics" | "c_sharp") => void;
};

type TempTable = {
  columns: string[];
  rows: string[][];
};

type SqlDialect = "postgresql" | "mysql" | "sqlite";
type SandboxTables = Record<string, TempTable>;
type SandboxRole = "analyst" | "manager" | "admin";
type SandboxView = {
  sourceTable: string;
  columns: string[];
};
type TransactionState = {
  active: boolean;
  baseTables: SandboxTables;
  workingTables: SandboxTables;
  savepoints: Record<string, SandboxTables>;
};
type RolePermissionMap = Record<SandboxRole, string[]>;
type SandboxMode = "sql" | "web_basics";
type DroidBindingState = {
  model: string;
  powerLevel: number;
  transitionTargets: string[];
};

function normalizeSql(sql: string): string {
  return sql.trim().replace(/;$/, "");
}

export function dialectStarter(dialect: SqlDialect): string {
  if (dialect === "mysql") return "CREATE TEMPORARY TABLE sparring (name, score)";
  if (dialect === "sqlite") return "CREATE TEMP TABLE sparring (name, score)";
  return "CREATE TEMP TABLE sparring (name, score)";
}

export function dialectSyntaxError(cleanSql: string, dialect: SqlDialect): string | null {
  const sql = cleanSql.toUpperCase();
  if (dialect === "mysql") {
    if (/CREATE\s+TEMP\s+TABLE/.test(sql)) return "mysql expects CREATE TEMPORARY TABLE";
  }
  if (dialect === "sqlite") {
    if (/ALTER\s+TABLE\s+\w+\s+DROP\s+COLUMN/i.test(cleanSql)) return "sqlite sandbox blocks DROP COLUMN in training mode";
  }
  if (dialect === "postgresql") {
    if (/REPLACE\s+INTO/i.test(sql)) return "postgresql uses INSERT ON CONFLICT instead of REPLACE";
  }
  return null;
}

export function translateSqlToDialect(sql: string, targetDialect: SqlDialect): string {
  let translated = sql.trim();
  if (targetDialect === "mysql") {
    translated = translated.replace(/CREATE\s+TEMP\s+TABLE/gi, "CREATE TEMPORARY TABLE");
    translated = translated.replace(/INSERT\s+INTO/gi, "REPLACE INTO");
  } else if (targetDialect === "postgresql") {
    translated = translated.replace(/CREATE\s+TEMPORARY\s+TABLE/gi, "CREATE TEMP TABLE");
    translated = translated.replace(/REPLACE\s+INTO/gi, "INSERT INTO");
  } else {
    translated = translated.replace(/CREATE\s+TEMPORARY\s+TABLE/gi, "CREATE TEMP TABLE");
    translated = translated.replace(/REPLACE\s+INTO/gi, "INSERT INTO");
  }
  return translated;
}

type DialectWarning = {
  dialect: SqlDialect;
  label: string;
};

export function collectDialectWarnings(sql: string): DialectWarning[] {
  const upper = sql.toUpperCase();
  const warnings: DialectWarning[] = [];
  if (/\bALTER\s+TABLE\b/.test(upper) && /\bDROP\s+COLUMN\b/.test(upper)) {
    warnings.push({ dialect: "sqlite", label: "SQLite training guard DROP COLUMN restricted" });
  }
  if (/\bREPLACE\s+INTO\b/.test(upper)) {
    warnings.push({ dialect: "postgresql", label: "PostgreSQL prefers INSERT ON CONFLICT flow" });
  }
  if (/\bCREATE\s+TEMP\s+TABLE\b/.test(upper)) {
    warnings.push({ dialect: "mysql", label: "MySQL expects TEMPORARY keyword" });
  }
  return warnings;
}

function cloneTables(tables: SandboxTables): SandboxTables {
  return JSON.parse(JSON.stringify(tables)) as SandboxTables;
}

export function createTransactionState(tables: SandboxTables): TransactionState {
  const snapshot = cloneTables(tables);
  return {
    active: false,
    baseTables: snapshot,
    workingTables: snapshot,
    savepoints: {},
  };
}

function normalizeTableName(tableName: string): string {
  return tableName.trim().toLowerCase();
}

const RESTRICTED_TABLES = new Set(["salary", "admin_data"]);

function defaultRolePermissions(): RolePermissionMap {
  return {
    analyst: ["sparring"],
    manager: ["sparring", "salary"],
    admin: ["sparring", "salary", "admin_data"],
  };
}

export function applyGrantRevokeCommand(
  sql: string,
  rolePermissions: RolePermissionMap,
): { nextPermissions: RolePermissionMap; message: string } | null {
  const grantMatch = normalizeSql(sql).match(/^GRANT\s+SELECT\s+ON\s+([a-z_][a-z0-9_]*)\s+TO\s+(analyst|manager|admin)$/i);
  if (grantMatch) {
    const table = normalizeTableName(grantMatch[1] ?? "");
    const role = (grantMatch[2] ?? "analyst").toLowerCase() as SandboxRole;
    const nextPermissions: RolePermissionMap = {
      ...rolePermissions,
      [role]: Array.from(new Set([...rolePermissions[role], table])),
    };
    return { nextPermissions, message: `grant applied ${role} can access ${table}` };
  }
  const revokeMatch = normalizeSql(sql).match(/^REVOKE\s+SELECT\s+ON\s+([a-z_][a-z0-9_]*)\s+FROM\s+(analyst|manager|admin)$/i);
  if (revokeMatch) {
    const table = normalizeTableName(revokeMatch[1] ?? "");
    const role = (revokeMatch[2] ?? "analyst").toLowerCase() as SandboxRole;
    const nextPermissions: RolePermissionMap = {
      ...rolePermissions,
      [role]: rolePermissions[role].filter((entry) => entry !== table),
    };
    return { nextPermissions, message: `revoke applied ${role} lost access to ${table}` };
  }
  return null;
}

export function canRoleAccessTable(rolePermissions: RolePermissionMap, role: SandboxRole, tableName: string): boolean {
  const table = normalizeTableName(tableName);
  if (!RESTRICTED_TABLES.has(table)) return true;
  return rolePermissions[role].includes(table);
}

export function applyViewCommand(
  sql: string,
  views: Record<string, SandboxView>,
  tables: SandboxTables,
): { nextViews: Record<string, SandboxView>; message: string } | null {
  const createMatch = normalizeSql(sql).match(
    /^CREATE\s+VIEW\s+([a-z_][a-z0-9_]*)\s+AS\s+SELECT\s+(.+)\s+FROM\s+([a-z_][a-z0-9_]*)$/i,
  );
  if (createMatch) {
    const viewName = normalizeTableName(createMatch[1] ?? "");
    const columnSpec = (createMatch[2] ?? "").trim();
    const sourceTable = normalizeTableName(createMatch[3] ?? "");
    const source = tables[sourceTable];
    if (!source) return { nextViews: views, message: `source table ${sourceTable} not found for view` };
    const columns =
      columnSpec === "*"
        ? [...source.columns]
        : columnSpec
            .split(",")
            .map((entry) => normalizeTableName(entry))
            .filter((entry) => source.columns.includes(entry));
    if (columns.length === 0) return { nextViews: views, message: "view create failed no valid columns selected" };
    return {
      nextViews: { ...views, [viewName]: { sourceTable, columns } },
      message: `view ${viewName} created on ${sourceTable}`,
    };
  }
  const dropMatch = normalizeSql(sql).match(/^DROP\s+VIEW\s+([a-z_][a-z0-9_]*)$/i);
  if (dropMatch) {
    const viewName = normalizeTableName(dropMatch[1] ?? "");
    if (!views[viewName]) return { nextViews: views, message: `view ${viewName} not found` };
    const nextViews = { ...views };
    delete nextViews[viewName];
    return { nextViews, message: `view ${viewName} dropped` };
  }
  return null;
}

export function runTransactionCommand(command: string, tx: TransactionState, committed: SandboxTables): {
  tx: TransactionState;
  committed: SandboxTables;
  message: string;
} {
  const clean = normalizeSql(command).toUpperCase();
  if (clean === "BEGIN") {
    const base = cloneTables(committed);
    return {
      committed,
      tx: { active: true, baseTables: base, workingTables: cloneTables(base), savepoints: {} },
      message: "transaction begin pending state active",
    };
  }
  if (clean === "COMMIT") {
    if (!tx.active) return { tx, committed, message: "no active transaction for commit" };
    return {
      committed: cloneTables(tx.workingTables),
      tx: createTransactionState(tx.workingTables),
      message: "transaction committed pending state cleared",
    };
  }
  if (clean === "ROLLBACK") {
    if (!tx.active) return { tx, committed, message: "no active transaction for rollback" };
    return {
      committed,
      tx: createTransactionState(tx.baseTables),
      message: "transaction rollback restored snapshot",
    };
  }
  const savepointMatch = clean.match(/^SAVEPOINT\s+([A-Z_][A-Z0-9_]*)$/);
  if (savepointMatch && tx.active) {
    const id = savepointMatch[1] ?? "SP";
    return {
      committed,
      tx: { ...tx, savepoints: { ...tx.savepoints, [id]: cloneTables(tx.workingTables) } },
      message: `savepoint ${id.toLowerCase()} captured`,
    };
  }
  const rollbackToMatch = clean.match(/^ROLLBACK\s+TO\s+([A-Z_][A-Z0-9_]*)$/);
  if (rollbackToMatch && tx.active) {
    const id = rollbackToMatch[1] ?? "";
    const target = tx.savepoints[id];
    if (!target) return { tx, committed, message: `savepoint ${id.toLowerCase()} missing` };
    return {
      committed,
      tx: { ...tx, workingTables: cloneTables(target) },
      message: `rollback to ${id.toLowerCase()} restored partial changes`,
    };
  }
  return { tx, committed, message: "" };
}

export function renderWebPreviewDocument(html: string, css: string, cssVars: Record<string, string> = {}): string {
  const cssVarBlock = `:root { ${Object.entries(cssVars)
    .map(([key, value]) => `${key}: ${value};`)
    .join(" ")} }`;
  return (
    "<!doctype html><html><head><meta charset='utf-8'/>" +
    "<meta name='viewport' content='width=device-width,initial-scale=1'/>" +
    "<style>" +
    "html,body{margin:0;min-height:100%;background:#020617;color:#dbeafe;font-family:JetBrains Mono,monospace}" +
    "body::before{content:'';position:fixed;inset:0;background:repeating-linear-gradient(0deg,transparent 0 2px,#22d3ee11 2px 4px);pointer-events:none}" +
    cssVarBlock +
    css +
    "</style></head><body>" +
    html +
    "</body></html>"
  );
}

export function parseDroidObjectBinding(source: string, transitionIds: string[]): DroidBindingState | null {
  const modelMatch = source.match(/new\s+Droid\s*\(\s*["']([^"']+)["']/i);
  const powerMatch = source.match(/\bPowerLevel\s*=\s*(\d{1,3})\b/i);
  if (!modelMatch) return null;
  const rawPower = powerMatch ? Number(powerMatch[1]) : 0;
  return {
    model: modelMatch[1] ?? "R2 Unit",
    powerLevel: Math.max(0, Math.min(100, rawPower)),
    transitionTargets: transitionIds,
  };
}

export function EliteSandbox({
  unlocked,
  preferredDialect = "postgresql",
  onDialectChange,
  preferredTrack = "sql",
  onTrackChange,
}: EliteSandboxProps) {
  const t = useTranslation();
  const reduceMotion = useReducedMotion();
  const [dialect, setDialect] = useState<SqlDialect>(preferredDialect);
  const [mode, setMode] = useState<SandboxMode>(preferredTrack === "web_basics" ? "web_basics" : "sql");
  const [sql, setSql] = useState(dialectStarter(preferredDialect));
  const [tables, setTables] = useState<Record<string, TempTable>>({});
  const [tx, setTx] = useState<TransactionState>(() => createTransactionState({}));
  const [result, setResult] = useState<string>("ready");
  const [selectedTable, setSelectedTable] = useState("");
  const [comparisonOpen, setComparisonOpen] = useState(false);
  const [views, setViews] = useState<Record<string, SandboxView>>({});
  const [activeRole, setActiveRole] = useState<SandboxRole>("analyst");
  const [rolePermissions, setRolePermissions] = useState<RolePermissionMap>(() => defaultRolePermissions());
  const webPath = useMemo(() => buildWebBasicsJediPath(), []);
  const [webStepId, setWebStepId] = useState(webPath.steps[0]?.id ?? "");
  const selectedWebStep = webPath.steps.find((step) => step.id === webStepId) ?? webPath.steps[0];
  const [htmlCode, setHtmlCode] = useState(selectedWebStep?.starterHtml ?? "");
  const [cssCode, setCssCode] = useState(selectedWebStep?.starterCss ?? "");
  const [webCssVars, setWebCssVars] = useState<Record<string, string>>({});
  const [webPulse, setWebPulse] = useState(0);
  const [armyRegistry, setArmyRegistry] = useState<BaseDroid[]>([]);
  const [armyModelInput, setArmyModelInput] = useState("BX Unit");
  const [armyPowerInput, setArmyPowerInput] = useState(70);
  const [armyKind, setArmyKind] = useState<DroidKind>("battle");
  const [selectedArmyIndex, setSelectedArmyIndex] = useState(0);
  const csharpContracts = useMemo(() => buildCSharpActionContracts(selectedWebStep?.transitionIds ?? []), [selectedWebStep]);
  const webPreviewDoc = useMemo(() => renderWebPreviewDocument(htmlCode, cssCode, webCssVars), [htmlCode, cssCode, webCssVars]);

  const canRun = useMemo(() => unlocked && sql.trim().length > 0, [unlocked, sql]);
  const comparisonDialects = useMemo(
    () => (["postgresql", "mysql", "sqlite"] as SqlDialect[]).filter((entry) => entry !== dialect),
    [dialect],
  );
  const warnings = useMemo(() => collectDialectWarnings(sql), [sql]);
  const droidBinding = useMemo(
    () => parseDroidObjectBinding(`${htmlCode}\n${cssCode}`, selectedWebStep?.transitionIds ?? []),
    [htmlCode, cssCode, selectedWebStep],
  );
  const activeTables = tx.active ? tx.workingTables : tables;
  const selectedTableData = selectedTable ? activeTables[selectedTable] : undefined;

  function runSql() {
    if (mode !== "sql") return;
    const clean = normalizeSql(sql);
    const txCommandResult = runTransactionCommand(clean, tx, tables);
    if (txCommandResult.message) {
      setTables(txCommandResult.committed);
      setTx(txCommandResult.tx);
      setResult(txCommandResult.message);
      return;
    }
    const roleCommand = applyGrantRevokeCommand(clean, rolePermissions);
    if (roleCommand) {
      setRolePermissions(roleCommand.nextPermissions);
      setResult(roleCommand.message);
      return;
    }
    const viewCommand = applyViewCommand(clean, views, activeTables);
    if (viewCommand) {
      setViews(viewCommand.nextViews);
      setResult(viewCommand.message);
      return;
    }
    const syntaxError = dialectSyntaxError(clean, dialect);
    if (syntaxError) {
      setResult(syntaxError);
      return;
    }
    const createMatch = clean.match(/^CREATE\s+TEMP\s+TABLE\s+([a-z_][a-z0-9_]*)\s*\((.+)\)$/i);
    const createTemporaryMatch = clean.match(/^CREATE\s+TEMPORARY\s+TABLE\s+([a-z_][a-z0-9_]*)\s*\((.+)\)$/i);
    const createResolved = createMatch ?? createTemporaryMatch;
    if (createResolved) {
      const tableName = createResolved[1] ?? "";
      const columns = (createResolved[2] ?? "")
        .split(",")
        .map((c) => c.trim())
        .filter(Boolean);
      if (!tableName || columns.length === 0) {
        setResult("invalid create syntax");
        return;
      }
      const nextTables = { ...activeTables, [tableName]: { columns, rows: [] } };
      if (tx.active) {
        setTx((prev) => ({ ...prev, workingTables: nextTables }));
      } else {
        setTables(nextTables);
      }
      setSelectedTable(tableName);
      setResult(`created ${dialect} temp table ${tableName}`);
      return;
    }

    const insertMatch = clean.match(/^INSERT\s+INTO\s+([a-z_][a-z0-9_]*)\s+VALUES\s*\((.+)\)$/i);
    if (insertMatch) {
      const tableName = insertMatch[1] ?? "";
      if (!canRoleAccessTable(rolePermissions, activeRole, tableName)) {
        setResult(`access denied ${activeRole} cannot write ${tableName}`);
        return;
      }
      const values = (insertMatch[2] ?? "")
        .split(",")
        .map((v) => v.trim().replace(/^['"]|['"]$/g, ""));
      const table = activeTables[tableName];
      if (!table) {
        setResult(`table ${tableName} not found`);
        return;
      }
      if (values.length !== table.columns.length) {
        setResult("value count does not match columns");
        return;
      }
      const nextTables = { ...activeTables, [tableName]: { ...table, rows: [...table.rows, values] } };
      if (tx.active) {
        setTx((prev) => ({ ...prev, workingTables: nextTables }));
      } else {
        setTables(nextTables);
      }
      setResult(`inserted into ${tableName}${tx.active ? " pending commit" : ""}`);
      setSelectedTable(tableName);
      return;
    }

    const selectMatch = clean.match(/^SELECT\s+\*\s+FROM\s+([a-z_][a-z0-9_]*)$/i);
    if (selectMatch) {
      const tableName = selectMatch[1] ?? "";
      const targetView = views[normalizeTableName(tableName)];
      const targetTableName = targetView?.sourceTable ?? tableName;
      if (!canRoleAccessTable(rolePermissions, activeRole, targetTableName)) {
        setResult(`access denied ${activeRole} cannot read ${tableName}`);
        return;
      }
      const table = activeTables[targetTableName];
      if (!table) {
        setResult(`table ${tableName} not found`);
        return;
      }
      const renderColumns = targetView?.columns ?? table.columns;
      const columnIndexes = renderColumns.map((column) => table.columns.indexOf(column)).filter((index) => index >= 0);
      const header = renderColumns.join(" | ");
      const body = table.rows
        .map((row) => columnIndexes.map((index) => row[index] ?? "").join(" | "))
        .join("\n");
      setSelectedTable(targetTableName);
      setResult(
        body.length > 0 ? `${header}\n${body}` : `${header}\nempty${tx.active ? "\npending transaction state" : ""}`,
      );
      return;
    }

    setResult(`only ${dialect} CREATE TEMP TABLE, INSERT INTO, SELECT * FROM supported`);
  }

  function applyWebStep(stepId: string) {
    const step = webPath.steps.find((entry) => entry.id === stepId);
    if (!step) return;
    setWebStepId(step.id);
    setHtmlCode(step.starterHtml);
    setCssCode(step.starterCss);
    setWebCssVars({});
    setResult(`web mission loaded ${step.title.toLowerCase()}`);
  }

  function download(name: string, content: string, type: string) {
    const blob = new Blob([content], { type });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = name;
    a.click();
    window.setTimeout(() => URL.revokeObjectURL(url), 500);
  }

  function exportJson() {
    const table = activeTables[selectedTable];
    if (!table) return;
    const rows = table.rows.map((values) => Object.fromEntries(table.columns.map((col, idx) => [col, values[idx] ?? null])));
    download(`${selectedTable}.json`, JSON.stringify(rows), "application/json");
  }

  function exportCsv() {
    const table = activeTables[selectedTable];
    if (!table) return;
    const header = table.columns.join(",");
    const body = table.rows.map((row) => row.map((cell) => `"${String(cell).replaceAll('"', '""')}"`).join(",")).join("\n");
    download(`${selectedTable}.csv`, `${header}\n${body}`, "text/csv;charset=utf-8");
  }

  return (
    <section className="rounded-xl border border-fuchsia-400/30 bg-slate-950/70 p-6">
      <div className="slide-label mb-3">{t.ui.eliteSandbox}</div>
      {!unlocked ? (
        <div className="rounded-lg border border-fuchsia-300/40 bg-fuchsia-950/20 p-4">
          <p className="text-sm font-semibold text-fuchsia-200">{t.ui.eliteSandboxLocked}</p>
          <p className="mt-1 text-xs text-fuchsia-100/90">{t.ui.eliteSandboxUnlockHint}</p>
        </div>
      ) : (
        <>
          <label className="text-[10px] uppercase tracking-[0.14em] text-fuchsia-300">{t.ui.eliteSandboxInputLabel}</label>
          <div className="mt-2 flex items-center gap-2">
            <p className="text-[10px] uppercase tracking-[0.14em] text-fuchsia-200">Module</p>
            <select
              className="rounded-md border border-fuchsia-300/45 bg-slate-900/70 px-2 py-1.5 text-[10px] uppercase tracking-[0.14em] text-fuchsia-100"
              value={mode}
              onChange={(event) => {
                const nextMode = event.target.value as SandboxMode;
                setMode(nextMode);
                onTrackChange?.(nextMode);
                setResult(nextMode === "sql" ? "sql module active" : "web basics module active");
              }}
            >
              <option value="sql">SQL Arena</option>
              <option value="web_basics">Web Basics</option>
            </select>
            <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-200">Dialect</p>
            <select
              className="rounded-md border border-cyan-300/45 bg-slate-900/70 px-2 py-1.5 text-[10px] uppercase tracking-[0.14em] text-cyan-100"
              value={dialect}
              onChange={(event) => {
                const next = event.target.value as SqlDialect;
                setDialect(next);
                setSql(dialectStarter(next));
                setResult(`dialect switched to ${next}`);
                onDialectChange?.(next);
              }}
            >
              <option value="postgresql">PostgreSQL</option>
              <option value="mysql">MySQL</option>
              <option value="sqlite">SQLite</option>
            </select>
            <p className="ml-3 text-[10px] uppercase tracking-[0.14em] text-amber-200">Role</p>
            <select
              className="rounded-md border border-amber-300/45 bg-slate-900/70 px-2 py-1.5 text-[10px] uppercase tracking-[0.14em] text-amber-100"
              value={activeRole}
              onChange={(event) => setActiveRole(event.target.value as SandboxRole)}
            >
              <option value="analyst">Analyst</option>
              <option value="manager">Manager</option>
              <option value="admin">Admin</option>
            </select>
          </div>
          {mode === "sql" ? (
            <textarea
              className="mt-2 w-full rounded-lg border border-fuchsia-300/35 bg-slate-900/75 p-3 font-mono text-xs text-fuchsia-100 outline-none"
              rows={4}
              value={sql}
              onChange={(event) => setSql(event.target.value)}
            />
          ) : (
            <motion.div
              className="mt-2 space-y-3"
              initial={false}
              animate={reduceMotion ? { opacity: 1 } : { opacity: [0.94, 1] }}
              transition={{ duration: 0.3 }}
            >
              <div className="rounded border border-cyan-300/35 bg-cyan-950/20 px-2 py-2">
                <p className="text-[10px] uppercase tracking-[0.12em] text-cyan-100">Jedi UI Path Mission</p>
                <select
                  className="mt-1 w-full rounded border border-cyan-300/35 bg-slate-900/70 px-2 py-1.5 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
                  value={selectedWebStep?.id ?? ""}
                  onChange={(event) => applyWebStep(event.target.value)}
                >
                  {webPath.steps.map((step) => (
                    <option key={step.id} value={step.id}>
                      {step.order} {step.title}
                    </option>
                  ))}
                </select>
                <p className="mt-1 text-[10px] text-cyan-50">{selectedWebStep?.mission}</p>
                <p className="mt-1 text-[10px] text-cyan-200">Concepts {selectedWebStep?.concepts.join(" | ")}</p>
                <button
                  type="button"
                  className="mt-2 rounded border border-blue-300/55 bg-blue-950/30 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-blue-100"
                  onClick={() => {
                    const transitionId = selectedWebStep?.transitionIds[0];
                    if (!transitionId) return;
                    const sim = simulateCSharpClickEvent({
                      transitionId,
                      contracts: csharpContracts,
                      existingCssVariables: webCssVars,
                    });
                    if (!sim.triggered) return;
                    setWebCssVars(sim.cssVariables);
                    setResult(`logic bridge triggered ${sim.handlerName.toLowerCase()}`);
                    setWebPulse((prev) => prev + 1);
                  }}
                >
                  Simulate CSharp click
                </button>
                <div className="mt-2 rounded border border-fuchsia-300/35 bg-fuchsia-950/20 p-2">
                  <p className="text-[10px] uppercase tracking-[0.12em] text-fuchsia-100">Army Registry</p>
                  <div className="mt-1 flex gap-2">
                    <select
                      className="rounded border border-fuchsia-300/35 bg-slate-950/75 px-2 py-1 text-[10px] text-fuchsia-100"
                      value={armyKind}
                      onChange={(event) => setArmyKind(event.target.value as DroidKind)}
                    >
                      <option value="battle">BattleDroid</option>
                      <option value="protocol">ProtocolDroid</option>
                    </select>
                    <input
                      className="rounded border border-fuchsia-300/35 bg-slate-950/75 px-2 py-1 text-[10px] text-fuchsia-100"
                      value={armyModelInput}
                      onChange={(event) => setArmyModelInput(event.target.value)}
                    />
                    <input
                      type="number"
                      min={0}
                      max={100}
                      className="w-16 rounded border border-fuchsia-300/35 bg-slate-950/75 px-2 py-1 text-[10px] text-fuchsia-100"
                      value={armyPowerInput}
                      onChange={(event) => setArmyPowerInput(Number(event.target.value))}
                    />
                    <button
                      type="button"
                      className="rounded border border-fuchsia-300/45 bg-fuchsia-950/35 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-fuchsia-100"
                      onClick={() => {
                        const next = createDroid(armyKind, armyModelInput, armyPowerInput);
                        setArmyRegistry((prev) => [...prev, next]);
                      }}
                    >
                      Add Droid
                    </button>
                  </div>
                  <button
                    type="button"
                    className="mt-2 rounded border border-cyan-300/45 bg-cyan-950/30 px-2 py-1 text-[10px] uppercase tracking-[0.12em] text-cyan-100"
                    onClick={() => {
                      const effects = armyRegistry.map((droid) => droid.ExecuteFunction());
                      const nextVars = { ...webCssVars };
                      for (const effect of effects) nextVars[effect.cssVariable] = effect.cssValue;
                      setWebCssVars(nextVars);
                      setResult(effects.map((effect) => effect.message).join(" | ") || "registry empty");
                    }}
                  >
                    Execute Functions
                  </button>
                  <div className="mt-2 space-y-1">
                    {armyRegistry.map((droid, index) => (
                      <p key={`army-${index}-${droid.model}`} className="text-[10px] text-fuchsia-100">
                        {droid.model} {droid.constructor.name} Power {droid.powerLevel}
                      </p>
                    ))}
                  </div>
                </div>
              </div>
              <textarea
                className="w-full rounded-lg border border-cyan-300/35 bg-slate-900/75 p-3 font-mono text-xs text-cyan-100 outline-none"
                rows={7}
                value={htmlCode}
                onChange={(event) => {
                  setHtmlCode(event.target.value);
                  setWebPulse((prev) => prev + 1);
                }}
              />
              <textarea
                className="w-full rounded-lg border border-fuchsia-300/35 bg-slate-900/75 p-3 font-mono text-xs text-fuchsia-100 outline-none"
                rows={8}
                value={cssCode}
                onChange={(event) => {
                  setCssCode(event.target.value);
                  setWebPulse((prev) => prev + 1);
                }}
              />
              <motion.div
                key={`web-pulse-${webPulse}`}
                className="rounded border border-cyan-300/40 bg-slate-950/80 p-2 shadow-[0_0_20px_rgb(34_211_238_/_0.25)]"
                initial={reduceMotion ? false : { opacity: 0.85, scale: 0.995 }}
                animate={reduceMotion ? { opacity: 1 } : { opacity: 1, scale: 1 }}
                transition={{ duration: 0.2 }}
              >
                <p className="text-[10px] uppercase tracking-[0.12em] text-cyan-100">Live Web Preview</p>
                <iframe title="web-basics-live-preview" className="mt-2 h-72 w-full rounded border border-cyan-300/30 bg-slate-900" srcDoc={webPreviewDoc} />
              </motion.div>
              {droidBinding ? (
                <div className="rounded border border-fuchsia-300/45 bg-fuchsia-950/20 p-2 shadow-[0_0_20px_rgb(217_70_239_/_0.22)]">
                  <p className="text-[10px] uppercase tracking-[0.12em] text-fuchsia-100">Droid Diagnostic Panel</p>
                  <p className="mt-1 text-[10px] text-fuchsia-50">Model {droidBinding.model}</p>
                  <p className="mt-1 text-[10px] text-fuchsia-200">PowerLevel {droidBinding.powerLevel}</p>
                  <p className="mt-1 text-[10px] text-fuchsia-200">
                    TransitionIds {droidBinding.transitionTargets.length > 0 ? droidBinding.transitionTargets.join(" | ") : "none"}
                  </p>
                </div>
              ) : null}
              {armyRegistry.length > 0 ? (
                <div className="rounded border border-blue-300/45 bg-blue-950/20 p-2 shadow-[0_0_20px_rgb(56_189_248_/_0.24)]">
                  <p className="text-[10px] uppercase tracking-[0.12em] text-blue-100">Polymorphic Registry View</p>
                  {armyRegistry.map((droid, index) => (
                    <p key={`poly-${index}-${droid.model}`} className="mt-1 text-[10px] text-blue-100">
                      {droid.model} {droid.constructor.name} Function {droid.ExecuteFunction().message}
                    </p>
                  ))}
                </div>
              ) : null}
              {armyRegistry.length > 0 ? (
                <div className="rounded border border-emerald-300/45 bg-emerald-950/20 p-2 shadow-[0_0_20px_rgb(16_185_129_/_0.24)]">
                  <p className="text-[10px] uppercase tracking-[0.12em] text-emerald-100">Skill Trigger Panel</p>
                  <select
                    className="mt-1 rounded border border-emerald-300/35 bg-slate-950/75 px-2 py-1 text-[10px] text-emerald-100"
                    value={selectedArmyIndex}
                    onChange={(event) => setSelectedArmyIndex(Number(event.target.value))}
                  >
                    {armyRegistry.map((droid, index) => (
                      <option key={`skill-droid-${index}-${droid.model}`} value={index}>
                        {droid.model} {droid.constructor.name}
                      </option>
                    ))}
                  </select>
                  {(() => {
                    const selected = armyRegistry[selectedArmyIndex];
                    if (!selected || !hasDroidAbility(selected)) return null;
                    const skills = selected.listSkills();
                    return (
                      <div className="mt-2 flex flex-wrap gap-1">
                        {skills.map((skill) => (
                          <button
                            key={`skill-${selected.model}-${skill}`}
                            type="button"
                            className="rounded border border-emerald-300/45 bg-emerald-950/25 px-2 py-1 text-[10px] uppercase tracking-[0.1em] text-emerald-100"
                            onClick={() => {
                              const effect = selected.PerformSkill(skill as DroidSkill);
                              setWebCssVars((prev) => ({ ...prev, [effect.cssVariable]: effect.cssValue }));
                              setResult(effect.message);
                            }}
                          >
                            {skill}
                          </button>
                        ))}
                      </div>
                    );
                  })()}
                </div>
              ) : null}
            </motion.div>
          )}
          <div className="mt-3 flex flex-wrap gap-2">
            <button
              type="button"
              className="rounded-md border border-fuchsia-300/50 bg-fuchsia-950/25 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-fuchsia-100"
              onClick={runSql}
              disabled={!canRun || mode !== "sql"}
            >
              {t.ui.eliteSandboxRun}
            </button>
            <button
              type="button"
              className="rounded-md border border-slate-500/60 bg-slate-900/70 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-slate-200"
              onClick={() => {
                setSql(dialectStarter(dialect));
                setTables({});
                setTx(createTransactionState({}));
                setViews({});
                if (selectedWebStep) {
                  setHtmlCode(selectedWebStep.starterHtml);
                  setCssCode(selectedWebStep.starterCss);
                }
                setWebCssVars({});
                setResult("ready");
              }}
            >
              {t.ui.eliteSandboxReset}
            </button>
            <select
              className="rounded-md border border-fuchsia-300/45 bg-slate-900/70 px-2 py-1.5 text-[10px] uppercase tracking-[0.14em] text-fuchsia-100"
              value={selectedTable}
              onChange={(event) => setSelectedTable(event.target.value)}
            >
              <option value="">Table</option>
              {Object.keys(activeTables).map((tableName) => (
                <option key={tableName} value={tableName}>
                  {tableName}
                </option>
              ))}
            </select>
            <button
              type="button"
              className="rounded-md border border-cyan-300/50 bg-cyan-950/25 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-cyan-100"
              onClick={exportCsv}
              disabled={!selectedTable}
            >
              Export CSV
            </button>
            <button
              type="button"
              className="rounded-md border border-cyan-300/50 bg-cyan-950/25 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-cyan-100"
              onClick={exportJson}
              disabled={!selectedTable}
            >
              Export JSON
            </button>
            <button
              type="button"
              className="rounded-md border border-cyan-300/50 bg-slate-900/70 px-3 py-1.5 text-[10px] font-semibold uppercase tracking-[0.14em] text-cyan-100"
              onClick={() => setComparisonOpen((prev) => !prev)}
            >
              {comparisonOpen ? "Hide Dialect Comparison" : "Show Dialect Comparison"}
            </button>
          </div>
          <div className="mt-2 rounded border border-amber-300/35 bg-amber-950/20 px-2 py-2">
            <p className="text-[10px] uppercase tracking-[0.12em] text-amber-100">Role Permissions</p>
            <p className="mt-1 text-[10px] text-amber-50">
              {activeRole} can access {rolePermissions[activeRole].join(" | ")}
            </p>
            <p className="mt-1 text-[10px] text-amber-100/90">Use GRANT SELECT ON salary TO analyst and REVOKE SELECT ON salary FROM analyst</p>
          </div>
          <div className="mt-2 rounded border border-cyan-300/35 bg-cyan-950/20 px-2 py-2">
            <p className="text-[10px] uppercase tracking-[0.12em] text-cyan-100">View Management</p>
            <p className="mt-1 text-[10px] text-cyan-50">Use CREATE VIEW sparring_view AS SELECT name,score FROM sparring</p>
            <p className="mt-1 text-[10px] text-cyan-100/90">Drop with DROP VIEW sparring_view</p>
            <p className="mt-1 text-[10px] text-cyan-200">Views {Object.keys(views).join(" | ") || "none"}</p>
          </div>
          {comparisonOpen ? (
            <div className="mt-3 rounded-lg border border-cyan-400/30 bg-slate-950/85 p-3">
              <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-200">Dialect Comparison</p>
              <div className="mt-2 grid gap-2 md:grid-cols-2">
                {comparisonDialects.map((engine) => (
                  <div key={engine} className="rounded border border-cyan-300/30 bg-slate-900/70 p-2">
                    <p className="text-[10px] uppercase tracking-[0.12em] text-cyan-200">{engine}</p>
                    <pre className="mt-1 overflow-x-auto whitespace-pre-wrap text-[11px] text-slate-100">
                      {translateSqlToDialect(sql, engine)}
                    </pre>
                    <div className="mt-1 flex flex-wrap gap-1">
                      {warnings
                        .filter((warning) => warning.dialect === engine)
                        .map((warning) => (
                          <span
                            key={`${engine}-${warning.label}`}
                            className="rounded border border-amber-300/50 bg-amber-950/35 px-1.5 py-0.5 text-[10px] uppercase tracking-[0.1em] text-amber-100"
                          >
                            {warning.label}
                          </span>
                        ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ) : null}
          <pre className="mt-3 whitespace-pre-wrap rounded-lg border border-fuchsia-300/35 bg-slate-950/80 p-3 text-xs text-fuchsia-100">
            {t.ui.eliteSandboxResult}: {result}
          </pre>
          {selectedTableData ? (
            <div className={`mt-3 rounded-lg border p-3 ${tx.active ? "animate-pulse border-amber-300/55 bg-amber-950/20" : "border-cyan-300/35 bg-slate-900/60"}`}>
              <p className="text-[10px] uppercase tracking-[0.14em] text-cyan-100">
                {tx.active ? "Pending State Preview" : "Committed State Preview"}
              </p>
              <p className="mt-1 text-[10px] text-slate-200">
                Table {selectedTable} rows {selectedTableData.rows.length}
              </p>
              <div className="mt-2 overflow-x-auto rounded border border-cyan-300/25">
                <table className="w-full border-collapse text-[10px] text-slate-100">
                  <thead>
                    <tr className="bg-slate-950/70">
                      {selectedTableData.columns.map((column) => (
                        <th key={`col-${column}`} className="border-b border-cyan-500/25 px-2 py-1 text-left">
                          {column}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {selectedTableData.rows.map((row, rowIndex) => (
                      <tr key={`pending-row-${rowIndex}`} className="odd:bg-slate-900/70 even:bg-slate-950/70">
                        {row.map((cell, cellIndex) => (
                          <td key={`pending-cell-${rowIndex}-${cellIndex}`} className="border-b border-cyan-500/15 px-2 py-1">
                            {cell}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          ) : null}
        </>
      )}
    </section>
  );
}
