import { ACHIEVEMENT_LIST, sanitizeAchievementIds } from "../../data/achievementSchema";
import { cn } from "../../lib/cn";
import { AchievementMedalTile } from "./AchievementMedalTile";

type AchievementCabinetProps = {
  unlockedIds: readonly string[];
  className?: string;
};

export function AchievementCabinet({ unlockedIds, className }: AchievementCabinetProps) {
  const unlocked = sanitizeAchievementIds([...unlockedIds]);
  return (
    <section className={cn("space-y-3", className)}>
      <div className="flex items-baseline justify-between gap-2 border-b border-white/[0.1] pb-2">
        <h3 className="font-mono text-[10px] font-bold uppercase tracking-[0.28em] text-foreground-muted">ACHIEVEMENTS</h3>
        <span className="font-mono text-[9px] uppercase tracking-[0.16em] text-foreground-muted/80">
          {unlocked.length}/{ACHIEVEMENT_LIST.length}
        </span>
      </div>
      <div className="grid grid-cols-3 gap-2 sm:grid-cols-4 md:grid-cols-5">
        {ACHIEVEMENT_LIST.map((def) => {
          const on = unlocked.includes(def.id);
          return (
            <div
              key={def.id}
              className={cn(
                "min-h-[5.5rem] border transition-colors",
                on
                  ? "border-white/[0.12] bg-transparent"
                  : "border-white/[0.06] bg-black/40 opacity-[0.28] grayscale",
              )}
            >
              {on ? (
                <AchievementMedalTile id={def.id} className="h-full min-h-[5.5rem] w-full border-0" />
              ) : (
                <div
                  title={def.requirement}
                  className="flex h-full min-h-[5.5rem] flex-col items-center justify-center gap-1 px-1 py-2"
                >
                  <div className="size-7 border border-dashed border-white/[0.14] bg-white/[0.02]" />
                  <span className="max-w-[5.5rem] text-center font-mono text-[7px] uppercase leading-tight tracking-[0.1em] text-foreground-muted">
                    Locked
                  </span>
                </div>
              )}
            </div>
          );
        })}
      </div>
    </section>
  );
}
