import { motion, useReducedMotion } from "framer-motion";

export function TableAnatomy() {
  const reduce = !!useReducedMotion();

  return (
    <motion.svg
      viewBox="0 0 640 260"
      className="academy-diagram"
      role="img"
      aria-label="Tabellen Anatomie mit Zeilen Spalten und Primary Key"
      initial={{ opacity: 0.84 }}
      animate={reduce ? { opacity: 0.9 } : { opacity: [0.84, 0.94, 0.84] }}
      transition={reduce ? { duration: 0 } : { duration: 4.8, repeat: Infinity, ease: "easeInOut" }}
    >
      <rect x="16" y="18" width="608" height="224" rx="16" fill="#060D19" stroke="#00E5FF" strokeOpacity="0.58" />

      <rect x="40" y="54" width="560" height="156" rx="10" fill="#071426" stroke="#FF2BD6" strokeOpacity="0.5" />
      <line x1="40" y1="88" x2="600" y2="88" className="diagram-line" />
      <line x1="140" y1="54" x2="140" y2="210" className="diagram-line" />
      <line x1="330" y1="54" x2="330" y2="210" className="diagram-line" />
      <line x1="40" y1="126" x2="600" y2="126" className="diagram-line" />
      <line x1="40" y1="164" x2="600" y2="164" className="diagram-line" />

      <text x="90" y="78" textAnchor="middle" className="diagram-title">id</text>
      <text x="235" y="78" textAnchor="middle" className="diagram-title">name</text>
      <text x="465" y="78" textAnchor="middle" className="diagram-title">makro_fokus</text>

      <text x="90" y="114" textAnchor="middle" className="diagram-sub">1</text>
      <text x="235" y="114" textAnchor="middle" className="diagram-sub">Haehnchenbrust</text>
      <text x="465" y="114" textAnchor="middle" className="diagram-sub">Protein</text>
      <text x="90" y="152" textAnchor="middle" className="diagram-sub">2</text>
      <text x="235" y="152" textAnchor="middle" className="diagram-sub">Haferflocken</text>
      <text x="465" y="152" textAnchor="middle" className="diagram-sub">Kohlenhydrate</text>
      <text x="90" y="190" textAnchor="middle" className="diagram-sub">3</text>
      <text x="235" y="190" textAnchor="middle" className="diagram-sub">Olivenoel</text>
      <text x="465" y="190" textAnchor="middle" className="diagram-sub">Fett</text>

      <motion.rect
        x="44"
        y="92"
        width="92"
        height="32"
        rx="8"
        fill="#00E5FF"
        fillOpacity={reduce ? 0.15 : 0.11}
        stroke="#00E5FF"
        strokeOpacity="0.58"
        animate={reduce ? { opacity: 0.45 } : { opacity: [0.22, 0.52, 0.22] }}
        transition={reduce ? { duration: 0 } : { duration: 3.6, repeat: Infinity, ease: "easeInOut" }}
      />

      <text x="90" y="36" textAnchor="middle" className="diagram-sub">Primary Key Zone</text>
      <text x="236" y="36" textAnchor="middle" className="diagram-sub">Spalten</text>
      <text x="560" y="232" textAnchor="end" className="diagram-sub">Zeilen laufen horizontal</text>
    </motion.svg>
  );
}
