import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useCallback, useEffect, useMemo, useState } from "react";
import { PSEUDO_LEVELS } from "../../data/pseudoLevels";
import { cn } from "../../lib/cn";
import { useAppStore } from "../../store/useAppStore";

function normalizePseudo(s: string): string {
  return s.replace(/\s+/g, " ").trim().toLowerCase();
}

export function PseudoCodeTrainer() {
  const prefersReduced = useReducedMotion();
  const unlocked = useAppStore((s) => s.pseudoUnlockedLevels);
  const completePseudoLevel = useAppStore((s) => s.completePseudoLevel);

  const [activeId, setActiveId] = useState(PSEUDO_LEVELS[0].id);
  const [drafts, setDrafts] = useState<Record<string, string>>({});
  const [consoleLines, setConsoleLines] = useState<string[]>([]);
  const [runFlash, setRunFlash] = useState(0);
  const [lastOk, setLastOk] = useState(false);
  const [lastShake, setLastShake] = useState(0);

  const active = useMemo(
    () => PSEUDO_LEVELS.find((l) => l.id === activeId) ?? PSEUDO_LEVELS[0],
    [activeId],
  );

  const code = drafts[active.id] ?? active.starterCode;

  useEffect(() => {
    setLastOk(false);
  }, [activeId]);

  useEffect(() => {
    setDrafts((d) => {
      if (d[active.id] !== undefined) return d;
      return { ...d, [active.id]: active.starterCode };
    });
  }, [active.id, active.starterCode]);

  const setCode = useCallback(
    (next: string) => setDrafts((d) => ({ ...d, [active.id]: next })),
    [active.id],
  );

  const runCode = useCallback(() => {
    setRunFlash((k) => k + 1);
    setLastOk(false);
    const norm = normalizePseudo(code);
    const needle = active.successContains.toLowerCase();
    const ok = norm.includes(needle);
    setConsoleLines((prev) => {
      const stamp = new Date().toLocaleTimeString("de-DE", {
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
      });
      const line = ok
        ? `[${stamp}] » SIM OK — Checkpoint geschrieben`
        : `[${stamp}] » SIM FEHL — Bedingung noch nicht erfüllt`;
      return [...prev.slice(-12), line];
    });
    if (ok) {
      setLastOk(true);
      completePseudoLevel(active.id);
    } else {
      setLastShake((k) => k + 1);
    }
  }, [active.id, active.successContains, code, completePseudoLevel]);

  return (
    <div className="flex min-h-[min(72vh,640px)] flex-col gap-4 lg:flex-row lg:gap-6">
      <aside className="w-full shrink-0 space-y-3 lg:w-64">
        <div>
          <p className="font-sans text-[10px] font-semibold uppercase tracking-[0.28em] text-cyber-cyan">
            Story-Modus
          </p>
          <h2 className="font-display text-xl font-bold uppercase tracking-wide text-foreground">
            Level
          </h2>
        </div>
        <nav className="flex max-h-[40vh] flex-col gap-2 overflow-y-auto pr-1 lg:max-h-none">
          {PSEUDO_LEVELS.map((lvl) => {
            const isUnlocked = unlocked.includes(lvl.id);
            const isActive = lvl.id === active.id;
            return (
              <motion.button
                key={lvl.id}
                type="button"
                layout
                disabled={!isUnlocked}
                onClick={() => isUnlocked && setActiveId(lvl.id)}
                whileTap={isUnlocked ? { scale: 0.98 } : undefined}
                className={cn(
                  "rounded-2xl border px-3 py-3 text-left font-sans text-xs transition",
                  isUnlocked
                    ? isActive
                      ? "border-cyber-cyan/55 bg-surface-muted/90 ring-1 ring-white/10"
                      : "border-border-glass bg-surface/70 text-foreground-muted hover:border-cyber-cyan/35 hover:text-foreground"
                    : "cursor-not-allowed border-border-glass/60 bg-void/80 text-foreground-muted/40",
                )}
              >
                <span className="block font-mono text-[10px] uppercase tracking-wider text-cyber-cyan/80">
                  {lvl.id.replace("pseudo-", "L")}
                </span>
                <span className="mt-1 block font-semibold text-foreground">{lvl.title}</span>
              </motion.button>
            );
          })}
        </nav>
      </aside>

      <section className="relative flex min-h-0 flex-1 flex-col overflow-hidden rounded-3xl border border-border-glass bg-surface/85 ring-1 ring-white/10 backdrop-blur-xl">
        <div className="pointer-events-none absolute inset-0 noise-overlay opacity-25" />
        <div className="pointer-events-none absolute inset-0 hud-grid opacity-20" />
        <div className="relative flex flex-1 flex-col gap-3 p-4 sm:p-5">
          <header className="space-y-1">
            <h3 className="font-display text-lg font-bold uppercase tracking-wide text-toxic">
              {active.title}
            </h3>
            <p className="font-sans text-sm text-foreground-muted">{active.briefing}</p>
          </header>

          <motion.div
            key={lastShake}
            animate={
              prefersReduced || lastShake === 0
                ? undefined
                : { x: [0, -10, 10, -7, 7, 0] }
            }
            transition={{ duration: 0.38 }}
            className="relative min-h-0 flex-1 rounded-2xl border border-white/10 bg-[#050608]/95 p-3 ring-1 ring-white/[0.06]"
          >
            <textarea
              value={code}
              onChange={(e) => setCode(e.target.value)}
              spellCheck={false}
              className="h-full min-h-[200px] w-full resize-none bg-transparent font-mono text-[13px] leading-relaxed text-cyber-cyan/95 caret-cyber-cyan outline-none sm:min-h-[260px] sm:text-sm"
              aria-label="Pseudocode-Editor"
            />
          </motion.div>

          <div className="flex flex-wrap items-center justify-between gap-3">
            <div className="min-h-[4.5rem] flex-1 rounded-xl border border-border-glass bg-void/90 px-3 py-2 font-mono text-[11px] text-foreground-muted">
              {consoleLines.length === 0 ? (
                <span className="opacity-50">Konsole bereit — Code ausführen</span>
              ) : (
                <ul className="space-y-1">
                  {consoleLines.map((line, i) => (
                    <li key={`${i}-${line.slice(0, 24)}`}>{line}</li>
                  ))}
                </ul>
              )}
            </div>
            <motion.div
              className="relative shrink-0"
              animate={
                prefersReduced
                  ? undefined
                  : lastOk
                    ? { scale: [1, 1.06, 1] }
                    : undefined
              }
              transition={{ type: "spring", stiffness: 420, damping: 18 }}
            >
              <AnimatePresence>
                {runFlash > 0 ? (
                  <motion.span
                    key={runFlash}
                    initial={{ opacity: 0.9, scale: 1.15 }}
                    animate={{ opacity: 0, scale: 1.6 }}
                    transition={{ duration: 0.35, ease: "easeOut" }}
                    className="pointer-events-none absolute inset-0 rounded-2xl bg-cyber-cyan/25 opacity-60"
                  />
                ) : null}
              </AnimatePresence>
              <motion.button
                type="button"
                onClick={runCode}
                whileTap={{ scale: 0.94 }}
                className={cn(
                  "relative overflow-hidden rounded-2xl border-2 border-cyber-cyan/70 bg-surface-muted px-6 py-3 font-display text-sm font-bold uppercase tracking-widest text-cyber-cyan",
                  "ring-1 ring-white/10 hover:border-cyber-cyan hover:bg-white/[0.04]",
                )}
              >
                Code ausführen
              </motion.button>
            </motion.div>
          </div>
        </div>
      </section>
    </div>
  );
}
